-- Poems batch 305
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0caa30ca-631e-4c52-a6a2-7924edd82187','漁父樂 君不悟','徐積','宋','宋诗','song-poetry','','[]','一酌村醪一曲歌，回看塵世足風波。',32,'全唐诗/poet.song.37000.json','["一酌村醪一曲歌，回看塵世足風波。", "憂患大，是非多，縱得榮華有幾何。"]'),
('7bf965f2-32b0-45f5-98d6-59b6886a4586','濉陽','徐積','宋','宋诗','song-poetry','','[]','嘗聞唐李氏，世號爲賢妻。',288,'全唐诗/poet.song.37000.json','["嘗聞唐李氏，世號爲賢妻。", "以力營七喪，或謂難庶幾。", "孰知蔡家婦，其事乃同之。", "豈特在中饋，無往而無儀。", "孝於其所尊，慈於其所卑。", "即知義所在，能終義所爲。", "我生至此極，我嫁逢百罹。", "其屬死略盡，其骨俱無歸。", "身爲未亡人，心乃真男兒。", "以己任其責，無忘須臾時。", "但恐事不濟，安知卹寒饑。", "乃捐奉生具，而爲送亡資。", "面不御膏沐，首不加冠笄。", "金珠鬻於市，文繡容何施。", "更無囊中裝，唯有身上衣。", "殆將截其髪，幸苟完其肌。", "所得蓋良苦，所積從細微。", "如此十年久，猶以爲支離。", "日下卜諸良，宅兆相厥宜。", "一舉十八喪，一旦得所依。", "手自植松楸，身亦沾塗泥。", "何暇裹兩足，但知勤四肢。", "居者歎於室，行者泣於歧。", "鳥亦助叫號，人思操虆梩。"]'),
('d1f943a6-4f41-40de-96f3-cbd0cbeb8390','臨卧','徐積','宋','宋诗','song-poetry','','[]','臨卧更飲一盃酒，自唱仙謠拍雙手。',32,'全唐诗/poet.song.37000.json','["臨卧更飲一盃酒，自唱仙謠拍雙手。", "春風欺醉入懷來，留下亂花香一斗。"]'),
('8a032a15-5225-4805-aa8a-cda431cd1b46','哀哀詞','徐積','宋','宋诗','song-poetry','','[]','哀哀復哀哀，哀哀至此極。',163,'全唐诗/poet.song.37000.json','["哀哀復哀哀，哀哀至此極。", "孤兒與慈母，中路忽相失。", "恍惚須臾閒，終日不復得。", "誰復坐我堂，誰復入我室。", "誰復飲兒酒，誰復哺兒食。", "兒饑復誰念，兒寒復誰卹。", "耳不聞慈語，目不見慈色。", "譬如行路人，日遠如一日。", "行人猶可期，遠道猶可追。", "天窮地盡處，一日猶可歸。", "哀哀復哀哀，此去無盡時。", "誰言生離別，不知死別離。", "君不見人已閉門鳥已棲，黄昏塚畔孤兒啼。"]'),
('4812d3aa-ee0e-4824-b2e3-f65a0a71e19f','李陽冰篆','徐積','宋','宋诗','song-poetry','','[]','書之有古篆，文之有六經。',380,'全唐诗/poet.song.37000.json','["書之有古篆，文之有六經。", "秦漢而下浸以徙，隸學基路生重扃。", "其閒述者亦世出，牛蹄之水纔一泓。", "先生之志在復古，胸中直氣何森森。", "獨乘騏驥追大朴，執縛浮銳攘欃槍。", "手中一筆千萬變，天風號令驅雷霆。", "蛇蟠蠖屈體既具，鶚立虎視勢乃成。", "剛柔伸屈有常勢，天地之道陽與陰。", "傑然出者其勢聳，嶽仞五千磨太清。", "盤然屈者非一屈，黄河九折來滄溟。", "龐然一畫勢自若，老將堅卧中軍營。", "至於一點亦有象，地丘人目天之星。", "先生大體貴淳古，輕輕重重齊權衡。", "周家太師負黼扆，高冠大旆朝王庭。", "唐虞二帝正揖讓，臯夔稷契環兩楹。", "聖人作樂有大本，剔抉淫衛完古音。", "大匠作室以規矩，悉去臲𡰈除斜撐。", "專車骨節世不朽，今乃一縱而一橫。", "巨靈以手遏大難，印入山骨磨不平。", "雄恢嚴毅不可犯，手中常握十萬兵。", "信乎創字自有說，宜必象形而象聲。", "天地之大有萬象，萬象不能遁其情。", "嗚呼篆法乃如此，大哉剛健純粹精。", "走獸之類爲麒麟，飛鳥之類爲鷦鵬。"]'),
('d800b081-483c-4b9b-b493-ca202d4a6f22','弔屈平','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭湖口君須過，爲我回頭弔屈平。',64,'全唐诗/poet.song.37000.json','["洞庭湖口君須過，爲我回頭弔屈平。", "楚國誰曾怜直道，湘江依舊寄冤聲。", "反騷義命賢揚子，作賦譏傷陋賈生。", "若是獨醒無不可，荷蓑猶可釣而耕。"]'),
('9c7810be-75ed-44a8-9739-9a1f7c309f65','重陽日訪馬存秀才席上寄崔公太守','徐積','宋','宋诗','song-poetry','','[]','區區拖損一紬袍，行到郊居力已勞。',64,'全唐诗/poet.song.37000.json','["區區拖損一紬袍，行到郊居力已勞。", "有命自知誰畏禍，無災可避謾登高。", "黄金菊滿花情薄，白玉樽深酒興豪。", "盡日使君人不至，淵明吟醉也陶陶。"]'),
('e8b15009-c521-48a9-9fdf-861768a853bf','哭彥規  其一','徐積','宋','宋诗','song-poetry','','[]','已矣哀哉死有終，青衫就木未爲窮。',64,'全唐诗/poet.song.37000.json','["已矣哀哉死有終，青衫就木未爲窮。", "義如有枉榮斯辱，事苟無邪蹇勝通。", "力致全喪關右帥，泣尋孤櫬郭西翁。", "精神入夢非生及，使我低顔愧古風。"]'),
('3f75cadb-9d59-4838-9036-da252a756d53','哭彥規  其二','徐積','宋','宋诗','song-poetry','','[]','初余視子髪垂肩，及至成童便聳然。',64,'全唐诗/poet.song.37000.json','["初余視子髪垂肩，及至成童便聳然。", "憂患纏來成白頷，聲名隨去入黄泉。", "孤甥見卹情非淺，暴骨收藏義可傳。", "多少文章零落盡，朝廷何處訪遺編。"]'),
('fe8b0747-5c0f-459c-9cda-d8d62585cb0c','哭彥規  其三','徐積','宋','宋诗','song-poetry','','[]','與君相得久忘言，晚更傾腸共豁然。',64,'全唐诗/poet.song.37000.json','["與君相得久忘言，晚更傾腸共豁然。", "剗盡丘陵平作路，决開溝澮合爲川。", "古人刎頸終相殺，世俗操心愛脇肩。", "六十老翁能有幾，却尋舊友向黄泉。"]'),
('ba11353f-28f7-4495-adc2-bd7ba5be8ec2','哭彥規  其四','徐積','宋','宋诗','song-poetry','','[]','有時半日兩敲門，語罷南窗坐北軒。',64,'全唐诗/poet.song.37000.json','["有時半日兩敲門，語罷南窗坐北軒。", "意外得文哀絕筆，理中論事酷能言。", "須知是物非無本，若論斯人自有源。", "不蹈不襲真所性，洪河自古出崑崙。"]'),
('2cbcbbd7-287d-4a46-9b05-68cfcc099124','哭彥規  其五','徐積','宋','宋诗','song-poetry','','[]','青衫伴我情彌重，白首期君事忽乖。',64,'全唐诗/poet.song.37000.json','["青衫伴我情彌重，白首期君事忽乖。", "天下若教俱好義，道傍安得有遺骸。", "且將綿蓋孤兒寢，誰折荆爲稚女釵。", "吟至此篇還索酒，更持薑桂坐寒齋。"]'),
('f9cb535e-7083-4e98-9d2e-74cd042b9129','哭彥規  其六','徐積','宋','宋诗','song-poetry','','[]','我誦千濤噴雪詩，急提筆去寫僧扉。',64,'全唐诗/poet.song.37000.json','["我誦千濤噴雪詩，急提筆去寫僧扉。", "碧蘆陰處評文坐，黄菊花時載酒隨。", "老丈爲兒親送藥，衰翁頼子少呼醫。", "最是秦中葬枯骨，不須銘墓只鎸肌。"]'),
('bc455d37-8553-462a-b396-4438ae4bac4c','哭彥規  其七','徐積','宋','宋诗','song-poetry','','[]','道傍有無車馬通，朝復莫兮秋且冬。',64,'全唐诗/poet.song.37000.json','["道傍有無車馬通，朝復莫兮秋且冬。", "草頭半折木已空，鳥啄噤兮霜與風。", "白鷗肚上殘日紅，一丘莽蒼黄昏中。", "亦有松陵怨詩否，此時誰訪談玄翁。"]'),
('30c6a383-bc8d-4fbf-9fd3-1c7a5a001f1a','贈胡大夫','徐積','宋','宋诗','song-poetry','','[]','好讀奇書好運籌，橫刀常賦玉關秋。',64,'全唐诗/poet.song.37000.json','["好讀奇書好運籌，橫刀常賦玉關秋。", "銅符正選千兵守，金印猶虛萬戶侯。", "艗趁潮來家易到，龍投池上劍難求。", "應須讀盡平蠻策，二廣封疆近吉州。"]'),
('11da5f3d-3909-4042-8f86-c19b5e6d63ca','寄呂帥  其一','徐積','宋','宋诗','song-poetry','','[]','北邊控扼重瀛州，虎視鷹揚屬壯猷。',64,'全唐诗/poet.song.37000.json','["北邊控扼重瀛州，虎視鷹揚屬壯猷。", "盡道胡人新斷臂，安知漢將欲舂喉。", "爲文法度堆青簡，奉使勳勞半白頭。", "六路全秦與全魏，不須野戰覓封侯。"]'),
('4754910e-bc3d-48f7-ac0a-7b15f2522e5f','寄呂帥  其二','徐積','宋','宋诗','song-poetry','','[]','師屯十萬建牙旗，大纛森森重使威。',64,'全唐诗/poet.song.37000.json','["師屯十萬建牙旗，大纛森森重使威。", "燕頷將軍宜繡帽，龍驤戰士愛犀衣。", "銀鎗作隊行春去，蠟炬成林校獵歸。", "更看鈴齋憑几處，文如布陣翰如飛。"]'),
('4a0f38f1-ae26-46f7-9996-9362d1be4ed3','寄呂帥  其三','徐積','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','胡人勇悍真勍敵，漢將威名重泰山。',64,'全唐诗/poet.song.37000.json','["胡人勇悍真勍敵，漢將威名重泰山。", "隠若金城當一面，橫如鐵陣控三關。", "防秋甲士屯田去，牧馬氈裘避塞還。", "儒帥著書閒暇否，兩淮人物太平閒。"]'),
('211973ff-7747-4630-830e-cae6cf7ae361','寄呂帥  其四','徐積','宋','宋诗','song-poetry','','[]','帥臣所統在燕南，事事如窺指掌閒。',64,'全唐诗/poet.song.37000.json','["帥臣所統在燕南，事事如窺指掌閒。", "仗鉞精神堪破虜，搤吭形勢正當關。", "十洲部分連滄海，一道軍聲過黑山。", "文武非徒尹吉甫，前時方叔已平蠻。"]'),
('a891e529-070b-488a-a526-f2eeb71327b4','寄呂帥  其五','徐積','宋','宋诗','song-poetry','','[]','事皆術內宜謀帥，奇在胸中合運籌。',64,'全唐诗/poet.song.37000.json','["事皆術內宜謀帥，奇在胸中合運籌。", "戰士常騎突陣馬，將軍須養犒師牛。", "雅歌坐燕春歸塞，緩带行吟月上樓。", "且勸主人宜飲酒，邊城六月已如秋。"]'),
('a4bdd3e9-1af4-4773-a9b0-16ec23a0e65a','贈劉懋功','徐積','宋','宋诗','song-poetry','','[]','李令歸來歲月深，池人得子貴其情。',64,'全唐诗/poet.song.37000.json','["李令歸來歲月深，池人得子貴其情。", "定知縣事依前簡，還記官曹復舊清。", "如問以思謀所貴，能嚴而恕罰斯輕。", "芙蓉水上人相憶，因寄梅花附此聲。"]'),
('0da55db4-eea8-49ee-901c-471099edcc57','贈汪判官','徐積','宋','宋诗','song-poetry','','[]','庾郎醖藉本仙材，適自王家池上回。',64,'全唐诗/poet.song.37000.json','["庾郎醖藉本仙材，適自王家池上回。", "楊柳風前紅蠟炬，芙蓉香畔白髯顋。", "便摇健筆揮詩藁，仍替衰翁倒酒罍。", "說與泗州倪發勾，夢隨淮水向東來。"]'),
('830ed39f-5566-4f9e-9aa7-57f3388eed36','贈劉閤使','徐積','宋','宋诗','song-poetry','','[]','犖犖雄名駭世閒，堂堂誰敢舉頭看。',64,'全唐诗/poet.song.37000.json','["犖犖雄名駭世閒，堂堂誰敢舉頭看。", "高談豹略今無敵，誰污龍泉血未乾。", "蠻貢急趨金殿肅，胡蹝深入鐵山閒。", "關中自號詩書將，肯愧齊王在將壇。"]'),
('d3f12d9f-c52d-4ccd-93dc-2d996452694f','寄路倅','徐積','宋','宋诗','song-poetry','','[]','此中可恨恨無山，猶勝紛紛富貴閒。',64,'全唐诗/poet.song.37000.json','["此中可恨恨無山，猶勝紛紛富貴閒。", "綠野盡充公好尚，朱門安得水回環。", "對雲披住雲邊浪，踏月空行月下灣。", "好戴宮紗著宮錦，時時吟去復吟還。"]'),
('f45c21ca-9338-4c01-919e-6e8af9ba331c','和范君錫觀梅  其一','徐積','宋','宋诗','song-poetry','','[]','君看梅艷似何人，不畫蛾眉色自真。',64,'全唐诗/poet.song.37000.json','["君看梅艷似何人，不畫蛾眉色自真。", "冷寄北風淮上雪，暖思南國嶺頭春。", "莫嗔俗眼偏相棄，若比夭桃太不勻。", "我共參軍同所好，折來酣笑插烏巾。"]'),
('63ab22b9-2e6a-46fb-99a7-195eb0cf51dd','和范君錫觀梅  其二','徐積','宋','宋诗','song-poetry','','[]','月庭有影終難辨，雪徑無香不易分。',64,'全唐诗/poet.song.37000.json','["月庭有影終難辨，雪徑無香不易分。", "江上肌膚新出浴，嶺頭環珮忽藏雲。", "少他幾幅青羅袂，解與何人繡段裙。", "我愛此花真一色，將詩急報范參軍。"]'),
('51ffe69d-6bcf-4d40-835e-a1386785d11c','和呂祕校觀梅  其一','徐積','宋','宋诗','song-poetry','','[]','若論君顔色，瓊瑶未足珍。',96,'全唐诗/poet.song.37000.json','["若論君顔色，瓊瑶未足珍。", "花中誰作偶，物外獨先春。", "有艷皆歸樸，無妖可媚人。", "江南看已厭，洛浦種還新。", "日晚巫山雨，牆低宋玉鄰。", "施朱其已僞，傅粉亦非真。", "堪把歌詩贈，何辭唱和頻。", "君篇爲第一，便可獻楓宸。"]'),
('29f5aaa7-bca5-46da-b653-eb1c550ff9d4','和呂祕校觀梅  其二','徐積','宋','宋诗','song-poetry','','[]','寒梅雖淡薄，乃是物之珍。',96,'全唐诗/poet.song.37000.json','["寒梅雖淡薄，乃是物之珍。", "天與離羣性，花前獨步春。", "江臯多冒雪，山路不逢人。", "根本蟠雖久，花趺長自新。", "妖姿雖共處，正色願相鄰。", "縱使紅爲飾，何如素是真。", "北人殊未識，南國見何頻。", "須假東風力，春香到紫宸。"]'),
('af4c4adc-9d70-4657-854b-1544bf98d3df','寄顧瀛州','徐積','宋','宋诗','song-poetry','','[]','本朝謀帥得雄剛，氣語無邪面目方。',64,'全唐诗/poet.song.37000.json','["本朝謀帥得雄剛，氣語無邪面目方。", "掌握事嚴持斧鉞，咽喉地緊扼豺狼。", "鐵林猛士新翻陣，幕府奇書舊滿囊。", "可減邊兵三十萬，匈奴走入黑山藏。"]'),
('887ea8c2-5dba-47b7-9fd7-f15758c5244a','送倪敦復  其一','徐積','宋','宋诗','song-poetry','','[]','手持報簡人歸後，足步迴廊角住聲。',64,'全唐诗/poet.song.37000.json','["手持報簡人歸後，足步迴廊角住聲。", "但恐舟行隨早晚，此時秋色半陰晴。", "明朝路向雲邊望，今夜詩須枕上成。", "四壁無燈窗有月，直無老夢到三更。"]'),
('0579169d-ba8c-461f-8659-46c7726e9618','送倪敦復  其二','徐積','宋','宋诗','song-poetry','','[]','連朝送客經三日，每夜忘眠約數更。',64,'全唐诗/poet.song.37000.json','["連朝送客經三日，每夜忘眠約數更。", "枕上尋船無夢去，窗間望月有詩成。", "莫愁病叟添愁思，爲恐行人趁曉晴。", "急送村醪追後乘，要教飲處憶南城。"]'),
('3300d898-6b80-4b8c-a011-79abe2681834','送倪敦復  其三','徐積','宋','宋诗','song-poetry','','[]','各自逢人且寄音，仍須南北夢相尋。',64,'全唐诗/poet.song.37000.json','["各自逢人且寄音，仍須南北夢相尋。", "已成鳬雁分飛勢，更值淮湖連日陰。", "每論事時於義切，重來別後此情深。", "山東定飲登高酒，剩折黄花望我吟。"]'),
('3c311693-d825-4620-9c24-16c9bb7cc44b','寄呂海州','徐積','宋','宋诗','song-poetry','','[]','朱輪海上新迎部，玉筍朝中舊立班。',64,'全唐诗/poet.song.37000.json','["朱輪海上新迎部，玉筍朝中舊立班。", "曾屈高風來泮水，宜將老夢到朐山。", "霞張列炬紅彌野，潮作飛霜白叩關。", "三四百州爲第一，日華先照郡樓閒。"]'),
('b6fa8f9d-f8a6-4688-8655-0b7ef713f160','贈至幾  其一','徐積','宋','宋诗','song-poetry','','[]','淮東學士求新範，海角仙人棄舊居。',64,'全唐诗/poet.song.37000.json','["淮東學士求新範，海角仙人棄舊居。", "不用更携揚子醖，但來同噉庾郎蔬。", "赤墀待把文章獻，黄綬難親議論餘。", "泮水宮中方就講，何煩留下橐中書。"]'),
('e0756b45-db77-45e6-b432-50dfb47a60dd','贈至幾  其二','徐積','宋','宋诗','song-poetry','','[]','西城塔下逢君後，南郭庠中借館居。',64,'全唐诗/poet.song.37000.json','["西城塔下逢君後，南郭庠中借館居。", "正共孤甥棲暖席，未如老圃灌寒蔬。", "直生豈敢嗟年暮，餓死猶慚乞祭餘。", "六十衰翁如可教，更忙須遺所藏書。"]'),
('3b1825fa-eea8-444d-a2f7-a4f43f93ddbe','贈至幾  其三','徐積','宋','宋诗','song-poetry','','[]','僧房幾載如禪定，州序今來以義居。',64,'全唐诗/poet.song.37000.json','["僧房幾載如禪定，州序今來以義居。", "直道褐衣猶勝錦，枉身牢鼎不如蔬。", "何心敢冀漿先饋，無善兼令歲有餘。", "最是學文方自訟，只堪把筆教兒書。"]'),
('cc7d7d32-6ef0-439d-a8b0-5e6a78d1a37a','贈至幾  其四','徐積','宋','宋诗','song-poetry','','[]','南州本是諸儒秀，上國宜從大隠居。',64,'全唐诗/poet.song.37000.json','["南州本是諸儒秀，上國宜從大隠居。", "別我好留仙竹杖，送君欲獻野芹蔬。", "所慚下士文章陋，未報諸公禮義餘。", "若見汝陰前太守，爲言迂闊正談書。"]'),
('9014f970-db04-4a8d-8de1-7fedc7bc721c','贈至幾  其五','徐積','宋','宋诗','song-poetry','','[]','誰家門外柳雙株，滿屋清風是我居。',64,'全唐诗/poet.song.37000.json','["誰家門外柳雙株，滿屋清風是我居。", "霜後正逢籬下菊，雪前已貯甕中蔬。", "沫流口角耽吟睡，毛墜頭心久病餘。", "努力正如初學輩，老瞳昏澀夜看書。"]'),
('3ad4617c-9b2a-4e72-b4a5-c0a1474289e1','復明經','徐積','宋','宋诗','song-poetry','','[]','上欲求稽古，天書下四溟。',72,'全唐诗/poet.song.37000.json','["上欲求稽古，天書下四溟。", "儒風久湮鬰，詔意乃丁寧。", "削剝因唐氏，源流自漢庭。", "春秋披日月，易象炳丹青。", "禮樂搜潜奧，詩書抉杳冥。", "今焉拘注疏，何謂復明經。"]'),
('91c27baa-224b-49eb-9ec1-7bfa0c05dfa3','和蔣龍圖','徐積','宋','宋诗','song-poetry','','[]','吟翁如共老莊游，物外能齊樂與憂。',64,'全唐诗/poet.song.37000.json','["吟翁如共老莊游，物外能齊樂與憂。", "鼇背不爲三島客，魚竿終泛五湖舟。", "何須大使詩來問，合使幽人病爲瘳。", "陶令菊花猶有在，未知肯飲一杯不。"]'),
('bcbfdce1-6231-4bf9-909f-4ba2ba7df318','送呂清叔  其一','徐積','宋','宋诗','song-poetry','','[]','人爲多情乃送君，余雖不送情更深。',32,'全唐诗/poet.song.37000.json','["人爲多情乃送君，余雖不送情更深。", "破窗半夜風霜冷，危坐燈前爲子吟。"]'),
('56ae2abb-89b5-4ca1-90f2-f36757a7799d','送呂清叔  其二','徐積','宋','宋诗','song-poetry','','[]','平生志在青雲霄，十年不飛藏羽毛。',32,'全唐诗/poet.song.37000.json','["平生志在青雲霄，十年不飛藏羽毛。", "夫子乃是知我者，吟詩贈子何辭勞。"]'),
('ffff8456-46bc-4d6d-9b82-96b8e120f59b','送呂清叔  其三','徐積','宋','宋诗','song-poetry','','[]','匆匆一棹向東行，抖擻空囊無一金。',32,'全唐诗/poet.song.37000.json','["匆匆一棹向東行，抖擻空囊無一金。", "買魚沽酒向村市，典却蔡家焦尾琴。"]'),
('b18fb2df-ca3f-4105-a487-8da32d9226ab','送呂清叔  其四','徐積','宋','宋诗','song-poetry','','[]','深院吟哦夜半時，須有鬼神聽此詩。',32,'全唐诗/poet.song.37000.json','["深院吟哦夜半時，須有鬼神聽此詩。", "吟聲往往到明月，淮上有風摇桂枝。"]'),
('8d1a546b-b8bf-4fe8-a730-866e25d9c773','和蔣穎叔  其一','徐積','宋','宋诗','song-poetry','','[]','城外人傳大使來，吟翁正共客啣杯。',64,'全唐诗/poet.song.37000.json','["城外人傳大使來，吟翁正共客啣杯。", "赤帷便記長安道，駿馬仍思御史臺。", "義色可令姦膽破，剛姿不爲疾風摧。", "公能幾日山陽住，待報舟人且倒桅。"]'),
('4c860665-5592-48e5-a20f-1ad04bebabae','和蔣穎叔  其二','徐積','宋','宋诗','song-poetry','','[]','盛德尊光不召賓，玉環星弁自迂身。',64,'全唐诗/poet.song.37000.json','["盛德尊光不召賓，玉環星弁自迂身。", "北窗卧者陶元亮，大使車中陸子真。", "自道老來心逾壯，若論兵後氣彌真。", "所慚舊學非精義，仰負高風如古人。"]'),
('1710724f-5f1b-4302-b4c0-ccaa2d802529','送人之洛陽','徐積','宋','宋诗','song-poetry','','[]','待到伊川濯盡塵，洛陽城下且留身。',32,'全唐诗/poet.song.37000.json','["待到伊川濯盡塵，洛陽城下且留身。", "文才得似長沙傅，試問如今有幾人。"]'),
('dbd6d932-aac3-4fb7-8177-4c0ad6d4a9cb','寄蘇子由','徐積','宋','宋诗','song-poetry','','[]','午日移陰後，行人罷燕時。',48,'全唐诗/poet.song.37000.json','["午日移陰後，行人罷燕時。", "路從西郭去，船值北風吹。", "夢裏猶迴首，心中欲附詩。", "從來義如此，兩意自相知。"]'),
('969632b1-7a6f-4648-8156-9663e2242399','贈慎叔良','徐積','宋','宋诗','song-poetry','','[]','我是東臯叟，君居在屋東。',48,'全唐诗/poet.song.37000.json','["我是東臯叟，君居在屋東。", "已曾同硯席，最好共耕農。", "蕙帳兼棲鶴，籃輿亦带笻。", "若評樵採事，須更喚鄰翁。"]'),
('6d0e9a9f-f3e4-4dd9-b1df-3da6cad17b84','寄田大夫','徐積','宋','宋诗','song-poetry','','[]','老掾成迂闊，彌年信不通。',48,'全唐诗/poet.song.37000.json','["老掾成迂闊，彌年信不通。", "白頭負高義，病眼想清風。", "奉使更三節，題名在兩宮。", "有人能舉類，舊德起淮東。"]'),
('38a7d976-116d-4762-9b1c-21f992199f1b','寄慎朝奉','徐積','宋','宋诗','song-poetry','','[]','一別三千里，俱爲六十翁。',48,'全唐诗/poet.song.37000.json','["一別三千里，俱爲六十翁。", "日中多俗事，枕上憶清風。", "聞子生雙鳳，看書快兩瞳。", "以囊仍貯果，寄我厥苞紅。"]'),
('33193347-c71e-4ee3-af8a-4da3b33a903f','寄張景修','徐積','宋','宋诗','song-poetry','','[]','東南未回客，行樂又經年。',48,'全唐诗/poet.song.37000.json','["東南未回客，行樂又經年。", "吳市花朝酒，松江月夜船。", "窮閻無屋住，廣殿有詩傳。", "若論平生事，無如任自然。"]'),
('f49f5e09-2708-48ee-a618-5b8e5248e89d','寄朱博士','徐積','宋','宋诗','song-poetry','','[]','吳有朱夫子，相知凡幾年。',48,'全唐诗/poet.song.37000.json','["吳有朱夫子，相知凡幾年。", "心怜閉門叟，書附過江船。", "行已爲人表，文應許世傳。", "臨風有餘誨，時復慰皤然。"]'),
('a807b7ba-627f-4093-9d59-5aa11105e6a9','和李閎中','徐積','宋','宋诗','song-poetry','','[]','幕官真有道，野叟是何人。',48,'全唐诗/poet.song.37000.json','["幕官真有道，野叟是何人。", "被此新詩贈，兼之古意醇。", "若論今古事，前是老農身。", "誰謂芙蓉客，能來相顧頻。"]'),
('9ee5fff1-a290-4059-ad28-4e65e5346811','送王潜聖  其一','徐積','宋','宋诗','song-poetry','','[]','前日喜重來，今朝復送迴。',48,'全唐诗/poet.song.37000.json','["前日喜重來，今朝復送迴。", "出門無僕馬，爲子走風埃。", "遠客有詩贈，短亭無酒杯。", "南州雖得士，東觀却遺才。"]'),
('780dfa7f-c6ac-4066-9818-df4b04e6bf5a','送王潜聖  其二','徐積','宋','宋诗','song-poetry','','[]','一自渡江津，茫然不記春。',48,'全唐诗/poet.song.37000.json','["一自渡江津，茫然不記春。", "船諳淮上月，馬慣洛陽塵。", "可去問唐舉，未須慚買臣。", "終令舊關吏，還似棄繻人。"]'),
('e28eed50-0b8f-4466-a685-cdacdbb15cbf','送王潜聖  其三','徐積','宋','宋诗','song-poetry','','[]','兩翅慢如雲，倦飛歸故林。',48,'全唐诗/poet.song.37000.json','["兩翅慢如雲，倦飛歸故林。", "褐夫懷有玉，貧女歎無金。", "北闕報初罷，南陔情更深。", "升堂拜親後，先看白頭簪。"]'),
('895df5f9-9caa-4aa6-a193-dd355327b15a','送王潜聖  其四','徐積','宋','宋诗','song-poetry','','[]','南北倦遊客，離家幾問津。',48,'全唐诗/poet.song.37000.json','["南北倦遊客，離家幾問津。", "文隨年共老，名與德俱新。", "射策謾稽古，抱關猶誤親。", "窮通只如此，寧愧斷機人。"]'),
('101ea83f-556b-4a6b-841a-7d562e81441e','送李守','徐積','宋','宋诗','song-poetry','','[]','千兵州將已嚴裝，猶入西菴曳繡裳。',64,'全唐诗/poet.song.37000.json','["千兵州將已嚴裝，猶入西菴曳繡裳。", "坐燕起來中酒色，行春歸後落花香。", "難酬高義情彌重，欲述餘恩事更長。", "但看楚人遮道處，草頭垂淚濕殘陽。"]'),
('58e82de4-2ce6-46c7-84e7-2d3b509124c5','寄林虙','徐積','宋','宋诗','song-poetry','','[]','昔者淮南使，剛中輔以和。',48,'全唐诗/poet.song.37000.json','["昔者淮南使，剛中輔以和。", "生前無所苟，身後事如何。", "有子泣枯草，無人誦蓼莪。", "林公爲不死，下客謾悲歌。"]'),
('e39158dc-1c05-490d-91fc-74b3a8ffbfa2','送蔣憲  其一','徐積','宋','宋诗','song-poetry','','[]','節用黄金詔紫泥，皇華仍賦使臣詩。',64,'全唐诗/poet.song.37000.json','["節用黄金詔紫泥，皇華仍賦使臣詩。", "三千里路爭迎送，五十州官待指揮。", "盡解纍囚南到日，却尋急傳北歸時。", "趣裝亦有明珠否，八樹成林桂一枝。"]'),
('691624a6-bfe0-4bcf-b8b2-62c7c9f48406','送蔣憲  其二','徐積','宋','宋诗','song-poetry','','[]','遠服兵刑事可知，全吳分野有星移。',64,'全唐诗/poet.song.37000.json','["遠服兵刑事可知，全吳分野有星移。", "漢家詔使登車後，蜀道忠臣叱馭時。", "山色迎來城到近，桂香隨去馬行遲。", "梅林亦是公家管，廣帥應須寄北枝。"]'),
('b3216add-2d82-4b3e-97df-74041fe3f9d9','和蹇受之 詩','徐積','宋','宋诗','song-poetry','','[]','出乎志者莫如詩，商也能言得自誰。',64,'全唐诗/poet.song.37000.json','["出乎志者莫如詩，商也能言得自誰。", "雅頌漢時猶未遠，風騷齊後若何衰。", "翰林飛去秋鷹健，工部行來老驥遲。", "亦有孟韓聯句好，姓張員外合肩隨。"]'),
('44a6acc1-2693-4361-9b2c-14c5c29461ec','和蹇受之 笛','徐積','宋','宋诗','song-poetry','','[]','清而勁者笛爲奇，哀絕孤高更不卑。',64,'全唐诗/poet.song.37000.json','["清而勁者笛爲奇，哀絕孤高更不卑。", "日暮誰人憑樓處，月明離婦擣衣時。", "何煩作賦攄師憤，最好傾心破主疑。", "一弄便能歌怨曲，唐衢義哭合相隨。"]'),
('d90f5a4f-fd50-4227-ac4d-1f1d5f139f29','和蹇受之 醉','徐積','宋','宋诗','song-poetry','','[]','醉鄉恍惚在空虛，若論真恬世所無。',64,'全唐诗/poet.song.37000.json','["醉鄉恍惚在空虛，若論真恬世所無。", "坐客任貪清者聖，今人何作古之愚。", "宜教側帽穿花過，更好敲門趁月沽。", "誰似陶潜最瀟灑，籃輿歸去不須扶。"]'),
('cdb798da-e920-4f02-a0eb-d0f503273687','和蹇受之 笑','徐積','宋','宋诗','song-poetry','','[]','笑樂真情豈可誣，樂而不笑是何拘。',64,'全唐诗/poet.song.37000.json','["笑樂真情豈可誣，樂而不笑是何拘。", "日中無事逢棋局，春後有花兼酒壺。", "輕俠兒前撫手掌，滑稽傳後掩髭鬚。", "江南陸俊還安否，乞與笻枝使自扶。"]'),
('ce49cbc4-07e2-4283-96e1-57e999cdfb7a','謝趙朝散','徐積','宋','宋诗','song-poetry','','[]','一識明侯二十年，老農依舊未歸田。',64,'全唐诗/poet.song.37000.json','["一識明侯二十年，老農依舊未歸田。", "學無所得成迂闊，義有其終尚愛憐。", "下筆自書青竹汗，上樽仍附玉山泉。", "如斯厚意難空飲，待折梅花配酒船。"]'),
('cc7ee1ae-a4e0-418c-9f64-26ac753760ee','謝秦少游','徐積','宋','宋诗','song-poetry','','[]','講罷潮溝吟綠槐，手持銅鉢待相陪。',64,'全唐诗/poet.song.37000.json','["講罷潮溝吟綠槐，手持銅鉢待相陪。", "青瞳好客難留住，白足高僧又带迴。", "今日許尋陶令菊，明年約寄陸生梅。", "龐公妻子方炊黍，且報舟人莫起桅。"]'),
('bfab7f36-5ef7-4d61-a823-31632cc71e86','送李漕','徐積','宋','宋诗','song-poetry','','[]','淮上衰翁何所爲，有人寬厚誤相知。',64,'全唐诗/poet.song.37000.json','["淮上衰翁何所爲，有人寬厚誤相知。", "光華奉使方行部，款密成書更附詩。", "在泮飲時常睠睠，乘軺過日倍遲遲。", "緣公禮義如斯重，好寄梅花近北枝。"]'),
('f801a129-b6be-4f38-99ac-fb9434eebbd6','送雲鶴山人','徐積','宋','宋诗','song-poetry','','[]','倦鶴尋流水，閒雲歸故山。',24,'全唐诗/poet.song.37000.json','["倦鶴尋流水，閒雲歸故山。", "青囊書在否，留取教人閒。"]'),
('6427e1e4-8332-485b-ab61-83ff3049220f','和孫元規資政游園  其一','徐積','宋','宋诗','song-poetry','','[]','禁烟娛樂且須頻，二月風光特地新。',64,'全唐诗/poet.song.37000.json','["禁烟娛樂且須頻，二月風光特地新。", "料得壺中無俗客，更聞歌者盡陽春。", "酒來花下斟瓊液，茶向松閒碾玉塵。", "應笑謝安空寂寞，東山終日爲何人。"]'),
('46aee213-04f2-4706-b2a7-670fba039c1c','和孫元規資政游園  其二','徐積','宋','宋诗','song-poetry','','[]','紅作簾帷翠作裀，隨軒歌舞一時新。',64,'全唐诗/poet.song.37000.json','["紅作簾帷翠作裀，隨軒歌舞一時新。", "未知醒者何如醉，且向樽前莫負春。", "烟重柳梢寒蘸水，日高花徑暖生塵。", "自從三月芳菲後，誤入桃源又幾人。"]'),
('418bdf2b-2203-47e8-98a4-c981a94083de','和孫元規資政游園  其三','徐積','宋','宋诗','song-poetry','','[]','竹爲籬落水爲鄰，草碧花紅一徑新。',64,'全唐诗/poet.song.37000.json','["竹爲籬落水爲鄰，草碧花紅一徑新。", "盡日歡聲連綠野，滿城和氣入韶春。", "歌姬汗濕眉閒翠，舞妓香生襪下塵。", "酒陣詩兵皆大敵，未知元帥屬何人。"]'),
('0ccdb41c-711b-41d7-96ed-831cdb6e70a7','贈玉師失鸚鵡  其一','徐積','宋','宋诗','song-poetry','','[]','淮邊羈思嶺頭雲，紺彩騰時電影奔。',64,'全唐诗/poet.song.37000.json','["淮邊羈思嶺頭雲，紺彩騰時電影奔。", "一日恰如時輩事，十年空負主人恩。", "良因外貌貪馴性，何況中心狎巧言。", "他日雕籠如再養，玉環金鏁鐵爲門。"]'),
('e30a47b1-ecc6-42d7-9092-5fc31ae3e365','贈玉師失鸚鵡  其二','徐積','宋','宋诗','song-poetry','','[]','淡烟白浦月黄昏，倚遍闌干空倚門。',64,'全唐诗/poet.song.37000.json','["淡烟白浦月黄昏，倚遍闌干空倚門。", "接翅定思雲外侶，偷棲應望水邊村。", "盡傳世上新詩去，惟有籠中舊物存。", "便是却來休更養，不能成事只能言。"]'),
('2025449f-581e-42dc-873f-6281b903797c','謝蔣穎叔  其一','徐積','宋','宋诗','song-poetry','','[]','赤帷大乘皇華使，鳴玉鏘金訪教官。',64,'全唐诗/poet.song.37000.json','["赤帷大乘皇華使，鳴玉鏘金訪教官。", "紅旆緩摇春日晚，清風先入泮宮寒。", "一瓢鄭叟醉初醒，五柳陶翁卧不安。", "便著青衫迎謝傅，更無茶果薦杯盤。"]'),
('bee1fec2-6c59-464a-8e6b-7326c48b2fe5','謝蔣穎叔  其二','徐積','宋','宋诗','song-poetry','','[]','吟翁未去水雲閒，坐假虛名屈上官。',64,'全唐诗/poet.song.37000.json','["吟翁未去水雲閒，坐假虛名屈上官。", "忽似仰山心貌竦，更思言事骨毛寒。", "繡衣自可招黄綬，星弁須來對鶡冠。", "莫怪開門迎候早，今冬無雪卧袁安。"]'),
('fc30b71c-870c-4b0d-9fec-75702c3498a7','泣謝陳德任','徐積','宋','宋诗','song-poetry','','[]','義重江湖叟，情施墟墓閒。',48,'全唐诗/poet.song.37000.json','["義重江湖叟，情施墟墓閒。", "孤魂慰長夜，老淚濕衰顔。", "一奠方銘骨，三年更倚山。", "更分心兩處，恍惚自收還。"]'),
('b70e844a-db61-4f64-b772-a04965cbb145','和湯令','徐積','宋','宋诗','song-poetry','','[]','所幸生平世，甘於貧與痾。',48,'全唐诗/poet.song.37000.json','["所幸生平世，甘於貧與痾。", "被譽嗤杜簿，挾勇恥荆軻。", "已恨逢君晚，無辭教我多。", "野芹容一獻，更索採樵歌。"]'),
('76bb3d72-a700-4412-9fc0-ffc8f02bf85a','召汝弼','徐積','宋','宋诗','song-poetry','','[]','外府新讎校，問君來不來。',48,'全唐诗/poet.song.37000.json','["外府新讎校，問君來不來。", "春隨流水遠，日被落花催。", "煩子神仙御，盡予賢聖杯。", "何時松徑下，同坐踏蒼苔。"]'),
('b8e1a496-b06f-4767-912d-0e83d8d12a79','賑饑篇贈程守  其一','徐積','宋','宋诗','song-poetry','','[]','楚有循良守，流民萃一方。',48,'全唐诗/poet.song.37000.json','["楚有循良守，流民萃一方。", "薪蒸溫病骨，菽粟飫饑腸。", "永欲充編戶，無心憶故鄉。", "恩深何以報，惟有一爐香。"]'),
('48117a41-c4c7-4ba8-940b-9933c39bfe9d','賑饑篇贈程守  其二','徐積','宋','宋诗','song-poetry','','[]','乞得諸倉粟，流民獲所依。',48,'全唐诗/poet.song.37000.json','["乞得諸倉粟，流民獲所依。", "已燃薪禦凍，仍用楮爲衣。", "病骨蒙新暖，羸肌復舊肥。", "故鄉雖有屋，此處可忘歸。"]'),
('efac33e1-a4f5-49f1-be1a-ed0db6786f3c','送山陽宰高奉議','徐積','宋','宋诗','song-poetry','','[]','大夫歸旆暖摇春，正好浮淮向汴津。',64,'全唐诗/poet.song.37000.json','["大夫歸旆暖摇春，正好浮淮向汴津。", "一片青山迎去棹，兩隄芳草伴行人。", "當官事業今彌劭，滿橐文章老更新。", "記取吾鄉蒙實惠，吟翁亦是舊編民。"]'),
('432b87ac-d701-44a4-86dc-33c0d81ee143','送吳坦求','徐積','宋','宋诗','song-poetry','','[]','清風門外客移船，南郭衰翁但惘然。',64,'全唐诗/poet.song.37000.json','["清風門外客移船，南郭衰翁但惘然。", "未吐赤心無限事，重尋皓首幾何年。", "茶須飽飯吞甘溜，酒便空心注玉泉。", "醉倒淮東鄭雲叟，吟哦聲調入雲烟。"]'),
('7c6d5646-0b8e-4838-a6a8-6468fbade72d','贈穎叔','徐積','宋','宋诗','song-poetry','','[]','一從西郭恩初重，又至南庠義更深。',64,'全唐诗/poet.song.37000.json','["一從西郭恩初重，又至南庠義更深。", "自恨杜微無所聽，若忘龔遂是何心。", "已知霜露情彌感，更值淮湖氣作陰。", "昨夜起來無月色，誰知我爲蔣公吟。"]'),
('0a02de6d-b99f-4d5d-bbe5-a623f29a637a','答李閎中節推','徐積','宋','宋诗','song-poetry','','[]','王家池上芙蓉客，曾把新詩贈野人。',64,'全唐诗/poet.song.37000.json','["王家池上芙蓉客，曾把新詩贈野人。", "不道形骸成土木，却言風月長精神。", "凡禽易識甘題鳳，野獸難分誤比麟。", "努力唱歌酬不得，枉教白雪落紅塵。"]'),
('663a1e7a-bdf6-4420-ae09-5258e1ffa492','和沈判官','徐積','宋','宋诗','song-poetry','','[]','精神滿腹其才裕，清白當官所性存。',64,'全唐诗/poet.song.37000.json','["精神滿腹其才裕，清白當官所性存。", "國士正居王儉府，野人未識李膺門。", "詩筒便恐傳新句，酒席方陪飲上樽。", "從此定須懷賤叟，他時來訪我兒孫。"]'),
('8881f6cd-f187-495c-995b-3f19286dcf86','謝蔡子驤','徐積','宋','宋诗','song-poetry','','[]','好客重來直上廳，龐家妻女合炊秔。',64,'全唐诗/poet.song.37000.json','["好客重來直上廳，龐家妻女合炊秔。", "名言一坐令誰聽，老病雙瞳爲子明。", "有道長官方就祿，無能司戶欲歸耕。", "如斯出處俱平易，義理難時即共評。"]'),
('402eb793-0ec8-42d4-aa93-da064c6da2b2','寄朱至機  其一','徐積','宋','宋诗','song-poetry','','[]','雲出無心鶴倦飛，還家歡笑綵爲衣。',64,'全唐诗/poet.song.37000.json','["雲出無心鶴倦飛，還家歡笑綵爲衣。", "雪醅爲壽酒初熟，玉臠供甘魚正肥。", "侍燕每操笻杖去，看花常御板輿歸。", "故人願子無窮慶，莫使淮南音信稀。"]'),
('f0092f00-6d7c-465d-b297-7e5016765b17','寄朱至機  其二','徐積','宋','宋诗','song-poetry','','[]','六十詩翁愛幅巾，清江濯盡洛陽塵。',64,'全唐诗/poet.song.37000.json','["六十詩翁愛幅巾，清江濯盡洛陽塵。", "若無野客來同巷，合有山僧去作鄰。", "醉卧不知雲到枕，吟行唯許鶴隨身。", "眼看富貴真如夢，說到窮通定笑人。"]'),
('073c935f-9dde-40b1-b644-e1c828f19249','寄穎叔','徐積','宋','宋诗','song-poetry','','[]','南郭茶杯菊未香，西簷老柳覺疏黄。',64,'全唐诗/poet.song.37000.json','["南郭茶杯菊未香，西簷老柳覺疏黄。", "家無縣令雙鳬舄，夢有仙人五色羊。", "梅信易傳來嶺北，雁書難附過衡陽。", "定知遠俗懷公義，若說威名背負芒。"]'),
('131c3d95-1534-44c2-9acc-6a3acda9942a','送婁六秀才','徐積','宋','宋诗','song-poetry','','[]','趨時之悔真良說，枉己之徒信厚顔。',64,'全唐诗/poet.song.37000.json','["趨時之悔真良說，枉己之徒信厚顔。", "學者淵源當似海，丈夫持守要如山。", "挺然特起麟孤角，鄙矣誰窺豹一斑。", "爲子臨行雙泣下，白頭人倚夕陽關。"]'),
('7f817cfb-a4ae-480b-b49b-3bfaa5c54856','和楊守清容堂','徐積','宋','宋诗','song-poetry','','[]','赤縣堂名清與容，主人兼得古人風。',64,'全唐诗/poet.song.37000.json','["赤縣堂名清與容，主人兼得古人風。", "此閒便是烟波上，何處更尋山谷中。", "志激懦貪無弊俗，詔宣寬大有餘功。", "若將全德評今昔，應笑陳蕃郭令公。"]'),
('2eaf9ea8-4db1-49e0-ae73-439f693a2885','書狄梁公傳','徐積','宋','宋诗','song-poetry','','[]','李氏山河勢若蓬，手提長劍截長虹。',64,'全唐诗/poet.song.37000.json','["李氏山河勢若蓬，手提長劍截長虹。", "請將唐室中興事，可比汾陽再造功。", "直道不爲邪黨敗，逆鱗深得諍臣風。", "儒生若有逢時幸，未必勳勞盡在公。"]'),
('ff3aa037-8616-402f-bd7f-d18ded4a4f6c','夜賞春寄敦復','徐積','宋','宋诗','song-poetry','','[]','莫道山陽官苦辛，大夫未是不閒人。',64,'全唐诗/poet.song.37000.json','["莫道山陽官苦辛，大夫未是不閒人。", "晝來琴上披尋曲，夜入花閒點檢春。", "拖袂带歸香滿袖，迴燈引去蝶隨身。", "高才自有風流格，吟作吳謠事最新。"]'),
('80bee74a-17a2-408a-8e59-ecd15a1b6c37','戲答君錫酣戰之句','徐積','宋','宋诗','song-poetry','','[]','檄書插羽來何速，鐵騎成林勢未分。',64,'全唐诗/poet.song.37000.json','["檄書插羽來何速，鐵騎成林勢未分。", "北壘噉聲雄似虎，南營殺氣猛如雲。", "陣前劍客投犀袂，帳外歌姬曳繡裙。", "且待揮兵酣戰罷，却行三舍避將軍。"]'),
('efd406c7-ba45-4709-b5e3-86309812eeee','和崔刑部憑欄','徐積','宋','宋诗','song-poetry','','[]','伏讀憑欄意，私心輒慨然。',48,'全唐诗/poet.song.37000.json','["伏讀憑欄意，私心輒慨然。", "聖徒須企聖，賢黨必思賢。", "主上方高枕，民閒正息肩。", "使君當自逸，治狀已光前。"]'),
('d3e13a8a-8193-41e0-a8bb-287778993e91','示汝弼','徐積','宋','宋诗','song-poetry','','[]','十載交情義有餘，離羣還歎索然居。',64,'全唐诗/poet.song.37000.json','["十載交情義有餘，離羣還歎索然居。", "一番思我須成夢，每度人來定寄書。", "此日相從尤款密，他時何處覓迂疏。", "回來徑哭青墩墓，莫向南城問舊廬。"]'),
('bee3f261-f230-4d9f-b218-ee7aa127a74b','和汝弼','徐積','宋','宋诗','song-poetry','','[]','蘆葉啣來逢北雁，筠筒信斷候南風。',64,'全唐诗/poet.song.37000.json','["蘆葉啣來逢北雁，筠筒信斷候南風。", "看回白馬殘陽後，吟盡閒雲落月中。", "酌水何時尋陸子，寄裙前日爲梁鴻。", "孟光多謝閨房秀，醉酒亡繒是我翁。"]'),
('c20745f9-ab1f-46d6-9455-e378f864cab3','呈敦復','徐積','宋','宋诗','song-poetry','','[]','朝奉清心自皎然，應將外物比腥羶。',64,'全唐诗/poet.song.37000.json','["朝奉清心自皎然，應將外物比腥羶。", "詩歌與性相娛樂，聲色因喪永棄捐。", "有義睠余東野舊，無能留子北窗眠。", "殷勤爲釂陶家酒，更送甆杯與竹牋。"]'),
('4cfc1437-6cfe-48e1-85e4-ae3cf5811ba7','代書寄次翁','徐積','宋','宋诗','song-poetry','','[]','病叟雖迂闊，交情自不疏。',48,'全唐诗/poet.song.37000.json','["病叟雖迂闊，交情自不疏。", "喜逢歸去客，爲謝寄來書。", "入幕評文後，臨川視事餘。", "携壺吟兩柳，還夢野人居。"]'),
('36dea620-0caf-463a-a6e3-5c7c5ca81ffa','上蔣公','徐積','宋','宋诗','song-poetry','','[]','公如鄭相怜窮士，我在所知韓孟閒。',64,'全唐诗/poet.song.37000.json','["公如鄭相怜窮士，我在所知韓孟閒。", "下客心形渾是木，高賢禮義欲齊山。", "十年用力人誰及，百計酬恩事總艱。", "投筆若從班定遠，橫戈先出玉門關。"]'),
('fe7f9ca1-5f21-48a6-968c-082349dbff7e','和路朝奉退居','徐積','宋','宋诗','song-poetry','','[]','彼美東南雋，堯時作外臣。',240,'全唐诗/poet.song.37000.json','["彼美東南雋，堯時作外臣。", "有何歸去物，全得老來身。", "一節都無變，平生總是真。", "勇於羅守退，甘似庾郎貧。", "士望今誰耦，儒林舊絕倫。", "其心醇是本，以德厚爲珍。", "避盜抽園筍，容奴取庫銀。", "時情付流水，外物盡浮雲。", "久矣謀閒坐，誰乎願要津。", "書藏萬卷好，詩換一筒新。", "聚道爲家法，分糧卹外姻。", "清風還楚部，餘惠在江民。", "藉草宜蘭佩，穿松稱鹿巾。", "鱠材須活鯉，羹劑要香蓴。", "日暖花村路，風溫荇浦春。", "耽吟白居士，沈醉李仙人。", "驥鳳鳴來久，駒雛教已馴。", "義終光國史，名自壓朝紳。", "顧我愚而陋，煩公愛以仁。", "深恩無報處，北望正勞神。"]'),
('d696ca1a-4a66-480c-8c66-42729e1817ad','送至機','徐積','宋','宋诗','song-poetry','','[]','閉門有幸藏衰病，策杖無因奉俊游。',64,'全唐诗/poet.song.37000.json','["閉門有幸藏衰病，策杖無因奉俊游。", "繩纏筋骸方就枕，火燒皮骨正思秋。", "覽君健句如逢藥，慰我孤懷勝憑樓。", "見說束裝行未得，夢魂先到楚江頭。"]'),
('410cd8f4-2f5e-4aae-a674-cb666cf1ac90','寄路倅洪澤阻水  其一','徐積','宋','宋诗','song-poetry','','[]','黄金宮闕紫瑶關，鵷鷺思陪玉筍班。',64,'全唐诗/poet.song.37000.json','["黄金宮闕紫瑶關，鵷鷺思陪玉筍班。", "仙仗好教鳬舄去，客槎却在斗牛閒。", "有爲義對霜濤湧，無敵詩同鐵陣閒。", "誰報京師羣弟子，先生吏隠鬢毛斑。"]'),
('f45d64ba-5b87-4180-99e9-02ba1b58421e','寄路倅洪澤阻水  其二','徐積','宋','宋诗','song-poetry','','[]','莫教容易過龜山，多少人心願復還。',64,'全唐诗/poet.song.37000.json','["莫教容易過龜山，多少人心願復還。", "更有南城黄綬客，但吟西戶綠楊閒。", "纔經濁汴無澄浪，且趁清淮洗醉顔。", "安得就公歌一曲，緩吟遲步夕陽灣。"]'),
('cf0f8bcd-ebff-42fd-b43b-eabd5dc5c313','和潘朝奉鄒國公配饗','徐積','宋','宋诗','song-poetry','','[]','丹書一下人神慶，美矣先朝貴孟公。',64,'全唐诗/poet.song.37000.json','["丹書一下人神慶，美矣先朝貴孟公。", "能與百王興漏典，長令萬國仰遺風。", "躬爲獨行生無祿，道配彌高祭有宮。", "孰謂闊迂窮至死，正而窮勝枉而通。"]'),
('d24dea63-8ad2-4359-a7ad-64d0da27c897','和路朝奉新居  其一','徐積','宋','宋诗','song-poetry','','[]','世俗紛紛事總虛，詩翁今作逸人居。',64,'全唐诗/poet.song.37000.json','["世俗紛紛事總虛，詩翁今作逸人居。", "勤穿東地緣栽竹，喜占明窗爲著書。", "近市好賒春肆酒，就淮仍買晚罾魚。", "忽撐小艇來西郭，不問皆知訪仲車。"]'),
('531a1974-063f-407d-aba3-335077b86b35','和路朝奉新居  其二','徐積','宋','宋诗','song-poetry','','[]','詩翁愛酒典衣沽，六子將孫侍燕居。',64,'全唐诗/poet.song.37000.json','["詩翁愛酒典衣沽，六子將孫侍燕居。", "正要白家醇釀法，不須劉德僞金書。", "厨經雪後炊無黍，門近淮瀕食有魚。", "何以獻公尋一物，庾郎三韭載盈車。"]'),
('07d7d9a9-1773-477e-be83-0cbc2abfe921','和路朝奉新居  其三','徐積','宋','宋诗','song-poetry','','[]','昔也聞名誦子虛，今來白頷隔城居。',64,'全唐诗/poet.song.37000.json','["昔也聞名誦子虛，今來白頷隔城居。", "新詩解道論頭句，舊客仍移把臂書。", "北郭高風真隠豹，南州循政喻烹魚。", "歸時見說臨川路，父老爭留太守車。"]'),
('69c86057-019d-4f2f-8679-c096cc40a144','和路朝奉新居  其四','徐積','宋','宋诗','song-poetry','','[]','陳傅門前客姓徐，有何智術佐閒居。',64,'全唐诗/poet.song.37000.json','["陳傅門前客姓徐，有何智術佐閒居。", "接簷俛仰令遮雨，縛竹縱橫爲架書。", "趁雪斸田移草木，和灣汲水貯龜魚。", "上元已過清明近，更約尋花不用車。"]'),
('c5938640-8490-425a-b5a4-40d3ca73c8a9','和路朝奉新居  其五','徐積','宋','宋诗','song-poetry','','[]','誰家住處近田廬，朝奉抽簪就退居。',64,'全唐诗/poet.song.37000.json','["誰家住處近田廬，朝奉抽簪就退居。", "竹葉已成新歲酒，梅花未領故人書。", "呼童解袂捫饑蝨，趁日開箱曝蠹魚。", "一似散仙閒到夜，卧屏仍看五雲車。"]'),
('70b7e76b-9e44-49b1-abf6-06d5fb063ea6','和路朝奉新居  其六','徐積','宋','宋诗','song-poetry','','[]','坐想堂前弄白鬚，蒲茵筍席正高居。',64,'全唐诗/poet.song.37000.json','["坐想堂前弄白鬚，蒲茵筍席正高居。", "綵衣六子傍供膳，錦髻諸孫自教書。", "愛士主人新置榻，清身太守舊懸魚。", "更吟整斗論頭句，勝却西菴詩一車。"]'),
('d53ec97b-d851-47be-91e6-b5dc68c62459','和路朝奉新居  其七','徐積','宋','宋诗','song-poetry','','[]','不辨時人直與迂，濁纓且喜近淮居。',64,'全唐诗/poet.song.37000.json','["不辨時人直與迂，濁纓且喜近淮居。", "朝衣脫後常耽睡，野史修時或借書。", "恨乏青山供採藥，愛看白鳥伺吞魚。", "東園賣酒花開近，待看詩翁倒載車。"]'),
('2cbe2dcc-e1d5-4b7c-a270-2adf8b43894e','和路朝奉新居  其八','徐積','宋','宋诗','song-poetry','','[]','簿領脫來如一夢，身名全後喜寧居。',64,'全唐诗/poet.song.37000.json','["簿領脫來如一夢，身名全後喜寧居。", "生來自信無非義，世上何緣作謗書。", "所養有源數大水，其賢可樂比嘉魚。", "願公八十爲更老，玉幣三招乃就車。"]'),
('bc9408b6-6d47-4725-ba81-4f80ef451ee3','和路朝奉新居  其九','徐積','宋','宋诗','song-poetry','','[]','自是平時大隠徒，何須水宿與山居。',64,'全唐诗/poet.song.37000.json','["自是平時大隠徒，何須水宿與山居。", "都無長物垂空橐，却有閒房聚逸書。", "近見雪消思野蕨，遥呼船問憶江魚。", "卸帆便去尋村酒，醉使兒孫推鹿車。"]'),
('d8b1f50e-59f5-4184-b9c6-b4a4a1d4b9f2','和路朝奉新居  其一○','徐積','宋','宋诗','song-poetry','','[]','身著練袍履用蒲，鶡冠鳩杖稱郊居。',64,'全唐诗/poet.song.37000.json','["身著練袍履用蒲，鶡冠鳩杖稱郊居。", "家中但乏青囊印，坐處便看黄卷書。", "賃屋爲無揚子宅，休官非爲武昌魚。", "長年不出何妨事，況是門懸致仕車。"]'),
('4397c9a1-c0fb-474a-84e4-c326522ba62c','和路朝奉新居  其一一','徐積','宋','宋诗','song-poetry','','[]','夷白先生好對廬，醉吟處士作鄰居。',64,'全唐诗/poet.song.37000.json','["夷白先生好對廬，醉吟處士作鄰居。", "幅巾自去呼樵父，蠟屐何時訪竹書。", "坐想高談摇麈尾，情知相誶跨鯨魚。", "更憐同姓陪罇酒，勝却荀生得御車。"]'),
('bf36dda3-c1b4-495c-8853-b13ccc01d4db','和路朝奉新居  其一二','徐積','宋','宋诗','song-poetry','','[]','路家巷口是何渠，半似城中半野居。',64,'全唐诗/poet.song.37000.json','["路家巷口是何渠，半似城中半野居。", "已退白仙常按曲，未歸陸俊謾傳書。", "雪消牆外逢挑菜，日暖門前見捕魚。", "更有花閒行處樂，舊時歌舞願隨車。"]'),
('ff716ccf-ff4e-439b-b4dd-162f369c7b1f','和路朝奉新居  其一三','徐積','宋','宋诗','song-poetry','','[]','好養玄猿共鶴雛，茅茨蓋屋竹閒居。',64,'全唐诗/poet.song.37000.json','["好養玄猿共鶴雛，茅茨蓋屋竹閒居。", "家無越使千金橐，腹有齊臣四部書。", "一自臨川登畫鷁，便煩別駕掌銅魚。", "吟哦還作詩仙退，恰似驂鸞鳳駕車。"]'),
('f2dae6f5-edd0-4459-bcb1-386bdadc8ef4','和路朝奉新居  其一四','徐積','宋','宋诗','song-poetry','','[]','世閒詩淡鄭雲叟，壽且安寧陶隠居。',64,'全唐诗/poet.song.37000.json','["世閒詩淡鄭雲叟，壽且安寧陶隠居。", "愛酒自開浮蟻甕，耽詩如好換鵝書。", "籜冠戴後搘笻竹，鶴氅披來控鯉魚。", "學作蓬萊吟醉客，何須駟馬駕安車。"]'),
('6a483d67-3283-40a6-8a4b-90d6c3e936d7','和路朝奉新居  其一五','徐積','宋','宋诗','song-poetry','','[]','西菴翁上北城隅，爲望臨川舊守居。',64,'全唐诗/poet.song.37000.json','["西菴翁上北城隅，爲望臨川舊守居。", "所恨足無雙翅舄，但將詩代一函書。", "甥教洗遊多沽酒，妻使磨刀細切魚。", "灑掃待公來獻壽，親扶杖履醉升車。"]'),
('a1f9174c-6596-47d7-ae8f-b586dbe09153','送路倅  其一','徐積','宋','宋诗','song-poetry','','[]','所居有本能行義，此去無人不戀恩。',64,'全唐诗/poet.song.37000.json','["所居有本能行義，此去無人不戀恩。", "情似綠波長送棹，夢如飛絮忽隨軒。", "帳前舊學千餘子，橐裏新文數萬言。", "何日從君溫故業，待操几杖問淵源。"]'),
('dacda3a9-942e-4705-a362-7326babf7dfe','送路倅  其二','徐積','宋','宋诗','song-poetry','','[]','我曹初作綵衣郎，白紵先生正擅場。',64,'全唐诗/poet.song.37000.json','["我曹初作綵衣郎，白紵先生正擅場。", "大筆可堪專簿領，遠圖終恐用文章。", "清淮絕唱新盈卷，綠髪奇篇舊滿囊。", "此去功名都未測，公年方永力方强。"]'),
('711789a3-d10c-469a-bd3e-8e2e23cf0454','和石宣德五柳亭','徐積','宋','宋诗','song-poetry','','[]','五柳神君氣貌端，所希所向靜而安。',64,'全唐诗/poet.song.37000.json','["五柳神君氣貌端，所希所向靜而安。", "每思往行投閒地，肯逐時情慕熱官。", "秫酒易醒風戶猛，葛巾難卧月窗寒。", "也應種得東籬菊，好置籃輿自在觀。"]'),
('d4ec3995-85ce-4c45-8dbb-7711d05f3109','送秦漕','徐積','宋','宋诗','song-poetry','','[]','昭昭所性詳而辨，坦坦其行樂且恬。',64,'全唐诗/poet.song.37000.json','["昭昭所性詳而辨，坦坦其行樂且恬。", "公義已令淮部肅，清風更入朔方嚴。", "行無瑕纇孤標聳，養有根源數器兼。", "猶使樵夫來教我，樵歌爲述古人謙。"]'),
('27a2b222-59dc-44de-ad26-73d8369e303a','送宮教郎朝奉','徐積','宋','宋诗','song-poetry','','[]','博士高才御點名，往陪羣俊盍朝簪。',64,'全唐诗/poet.song.37000.json','["博士高才御點名，往陪羣俊盍朝簪。", "門頒錦詔先生入，帝錫綈衣後殿深。", "設坐宮官嚴絳帳，執經王子肅青衿。", "堯親已被欽文化，更倚師謨稱上心。"]'),
('1b57bbd8-06f5-431a-ba3d-f0156f02e560','送李憲  其一','徐積','宋','宋诗','song-poetry','','[]','使臣車用赤帷裳，帝選明侯重嶺陽。',64,'全唐诗/poet.song.37000.json','["使臣車用赤帷裳，帝選明侯重嶺陽。", "後乘未離淮分野，先聲已遍越封疆。", "宜教廉吏心如水，但恐貪夫背有霜。", "大抵當官須去害，人閒所在有豺狼。"]'),
('ec0a6b9d-17ce-4c69-99e3-ab036a3e017a','送李憲  其二','徐積','宋','宋诗','song-poetry','','[]','五船鳴鼓待嚴裝，且赴雙蓮舊燕堂。',32,'全唐诗/poet.song.37000.json','["五船鳴鼓待嚴裝，且赴雙蓮舊燕堂。", "不用水沈薰紫綬，過梅林後一身香。"]'),
('ce01599b-7dca-4a63-975f-d87637b9f0ea','送程守  其一','徐積','宋','宋诗','song-poetry','','[]','楚人相喚守河梁，鳴角樓前駐畫檣。',64,'全唐诗/poet.song.37000.json','["楚人相喚守河梁，鳴角樓前駐畫檣。", "未肯放船來北渚，且教載酒去東堂。", "傾城和氣傳芳草，沿路清風配綠楊。", "見說新班名玉筍，赤墀登對待馮唐。"]'),
('8ae9ced6-1b52-47f8-bd32-9a453b7d039e','送程守  其二','徐積','宋','宋诗','song-poetry','','[]','聞道西城欲解船，病翁懷抱更騷然。',64,'全唐诗/poet.song.37000.json','["聞道西城欲解船，病翁懷抱更騷然。", "將心已附諸生輩，策杖難隨庶老肩。", "負義本非今世俗，報恩終愧古人賢。", "不才自訟無他技，合作詩歌更百篇。"]'),
('accdca42-cb5d-4751-a196-67f9d8134131','送人從軍','徐積','宋','宋诗','song-poetry','','[]','古來雄雋是從軍，問罪殘羌正有名。',96,'全唐诗/poet.song.37000.json','["古來雄雋是從軍，問罪殘羌正有名。", "黑槊將陪黄鉞帥，銀鎗隊擁鐵林兵。", "十州假息恩涵覆，百載逋誅事貫盈。", "首惡更應囚巨轞，壯圖難議請長纓。", "須空大漠遷降虜，好决洪河刷逆城。", "報國主人心更勇，西山勒頌得班生。"]'),
('d9a7a8f3-bb38-412c-ad2e-93a19458f4f0','贈山翁','徐積','宋','宋诗','song-poetry','','[]','耳聽人言似不聞，心於時事若無分。',32,'全唐诗/poet.song.37000.json','["耳聽人言似不聞，心於時事若無分。", "一生已是青山物，更欲將身換白雲。"]'),
('ea401b3b-08f1-4203-8efd-e71f45b6cc88','山翁答無分之句','徐積','宋','宋诗','song-poetry','','[]','身邊外物雖無語，事到中心自有分。',32,'全唐诗/poet.song.37000.json','["身邊外物雖無語，事到中心自有分。", "莫道山翁頭似雪，心如劍戟氣如雲。"]'),
('bf906997-2a14-42d9-b487-931fa508585a','謝張才甫笻竹杖  其一','徐積','宋','宋诗','song-poetry','','[]','老來無物可搘頤，正要一莖筇竹枝。',32,'全唐诗/poet.song.37000.json','["老來無物可搘頤，正要一莖筇竹枝。", "滿袖清風秋月淡，陶潜遶遍菊花籬。"]'),
('72e8ef21-08ec-4fe3-9f51-7e84dd20dc7d','謝張才甫笻竹杖  其二','徐積','宋','宋诗','song-poetry','','[]','手中忽把一枝笻，稱我逍遥林下風。',32,'全唐诗/poet.song.37000.json','["手中忽把一枝笻，稱我逍遥林下風。", "不是西征車上物，臨行自合與詩翁。"]'),
('2f32a851-3d8c-434c-952d-cf2a063ff857','戲呈魏評事  其一','徐積','宋','宋诗','song-poetry','','[]','北齋有酒夜開門，獨酌燈前酒一樽。',32,'全唐诗/poet.song.37000.json','["北齋有酒夜開門，獨酌燈前酒一樽。", "只被詩魔無處避，待教醉魄戰吟魂。"]'),
('ba857558-9e92-4c11-a586-0713fdf4f73d','戲呈魏評事  其二','徐積','宋','宋诗','song-poetry','','[]','我向燈前置酒杯，南軒北戶一時開。',32,'全唐诗/poet.song.37000.json','["我向燈前置酒杯，南軒北戶一時開。", "如今正是花時節，且放春風數路來。"]'),
('293a3b91-6b63-442d-9fb4-c7da0a1d6145','戲呈魏評事  其三','徐積','宋','宋诗','song-poetry','','[]','紫府瑶關夜更深，阿誰閒醉洞中春。',32,'全唐诗/poet.song.37000.json','["紫府瑶關夜更深，阿誰閒醉洞中春。", "呼童去問烟霞事，只見桃花不見人。"]'),
('dd948fdf-3c93-4fc3-94a2-b7fdccc8fa14','寄江子和','徐積','宋','宋诗','song-poetry','','[]','爲問江行輩，何時訪白鬚。',24,'全唐诗/poet.song.37000.json','["爲問江行輩，何時訪白鬚。", "老懷何所慰，得子寄來書。"]'),
('9b9294cc-f6d6-4fb3-9d2d-b32b61dc7239','和路太博','徐積','宋','宋诗','song-poetry','','[]','莫教竹馬誤羣兒，謝守行春未可知。',32,'全唐诗/poet.song.37000.json','["莫教竹馬誤羣兒，謝守行春未可知。", "落盡梅花寒食近，却應桃李怪來遲。"]'),
('03119d3b-12ea-47f5-8331-ecb25f35e433','謝穎叔','徐積','宋','宋诗','song-poetry','','[]','能歌白雪公常事，不醉黄花我幾曾。',32,'全唐诗/poet.song.37000.json','["能歌白雪公常事，不醉黄花我幾曾。", "一絕便勝書一紙，情知高義過劉弘。"]'),
('a80db331-3dc6-48fc-ae58-95afe27186ce','寄王觀文','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','扁舟欲泛湘江月，亦泛洞庭湖上春。',32,'全唐诗/poet.song.37000.json','["扁舟欲泛湘江月，亦泛洞庭湖上春。", "十年此意逢今日，且喜洪州有主人。"]'),
('ad579e19-d725-40ec-aceb-d7c0e309f2cb','別崔刑部','徐積','宋','宋诗','song-poetry','','[]','黄金何日上燕臺，致主猶輕樂毅才。',32,'全唐诗/poet.song.37000.json','["黄金何日上燕臺，致主猶輕樂毅才。", "便是功名未如意，報恩寧肯惜重來。"]'),
('b368bd19-bdaa-4a9f-a977-b23f55bfa57c','送秦少遊','徐積','宋','宋诗','song-poetry','','[]','叟罷耕耘妾罷機，匆匆人意甚牽衣。',32,'全唐诗/poet.song.37000.json','["叟罷耕耘妾罷機，匆匆人意甚牽衣。", "可憐數里笙歌地，但見一番楊柳稀。"]'),
('e26dc795-eba0-4bdd-aa5a-adb8954d9fd1','送慎彥鄰赴舉','徐積','宋','宋诗','song-poetry','','[]','天子詔多士，喜君爲此行。',24,'全唐诗/poet.song.37000.json','["天子詔多士，喜君爲此行。", "美璞必三獻，大禽終一鳴。"]'),
('f48214de-a645-432d-9f9c-0937bfe574e8','寄蔡子驤','徐積','宋','宋诗','song-poetry','','[]','爲報廬陵客，逢人且寄聲。',24,'全唐诗/poet.song.37000.json','["爲報廬陵客，逢人且寄聲。", "不知無恙否，何日到南城。"]'),
('85029bd7-2f39-473b-86ba-095057cbda33','送管久中','徐積','宋','宋诗','song-poetry','','[]','半開醉眼天方曉，急遣詩筒去已遲。',32,'全唐诗/poet.song.37000.json','["半開醉眼天方曉，急遣詩筒去已遲。", "別恨離愁無盡處，青山綠水有窮時。"]'),
('3855b77e-f84c-48a1-8f0d-ab252899d13b','贈鄭毅夫','徐積','宋','宋诗','song-poetry','','[]','致主躋民道未完，白衣卿相且盤桓。',32,'全唐诗/poet.song.37000.json','["致主躋民道未完，白衣卿相且盤桓。", "龍頭已是輸君早，更向麒麟閣上看。"]'),
('7ac9decd-2b37-40f5-a41a-80cc28f8532d','戲答何楚才酒肆','徐積','宋','宋诗','song-poetry','','[]','身在塵埃氣在雲，丈夫貧賤豈須論。',32,'全唐诗/poet.song.37000.json','["身在塵埃氣在雲，丈夫貧賤豈須論。", "且爲韓信淮陰事，休著相如犢鼻褌。"]'),
('cd0d26b9-14e1-4500-b326-26886af2ae46','和張文潛晚春  其一','徐積','宋','宋诗','song-poetry','','[]','留春是芳草，送春宜柳花。',24,'全唐诗/poet.song.37000.json','["留春是芳草，送春宜柳花。", "日長花正亂，誰倚闌干斜。"]'),
('c83b4b78-13fa-4922-9e93-d74745c6ba88','和張文潛晚春  其二','徐積','宋','宋诗','song-poetry','','[]','問花開何遲，問花底急飛。',24,'全唐诗/poet.song.37000.json','["問花開何遲，問花底急飛。", "人閒惜花少，閬苑等花歸。"]'),
('f3010117-3921-4a7b-8405-bb900cffa540','和張文潛晚春  其三','徐積','宋','宋诗','song-poetry','','[]','易貯千尋水，難藏一點春。',24,'全唐诗/poet.song.37000.json','["易貯千尋水，難藏一點春。", "也須幾杯酒，還似送行人。"]'),
('98b1b346-16ef-4257-bc62-1abd12331c19','和張文潛晚春  其四','徐積','宋','宋诗','song-poetry','','[]','渡水衣須扱，穿林手自披。',24,'全唐诗/poet.song.37000.json','["渡水衣須扱，穿林手自披。", "經春脚力軟，但恐上山遲。"]'),
('68e551eb-4b5c-4ddc-86a8-1a49f9a8e858','二老寄朱廣微  其一','徐積','宋','宋诗','song-poetry','','[]','二老相思又隔年，僧窗閒坐復何緣。',32,'全唐诗/poet.song.37000.json','["二老相思又隔年，僧窗閒坐復何緣。", "吟翁最好鹽城住，時把歌詩付酒船。"]'),
('da509890-8fb6-4d3c-ac20-e638553040bd','二老寄朱廣微  其二','徐積','宋','宋诗','song-poetry','','[]','寄聲切問朱監利，對面勤詢劉貴池。',32,'全唐诗/poet.song.37000.json','["寄聲切問朱監利，對面勤詢劉貴池。", "或見廣東程使者，爲言收得寄來詩。"]'),
('4e4dcb73-bd42-4159-a333-121b06c38e28','送曾子開','徐積','宋','宋诗','song-poetry','','[]','揚子江頭風正寒，行人莫歎渡頭難。',32,'全唐诗/poet.song.37000.json','["揚子江頭風正寒，行人莫歎渡頭難。", "江頭楊柳豈常在，但向江頭洗眼看。"]'),
('60b5cf3a-2093-4b33-a75e-e9f9559e625e','送慎彥鄰','徐積','宋','宋诗','song-poetry','','[]','只知北海鵬將化，不謂丹山鳳正棲。',32,'全唐诗/poet.song.37000.json','["只知北海鵬將化，不謂丹山鳳正棲。", "却憶吳江橋上月，共君長嘯入雲霓。"]'),
('09fd1711-9da0-4842-bcbe-42274f00a1f1','呈舒信道','徐積','宋','宋诗','song-poetry','','[]','淮干風起木枝摇，頷下甆甌一尺高。',32,'全唐诗/poet.song.37000.json','["淮干風起木枝摇，頷下甆甌一尺高。", "我是折薪扶耒手，中丞且莫笑麤豪。"]'),
('c94711ae-38f3-40f1-a030-0d5d7a21ca8f','呈張敏叔','徐積','宋','宋诗','song-poetry','','[]','子善居官事可宗，淮西聲譽接淮東。',64,'全唐诗/poet.song.37000.json','["子善居官事可宗，淮西聲譽接淮東。", "皆知所識明無敵，兩主斯文敏有功。", "麗賦總應輸老匠，清詩恰好送秋風。", "便乘急棹辭譙守，酌酒仍吟塞上翁。"]'),
('286914f1-62fb-4e13-83be-8bc62de83d03','贈探花郎','徐積','宋','宋诗','song-poetry','','[]','採花車騎似游龍，未入桃園先閬風。',64,'全唐诗/poet.song.37000.json','["採花車騎似游龍，未入桃園先閬風。", "衫上十分新染翠，衣閒一點半開紅。", "身如驥子無雙俊，人報鼇山第幾宮。", "便是醉仙何處去，上林園在五雲中。"]'),
('51d4f9f2-c097-401e-9ade-843299fee538','寄呂秘校','徐積','宋','宋诗','song-poetry','','[]','淮上詩盟不可尋，詩筒來往負初心。',32,'全唐诗/poet.song.37000.json','["淮上詩盟不可尋，詩筒來往負初心。", "風花雪月雖無限，留待他年共子吟。"]'),
('4165a2d0-143f-4cd8-8181-bcd892b59dca','贈余進士','徐積','宋','宋诗','song-poetry','','[]','江南風物清溫好，關內河山氣勢雄。',32,'全唐诗/poet.song.37000.json','["江南風物清溫好，關內河山氣勢雄。", "更看蜀中山水秀，一時兼取作吟翁。"]'),
('13fdc8a7-39df-4575-8be6-1f6cf26d00ea','寄王潛聖','徐積','宋','宋诗','song-poetry','','[]','誰言急景似飛梭，我把光陰欲快磨。',32,'全唐诗/poet.song.37000.json','["誰言急景似飛梭，我把光陰欲快磨。", "却想殘春笑君處，無何有路覓君多。"]'),
('c4fd097c-6a06-4168-8081-4830307ce61b','答范君錫','徐積','宋','宋诗','song-poetry','','[]','有人惠我一枝花，五彩妝成千萬葩。',64,'全唐诗/poet.song.37000.json','["有人惠我一枝花，五彩妝成千萬葩。", "蜀紙寫詩酬國艷，吳缾汲水貯香霞。", "半酣酒色從人贈，盡带春風入我家。", "醉倒吟翁君不見，兒童偷與插烏紗。"]'),
('5c3a1e7f-832e-49d5-a7a0-8dc4a9c5a216','上胡先生','徐積','宋','宋诗','song-poetry','','[]','昨夜重思太古音，確然獨抱一張琴。',32,'全唐诗/poet.song.37000.json','["昨夜重思太古音，確然獨抱一張琴。", "因何不聽吾夫子，枉被雕蟲累到今。"]'),
('0a1d3049-be16-4396-9118-0938c537d003','和潘朝奉','徐積','宋','宋诗','song-poetry','','[]','大人高調我旁酬，韵欲更時更少留。',64,'全唐诗/poet.song.37000.json','["大人高調我旁酬，韵欲更時更少留。", "待學鸞歌聲已嗄，將追驥乘老而遒。", "曉隨帆去雲連海，莫望潮來月滿洲。", "須道詩翁非世俗，年家情義幾時休。"]'),
('765a7071-195b-4939-b56a-27c4341a9e9a','和呂秘校  其一','徐積','宋','宋诗','song-poetry','','[]','董子書幃正寂寥，阮君何事顧吾曹。',64,'全唐诗/poet.song.37000.json','["董子書幃正寂寥，阮君何事顧吾曹。", "兩篇有若雙瓊贈，八句多於一字褒。", "莫恨潘安頭早白，須知郢客調彌高。", "鸞凰豈是塵埃物，待看青雲振羽毛。"]'),
('e1cce8fe-e194-47bf-b6bd-b6ca517afe46','和呂秘校  其二','徐積','宋','宋诗','song-poetry','','[]','王子如今未夢刀，不須感慨論官曹。',64,'全唐诗/poet.song.37000.json','["王子如今未夢刀，不須感慨論官曹。", "寢郎悟意猶爲相，鄠尉知名固可褒。", "嗟爾歲華何太速，顧予儒業若爲高。", "四詩已有重箋意，肯學區區鄭與毛。"]'),
('088bc44d-77ea-445a-9709-e05bcf2b329a','和呂秘校  其三','徐積','宋','宋诗','song-poetry','','[]','東平心事本雄豪，何必才名獨慕曹。',64,'全唐诗/poet.song.37000.json','["東平心事本雄豪，何必才名獨慕曹。", "學比今儒醇且奧，詩如古義刺而褒。", "鄒之夫子誠堪歎，霸者將軍未足高。", "賢傑固當謀遠到，莫論山岳與鴻毛。"]'),
('aa301fcf-2a39-4847-a2b0-6c4d01d68d10','和呂秘校  其四','徐積','宋','宋诗','song-poetry','','[]','能建功名是俊豪，區區時輩乃兒曹。',64,'全唐诗/poet.song.37000.json','["能建功名是俊豪，區區時輩乃兒曹。", "班超投筆寧無志，樊噲橫行謝見褒。", "兵法每羞孫臏詐，將才惟愛武侯高。", "他年不負東平約，待假偏師入不毛。"]'),
('42370135-3348-466c-a430-573cb42785ba','和呂秘校  其五','徐積','宋','宋诗','song-poetry','','[]','我謂君才似楚騷，文章自可作清曹。',64,'全唐诗/poet.song.37000.json','["我謂君才似楚騷，文章自可作清曹。", "但持古道徐而待，莫顧時人毀與褒。", "水以源深流自遠，竹因根老節彌高。", "如今且作東山卧，萬事紛紛比一毛。"]'),
('65ffa92a-1351-4c74-aad6-0ec15892e146','和呂秘校  其六','徐積','宋','宋诗','song-poetry','','[]','東平夫子困徒勞，又著青衫詣選曹。',64,'全唐诗/poet.song.37000.json','["東平夫子困徒勞，又著青衫詣選曹。", "州縣頗聞輿論屈，朝廷當用詔書褒。", "囊中莫把詩編去，輦下方虞紙價高。", "曼倩若教爲近侍，舍人須愧古無毛。"]'),
('b7fd2180-b884-4dcb-bfc4-f1d6f797f764','和呂秘校  其七','徐積','宋','宋诗','song-poetry','','[]','方今天子急賢時，不信王通願已違。',64,'全唐诗/poet.song.37000.json','["方今天子急賢時，不信王通願已違。", "梅福九江雖好遁，陶公八翮亦難飛。", "世排韓愈爲文僻，客顧揚生載酒稀。", "多謝好詩來贈我，曉齋歌誦暮而歸。"]'),
('f091ee92-c6b5-4df0-aaeb-85484a96c977','和呂秘校  其八','徐積','宋','宋诗','song-poetry','','[]','汾上儒生又續詩，陽春巴調本相違。',64,'全唐诗/poet.song.37000.json','["汾上儒生又續詩，陽春巴調本相違。", "聊因扣角攄深憤，安得摩天逞快飛。", "陶氏弄琴乖俗甚，井丹持刺出門稀。", "有時入市謀甘脆，懷橘携壺即便歸。"]'),
('828bf144-c2e6-4b08-8c1c-b176610fb555','和呂秘校  其九','徐積','宋','宋诗','song-poetry','','[]','太平儒者好吟詩，鼓腹而歌事豈違。',64,'全唐诗/poet.song.37000.json','["太平儒者好吟詩，鼓腹而歌事豈違。", "顧我才華常患少，喜君辭翰動而飛。", "不憂陋巷簞瓢罄，惟恐蘭亭唱和稀。", "更約山翁同一醉，梅花將謝燕將歸。"]'),
('da245824-3976-4a6c-9437-14ac02579680','和呂秘校  其一○','徐積','宋','宋诗','song-poetry','','[]','吾道窮通自有時，功名豈便與心違。',64,'全唐诗/poet.song.37000.json','["吾道窮通自有時，功名豈便與心違。", "摩天未逐溟鵬奮，歛翅尚如籬鶠飛。", "鳴鳳卜遲君莫笑，玉山醉倒事何稀。", "梅花將謝剩沽酒，待向花前倒載歸。"]'),
('bb355dc0-6526-4240-b5a8-d78fa7467f8d','贈蔡子驤二子','徐積','宋','宋诗','song-poetry','','[]','鳳子能雙舉，新從日下回。',24,'全唐诗/poet.song.37000.json','["鳳子能雙舉，新從日下回。", "日邊是雲霧，却带越書來。"]'),
('d761a008-37bf-406c-9e3b-0da33c1dc24e','答崔汝弼','徐積','宋','宋诗','song-poetry','','[]','忽對蒼髯叟，誰吟老柳枝。',48,'全唐诗/poet.song.37000.json','["忽對蒼髯叟，誰吟老柳枝。", "豈無解印日，兼是省官時。", "子實安於命，吾何戲以詩。", "如能少施設，亦可慰余思。"]'),
('d1a79814-418d-4344-b8c1-cfea008bbbae','答魏老  其一','徐積','宋','宋诗','song-poetry','','[]','滿面春風醉落暉，滿頭紅艷带花歸。',32,'全唐诗/poet.song.37000.json','["滿面春風醉落暉，滿頭紅艷带花歸。", "醉眠自有風流格，不是無人爲解衣。"]'),
('0d888f16-f89c-4e87-ad6e-23616ceee60b','答魏老  其二','徐積','宋','宋诗','song-poetry','','[]','一片山中雲自飛，葛巾有酒琴無徽。',32,'全唐诗/poet.song.37000.json','["一片山中雲自飛，葛巾有酒琴無徽。", "陶公自是秋風客，不見黄花未肯歸。"]'),
('9d9b6685-cc38-46f3-a98d-6990f81a3e08','答楊存中','徐積','宋','宋诗','song-poetry','','[]','出郭人來又換詩，七香官酒杏花枝。',32,'全唐诗/poet.song.37000.json','["出郭人來又換詩，七香官酒杏花枝。", "我詩却恐春風惜，莫使春風度度知。"]'),
('1b28df14-9add-4d10-930c-c15a6635959a','謝張先生出示鐵笛','徐積','宋','宋诗','song-poetry','','[]','南陽張老本仙才，鐵笛其形亦怪哉。',32,'全唐诗/poet.song.37000.json','["南陽張老本仙才，鐵笛其形亦怪哉。", "輒莫片時吹便已，鳳凰非獨待簫來。"]'),
('2d50dcb5-44a6-484a-b1b7-14a36f97a54a','上林殿院次公  其一','徐積','宋','宋诗','song-poetry','','[]','身雖老矣心彌壯，義必爲之世所諳。',64,'全唐诗/poet.song.37000.json','["身雖老矣心彌壯，義必爲之世所諳。", "新著繡衣行殿內，又騎驄馬使淮南。", "升堂避席非常禮，就室迂身共燕談。", "更問熊熊與老老，應咍稚女拜而參。"]'),
('ffb3c425-c57f-4363-a888-9af1af47b4ca','上林殿院次公  其二','徐積','宋','宋诗','song-poetry','','[]','一從縉笏垂紳後，所至官曹不苟拘。',64,'全唐诗/poet.song.37000.json','["一從縉笏垂紳後，所至官曹不苟拘。", "皓首積成高世義，赤心傾在逆鱗書。", "溫如冬日人之望，嚴載秋霜使者車。", "以愛以威無不濟，恩從城市入田廬。"]'),
('06c26fd5-5d46-4c7d-8bee-597a31ddfbe4','上林殿院次公  其三','徐積','宋','宋诗','song-poetry','','[]','衰翁大半白髭鬚，活到明年六十餘。',64,'全唐诗/poet.song.37000.json','["衰翁大半白髭鬚，活到明年六十餘。", "未死須爲治河說，此生難就賑饑書。", "西菴共坐諸僧榻，南郭親逢大使車。", "記得偶同詩韵否，淮東使者亦嗟歔。"]'),
('44cd30cf-243e-410e-b9c1-862a3612c3a1','上林殿院次公  其四','徐積','宋','宋诗','song-poetry','','[]','老身如坐白雲山，人日登高我自閒。',64,'全唐诗/poet.song.37000.json','["老身如坐白雲山，人日登高我自閒。", "莫道此心無樂事，未知何日有愁顔。", "月將寒影投書幌，菊遣秋香過竹關。", "悔不醉時籬下卧，和花和蘂一時攀。"]'),
('944ea8fc-f687-47aa-a92e-826902e5bbb4','上林殿院次公  其五','徐積','宋','宋诗','song-poetry','','[]','閉門老子卧遊山，心去穿雲身自閒。',64,'全唐诗/poet.song.37000.json','["閉門老子卧遊山，心去穿雲身自閒。", "平地散仙曾有號，坐曹爲吏亦何顔。", "吟詩著屐都無齒，探月開門更不關。", "酒後愛逢花後發，花枝好向醉中攀。"]'),
('a63aea7b-3cf5-464a-8fef-6cd4c30be6da','上林殿院次公  其六','徐積','宋','宋诗','song-poetry','','[]','老懷秋思各思山，綠髪兒童事事閒。',64,'全唐诗/poet.song.37000.json','["老懷秋思各思山，綠髪兒童事事閒。", "感物但搔頭上雪，呼人莫笑鏡中顔。", "籃輿自可來嘗酒，芒屐猶能去渡關。", "玉井有花高百尺，秦王宮女許誰攀。"]'),
('b06f1e6e-0cf3-4f2a-aa46-5f09038ef72e','上林殿院次公  其七','徐積','宋','宋诗','song-poetry','','[]','三歎枉教陪一唱，詩仙爭肯伴樵夫。',64,'全唐诗/poet.song.37000.json','["三歎枉教陪一唱，詩仙爭肯伴樵夫。", "金刀刮盡塵埃氣，玉水洗成冰雪膚。", "涸胃已慙搜思竭，乾喉兼覺出羣麤。", "餘篇只等功成後，留和棹歌尋五湖。"]'),
('39b6db82-a5a9-4eef-89e4-5aa9db5199b5','上林殿院次公  其八','徐積','宋','宋诗','song-poetry','','[]','兩人外迹本相疏，何故孤孤爲病夫。',64,'全唐诗/poet.song.37000.json','["兩人外迹本相疏，何故孤孤爲病夫。", "未報已慙公面目，有情顧入我肌膚。", "將身荷負嫌軀小，引臂鎸鎔要骨麤。", "盡力吟哦吟不盡，此時寒雨滿淮湖。"]'),
('a537347f-c602-48d7-8a13-2ec14d8fd1f6','上林殿院次公  其九','徐積','宋','宋诗','song-poetry','','[]','林氏家藏萬帙書，五船便可當五車。',64,'全唐诗/poet.song.37000.json','["林氏家藏萬帙書，五船便可當五車。", "別顧客舟施坐榻，更謀官舫作行厨。", "寫時教子烘青竹，讀處呼童捉蠹魚。", "悔不早知都借取，終身挾策灌園蔬。"]'),
('0f39a114-3d3d-4d04-ac5f-87573c3afa58','寄顧龍圖','徐積','宋','宋诗','song-poetry','','[]','龍圖莫怪白鬚翁，依舊閒吟閒笑中。',64,'全唐诗/poet.song.37000.json','["龍圖莫怪白鬚翁，依舊閒吟閒笑中。", "未有梅花充信物，但將竹簡換詩筒。", "子如行路真無巧，我信居山養有功。", "氣類相從應得士，并州兼有傅元通。"]'),
('33a05549-f4ea-4b5d-b296-14bb58976d07','寄張子中','徐積','宋','宋诗','song-poetry','','[]','時輩區區耳盡聾，姓張夫子在關中。',64,'全唐诗/poet.song.37000.json','["時輩區區耳盡聾，姓張夫子在關中。", "孤松節操乖今俗，獨鳳文章得古風。", "至寶却須三獻捷，病鸞終看一飛雄。", "儒家自是詩書將，又況潛心郭令公。"]'),
('849057ee-3850-4982-a75f-198b4bce4017','過故鄉','徐積','宋','宋诗','song-poetry','','[]','不似嚴生乞會稽，一身名義總無非。',64,'全唐诗/poet.song.37000.json','["不似嚴生乞會稽，一身名義總無非。", "何須佩印如金斗，若論還鄉勝錦衣。", "行處眼前新事滿，坐來門外故人稀。", "有時載酒尋閭巷，認得當年老父歸。"]'),
('5a26708d-b518-4814-8661-43e2bf99bfbf','少年行','徐積','宋','宋诗','song-poetry','','[]','車馬朝遊去，笙歌暮宴歸。',24,'全唐诗/poet.song.37000.json','["車馬朝遊去，笙歌暮宴歸。", "繡幃初睡起，紅日上簾衣。"]'),
('924fe6b5-413e-4d7d-b08b-bf15a9832d43','贈李通直','徐積','宋','宋诗','song-poetry','','[]','昨見君家父祖碑，德功俱茂節多奇。',64,'全唐诗/poet.song.37000.json','["昨見君家父祖碑，德功俱茂節多奇。", "初終義正今難有，積累源深後可知。", "但得名爲騏驥子，何須身到鳳凰池。", "其先付予皆良法，隨所居官任設施。"]'),
('c16042c8-9832-4656-8343-a4cdf6c212d3','寄范君錫','徐積','宋','宋诗','song-poetry','','[]','人事大難知，悲歡與合離。',48,'全唐诗/poet.song.37000.json','["人事大難知，悲歡與合離。", "忽驚殘臘盡，還憶去年時。", "對雪我無酒，招沽子有詩。", "春深相贈物，花共綠楊枝。"]'),
('728c7d33-9226-4ce7-a4dd-f3ac706ff232','寄崔汝弼  其一','徐積','宋','宋诗','song-poetry','','[]','黄艷花前白頷翁，憶君詩思入霜風。',32,'全唐诗/poet.song.37000.json','["黄艷花前白頷翁，憶君詩思入霜風。", "如今相去猶未遠，明年把酒望江東。"]'),
('9bf1e0af-ba7e-48ff-ab3f-c505367e9af7','寄崔汝弼  其二','徐積','宋','宋诗','song-poetry','','[]','除却行吾義，其他任自然。',48,'全唐诗/poet.song.37000.json','["除却行吾義，其他任自然。", "胸中清水溜，頷下白毛鮮。", "別我未逾月，思君似隔年。", "北軒翁在此，曾醉菊花邊。"]'),
('36caca2d-fbc5-424a-a77f-41e1c860f588','寄崔汝弼  其三','徐積','宋','宋诗','song-poetry','','[]','不見吾崔子，南城兩度春。',48,'全唐诗/poet.song.37000.json','["不見吾崔子，南城兩度春。", "應從湘水夢，來就泮宮人。", "壯氣胸中舊，衰毛頷下新。", "明年六十六，望子過淮濱。"]'),
('45738e78-3ee9-4c00-b148-deac787649aa','寄崔汝弼  其四','徐積','宋','宋诗','song-poetry','','[]','數幅長沙紙，慇勤爲寫懷。',48,'全唐诗/poet.song.37000.json','["數幅長沙紙，慇勤爲寫懷。", "知公富情義，念我老形骸。", "處世日無幾，歸耕計未諧。", "若論身後事，賤骨要深埋。"]'),
('6394a7fd-e3d3-4de0-a80d-c887c4ff55df','寄裴守','徐積','宋','宋诗','song-poetry','','[]','高麗亭下張帆日，引首將心送畫船。',64,'全唐诗/poet.song.37000.json','["高麗亭下張帆日，引首將心送畫船。", "本恨無因到夔國，誰知有夢向澶淵。", "情逾舊物非徒爾，義等高山合使然。", "料得政成公事少，冬溫常在北堂前。"]'),
('ad0eef75-2096-4c81-9abe-7e9fd27cb81e','贈盧君常','徐積','宋','宋诗','song-poetry','','[]','人世情懷已索然，幸無不義入黄泉。',32,'全唐诗/poet.song.37000.json','["人世情懷已索然，幸無不義入黄泉。", "不須永訣行相見，六十三翁能幾年。"]'),
('d0a171a5-cc90-42ed-a66b-0da6732edf20','君向瀟湘我向秦','徐積','宋','宋诗','song-poetry','','[]','我望秦關方整駕，子如湘水欲登舟。',64,'全唐诗/poet.song.37000.json','["我望秦關方整駕，子如湘水欲登舟。", "馬嘶山塢誰家宿，纜繫江楓何處留。", "壠上耕隨殘月去，日邊帆带落霞收。", "灞陵古恨騷人意，歌向樽前不易酬。"]'),
('89827526-f7ef-4caf-90db-99d23497cf7f','寄朱廣微','徐積','宋','宋诗','song-poetry','','[]','兩官本是好吟翁，雲出山來鶴入籠。',32,'全唐诗/poet.song.37000.json','["兩官本是好吟翁，雲出山來鶴入籠。", "記得僧軒閒坐否，無人到處水邊鴻。"]'),
('0b97bc98-8dec-4ddb-8d81-4af4a4573cf8','答白雲之句  其一','徐積','宋','宋诗','song-poetry','','[]','我是白雲雲是我，自知雲我不須分。',32,'全唐诗/poet.song.37000.json','["我是白雲雲是我，自知雲我不須分。", "時人若問山翁意，看取山頭一片雲。"]'),
('96170cb6-b79f-474d-a950-34a4cd58e413','答白雲之句  其二','徐積','宋','宋诗','song-poetry','','[]','朝共白雲行，暮共白雲歸。',56,'全唐诗/poet.song.37000.json','["朝共白雲行，暮共白雲歸。", "眠時雲亦眠，以雲爲寢衣。", "白雲白雲常在身，有時忽共白雲分。", "君看天外逍遥物，便是山翁身上雲。"]'),
('710d9701-40a5-4855-88bf-8ad9ce73a4bb','菊花','徐積','宋','宋诗','song-poetry','','[]','爲汝花中開最孤，詩翁何惜屢提壺。',64,'全唐诗/poet.song.37000.json','["爲汝花中開最孤，詩翁何惜屢提壺。", "却應有意酬青眼，渾似傾心向白鬚。", "擊銅鉢時吟更好，擲金錢後醉相娛。", "楊妃只有黄裙在，且問風霜留得無。"]'),
('b5a8eabc-c5ae-4423-9096-680d2228d241','贈黄魯直','徐積','宋','宋诗','song-poetry','','[]','不見故人彌有情，一見故人心眼明。',32,'全唐诗/poet.song.37000.json','["不見故人彌有情，一見故人心眼明。", "忘却問君船住處，夜來清夢遶西城。"]'),
('96b2e161-5e30-44c7-8f53-5a4b29bfde12','示諸君','徐積','宋','宋诗','song-poetry','','[]','古俗今時不用分，只將虛實判澆淳。',64,'全唐诗/poet.song.37000.json','["古俗今時不用分，只將虛實判澆淳。", "養心有要先除僞，入德無難只用真。", "此道若從爲得路，他歧如往是迷津。", "我曹好尚雖迂闊，最愛山夫共野人。"]'),
('231a6093-cbde-4eb1-9383-e92385786e8e','妾薄命  其一','徐積','宋','宋诗','song-poetry','','[]','偷把羅衣裛淚痕，落花江上泣青春。',64,'全唐诗/poet.song.37000.json','["偷把羅衣裛淚痕，落花江上泣青春。", "空將鳳管題君怨，自是蛾眉累汝身。", "翠黛不須勻綠鬢，紅膏休更點朱唇。", "自然彼此無心妬，猶恐多言巧中人。"]'),
('f20c27bc-0f3d-4bd5-bfa5-d52574c98b08','妾薄命  其二','徐積','宋','宋诗','song-poetry','','[]','春深江浦流還漲，雨後山花落更多。',64,'全唐诗/poet.song.37000.json','["春深江浦流還漲，雨後山花落更多。", "舉目未言先有淚，當樽欲唱不成歌。", "心知自古皆如此，事到如今不奈何。", "莫向夕陽樓上望，幾人遺恨滿烟波。"]'),
('4035def4-02dd-4d50-a8d8-2a9b7316faae','妾薄命  其三','徐積','宋','宋诗','song-poetry','','[]','將身誤入楚王宮，負却家山事總空。',64,'全唐诗/poet.song.37000.json','["將身誤入楚王宮，負却家山事總空。", "枕上無言吟夜雨，花前有淚灑春風。", "假饒醉飽朱門內，豈似寒饑漏屋中。", "更有文君作奔妾，爭如寂寞嫁梁鴻。"]'),
('49dfc608-732f-44ec-9ffd-bd610653b4a9','妾薄命  其四','徐積','宋','宋诗','song-poetry','','[]','女子恩讎事可知，我曹何用弔吳姬。',32,'全唐诗/poet.song.37000.json','["女子恩讎事可知，我曹何用弔吳姬。", "如斯才貌如斯苦，也似賢人被妬時。"]'),
('89ac10e1-acad-492a-9d6c-237107316929','璽書長句','徐積','宋','宋诗','song-poetry','','[]','隨船父老踏青莎，人各持杯奈醉何。',64,'全唐诗/poet.song.37000.json','["隨船父老踏青莎，人各持杯奈醉何。", "謠俗戀恩成太息，吟翁樂義合長歌。", "皆知察物嚴而恕，誰似當官正不阿。", "東漢武威任郡守，至今高義聳峨峨。"]'),
('f0e74503-0527-44a9-85d1-544c7ae0300f','瑶真詩  其一','徐積','宋','宋诗','song-poetry','','[]','此花所在宜開館，彼玉維瑶合比君。',64,'全唐诗/poet.song.37000.json','["此花所在宜開館，彼玉維瑶合比君。", "每到黄昏成淡月，却臨曉後作團雲。", "人閒僞采何如質，物裏孤芳自勝羣。", "應笑馬嵬坡下女，太真爲號繫黄裙。"]'),
('4aaded37-417f-4f0f-a7c2-949528743fcb','瑶真詩  其二','徐積','宋','宋诗','song-poetry','','[]','不知記得瑶林否，故國曾陪閬苑春。',64,'全唐诗/poet.song.37000.json','["不知記得瑶林否，故國曾陪閬苑春。", "色貌易分渾是正，性情雖辨總歸真。", "紅塵世上無雙物，白雪宮中第幾人。", "若問誰何名玉女，一般嚴靜敵霜神。"]'),
('a23dcf11-5b10-4f91-86c0-78de684c273b','詠慎郎中園木香','徐積','宋','宋诗','song-poetry','','[]','仙子霓裳曳紺霞，瓊姬仍坐碧雲車。',32,'全唐诗/poet.song.37000.json','["仙子霓裳曳紺霞，瓊姬仍坐碧雲車。", "誰言十日春歸去，猶有春風在慎家。"]'),
('6a699ccc-39f6-418f-96f6-76f1269d676d','長春花  其一','徐積','宋','宋诗','song-poetry','','[]','誰言造物無偏處，獨遣春光住此中。',64,'全唐诗/poet.song.37000.json','["誰言造物無偏處，獨遣春光住此中。", "葉裏深藏雲外碧，枝頭常借日邊紅。", "曾陪桃李開時雨，仍伴梧桐落後風。", "費盡主人歌與酒，不教閒却賣花翁。"]'),
('258d0f9a-95b0-4c6b-8756-09ba3b2bedd4','長春花  其二','徐積','宋','宋诗','song-poetry','','[]','一從春色入花來，便把春陽不放回。',64,'全唐诗/poet.song.37000.json','["一從春色入花來，便把春陽不放回。", "雪圃未容梅獨占，霜籬初約菊同開。", "長生洞裏神仙種，萬歲樓前錦繡堆。", "過盡白駒都不管，綠楊紅杏自相催。"]'),
('117cabb8-4d76-4ef9-b07c-f9fc447a7c53','長春花  其三','徐積','宋','宋诗','song-poetry','','[]','一謝芳菲更不還，誰何嬌步獨盤桓。',64,'全唐诗/poet.song.37000.json','["一謝芳菲更不還，誰何嬌步獨盤桓。", "雖於物態爲難有，却是時情總易闌。", "日曬香肌難避暑，雪濡粉面亦禁寒。", "等閒莫使人知處，長與詩家醉後看。"]'),
('c44b4b7c-3857-4ad6-b182-b5c7705cc315','長春花  其四','徐積','宋','宋诗','song-poetry','','[]','誰與猩猩血染紅，重重疊疊費春工。',64,'全唐诗/poet.song.37000.json','["誰與猩猩血染紅，重重疊疊費春工。", "應無暴物侵和氣，自有深根藏暖風。", "每見靈芝三秀了，回看凡艷一時空。", "如環光景循將遍，又到江南梅信通。"]'),
('ac434f77-ed6e-44f1-b705-a83aecc489dc','長春花  其五','徐積','宋','宋诗','song-poetry','','[]','枝上疏疏花啟房，輕綃重錦迭爲裳。',64,'全唐诗/poet.song.37000.json','["枝上疏疏花啟房，輕綃重錦迭爲裳。", "更分深淺兩般色，不作尋常一面妝。", "蕣有紅華須鬬艷，蘭雖清節亦交香。", "吟翁未暢先投筆，爲與東君詠海棠。"]'),
('d1db75f5-91e7-4634-9c00-236af36b6d48','天下風流無綠楊','徐積','宋','宋诗','song-poetry','','[]','天下風流無綠楊，半遮妝面出宮牆。',64,'全唐诗/poet.song.37000.json','["天下風流無綠楊，半遮妝面出宮牆。", "客醉任鋪紅錦段，馬嘶爭繫紫絲韁。", "上東門外我回首，長樂坡頭誰斷腸。", "最好春深山下路，亂花薰與一身香。"]'),
('9d7fd53a-1b36-41b9-bfda-63832a7f9e46','誰把閒愁付綠楊','徐積','宋','宋诗','song-poetry','','[]','誰把閒愁付綠楊，我疑渾是別離腸。',64,'全唐诗/poet.song.37000.json','["誰把閒愁付綠楊，我疑渾是別離腸。", "每教啼鳥呼春色，更共平蕪送夕陽。", "山下人行雲慘慘，渡頭船去水茫茫。", "高樓亦有思歸客，莫望天涯尋故鄉。"]'),
('37e09a00-f3e3-4695-ae0a-61e260e080c1','一生多恨瘦纖纖','徐積','宋','宋诗','song-poetry','','[]','一生多恨瘦纖纖，染盡春華綠試圓。',64,'全唐诗/poet.song.37000.json','["一生多恨瘦纖纖，染盡春華綠試圓。", "十二樓臺寒怕雨，九重宮殿煖愁烟。", "城邊放客尋花路，溪畔留人載酒船。", "莫向壩陵橋上望，白雲流水舊山川。"]'),
('21a5cb36-f42e-4d37-bf2f-333277bb1d9d','一片花飛減却春','徐積','宋','宋诗','song-poetry','','[]','一片花飛減却春，共君同作管花人。',32,'全唐诗/poet.song.37000.json','["一片花飛減却春，共君同作管花人。", "急將步障圍載圃，莫使狂風近四鄰。"]'),
('493dc4ee-9b01-429b-b997-b83bbea23872','問楊柳','徐積','宋','宋诗','song-poetry','','[]','我愛風流楊柳枝，楊柳如何報我詩。',32,'全唐诗/poet.song.37000.json','["我愛風流楊柳枝，楊柳如何報我詩。", "落花滿面春風曉，借與絲鞭走馬時。"]'),
('c3dc43c6-b739-4db9-873d-9483de9ae7af','白蓮花','徐積','宋','宋诗','song-poetry','','[]','水一重重玉一重，更無妖色媚西風。',32,'全唐诗/poet.song.37000.json','["水一重重玉一重，更無妖色媚西風。", "雖然物外能爲素，又恐人閒只愛紅。"]'),
('59b1525c-2314-42d4-8fcc-d1918c6c3f75','野花','徐積','宋','宋诗','song-poetry','','[]','一點香心寂寞春，牧童歸後更無人。',32,'全唐诗/poet.song.37000.json','["一點香心寂寞春，牧童歸後更無人。", "誰家庭院栽楊柳，猶自飛花入四鄰。"]'),
('99158f2f-4cdd-4deb-ac2b-679ec0a4ac57','謝人惠梅花','徐積','宋','宋诗','song-poetry','','[]','我共梅花情最深，左持樽酒右持燈。',32,'全唐诗/poet.song.37000.json','["我共梅花情最深，左持樽酒右持燈。", "持燈持酒豈辭倦，却是春香不自勝。"]'),
('2e5d2dcb-cc2e-4692-89a5-23e0efb410b8','海棠花  其一','徐積','宋','宋诗','song-poetry','','[]','彼美花兮宜晚春，柔姿淑艷是何人。',64,'全唐诗/poet.song.37000.json','["彼美花兮宜晚春，柔姿淑艷是何人。", "十分國色妝須淡，數點胭脂畫未勻。", "带雨容開渾是恨，出牆頭望恰如真。", "幾時謫下蓬萊島，霞污仙衣痕尚新。"]'),
('8d2cea03-b920-445f-9fe0-9153a973f241','海棠花  其二','徐積','宋','宋诗','song-poetry','','[]','一度相逢一度春，不知名姓是何人。',64,'全唐诗/poet.song.37000.json','["一度相逢一度春，不知名姓是何人。", "十分國色妝須淡，數點胭脂畫未勻。", "好把東皇爲上客，便堪宋玉作西鄰。", "臨卭道士今何在，說與唐宗是太真。"]'),
('cd4e5e5d-2c54-4561-80d2-53b67da139c9','別玉女花','徐積','宋','宋诗','song-poetry','','[]','辭他玉女難空手，酌盡銀缾醉未休。',32,'全唐诗/poet.song.37000.json','["辭他玉女難空手，酌盡銀缾醉未休。", "任是職嚴風望峻，也須一步一回頭。"]'),
('1ca21626-b042-48f3-a8c4-a837cf845e01','綠楊  其一','徐積','宋','宋诗','song-poetry','','[]','綠楊何處不相逢，到處伴他花草紅。',32,'全唐诗/poet.song.37000.json','["綠楊何處不相逢，到處伴他花草紅。", "只爲人閒苦離別，更無情緒管春風。"]'),
('507e243d-a33e-4987-940a-fa81609adffd','綠楊  其二','徐積','宋','宋诗','song-poetry','','[]','且尋綠院朱扉好，莫看山前水畔容。',32,'全唐诗/poet.song.37000.json','["且尋綠院朱扉好，莫看山前水畔容。", "肌膚瘦盡春風甚，更被春風舞不供。"]'),
('a05a06f4-4609-41dd-afba-215c7205d9b2','柳絮  其一','徐積','宋','宋诗','song-poetry','','[]','君看青蠶蘂，閒花便棄捐。',48,'全唐诗/poet.song.37000.json','["君看青蠶蘂，閒花便棄捐。", "臨風競離別，就地忽團圓。", "孤客正心亂，浮雲來馬前。", "灞橋逢杜甫，老淚更潸然。"]'),
('eec4c70c-5c6c-4288-8b7f-f9071db74d37','柳絮  其二','徐積','宋','宋诗','song-poetry','','[]','長條徒自重，狂絮去何之。',48,'全唐诗/poet.song.37000.json','["長條徒自重，狂絮去何之。", "禁籞穿花樹，春江撲酒旗。", "因風無定意，著物有閒時。", "謝女何爲者，深情在雪詩。"]'),
('27879961-5550-436d-bb91-60a4cdc4d406','荷花','徐積','宋','宋诗','song-poetry','','[]','池上交加礙釣船，漢宮新妓約三千。',64,'全唐诗/poet.song.37000.json','["池上交加礙釣船，漢宮新妓約三千。", "綠籮枝葉能承露，紅玉肌膚不惹烟。", "巫峽已曾縈客夢，西施何處擲金錢。", "無人爲把秋香惜，聊借西風贈此篇。"]'),
('cd27d387-f4f9-4599-9c70-f3fe521f3e4b','敗荷','徐積','宋','宋诗','song-poetry','','[]','有客方笑歌，誰人吟敗荷。',48,'全唐诗/poet.song.37000.json','["有客方笑歌，誰人吟敗荷。", "但言爲秋惜，不道礙船過。", "折柄刺芒在，亂絲根本多。", "江頭浪如屋，今夜奈風何。"]'),
('1f466a45-35f0-429c-9d25-713d90ffc585','杏花  其一','徐積','宋','宋诗','song-poetry','','[]','窗外花開紅滿枝，董生正下讀書帷。',32,'全唐诗/poet.song.37000.json','["窗外花開紅滿枝，董生正下讀書帷。", "東風到晚殊無定，今夜清香屬阿誰。"]'),
('35f0463f-682c-49d9-b40e-32eba51d9b8a','杏花  其二','徐積','宋','宋诗','song-poetry','','[]','一點胭脂淡染腮，十分顔色爲誰開。',32,'全唐诗/poet.song.37000.json','["一點胭脂淡染腮，十分顔色爲誰開。", "殘燈欲盡書幃閉，猶有清香半夜來。"]'),
('27cefb80-84aa-445f-84d2-f502863b8033','雙頭芍藥  其一','徐積','宋','宋诗','song-poetry','','[]','金谷栽培異，春皇養育殊。',168,'全唐诗/poet.song.37000.json','["金谷栽培異，春皇養育殊。", "一枝輕聳翠，雙萼密承朱。", "根是鴛鴦化，生來姊妹俱。", "同行雖有伴，并寢總無夫。", "共鑑勻妝臉，偷霞點絳膚。", "東鄰與西子，謝女共羅敷。", "解佩還曾否，爲雲總解無。", "情深難獨步，力弱易相扶。", "卓氏彌傷寡，長門愈恨孤。", "鬬誇紅粉面，齊著繡羅襦。", "盡好藏金屋，誰堪作舞姝。", "郎須待劉阮，家想住秦吳。", "翠幙渾遮步，雕闌并向隅。", "黄金難買笑，爲爾倒金壺。"]'),
('590af377-271c-4557-a946-de6806411353','雙頭芍藥  其二','徐積','宋','宋诗','song-poetry','','[]','國艷妝成總一般，月娥霜女不相干。',64,'全唐诗/poet.song.37000.json','["國艷妝成總一般，月娥霜女不相干。", "春閨有恨須招伴，夜帳無夫并怯寒。", "誰道皇英沈水去，好教劉阮憑闌看。", "陽臺雲雨如俱解，妬寵爭妍有萬端。"]'),
('2a5ecc7c-8235-4994-b3c2-7e9d7c251de0','雙頭芍藥  其三','徐積','宋','宋诗','song-poetry','','[]','越艷吳姿總一般，嬌鶑之外孰相干。',64,'全唐诗/poet.song.37000.json','["越艷吳姿總一般，嬌鶑之外孰相干。", "雖同交甫江邊見，不似劉郎洞裏看。", "未必解爭春帝寵，却應同笑月娥寒。", "阿誰能伴詩人醉，不惜紅綃與萬端。"]'),
('9a3f4acf-5879-440a-9420-d3622ca1bd2b','春草','徐積','宋','宋诗','song-poetry','','[]','日暖郊前雪盡時，東風吹起綠初齊。',64,'全唐诗/poet.song.37000.json','["日暖郊前雪盡時，東風吹起綠初齊。", "人來花下禽偷避，客到山前路已迷。", "洛邑少年金作彈，杜陵驕馬玉爲蹄。", "歌樓酒市無尋處，踏遍青青日已西。"]'),
('63b46231-a622-40c8-b6e1-852670c0e50c','題紫極宮','徐積','宋','宋诗','song-poetry','','[]','不須騎鳳跨鯨鰲，來訪蓬宮是我曹。',64,'全唐诗/poet.song.37000.json','["不須騎鳳跨鯨鰲，來訪蓬宮是我曹。", "玉笈著書金簡重，碧牌題字紫垣高。", "因思大道閒閒意，頓覺浮生事事勞。", "一榻清風曾晝卧，略無塵夢及三刀。"]'),
('6ede031d-2e42-4084-8a73-829ae975e377','移竹和倪敦復','徐積','宋','宋诗','song-poetry','','[]','孫公高義薄千金，豈顧池邊竹淺深。',64,'全唐诗/poet.song.37000.json','["孫公高義薄千金，豈顧池邊竹淺深。", "此物定非今俗好，與公相伴古人心。", "但看歲久孤堅操，不爲牆閒尺寸陰。", "正是北窗閒卧日，陶家兼有一張琴。"]'),
('dbccfa28-083d-4319-8fd2-d43ff396e6de','柳上見鶑','徐積','宋','宋诗','song-poetry','','[]','楊柳枝頭見，適從何處來。',48,'全唐诗/poet.song.37000.json','["楊柳枝頭見，適從何處來。", "青春三月盡，黄艷一花開。", "舊燕元相識，新鴉近與陪。", "聲聲吟得好，未必乏詩才。"]'),
('0cfae337-36ce-4685-9d34-1de319f4f877','贈玉師鸚鵡','徐積','宋','宋诗','song-poetry','','[]','學得能言不自閒，彫籠何異網羅閒。',64,'全唐诗/poet.song.37000.json','["學得能言不自閒，彫籠何異網羅閒。", "客來青鎖常遮面，人去長門深閉關。", "感物寸腸絲欲斷，離羣雙淚血猶殷。", "如何放我西歸去，骨肉相拋在隴山。"]'),
('91e312eb-f5ea-4a46-a753-c5b16fc4e09b','舞馬詩','徐積','宋','宋诗','song-poetry','','[]','開元天子太平時，夜舞朝歌意轉迷。',64,'全唐诗/poet.song.37000.json','["開元天子太平時，夜舞朝歌意轉迷。", "繡榻盡容騏驥足，錦衣渾蓋渥洼泥。", "纔敲畫鼓頭先奮，不假金鞭勢自齊。", "明日梨園翻舊曲，范陽戈甲滿西來。"]'),
('97c0f736-f86b-4f58-bba8-6757cedd41c2','題扇 儒扇','徐積','宋','宋诗','song-poetry','','[]','講罷窮神易，吟成泣鬼文。',24,'全唐诗/poet.song.37000.json','["講罷窮神易，吟成泣鬼文。", "心營四海事，手握一環雲。"]'),
('f97c707d-76d7-4533-822e-c1b67b069f33','題扇 道扇','徐積','宋','宋诗','song-poetry','','[]','携待真壇醮，摇吟玉笈書。',24,'全唐诗/poet.song.37000.json','["携待真壇醮，摇吟玉笈書。", "面題金鼎訣，背畫五雲車。"]'),
('e157ed80-644e-4548-9162-bbd639d27f44','題扇 釋扇','徐積','宋','宋诗','song-poetry','','[]','把月行杉徑，將風上竹軒。',24,'全唐诗/poet.song.37000.json','["把月行杉徑，將風上竹軒。", "倒持敲磬罷，還指佛書言。"]'),
('4381e7d5-db59-458f-9814-5b288db211b2','題扇 貞女扇','徐積','宋','宋诗','song-poetry','','[]','妾非宋家鄰，亦笑巫山神。',24,'全唐诗/poet.song.37000.json','["妾非宋家鄰，亦笑巫山神。", "便是楚王來，掩面不從人。"]'),
('320dd22c-3a0a-4ad6-920f-3f31a8843f01','題扇 貞婦扇','徐積','宋','宋诗','song-poetry','','[]','笑亦待君掩，泣亦待君遮。',24,'全唐诗/poet.song.37000.json','["笑亦待君掩，泣亦待君遮。", "黄金買不見，妾貌好如花。"]'),
('bff72a5b-8835-46e1-81da-ad100d0c0dce','題扇 妝婦扇','徐積','宋','宋诗','song-poetry','','[]','妾貌非不奇，行坐自遮面。',24,'全唐诗/poet.song.37000.json','["妾貌非不奇，行坐自遮面。", "樓上曉妝成，樓下無人見。"]'),
('1a568dcf-3c65-4fdc-ba2d-ef3728c39dfa','題扇 貧女扇','徐積','宋','宋诗','song-poetry','','[]','妾有一尺絹，已爲身上衣。',48,'全唐诗/poet.song.37000.json','["妾有一尺絹，已爲身上衣。", "自織清溪蒲，團團手中持。", "朝尋麥隴去，暮汲水泉歸。", "無人不看妾，不使見蛾眉。"]'),
('943c2811-e6b3-4db9-a52f-5cd980b1c3ff','題扇 寢婦扇','徐積','宋','宋诗','song-poetry','','[]','酒闌歌已闋，解佩燈先滅。',24,'全唐诗/poet.song.37000.json','["酒闌歌已闋，解佩燈先滅。", "羅帳隔清風，玉腕摇明月。"]'),
('67720732-f760-442e-b2b8-2961ba1bbfd2','題扇 離婦扇','徐積','宋','宋诗','song-poetry','','[]','年來不把紫簫吹，玉指摻摻弄素輝。',32,'全唐诗/poet.song.37000.json','["年來不把紫簫吹，玉指摻摻弄素輝。", "一自征人渡遼去，唯有清風動妾衣。"]'),
('69ed4e4b-4cf4-4400-973e-4ac72b6eb029','題扇 孀婦扇','徐積','宋','宋诗','song-poetry','','[]','已寫共姜誓，仍題督護歌。',24,'全唐诗/poet.song.37000.json','["已寫共姜誓，仍題督護歌。", "更無脂粉污，唯有淚痕多。"]'),
('3c65dbc6-f0d6-419d-a322-e2bf6e801542','華陽山和查教授  其一','徐積','宋','宋诗','song-poetry','','[]','衝斷浮雲截斷霞，滿天矛戟競槎牙。',64,'全唐诗/poet.song.37000.json','["衝斷浮雲截斷霞，滿天矛戟競槎牙。", "日來洞口迴龍馭，月倚風前開桂花。", "暮雨勢連巫峽遠，春泉流過楚江賒。", "物靈地怪非凡境，鳳子鸞雛各一家。"]'),
('66db496b-c3a2-4e38-b803-d930685db124','華陽山和查教授  其二','徐積','宋','宋诗','song-poetry','','[]','玉井溫溫浸月華，幢幢松檜聳高牙。',64,'全唐诗/poet.song.37000.json','["玉井溫溫浸月華，幢幢松檜聳高牙。", "半峰已斷人閒路，絕頂自開天上花。", "可恨白雲吟處起，何堪行路望中賒。", "怪來得似希夷子，借問如今有幾家。"]'),
('17dc0b79-3c22-4c0b-b330-701b209c56f7','華陽山和查教授  其三','徐積','宋','宋诗','song-poetry','','[]','險物背陰彌炅矗，奇峰當午更呀牙。',64,'全唐诗/poet.song.37000.json','["險物背陰彌炅矗，奇峰當午更呀牙。", "須知南地饒春色，安得北風吹雪花。", "紫府真人來最近，紅塵俗客到彌賒。", "因何占得多陽地，莫是南方火帝家。"]'),
('222dd2c4-4119-4af1-b311-c9223e29f0fb','華陽山和查教授  其四','徐積','宋','宋诗','song-poetry','','[]','芝似蒿萊玉似沙，更多麟趾與騶牙。',64,'全唐诗/poet.song.37000.json','["芝似蒿萊玉似沙，更多麟趾與騶牙。", "雲橫秦塞妨歸雁，風過荆州带落花。", "游似赤松人已絕，隠如玄豹事何賒。", "秦宮女子今何在，好問當時秦漢家。"]'),
('17595867-316f-4048-8214-f539b850b9e9','華陽山和查教授  其五','徐積','宋','宋诗','song-poetry','','[]','朝隠真風暮隠霞，鸞麟接步虎摩牙。',64,'全唐诗/poet.song.37000.json','["朝隠真風暮隠霞，鸞麟接步虎摩牙。", "巖藏午日冬無雪，池礙南箕荷有花。", "子欲高眠浮世外，我思長嘯白雲賒。", "攖寧未必非仙骨，況有峰頭玉女家。"]'),
('ac3f7e62-1df6-400c-bfb8-b42d5174510e','華山  其一','徐積','宋','宋诗','song-poetry','','[]','數峰向背隔秦吳，看盡名山畫不如。',64,'全唐诗/poet.song.37000.json','["數峰向背隔秦吳，看盡名山畫不如。", "秋灑玉漿和沆瀣，夜張雲窟隠蟾蜍。", "鳳迷丹穴來還近，羽化紅塵事總虛。", "何日共君同去看，也須閒步也騎馿。"]'),
('a9693557-3438-4c25-903a-64861fac3dbd','華山  其二','徐積','宋','宋诗','song-poetry','','[]','一條雲路誰曾到，萬丈仙梯也不如。',64,'全唐诗/poet.song.37000.json','["一條雲路誰曾到，萬丈仙梯也不如。", "好上青雲騎鸑鷟，更探明月弄蟾蜍。", "風初定處雲烟合，日未中時碧洞虛。", "山下不須騎駿馬，爲言行客且乘馿。"]'),
('d23a4f46-b03e-4264-b51a-cd00ed30378e','華山  其三','徐積','宋','宋诗','song-poetry','','[]','華陽山仞五千餘，便是蓬萊亦未如。',64,'全唐诗/poet.song.37000.json','["華陽山仞五千餘，便是蓬萊亦未如。", "泉脈無聲通渤澥，松梢有韵拂蟾蜍。", "朝逢逋客談仙籙，夜聽真人習步虛。", "見說猿猱猛似虎，莫教山下養黔馿。"]'),
('75aa9f24-e1b3-4f78-a5ae-50ee75c64ea2','華山  其四','徐積','宋','宋诗','song-poetry','','[]','諸山傴僂復盤紆，唯有三峰勢突如。',64,'全唐诗/poet.song.37000.json','["諸山傴僂復盤紆，唯有三峰勢突如。", "酒母下來乘夭矯，藥娥飛去化蟾蜍。", "可爲世上殊方樂，便覺人閒萬事虛。", "安得往來嚴下路，不持鞭策駕疲馿。"]'),
('a1039893-b5ab-4830-8053-bd8bcb66bff4','秋山','徐積','宋','宋诗','song-poetry','','[]','氣勢不可犯，秋從何處通。',48,'全唐诗/poet.song.37000.json','["氣勢不可犯，秋從何處通。", "新嵐滴欲盡，舊翠洗將空。", "徙履寒雲裏，倚樓殘照中。", "快吟吟不暢，長嘯入松風。"]'),
('44250ee8-8c6d-467a-9aa3-5984bf313161','太華','徐積','宋','宋诗','song-poetry','','[]','鎮壓秦衝仞五千，蓮薰白日掌捫天。',64,'全唐诗/poet.song.37000.json','["鎮壓秦衝仞五千，蓮薰白日掌捫天。", "旁連少華誠微類，西顧終南只一拳。", "大壑波濤終到海，東峰松檜久淩烟。", "可爲梁棟爲舟楫，一構明堂一濟川。"]'),
('0c1417c6-e1f1-41d0-b045-a24e128e5e5d','宿山館  其一','徐積','宋','宋诗','song-poetry','','[]','下馬開門日已沈，旋尋村路乞樵燈。',64,'全唐诗/poet.song.37000.json','["下馬開門日已沈，旋尋村路乞樵燈。", "隔雲吠去誰家犬，踏月歸來何處僧。", "潭上風生千嶂吼，枕前泉落一床冰。", "呼兒笑問今宵事，身在危峰第幾層。"]'),
('56b52eb3-9d03-40a8-ad14-a2661030ef99','宿山館  其二','徐積','宋','宋诗','song-poetry','','[]','且喜破窗明有月，不嫌壞壁暗無燈。',64,'全唐诗/poet.song.37000.json','["且喜破窗明有月，不嫌壞壁暗無燈。", "解衣就枕方成寐，渡澗穿林忽夢僧。", "一榻寒雲身卧水，半宵急雨竹敲冰。", "鷄鳴未曉鞭馿去，迴顧烟嵐疊萬層。"]'),
('746200a8-78a7-455e-85ed-05ccf8c6a008','宿山館  其三','徐積','宋','宋诗','song-poetry','','[]','烟蘿斷處初逢舍，雲竹疏時忽見燈。',64,'全唐诗/poet.song.37000.json','["烟蘿斷處初逢舍，雲竹疏時忽見燈。", "嶮磴未歸樵塢叟，破菴已去誦經僧。", "暗龍吟罷庭無月，寒狖啼來谷有冰。", "君看床頭鐵鱗甲，雨痕苔暈幾千層。"]'),
('3027d595-16d3-4fea-9f2e-e119630e3c20','宿山館  其四','徐積','宋','宋诗','song-poetry','','[]','倦客待沽山下酒，饑童先上竈頭燈。',64,'全唐诗/poet.song.37000.json','["倦客待沽山下酒，饑童先上竈頭燈。", "行經怪穴思防虎，坐聽疏鐘欲訪僧。", "手弄一張琴似鐵，匣藏三尺劍如冰。", "調高器古無人伴，身上烟霞空幾層。"]'),
('f1b8a12e-df93-4cde-8201-5c3d635de107','宿山館  其五','徐積','宋','宋诗','song-poetry','','[]','好勇不須探虎穴，愛奇何用點犀燈。',64,'全唐诗/poet.song.37000.json','["好勇不須探虎穴，愛奇何用點犀燈。", "當求義路勤行己，休把福田閒問僧。", "一榻靜無塵世物，半宵渾似玉池冰。", "起來題作清心館，此去泥污千萬層。"]'),
('6bde45a5-cafc-4b4e-9327-7ba2e9c37acb','宿山館  其六','徐積','宋','宋诗','song-poetry','','[]','龍歸潭面千尋黑，虎視林隈兩炬燈。',64,'全唐诗/poet.song.37000.json','["龍歸潭面千尋黑，虎視林隈兩炬燈。", "執爨正燃吹飯火，乞餐恰值寄眠僧。", "倦聽雨後諸巖溜，渴憶春前一片冰。", "卧看滿山紅日曉，碧瑶城闕鬰千層。"]'),
('025a2b8e-377d-4ed6-9d70-194fd61845ef','宿山館  其七','徐積','宋','宋诗','song-poetry','','[]','好雲入座邀爲伴，野火當門借作燈。',64,'全唐诗/poet.song.37000.json','["好雲入座邀爲伴，野火當門借作燈。", "汲水賣來樵舍婦，採芝携去竹溪僧。", "風巖暴響聞顛木，月幌微明見斷冰。", "誰信此來無路入，敗籬折壁兩三層。"]'),
('8be819a9-523d-40ea-bf97-dcdb5ee59fd6','宿山館  其八','徐積','宋','宋诗','song-poetry','','[]','厨頭火滅童偷飯，梁上巢空鳥避燈。',64,'全唐诗/poet.song.37000.json','["厨頭火滅童偷飯，梁上巢空鳥避燈。", "入夜更無同舍客，今朝唯有放猿僧。", "樵菴已貯霜前果，竹磴猶存臘後冰。", "誰道烟霄花上處，一梯雲級萬餘層。"]'),
('4f13ed8e-f295-4197-8f0b-3b53cf1d62c2','宿山館  其九','徐積','宋','宋诗','song-poetry','','[]','解鞍息馬夜將深，倦興貪眠輒廢燈。',64,'全唐诗/poet.song.37000.json','["解鞍息馬夜將深，倦興貪眠輒廢燈。", "感物忽驚塵世事，談真却憶舊山僧。", "當峰豹寢方潛霧，隔澗狐鳴若渡冰。", "此處不唯饒物怪，從來歧路險層層。"]'),
('be49b53c-36a9-4a00-97d5-c57479ce933a','宿山館  其一○','徐積','宋','宋诗','song-poetry','','[]','遠村樵採皆歸舍，近澗人烟已上燈。',64,'全唐诗/poet.song.37000.json','["遠村樵採皆歸舍，近澗人烟已上燈。", "黍飯未炊催秣馬，蕨羹初熟喜逢僧。", "獸爭食鬬牙磨血，鳥近泉棲羽刷冰。", "若到紅塵人見問，不將水溜結爲層。"]'),
('fb1833a7-a296-433c-9e0f-80ea6441e25f','宿溪亭','徐積','宋','宋诗','song-poetry','','[]','一榻溪亭直萬錢，滿床明月伴閒眠。',32,'全唐诗/poet.song.37000.json','["一榻溪亭直萬錢，滿床明月伴閒眠。", "荷花不把秋香惜，又逐西風到枕前。"]'),
('9625fc67-e11e-4e50-86d1-536620c09236','過望思臺','徐積','宋','宋诗','song-poetry','','[]','昔日姦邪事可哀，如今空築望思臺。',32,'全唐诗/poet.song.37000.json','["昔日姦邪事可哀，如今空築望思臺。", "冥冥恨魄何之去，唯有南山暮雨來。"]'),
('ede107d2-4368-4c1b-9592-7366d82a712e','望淮亭和君錫并簡敦復  其一','徐積','宋','宋诗','song-poetry','','[]','澤國茫茫似十洲，有情空上夕陽樓。',64,'全唐诗/poet.song.37000.json','["澤國茫茫似十洲，有情空上夕陽樓。", "可憑流水傳人意，莫望遠山添客愁。", "南浦雪思乘棹往，北軒春負插花游。", "若論仕宦何非義，二子無容說愧羞。"]'),
('5292fbd7-9cf4-410d-a42c-b265798fac3b','望淮亭和君錫并簡敦復  其二','徐積','宋','宋诗','song-poetry','','[]','烟波何處是汀洲，白鳥歸來且下樓。',64,'全唐诗/poet.song.37000.json','["烟波何處是汀洲，白鳥歸來且下樓。", "木落更隨寒雨盡，山空仍带夕陽愁。", "詩筒去是蘭亭事，客棹來非剡水游。", "我問兩人同榜彥，仕方行義若爲羞。"]'),
('ff97cb94-0f28-431f-9e42-dc710504d0d1','天都仙  其一','徐積','宋','宋诗','song-poetry','','[]','甘露灑時黄道肅，紺霞環處紫宮嚴。',32,'全唐诗/poet.song.37000.json','["甘露灑時黄道肅，紺霞環處紫宮嚴。", "金華未啟瑶臺曉，流月奔星共一簾。"]'),
('4973e3d4-220b-4331-89a8-a97a0320699f','天都仙  其二','徐積','宋','宋诗','song-poetry','','[]','真童列仗嚴如兵，誅姦號令雷風行。',32,'全唐诗/poet.song.37000.json','["真童列仗嚴如兵，誅姦號令雷風行。", "俄聞一物不遂性，急傳口詔春陽生。"]'),
('944d5ff1-f6dc-4758-a533-657c1b2ca77c','天都仙  其三','徐積','宋','宋诗','song-poetry','','[]','天兵十萬著犀衣，手執金幢踏彩霓。',32,'全唐诗/poet.song.37000.json','["天兵十萬著犀衣，手執金幢踏彩霓。", "龍共玉麟相次列，羣鸞班在鳳凰西。"]'),
('e3da8f0b-8588-42df-80b2-bbe1ced7703e','早朝仙  其一','徐積','宋','宋诗','song-poetry','','[]','紫瑶闕上烟霞曉，赤玉階前劍佩齊。',32,'全唐诗/poet.song.37000.json','["紫瑶闕上烟霞曉，赤玉階前劍佩齊。", "十二金童傳詔罷，雲冠星弁一時低。"]'),
('2d5613c7-9e9a-48a1-b12a-af3fe81636a2','早朝仙  其二','徐積','宋','宋诗','song-poetry','','[]','紫府真人朝玉京，三千玉版先進名。',32,'全唐诗/poet.song.37000.json','["紫府真人朝玉京，三千玉版先進名。", "叩頭欲跪紫烟合，但聞玉佩玲瓏聲。"]'),
('fd5c432a-9441-4b0b-ad92-6a9ffc06f14e','早朝仙  其三','徐積','宋','宋诗','song-poetry','','[]','閶闔雲深未啟關，霓衣夾道已成班。',32,'全唐诗/poet.song.37000.json','["閶闔雲深未啟關，霓衣夾道已成班。", "須臾特詔仙官入，日月諸星共放還。"]'),
('af3a51d0-6d97-4f2a-b29d-4d3c08a8d7d5','朝迴仙','徐積','宋','宋诗','song-poetry','','[]','匆匆朝罷九重天，便按蓬萊御紫烟。',32,'全唐诗/poet.song.37000.json','["匆匆朝罷九重天，便按蓬萊御紫烟。", "趁得蟠桃花下宴，鼓簫諸部約三千。"]'),
('68b59bb6-b152-4ce7-a8b0-7a62d8827237','文仙','徐積','宋','宋诗','song-poetry','','[]','紫微詔誥都經手，東壁圖書盡在家。',32,'全唐诗/poet.song.37000.json','["紫微詔誥都經手，東壁圖書盡在家。", "何日再游羣玉府，吟窗依舊鎖烟霞。"]'),
('ffbe35f9-a3e8-426b-8486-273ba77106bf','武仙','徐積','宋','宋诗','song-poetry','','[]','冠佩嚴嚴坐絳雲，環兵列仗是何人。',32,'全唐诗/poet.song.37000.json','["冠佩嚴嚴坐絳雲，環兵列仗是何人。", "諸仙稟命羣靈肅，玉冊金符盡在身。"]'),
('51c37818-0bc9-4955-9baa-30d8b77fad4f','富仙','徐積','宋','宋诗','song-poetry','','[]','碧霞樓上常先曉，白玉宮中愛早寒。',32,'全唐诗/poet.song.37000.json','["碧霞樓上常先曉，白玉宮中愛早寒。", "亂玉甃成池浴鳳，渾金削就棟棲鸞。"]'),
('93ed62ff-eb28-4a6d-88ca-f5bd0c7885b8','貧仙','徐積','宋','宋诗','song-poetry','','[]','莫怪先生身上貧，眼看外物似浮雲。',32,'全唐诗/poet.song.37000.json','["莫怪先生身上貧，眼看外物似浮雲。", "房中除却琴棋後，更有門前鶴一羣。"]'),
('d05edfe5-4d4b-4480-8a67-5d20de165df6','貴仙','徐積','宋','宋诗','song-poetry','','[]','鳳節霓旌擁萬神，五雲車騎駕龍麟。',32,'全唐诗/poet.song.37000.json','["鳳節霓旌擁萬神，五雲車騎駕龍麟。", "腰閒獨佩黄金籙，元是瑶宮第一人。"]'),
('d335c970-083f-42f2-90dd-94a9aaae9ea4','吟仙','徐積','宋','宋诗','song-poetry','','[]','金編誦處無人見，玉洞題時有鳳知。',32,'全唐诗/poet.song.37000.json','["金編誦處無人見，玉洞題時有鳳知。", "昨夜忽然何處去，月中吟就白雲詩。"]'),
('d48c77b9-9bd3-416f-a53f-1239365fa7f3','醉仙','徐積','宋','宋诗','song-poetry','','[]','曾共諸仙宴紫微，金鍾插羽疾於飛。',32,'全唐诗/poet.song.37000.json','["曾共諸仙宴紫微，金鍾插羽疾於飛。", "醉魂已望三山去，猶整華冠齊羽衣。"]'),
('0c7a57d6-383b-4bba-b1f8-8c3f24a858da','醉起仙','徐積','宋','宋诗','song-poetry','','[]','佩環聲動出金華，鳳引鸞隨入絳霞。',32,'全唐诗/poet.song.37000.json','["佩環聲動出金華，鳳引鸞隨入絳霞。", "行到瑶臺雲路狹，側身趨避玉妃車。"]'),
('442aea13-bb08-47ed-bc03-7eb3f655e9ac','廉仙','徐積','宋','宋诗','song-poetry','','[]','人閒日月分庭過，天外星河入戶流。',32,'全唐诗/poet.song.37000.json','["人閒日月分庭過，天外星河入戶流。", "是物化金無所用，滿田種玉不曾收。"]'),
('c1fbb25f-d2a7-49ad-96bf-6ab1acc51963','寡欲仙','徐積','宋','宋诗','song-poetry','','[]','膝上橫琴鶴在傍，白雲衣共白雲裳。',32,'全唐诗/poet.song.37000.json','["膝上橫琴鶴在傍，白雲衣共白雲裳。", "夜深閒卧南窗月，更有清風共一床。"]'),
('78a5b8b3-edec-4b51-92f9-1b0746b17932','地仙','徐積','宋','宋诗','song-poetry','','[]','瑶臺紫府都歸夢，碧洞紅塵總是家。',32,'全唐诗/poet.song.37000.json','["瑶臺紫府都歸夢，碧洞紅塵總是家。", "蓬島有時來問信，桃源無處不開花。"]'),
('77c7716c-b9db-4611-a68c-3c3b652ccae8','玉妃','徐積','宋','宋诗','song-poetry','','[]','琳琅宮殿本無塵，猶跨青鸞踏紫雲。',32,'全唐诗/poet.song.37000.json','["琳琅宮殿本無塵，猶跨青鸞踏紫雲。", "怪得曉來天色淡，海霞都在玉妃裙。"]'),
('b9ccc65e-d261-41d6-a130-43e29b315200','麻姑  其一','徐積','宋','宋诗','song-poetry','','[]','折盡青林多少花，麻姑却在蔡經家。',32,'全唐诗/poet.song.37000.json','["折盡青林多少花，麻姑却在蔡經家。", "瑶臺好醉無人醉，鳳怨鸞棲空暮霞。"]'),
('b2a890a3-e7da-461d-a503-cf1d55614908','麻姑  其二','徐積','宋','宋诗','song-poetry','','[]','不道風塵良苦辛，却停仙仗醉紅塵。',32,'全唐诗/poet.song.37000.json','["不道風塵良苦辛，却停仙仗醉紅塵。", "青鸞一去無消息，只被麻姑誤殺人。"]'),
('f117bc8f-e858-456c-a581-9c3ce2aa5a92','閒仙','徐積','宋','宋诗','song-poetry','','[]','先生坐時雲滿裳，先生卧時雲滿床。',32,'全唐诗/poet.song.37000.json','["先生坐時雲滿裳，先生卧時雲滿床。", "白雲終日自來去，若比先生雲尚忙。"]'),
('72e5d9c3-66ec-4bba-a00e-ba4f91f642e6','棋仙','徐積','宋','宋诗','song-poetry','','[]','壺中白日何曾夜，洞裏桃花別是春。',32,'全唐诗/poet.song.37000.json','["壺中白日何曾夜，洞裏桃花別是春。", "一局閒棋猶未了，坐中老却採樵人。"]'),
('f493eb68-197e-43ff-9fec-5a41c793c11d','夜宴仙  其一','徐積','宋','宋诗','song-poetry','','[]','閶闔宮中夜宴開，手揮明月坐瑶臺。',32,'全唐诗/poet.song.37000.json','["閶闔宮中夜宴開，手揮明月坐瑶臺。", "不教偷藥姮娥到，却放投壺玉女來。"]'),
('25510491-d69b-49af-9392-59721a547550','夜宴仙  其二','徐積','宋','宋诗','song-poetry','','[]','明月宮中夜宴多，坐中齊唱白雲歌。',32,'全唐诗/poet.song.37000.json','["明月宮中夜宴多，坐中齊唱白雲歌。", "瑶環玉珮三千女，不著人閒俗綺羅。"]'),
('31a816e1-0a74-4b4d-8828-1546f1320c3a','困仙','徐積','宋','宋诗','song-poetry','','[]','洞中一覺春風夢，落盡桃源萬樹花。',32,'全唐诗/poet.song.37000.json','["洞中一覺春風夢，落盡桃源萬樹花。", "竈上丹砂尋不見，騎鸞誤入阿誰家。"]'),
('66e150de-6144-48dc-b241-4fa3c2400844','浴仙','徐積','宋','宋诗','song-poetry','','[]','玉佩珠襦自辟塵，瑶池浴罷卧紅雲。',32,'全唐诗/poet.song.37000.json','["玉佩珠襦自辟塵，瑶池浴罷卧紅雲。", "指揮莫放香波去，留與龍兒并鳳羣。"]'),
('b38a4e09-54b5-4589-8679-4143734f36cb','詩酒仙  其一','徐積','宋','宋诗','song-poetry','','[]','玉譜天書金版字，桂花濃釀碧霞漿。',32,'全唐诗/poet.song.37000.json','["玉譜天書金版字，桂花濃釀碧霞漿。", "無人敢與爲詩敵，有客時來覓酒嘗。"]'),
('7902302a-c889-41ad-9686-e59529bb6155','詩酒仙  其二','徐積','宋','宋诗','song-poetry','','[]','閒雲淡月爲詩態，春日春風是酒容。',32,'全唐诗/poet.song.37000.json','["閒雲淡月爲詩態，春日春風是酒容。", "玉女爭求新樂府，金童時獻碧瑶鐘。"]'),
('48e3cd9b-acdc-449d-b651-a54f476ba687','太平仙','徐積','宋','宋诗','song-poetry','','[]','誰知我是太平仙，歌罷浮雲笑暮烟。',32,'全唐诗/poet.song.37000.json','["誰知我是太平仙，歌罷浮雲笑暮烟。", "更倚玉樓吟樂府，斷虹消盡月明天。"]'),
('6adf200a-b2ac-4260-8388-f22bb880b684','贈別仙','徐積','宋','宋诗','song-poetry','','[]','平日忠言薄萬金，此時何惜贈君行。',32,'全唐诗/poet.song.37000.json','["平日忠言薄萬金，此時何惜贈君行。", "好名不是真人事，莫向人閒留姓名。"]'),
('bc21b8a3-79e3-48be-bf5f-bf020199c758','雪仙','徐積','宋','宋诗','song-poetry','','[]','九重天路忽難通，誰與傳書寄閬風。',32,'全唐诗/poet.song.37000.json','["九重天路忽難通，誰與傳書寄閬風。", "鶴馭三千無處覓，銀潢萬丈一時空。"]'),
('38f248f5-3b20-4adc-9e77-af5232a56aa1','望仙','徐積','宋','宋诗','song-poetry','','[]','好雲消盡鶴空來，一去麻姑更不迴。',32,'全唐诗/poet.song.37000.json','["好雲消盡鶴空來，一去麻姑更不迴。", "紫府路從何處去，碧桃花向夢中開。"]'),
('a343eda7-9e27-429f-aae4-ec75bc44b251','無妄仙','徐積','宋','宋诗','song-poetry','','[]','清風窗外雲初去，明月池中鶴自還。',32,'全唐诗/poet.song.37000.json','["清風窗外雲初去，明月池中鶴自還。", "春色一簾閒睡過，瑶花落盡不抽關。"]'),
('6d804712-fb5f-47cb-a2f0-8e5c4e123c5f','希夷仙  其一','徐積','宋','宋诗','song-poetry','','[]','白雲夫子號希夷，碧玉窗中下絳帷。',32,'全唐诗/poet.song.37000.json','["白雲夫子號希夷，碧玉窗中下絳帷。", "皓首勒成書萬帙，病鸞偷見鶴偷知。"]'),
('27f24cc7-ff83-4a9f-b138-0dbd8e339774','希夷仙  其二','徐積','宋','宋诗','song-poetry','','[]','紅塵舊學今雖廢，紫府新書近已齊。',32,'全唐诗/poet.song.37000.json','["紅塵舊學今雖廢，紫府新書近已齊。", "三十六仙俱不見，玉函金鎖印龍泥。"]'),
('1c007f7a-65a9-486e-9a57-e5f724ca023c','悟仙','徐積','宋','宋诗','song-poetry','','[]','昔日聞人說上清，如今高步太元庭。',32,'全唐诗/poet.song.37000.json','["昔日聞人說上清，如今高步太元庭。", "有時却憶紅塵事，恰似夢回并酒醒。"]'),
('92b7db60-db2b-4609-965e-866c0cbf5a73','惡僞仙','徐積','宋','宋诗','song-poetry','','[]','本希上聖忘言學，傍采南華寓意書。',32,'全唐诗/poet.song.37000.json','["本希上聖忘言學，傍采南華寓意書。", "去僞即真雖有道，未知人意自何如。"]'),
('39466643-9464-4d0c-8621-039cf26f97d4','劍仙','徐積','宋','宋诗','song-poetry','','[]','此劍曾將赤霄倚，雲雷欲戰秋風起。',96,'全唐诗/poet.song.37000.json','["此劍曾將赤霄倚，雲雷欲戰秋風起。", "携下赤霄磨玉山，玉山色變龍蛇寒。", "霜飛浪活河漢精，星辰日月分光明。", "天生神物不可犯，曾向人閒誅不平。", "玉龍不死常在腰，一抹血腥猶未消。", "莫教望見延平水，待與天地除凶妖。"]'),
('9c6923ac-4bad-4516-b571-8ee80d899a00','水仙  其一','徐積','宋','宋诗','song-poetry','','[]','曾乘秋浪泛銀河，撥盡閒雲恣浩歌。',32,'全唐诗/poet.song.37000.json','["曾乘秋浪泛銀河，撥盡閒雲恣浩歌。", "明月一環來拂面，玉龍十萬總隨波。"]'),
('85a6c332-fcb3-4a17-80df-c8b57d776830','水仙  其二','徐積','宋','宋诗','song-poetry','','[]','天上瑶池爲別館，海閒金闕是離宮。',32,'全唐诗/poet.song.37000.json','["天上瑶池爲別館，海閒金闕是離宮。", "徐行按盡烟波國，高步却來雲漢中。"]'),
('370d42d1-b4a9-48d9-a982-1790c85307dd','水仙  其三','徐積','宋','宋诗','song-poetry','','[]','昨夜曾游洛女家，自知此處勝烟霞。',32,'全唐诗/poet.song.37000.json','["昨夜曾游洛女家，自知此處勝烟霞。", "回鸞更按湘妃曲，醉踏烟波弄月華。"]'),
('db63009a-45f3-4e95-84f8-3c408c07cca8','水仙  其四','徐積','宋','宋诗','song-poetry','','[]','龍馭曾游絳水霞，回來却坐赤鯨車。',32,'全唐诗/poet.song.37000.json','["龍馭曾游絳水霞，回來却坐赤鯨車。", "夜深正解雙珠珮，莫點犀燈照我家。"]'),
('852c2176-1d66-409a-bd8d-ae3e447f8759','無累仙','徐積','宋','宋诗','song-poetry','','[]','塵世紛紛總是空，花開花落幾時窮。',32,'全唐诗/poet.song.37000.json','["塵世紛紛總是空，花開花落幾時窮。", "有人若問烟霞事，我是逍遥無累翁。"]'),
('a218dd19-6f69-4fbb-912c-9a4506aa9ec7','笑仙','徐積','宋','宋诗','song-poetry','','[]','天上人閒自不同，莫將澆俗比真風。',32,'全唐诗/poet.song.37000.json','["天上人閒自不同，莫將澆俗比真風。", "真風大抵無今古，萬事都來一笑中。"]'),
('92cf6505-c528-49c0-88e6-050b7d77e8f9','憂仙','徐積','宋','宋诗','song-poetry','','[]','我是真人何所憂，所憂世俗好多求。',32,'全唐诗/poet.song.37000.json','["我是真人何所憂，所憂世俗好多求。", "相謀相詐何時了，一笑一啼無日休。"]'),
('8c30738c-fa0d-4440-b845-af56fa0b3799','閔仙','徐積','宋','宋诗','song-poetry','','[]','禍福之來本自求，世人聞語不回頭。',32,'全唐诗/poet.song.37000.json','["禍福之來本自求，世人聞語不回頭。", "但知自快身前欲，不道永爲身後羞。"]'),
('d1bace7c-ab93-4862-82c9-daf49af54526','又水仙  其一','徐積','宋','宋诗','song-poetry','','[]','紫金沙路明珠闕，浴罷龍兒洗明月。',32,'全唐诗/poet.song.37000.json','["紫金沙路明珠闕，浴罷龍兒洗明月。", "待來人世等麻姑，只被塵埃污羅襪。"]'),
('65be417c-035a-4c6a-bbd0-09087b372b6a','又水仙  其二','徐積','宋','宋诗','song-poetry','','[]','爲買蟠桃海上花，明珠滿載玉龍車。',32,'全唐诗/poet.song.37000.json','["爲買蟠桃海上花，明珠滿載玉龍車。", "蓬山諸子須相問，笑指烟波是我家。"]'),
('b55012f6-cdc9-4f8f-95d7-88cb11d7fede','又水仙  其三','徐積','宋','宋诗','song-poetry','','[]','我是江湖都一掬，海水雖深不濡足。',32,'全唐诗/poet.song.37000.json','["我是江湖都一掬，海水雖深不濡足。", "待教平地産明珠，但恐世人更多欲。"]'),
('75332d2b-4949-41c7-b7cd-99d1750387c0','又水仙  其四','徐積','宋','宋诗','song-poetry','','[]','伍子波濤空淼然，至今猶有不平言。',32,'全唐诗/poet.song.37000.json','["伍子波濤空淼然，至今猶有不平言。", "屈原褊淺尤多忿，但恐有時來訴冤。"]'),
('789018d6-338a-4563-a058-e38c4aad6880','勞仙','徐積','宋','宋诗','song-poetry','','[]','朝採藥，暮採藥，踏盡閒雲一雙脚。',96,'全唐诗/poet.song.37000.json','["朝採藥，暮採藥，踏盡閒雲一雙脚。", "出一山，入一山，先生如此何時閒。", "有時兩脚不出戶，不煉黄金即煉丹。", "先生手足已勞苦，一心欲把河沙數。", "却笑閒仙無所爲，閒仙端坐亦相嗤。", "大都世事亦如此，相笑相非無盡時。"]'),
('ee7e5ef4-1f50-4deb-9526-47617d583436','宴仙','徐積','宋','宋诗','song-poetry','','[]','紫瑶樓上宴真人，膾是鯨鯢脯是麟。',32,'全唐诗/poet.song.37000.json','["紫瑶樓上宴真人，膾是鯨鯢脯是麟。", "醉倒玉妃何處去，烟霞迎步鶴隨身。"]'),
('4fa11a69-d8c6-468c-8ecc-94e6a9f2d1a4','晨起仙','徐積','宋','宋诗','song-poetry','','[]','帳外雙童持劍履，一榻紅雲睡初起。',32,'全唐诗/poet.song.37000.json','["帳外雙童持劍履，一榻紅雲睡初起。", "滿面清風潄月華，瑶漿更挹明河水。"]'),
('c2d6b753-43bd-4703-b30e-7ebd05614d6d','童仙','徐積','宋','宋诗','song-poetry','','[]','憶昔爲兒跨竹梢，誰何傳與太平謠。',32,'全唐诗/poet.song.37000.json','["憶昔爲兒跨竹梢，誰何傳與太平謠。", "如今羽化已千載，綠鬢朱顔更不凋。"]'),
('fc1781e9-d823-4cce-8746-1baa0bf88e8b','老仙','徐積','宋','宋诗','song-poetry','','[]','脚踏青雲身已老，訪道修真恨不早。',32,'全唐诗/poet.song.37000.json','["脚踏青雲身已老，訪道修真恨不早。", "曾見商周全盛時，不及唐虞古風好。"]'),
('9d1b0f22-4714-4f0b-8348-ffb69a1bef2b','飽仙','徐積','宋','宋诗','song-poetry','','[]','誰道真人能辟穀，先生每食無餘肉。',32,'全唐诗/poet.song.37000.json','["誰道真人能辟穀，先生每食無餘肉。", "鄰家便是忍饑仙，餬口之糧猶不足。"]'),
('4b525a79-3bb3-4dd2-b43d-587b785a4621','饑仙','徐積','宋','宋诗','song-poetry','','[]','糧雖不足氣常充，真是根源久是功。',32,'全唐诗/poet.song.37000.json','["糧雖不足氣常充，真是根源久是功。", "真久不惟能養氣，幽明亦可感而通。"]'),
('9840fb4d-b6b1-4bf3-947f-61a8f9ac38dc','茶仙','徐積','宋','宋诗','song-poetry','','[]','賜得龍田不種花，自携瑶水灌烟霞。',32,'全唐诗/poet.song.37000.json','["賜得龍田不種花，自携瑶水灌烟霞。", "誰將玉樹雙枝換，只得春前一寸芽。"]'),
('64d35480-6166-4e15-8467-df69407f8148','狂仙','徐積','宋','宋诗','song-poetry','','[]','香枝灑面瑶池水，霞艷裝衣閬苑花。',32,'全唐诗/poet.song.37000.json','["香枝灑面瑶池水，霞艷裝衣閬苑花。", "一半是狂兼是醉，急教扶去卧烟霞。"]'),
('8dd529d3-126d-42e2-8d64-d262da842841','迷路仙','徐積','宋','宋诗','song-poetry','','[]','當時採藥因迷路，平上青雲不用梯。',32,'全唐诗/poet.song.37000.json','["當時採藥因迷路，平上青雲不用梯。", "却似人閒行路者，醉魂春夢至今迷。"]'),
('fc10173c-0adf-4790-8d8c-5816fc00773e','賣藥仙','徐積','宋','宋诗','song-poetry','','[]','蹄涔蟻垤何須較，芳草浮雲事可知。',32,'全唐诗/poet.song.37000.json','["蹄涔蟻垤何須較，芳草浮雲事可知。", "曾向人閒閑賣藥，塵埃滿眼看兒嬉。"]'),
('96a4c92a-7c9f-4179-b070-79ee6e34f1e4','無知仙','徐積','宋','宋诗','song-poetry','','[]','爲向平時尋古風，幅巾芒履走塵中。',32,'全唐诗/poet.song.37000.json','["爲向平時尋古風，幅巾芒履走塵中。", "俗人不識烟霞客，喚作無知賣藥翁。"]'),
('f46f5b96-bb71-448b-99f8-b8cf9c024acd','飛仙  其一','徐積','宋','宋诗','song-poetry','','[]','不用驂鸞不御風，騰身拖袂便乘空。',32,'全唐诗/poet.song.37000.json','["不用驂鸞不御風，騰身拖袂便乘空。", "方從碧海游三島，却駕烟霞上紫宮。"]'),
('13b02c61-cc28-4ba6-b3c7-dfee1348ca7f','飛仙  其二','徐積','宋','宋诗','song-poetry','','[]','十萬里餘都一息，須知此道非人力。',32,'全唐诗/poet.song.37000.json','["十萬里餘都一息，須知此道非人力。", "有時閒望玉山游，鸞鳳滿天追不得。"]'),
('df2c8cbc-0075-4b8a-a1b3-7c43d47e5b32','謫仙  其一','徐積','宋','宋诗','song-poetry','','[]','曾宴巫山十二峰，歸來謫下廣寒宮。',32,'全唐诗/poet.song.37000.json','["曾宴巫山十二峰，歸來謫下廣寒宮。", "如今已得瑶環賜，便揖浮丘騎玉虹。"]'),
('9bb2b645-9dc2-4b7a-832b-d1a3634e6305','謫仙  其二','徐積','宋','宋诗','song-poetry','','[]','自脫霓裳辭玉關，玉符金字謫人閒。',32,'全唐诗/poet.song.37000.json','["自脫霓裳辭玉關，玉符金字謫人閒。", "人閒雖與烟霞隔，醉夢吟魂自往還。"]'),
('06c60116-6a29-4ac2-9b96-9c6f9aacfab8','忘憂仙','徐積','宋','宋诗','song-poetry','','[]','鳥不曾喧獸不爭，鸞歌鳳舞碧瑶城。',32,'全唐诗/poet.song.37000.json','["鳥不曾喧獸不爭，鸞歌鳳舞碧瑶城。", "羣童盡唱忘憂曲，也似人閒樂太平。"]'),
('15304774-ae51-46ec-8117-1b7afbdad508','力仙  其一','徐積','宋','宋诗','song-poetry','','[]','崆峒道人良多識，易以真爲難以力。',32,'全唐诗/poet.song.37000.json','["崆峒道人良多識，易以真爲難以力。", "豈無羣聖可相師，亦有一篇言道德。"]'),
('fe8eec58-0a95-43dc-b3d3-9bf91a2eb1b4','力仙  其二','徐積','宋','宋诗','song-poetry','','[]','挾虎搏蛟良有力，扼斷鯨咽批豹額。',32,'全唐诗/poet.song.37000.json','["挾虎搏蛟良有力，扼斷鯨咽批豹額。", "虎豹雖獰却易防，螻蟻口中藏劍戟。"]'),
('c6c52826-67a6-47c3-bb88-aa6fa56013ac','急仙','徐積','宋','宋诗','song-poetry','','[]','但把真聲吹鼓簫，鳳來鳳去不須招。',32,'全唐诗/poet.song.37000.json','["但把真聲吹鼓簫，鳳來鳳去不須招。", "浮槎河上無徒涉，種玉田中莫揠苗。"]'),
('ef695e7e-79b8-4e67-91f5-18477fb25177','慢仙','徐積','宋','宋诗','song-poetry','','[]','急仙燒煉日盈罐，慢仙十日未能半。',32,'全唐诗/poet.song.37000.json','["急仙燒煉日盈罐，慢仙十日未能半。", "一人賣藥走不停，一人得金不肯換。"]'),
('3efec2c7-fa07-43f4-88ff-b35424eac4e2','又雪仙  其一','徐積','宋','宋诗','song-poetry','','[]','華蓋車前龍步滑，紫微垣上鳳巢寒。',32,'全唐诗/poet.song.37000.json','["華蓋車前龍步滑，紫微垣上鳳巢寒。", "一時掃下塵泥去，却入漢家盛露盤。"]'),
('0bcad7fb-c7bc-47b5-8294-8d84bd3ac596','又雪仙  其二','徐積','宋','宋诗','song-poetry','','[]','人閒多是苦寒饑，短褐疏衾正弊時。',32,'全唐诗/poet.song.37000.json','["人閒多是苦寒饑，短褐疏衾正弊時。", "欲把霞衣都覆蓋，却辭玉女宴瑶池。"]'),
('63f6cf8e-1760-47c2-b162-0ea2afb8491f','求仙','徐積','宋','宋诗','song-poetry','','[]','神仙不知真有無，其術可圖不可圖。',64,'全唐诗/poet.song.37000.json','["神仙不知真有無，其術可圖不可圖。", "得之不得存乎命，躁不以命良可吁。", "愚夫忘欲棄所愛，父母無子妻無夫。", "本求長生不死術，夭厥所壽殘厥軀。"]'),
('0224b07c-f878-4968-9716-3daaccc6d2d5','玉霞弟子','徐積','宋','宋诗','song-poetry','','[]','玉霞弟子非無學，金籙名仙亦有才。',32,'全唐诗/poet.song.37000.json','["玉霞弟子非無學，金籙名仙亦有才。", "却作左慈筵上術，誰將酒脯盡携來。"]'),
('748b3078-9969-4cc3-baac-589631bc3bd5','藐仙','徐積','宋','宋诗','song-poetry','','[]','藐哉小哉其奈何，牛蹄之水一泓多。',32,'全唐诗/poet.song.37000.json','["藐哉小哉其奈何，牛蹄之水一泓多。", "若是胸中能自養，長源巨派傾洪河。"]'),
('f70545d2-3cfa-48c9-91bb-efc099cc4c00','奇仙','徐積','宋','宋诗','song-poetry','','[]','奇哉奇哉有此仙，胸中廣大可容天。',32,'全唐诗/poet.song.37000.json','["奇哉奇哉有此仙，胸中廣大可容天。", "深莫測兮高可仰，滄浪之水太山顛。"]'),
('f0dc5522-a6b9-4895-b4fd-680ee3ed867e','不可知','徐積','宋','宋诗','song-poetry','','[]','歌謠纔作彩衣童，策杖俄爲白髪翁。',32,'全唐诗/poet.song.37000.json','["歌謠纔作彩衣童，策杖俄爲白髪翁。", "走遍紅塵人莫問，先生意在不言中。"]'),
('9afaf739-0802-4700-8a26-ffad4cfbbcc4','莫回頭','徐積','宋','宋诗','song-poetry','','[]','薄夫用意終歸險，更有鄉原事可羞。',32,'全唐诗/poet.song.37000.json','["薄夫用意終歸險，更有鄉原事可羞。", "多少古人遺恨在，紅塵歧路莫回頭。"]'),
('257b610d-0d75-4f19-b477-6f3ce09a4a2f','無奈何  其一','徐積','宋','宋诗','song-poetry','','[]','我曹意者非忘物，自是爲仙無奈何。',32,'全唐诗/poet.song.37000.json','["我曹意者非忘物，自是爲仙無奈何。", "海水玩來如股掌，人心難處甚風波。"]'),
('c3f3a959-9e5e-43fa-a46c-cb37a639750e','無奈何  其二','徐積','宋','宋诗','song-poetry','','[]','無奈何兮無奈何，失之哀兮得之歌。',32,'全唐诗/poet.song.37000.json','["無奈何兮無奈何，失之哀兮得之歌。", "巧拙其閒不容寸，得失相去能幾何。"]'),
('312c7497-cd21-4cd5-8c53-5dc509dffdcc','謫仙','徐積','宋','宋诗','song-poetry','','[]','我是蓬萊山上客，暫到人閒管春色。',64,'全唐诗/poet.song.37000.json','["我是蓬萊山上客，暫到人閒管春色。", "謝家池館聳吟魂，卓氏酒壚閒醉魄。", "人閒春色將奈何，瀲瀲灧灧濃如波。", "歸來說與秦王女，麻姑偷去唱爲歌。"]'),
('2871062d-36bc-4388-b73a-c561647ee66f','勸君','徐積','宋','宋诗','song-poetry','','[]','勸君莫折楊柳枝，枝無根本任風吹。',128,'全唐诗/poet.song.37000.json','["勸君莫折楊柳枝，枝無根本任風吹。", "勸君莫愛水中萍，萍隨流水何時停。", "莫愛春風山上草，纔到秋風便吹了。", "更有籬邊紅槿花，朝來錦繡暮泥漥。", "不似茅菴水上家，碧蘆門徑白汀沙。", "兩眼僅分鷗與鴉，口無巧語心無邪。", "不但無邪兼寡欲，釣得一魚心便足。", "漁衣便是岸頭莎，釣竿自種籬邊竹。"]'),
('378aa928-3138-4914-b45a-0bdfd0f312b8','龍','徐積','宋','宋诗','song-poetry','','[]','雲是口中氣，雨是口中沫。',28,'全唐诗/poet.song.37000.json','["雲是口中氣，雨是口中沫。", "口中噓吸須臾閒，天下焦枯一時活。"]'),
('ce155fce-6335-43b2-9a37-eea6a0a258f6','鳳','徐積','宋','宋诗','song-poetry','','[]','百尺樓頭鳳一羣，聲如韶濩羽如雲。',32,'全唐诗/poet.song.37000.json','["百尺樓頭鳳一羣，聲如韶濩羽如雲。", "開口一鳴天路白，六龍馳上海之濆。"]'),
('435b0c2c-aead-4c81-b6d6-90a092572c6f','鸞','徐積','宋','宋诗','song-poetry','','[]','吹簫臺上曾歌舞，留住秦雲伴秦女。',32,'全唐诗/poet.song.37000.json','["吹簫臺上曾歌舞，留住秦雲伴秦女。", "近來長趁紫宸朝，麟鳳肩隨龍接武。"]'),
('506e9797-d2d6-45da-9390-8d3d80e7c751','鶴','徐積','宋','宋诗','song-poetry','','[]','任教雞鶩爭糠粃，脫身一舉三千里。',48,'全唐诗/poet.song.37000.json','["任教雞鶩爭糠粃，脫身一舉三千里。", "如今直入鳳凰池，口啄琅玕飲瑶水。", "舊羣流落在人閒，爲趁稻粱飛不起。"]'),
('d80cca46-ac81-4b5c-90ed-b5e29536d08c','清虛臺題華州崔氏園','徐積','宋','宋诗','song-poetry','','[]','名園自郊谷，何況築高臺。',48,'全唐诗/poet.song.37000.json','["名園自郊谷，何況築高臺。", "酷暑未嘗到，清風長自來。", "雲嵐瞰山罅，烟水近池隈。", "誰更將松竹，蕭森四面栽。"]'),
('e5bef825-2c03-47c9-a628-72cb05125a23','華州太守花園','徐積','宋','宋诗','song-poetry','','[]','南園花謝北園開，紅拂欄干翠拂苔。',32,'全唐诗/poet.song.37000.json','["南園花謝北園開，紅拂欄干翠拂苔。", "却是梧桐且栽取，丹山相次鳳凰來。"]'),
('6fc5009e-22b5-4422-87f7-203294d8e784','送李守','徐積','宋','宋诗','song-poetry','','[]','莫說真州南畔路，楚望亭南路已遥。',64,'全唐诗/poet.song.37000.json','["莫說真州南畔路，楚望亭南路已遥。", "只可寄聲來見問，更難折簡去相招。", "船頭何處逢秋水，山下誰家把酒瓢。", "且趁潮行急摇櫓，到江州後更無潮。"]'),
('0a388017-93c6-408e-a355-558e4872bdfa','擬和御製賞花釣魚','徐積','宋','宋诗','song-poetry','','[]','禁苑千花一夜開，祥烟深處翠華來。',64,'全唐诗/poet.song.37000.json','["禁苑千花一夜開，祥烟深處翠華來。", "重輪日色輝天步，萬歲山聲薦壽杯。", "魚躍靈池初浩渺，鳳巢阿閣正徘徊。", "姚虞臣主方賡唱，蓬蓽儒生願竊陪。"]'),
('26624c07-a0af-4ba6-946f-8538cc7ae468','舞','徐積','宋','宋诗','song-poetry','','[]','十幅華裀遍畫堂，仙家妝束學霓裳。',64,'全唐诗/poet.song.37000.json','["十幅華裀遍畫堂，仙家妝束學霓裳。", "一雙舞袖鸞鳳勢，滿院春風羅綺香。", "巫峽朝雲無定意，漢濱珠珮雜鳴璫。", "歌聲未罷全無力，歸去重闈泣暈妝。"]'),
('4b0aa430-41e6-463a-8084-4d908c1a6fc5','錢塘江潮  其一','徐積','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','獨派豈從天漢墜，千濤爭趁海波還。',64,'全唐诗/poet.song.37000.json','["獨派豈從天漢墜，千濤爭趁海波還。", "齊聲怒過轟雷鼓，亂沫噴來碎玉山。", "塵土刮開心目外，冰霜留在骨毛閒。", "君看江上潮平後，恰似魚龍戰鬬閒。"]'),
('9113beb0-7736-44c0-a5c3-36e2149c2277','錢塘江潮  其二','徐積','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f", "\u897f\u6e56"]','滄溟幾道入江淮，此獨奇哉復怪哉。',64,'全唐诗/poet.song.37000.json','["滄溟幾道入江淮，此獨奇哉復怪哉。", "風雨初隨霜練起，雷霆俄送雪山來。", "豈無海物齊驅過，亦似神兵合陣迴。", "君向西湖亭上看，杭州不信有塵埃。"]'),
('047fdd05-4bdf-44fd-9dfb-2943a1722bcd','秋水','徐積','宋','宋诗','song-poetry','','[]','水與秋月色，清無一點瑕。',48,'全唐诗/poet.song.37000.json','["水與秋月色，清無一點瑕。", "有情山共遠，無限日初斜。", "鷺下沈寒葦，雁空遺暖沙。", "旋將隄畔木，學泛斗邊槎。"]'),
('3cc66bf2-ea0f-4fba-a0a3-e606d4e3961c','題東軒  其一','徐積','宋','宋诗','song-poetry','','[]','我有東軒景，喜君爲此行。',48,'全唐诗/poet.song.37000.json','["我有東軒景，喜君爲此行。", "一如曠野外，四面好風生。", "但見雲連樹，不知山是城。", "重來如有約，秋水夕陽明。"]'),
('be4dda96-ae8f-4720-9f94-be233bc3e35e','題東軒  其二','徐積','宋','宋诗','song-poetry','','[]','我家東軒好憑欄，柳一林邊水一灣。',32,'全唐诗/poet.song.37000.json','["我家東軒好憑欄，柳一林邊水一灣。", "城下人烟都似野，城頭雲樹恰如山。"]'),
('eb5030de-1e13-4c8d-8b09-96e8ca658d77','中秋月  其一','徐積','宋','宋诗','song-poetry','','[]','青女霜華夜不收，一天如掃月如流。',64,'全唐诗/poet.song.37000.json','["青女霜華夜不收，一天如掃月如流。", "素娥奔去已千古，狡兔隠來還幾秋。", "冷逼蚊雷聲陡息，光摧螢火色何幽。", "塵埃兩眼洗不浄，安得淩雲萬丈樓。"]'),
('577957b8-1838-467e-ac7e-d8a43201f571','中秋月  其二','徐積','宋','宋诗','song-poetry','','[]','珠箔珊珊掛玉鉤，金梯軋軋倚紅樓。',64,'全唐诗/poet.song.37000.json','["珠箔珊珊掛玉鉤，金梯軋軋倚紅樓。", "桂摇團影上層漢，桐墜疏陰纔半秋。", "萬頃玉田和露白，一環瑶水带霜流。", "何人獨向繡幃泣，燭淚淋漓香篆幽。"]'),
('9d967bae-434d-47ab-ad67-f7255a0e40d2','九月九  其一','徐積','宋','宋诗','song-poetry','','[]','九日諸公欲上山，淮東病叟正閒閒。',64,'全唐诗/poet.song.37000.json','["九日諸公欲上山，淮東病叟正閒閒。", "如從酒伴無慚色，儻論賢才即汗顔。", "適載巨皰尋陋巷，仍封大軸委樵關。", "不知我是扶犁手，玉樹成林盡許攀。"]'),
('676a7229-d6e4-42a2-b6ae-6eb58a1c756c','九月九  其二','徐積','宋','宋诗','song-poetry','','[]','何必南山與北山，此心非獨此時閒。',64,'全唐诗/poet.song.37000.json','["何必南山與北山，此心非獨此時閒。", "手持白酒爲常事，頭带黄華是强顔。", "醉後浩歌來就榻，醒時清嘯起抽關。", "誰人遺我明霞曲，聲在赤霄無處攀。"]'),
('c4fcd704-9960-4a6d-a080-e1a81f95ed7c','九月九  其三','徐積','宋','宋诗','song-poetry','','[]','有人才思聳如山，已燕淮亭未肯閒。',64,'全唐诗/poet.song.37000.json','["有人才思聳如山，已燕淮亭未肯閒。", "親載綠醽溫病骨，更歌白雪慰蒼顔。", "老憑書几猶操筆，暮等吟筒正啟關。", "兩手塵泥俱滌盡，金莖玉露我須攀。"]'),
('31d5c755-50a6-4e55-b095-057781acbd87','九月九  其四','徐積','宋','宋诗','song-poetry','','[]','桓家賓客正尋山，劉子藏身盡日閒。',64,'全唐诗/poet.song.37000.json','["桓家賓客正尋山，劉子藏身盡日閒。", "忽爲著書驚晚節，更因把菊覺衰顔。", "白衣來緩思沽酒，繡嶺登高夢入關。", "最好蓮華峰上路，藤條葛蔓手齊攀。"]'),
('e8b6fefc-1437-485e-afc9-dda5406d2f1f','九月九  其五','徐積','宋','宋诗','song-poetry','','[]','堂堂兵陣列如山，羽檄交飛勢未閒。',64,'全唐诗/poet.song.37000.json','["堂堂兵陣列如山，羽檄交飛勢未閒。", "敵國正强無備處，我師潛遁若爲顔。", "已張火炬嚴刁斗，更使轅門置鐵關。", "欲就將軍送降款，金城萬雉莫能攀。"]'),
('47d09eea-3fe4-4e02-bfd5-612c147a8458','九月九  其六','徐積','宋','宋诗','song-poetry','','[]','不是妻孥須入山，著書未得片時閒。',64,'全唐诗/poet.song.37000.json','["不是妻孥須入山，著書未得片時閒。", "琴逢嵇叔難施手，嘯比孫登合靦顔。", "幾日偃旗兼卧鼓，今朝延敵又開關。", "我師欲遁無歸路，嚴壘如雲試一攀。"]'),
('2c540416-6ab1-4881-bd56-e3a84f15b3f2','除夜  其一','徐積','宋','宋诗','song-poetry','','[]','春意匆匆又欲還，一年都似片時閒。',64,'全唐诗/poet.song.37000.json','["春意匆匆又欲還，一年都似片時閒。", "青雲有路終須到，白日無情不暫閒。", "任老豈妨修古道，更貧未肯憶深山。", "明朝獻壽何爲祝，長著斑衣奉母顔。"]'),
('11ad1d6b-3038-4cce-b73a-5059924cc56d','除夜  其二','徐積','宋','宋诗','song-poetry','','[]','但得文章與道深，年來年去不關心。',64,'全唐诗/poet.song.37000.json','["但得文章與道深，年來年去不關心。", "幾時上得青雲後，兩鬢從教白髪侵。", "匣內深藏三尺劍，罇前獨抱一張琴。", "辭高調古彈將曉，待倩春風聽此音。"]'),
('1f4ce7a1-5204-43fb-9f6b-e8ca97e78bfb','除夜  其三','徐積','宋','宋诗','song-poetry','','[]','一燈高照草堂中，大笑高歌送歲窮。',64,'全唐诗/poet.song.37000.json','["一燈高照草堂中，大笑高歌送歲窮。", "柳色花光將屬我，雪寒霜凜任相攻。", "銅壺漏促三更盡，白玉罇深一釂空。", "待到平明無別事，只將詩句贈春風。"]'),
('4cd73b97-f693-45e5-b3bb-16a61871821c','除夜  其四','徐積','宋','宋诗','song-poetry','','[]','前日慈闈獻壽觥，爲親歌詠祝長生。',32,'全唐诗/poet.song.37000.json','["前日慈闈獻壽觥，爲親歌詠祝長生。", "被君翻作陽春曲，却使巴人和不成。"]'),
('47cc1b17-5d34-4905-89df-e3d177ed087d','喜雨上山陽守','徐積','宋','宋诗','song-poetry','','[]','山陽太守奉更書，盡束行裝載軸艫。',64,'全唐诗/poet.song.37000.json','["山陽太守奉更書，盡束行裝載軸艫。", "已有仁風爲惠愛，更留甘雨活焦枯。", "秔塍带溜蒼苗奮，麥隴藏烟紺穎敷。", "看取北郊臨去日，爭先獻酒是農夫。"]'),
('bac4a05d-85a3-4f62-9d12-0291693ad6ac','詠雪','徐積','宋','宋诗','song-poetry','','[]','雪者陰之類，大寒之所爲。',48,'全唐诗/poet.song.37000.json','["雪者陰之類，大寒之所爲。", "於人無暖意，著物有消時。", "萬草若相畏，孤松亦自持。", "閒階不須掃，日照與風吹。"]'),
('dea2ac2d-c384-4bee-b809-5a9fb77584a3','答雪','徐積','宋','宋诗','song-poetry','','[]','一夜寒聲夢不成，讀書燈暗雪窗明。',32,'全唐诗/poet.song.37000.json','["一夜寒聲夢不成，讀書燈暗雪窗明。", "起來待唱巴人曲，閒得陽春第一聲。"]'),
('5bfab4e2-fef6-4887-88c0-30ec119c8a89','春雪  其一','徐積','宋','宋诗','song-poetry','','[]','天上星榆一夜彫，曉風吹緊下層霄。',64,'全唐诗/poet.song.37000.json','["天上星榆一夜彫，曉風吹緊下層霄。", "溪頭岸狹流應漲，簾外春寒到不消。", "數騎急投村墅宿，幾人忙奔酒家謠。", "登高望遍東城路，又領詩兵戰寂寥。"]'),
('9fc64022-db6d-490b-8e39-d00dbffe29d5','春雪  其二','徐積','宋','宋诗','song-poetry','','[]','雪滿東風只到關，西飛還不到長安。',64,'全唐诗/poet.song.37000.json','["雪滿東風只到關，西飛還不到長安。", "鷺翹孤白精神健，鶑斂黄金羽翼寒。", "遠嶺玉迷樵木徑，晚溪冰壓釣魚竿。", "隴頭鼓腹謳吟者，但向深秋前後看。"]'),
('c10a3e82-9b5f-485b-88e7-97bb39523ecb','雪中書事','徐積','宋','宋诗','song-poetry','','[]','聞道西家高捲簾，昂頭吟笑雪花天。',32,'全唐诗/poet.song.37000.json','["聞道西家高捲簾，昂頭吟笑雪花天。", "東家正泛一杯酒，北望孀親夜不眠。"]'),
('b6008e44-0825-4198-b0ee-1efac5e60c63','秋風','徐積','宋','宋诗','song-poetry','','[]','萬物已衰歇，乾坤正泬寥。',48,'全唐诗/poet.song.37000.json','["萬物已衰歇，乾坤正泬寥。", "數聲何處起，萬竅一時號。", "好木望君惜，殘蓬任汝飄。", "霜空靜如掃，努力助飛鵰。"]'),
('3f6c22d2-fe9d-4f49-87ef-7d4701558abf','秋雲','徐積','宋','宋诗','song-poetry','','[]','淡似秋河水，濃於春塢烟。',48,'全唐诗/poet.song.37000.json','["淡似秋河水，濃於春塢烟。", "隴頭寒塞雁，峽外晚江天。", "忽斷月華墜，乍明虹影連。", "西風休强管，飛勢自翩翩。"]'),
('a3e2d2a1-785c-4c68-af71-02cba7049b39','樵家','徐積','宋','宋诗','song-poetry','','[]','鄰叟是耕漁，怡然只自如。',48,'全唐诗/poet.song.37000.json','["鄰叟是耕漁，怡然只自如。", "草迷春徑狹，雀噪晚籬疏。", "自向林泉慣，翻嫌市井居。", "兒童盡樵採，斗粟亦無餘。"]'),
('2c77208f-c815-4105-a72e-45d2b78130ff','村家','徐積','宋','宋诗','song-poetry','','[]','階前生蔓草，門外是多歧。',48,'全唐诗/poet.song.37000.json','["階前生蔓草，門外是多歧。", "老叟行無伴，兒童飽自嬉。", "鴟羣巢衆樹，狐迹過疏籬。", "不肯勤耕耨，豐凶爲有時。"]'),
('1606136f-157f-46be-9d50-aeea6c00161c','漁者  其一','徐積','宋','宋诗','song-poetry','','[]','枯笠摇風雪滿衣，年年辛苦事漁磯。',32,'全唐诗/poet.song.37000.json','["枯笠摇風雪滿衣，年年辛苦事漁磯。", "有時釣得鱣鯨上，又被行人買得歸。"]'),
('2d994161-b313-465f-b549-b4a3c680b05a','漁者  其二','徐積','宋','宋诗','song-poetry','','[]','家住前村蘆葦中，一生無事是漁翁。',64,'全唐诗/poet.song.37000.json','["家住前村蘆葦中，一生無事是漁翁。", "眼看波浪如平地，身向江湖若斷蓬。", "小艇醉眠寒夜雨，短帆閒掛夕陽風。", "營營市井應相笑，不道錐刀盡是空。"]'),
('57b3df06-a5d6-4a2e-b4b0-aac7b9e0a4bd','織女','徐積','宋','宋诗','song-poetry','','[]','此身非不愛羅衣，月曉霜寒不下機。',32,'全唐诗/poet.song.37000.json','["此身非不愛羅衣，月曉霜寒不下機。", "織得羅成還不著，賣錢買得素絲歸。"]'),
('87312761-e162-424a-9153-ab8b78e89bfd','雪  其一','徐積','宋','宋诗','song-poetry','','[]','淮上飛花正皓然，日車月御欲停鞭。',160,'全唐诗/poet.song.37000.json','["淮上飛花正皓然，日車月御欲停鞭。", "千形凜凜如無地，一片蒼蒼忽露天。", "洞口似迷山路處，斗閒疑泛海槎年。", "長瓢酒挹雲泉釀，大軸詩題錦水牋。", "僧舍手抔留煮茗，漁菴缾貯借烹鮮。", "喜餘稻糝投饑喙，慚乏綈袍贈凍肩。", "白裏好張紅步障，猛中宜擺絳戎旃。", "掃開寥廓憑風帚，抉去紛紜憶劍仙。", "獵火正燃雲有焰，旅庖何在突無烟。", "未應門外同袁子，曾買汙萊數畝田。"]'),
('bcbfc906-7684-4115-9cbf-7bb290abeccc','雪  其二','徐積','宋','宋诗','song-poetry','','[]','君看飛雪競翩翩，雲將爭驅正著鞭。',160,'全唐诗/poet.song.37000.json','["君看飛雪競翩翩，雲將爭驅正著鞭。", "人望已酬殘臘後，物華兼值早梅天。", "招沽北掾輸平日，走馬西州憶少年。", "漏屋旋消濡弊褐，破窗穿過濕餘牋。", "蹄涔易見真漥滿，糞土難辭僞色鮮。", "席戶冷灰人削迹，朱門熱炙客摩肩。", "紛紛萬事還如此，寂寂幽懷盡舍旃。", "流水明中爭趁月，斷鴻深處獨藏仙。", "誰家漁棹空聞笛，何處樵村只見烟。", "最好耕農相賀了，牛衣醉卧夕陽田。"]'),
('72479a6c-0de6-417c-965e-1fe3d8e34b4d','雪  其三','徐積','宋','宋诗','song-poetry','','[]','侯款諸祠方徹奠，車回五駿既投鞭。',160,'全唐诗/poet.song.37000.json','["侯款諸祠方徹奠，車回五駿既投鞭。", "雲如大練生淮浦，雪似繁星落楚天。", "有客弄花知樂歲，何人感物惜流年。", "南城病僕惟沽酒，西郭詩章但買牋。", "隠伏急因明處見，垢汙多自夜來鮮。", "傭將粺穀纔餬口，拾去濡薪未息肩。", "白面韝鷹紅錦臂，烏山圍獸赤繒旃。", "却燃燈坐疑爲夢，欲上樓看恐有仙。", "玉鏡臺前侵皓月，碧紗窗外弄青烟。", "樹頭還有鴻棲否，船是寒沙水畔田。"]'),
('6c946001-a75f-49b1-8092-0a88dc5b7d70','雪  其四','徐積','宋','宋诗','song-poetry','','[]','諸少逸駕追無前，我乘駑馬持短鞭。',160,'全唐诗/poet.song.37000.json','["諸少逸駕追無前，我乘駑馬持短鞭。", "更添一老愛白雪，但開兩眼尋青天。", "詩中戈矛欲揮我，君家伯仲空忘年。", "摇筆吟哦有裂管，倒囊抖擻無遺牋。", "誰知羣形消即露，却還本質汙與鮮。", "田廬有蓬尚塞戶，樵衣無布堪補肩。", "羣兒上壟芻且牧，孤戍曝日旗與旃。", "人閒安得真洞府，空中失脚飛神仙。", "明月隨來會星弁，白雲迎去升紫烟。", "溪灣留下斷虹卧，山陰亦有玲瓏田。"]'),
('5bd349d8-63cf-4b88-b0e0-61a10a094fb7','雪  其五','徐積','宋','宋诗','song-poetry','','[]','一夜五宮星茫然，投壺笑電揮赤鞭。',160,'全唐诗/poet.song.37000.json','["一夜五宮星茫然，投壺笑電揮赤鞭。", "何物變爲淮上雪，餘花散入江南天。", "東家乞火溫稚子，西鄰賒酒娛高年。", "樵翁頭上笠戴月，漁父手中帆卷牋。", "庾子貞家但尋菜，鮑通直輩彌矜鮮。", "卞郎方弄瓠杯杓，浙帥已亡羊髀肩。", "當門正好張敝席，隔籬可笑窺華旃。", "最是珊珊上樓珮，恰如冉冉升空仙。", "牽牛童兒飲河漢，扶犁老子耕雲烟。", "漫翁何處拾瑶草，自有梅花大庾田。"]'),
('a864c16d-73d0-47bb-be31-7efc3a59f80c','雪  其六','徐積','宋','宋诗','song-poetry','','[]','江西詞客休刺船，馬上俊郎休弄鞭。',160,'全唐诗/poet.song.37000.json','["江西詞客休刺船，馬上俊郎休弄鞭。", "且看滿城花落地，恰如窮谷曉時天。", "松林獨幹凌堅操，麥壟疏毛白少年。", "犬信宜將筒護紙，鴻書須用帛爲牋。", "月中兩艷非投暗，物裏千形不較鮮。", "最好一環圍井口，有時數點露山肩。", "紛來上相揮長麈，側去諸卿蔽曲旃。", "水畔誰爲佩珠女，車中人是行雲仙。", "吟裁笛竹清梅瘦，忽爨琴桐濕更烟。", "近日無錢酬酒媼，且教借賣漫翁田。"]'),
('8eddd2d5-9db7-4e94-921a-912649f38abe','雪  其七','徐積','宋','宋诗','song-poetry','','[]','昨霄夢看六龍淵，鶴御驚回墜曉鞭。',160,'全唐诗/poet.song.37000.json','["昨霄夢看六龍淵，鶴御驚回墜曉鞭。", "萬頃落花春晚後，一床清水月明天。", "門無黄雀張羅地，室有玄熊應夢年。", "入竹好鳴寒玉珮，寄梅兼附白雲牋。", "楊妃繡段披方穩，李逸烏紗裹更鮮。", "避色莫投妝婦指，弄香須撲舞蛾肩。", "羣烏噪過巢無樹，一兔奔歸獵有旃。", "溪叟正如翹葦鷺，山翁彌似出塵仙。", "僧簷鳥伺齋餘飯，客竈貓棲爨後烟。", "且報漫翁來掘壁，牆閒便是我家田。"]'),
('585aa8fb-b66c-46c4-ac83-e20df9c64b17','雪  其八','徐積','宋','宋诗','song-poetry','','[]','吟懷忽共雪紛然，罪逆餘骸自可鞭。',160,'全唐诗/poet.song.37000.json','["吟懷忽共雪紛然，罪逆餘骸自可鞭。", "罔極之恩無報日，難平所感欲呼天。", "身騎騕褭成童歲，手握狻猊未丱年。", "三釂冷醅將及斗，一揮醉筆恰盈牋。", "當時飾束頭毛綠，今日衣濡眦血鮮。", "楚泮師儒新靦目，秦關父老舊隨肩。", "中心但比孤青檜，外物無庸大赤旃。", "每指多圖爲酖毒，自言寡欲即神仙。", "房中得子眠溫席，突外從人笑冷烟。", "以此終身慰泉壤，不須問舍與求田。"]'),
('adf435dd-d867-42cf-b38b-f34aa4659b1a','雪  其九','徐積','宋','宋诗','song-poetry','','[]','荀翁猶慕李膺賢，漫叟當車我執鞭。',160,'全唐诗/poet.song.37000.json','["荀翁猶慕李膺賢，漫叟當車我執鞭。", "轅下兩驂將逐驥，牆閒一穴欲窺天。", "兵鋒甚銳逢今日，鐵陣橫行記昔年。", "將鉞揮金何用劍，檄書插羽不須牋。", "勇騎龍子神彌俊，笑扼犀吭血正鮮。", "一鼓已輸元帥手，雙矛將解敵人肩。", "我徒北首思投甲，子使西來約卷旃。", "自是見羸謀餌虜，却云養氣欲希仙。", "已嚴軍令除添竈，但恐師期忽舉烟。", "設若渝盟相掩襲，衝車突騎占平田。"]'),
('c9a5162a-9069-4559-9a16-83faff76e0c6','雪  其一○','徐積','宋','宋诗','song-poetry','','[]','團團蘚暈埋青錢，稍稍竹樹藏紺鞭。',160,'全唐诗/poet.song.37000.json','["團團蘚暈埋青錢，稍稍竹樹藏紺鞭。", "鸕鷀覆水魚沉淵，罞罿蔽地禽沖天。", "梅房處女鶑坐禪，草頭稚子松耆年。", "浮光飛沫人游川，斜行大字鴻書牋。", "壯士可論持守堅，美人休說容華鮮。", "乞餘之夫尤慕羶，附炎之子彌脇肩。", "穿花走馬錦藏韉，垂雲閱武車張旃。", "虢姨滿路空遺鈿，陳妃倚閣真神仙。", "有人情似山中泉，其情濃如春深烟。", "留下斷蘆雲蓑篇，長令雪滿淮之田。"]'),
('76e02888-5a4d-4e56-9739-187d6436fc85','偶述','徐積','宋','宋诗','song-poetry','','[]','寂然閒地好弦歌，胸中森森萬仞戈。',96,'全唐诗/poet.song.37000.json','["寂然閒地好弦歌，胸中森森萬仞戈。", "自道壯圖終有用，未知時事竟如何。", "千金似糞無心願，一劍如霜爲國磨。", "吟輒廢眠詩骨瘦，酒能消思醉顔酡。", "起登夜閣乘明月，笑倚寒山望太阿。", "誰道吾儒無壯士，藺生功烈勝廉頗。"]'),
('fad679ee-5e9c-4887-a276-4ba5a583c3f1','催妝  其一','徐積','宋','宋诗','song-poetry','','[]','魯巷予方樂，秦樓子幸俱。',72,'全唐诗/poet.song.37000.json','["魯巷予方樂，秦樓子幸俱。", "所期爲列女，應不訕庸夫。", "野叟田無璧，仙娥佩有珠。", "鸞歌迎弄玉，麟脯宴麻姑。", "自是閨中秀，何煩臉上朱。", "君看閬風客，親駕五雲車。"]'),
('8ac2266f-83e9-43a7-9169-c5d70575b8b9','催妝  其二','徐積','宋','宋诗','song-poetry','','[]','行事從來號闊迂，酒閒詩興便豪觕。',32,'全唐诗/poet.song.37000.json','["行事從來號闊迂，酒閒詩興便豪觕。", "盧公誤妾平生事，嫁得東臯卧草夫。"]'),
('df9a4cf4-e5dc-469c-a9c9-0145c11d7015','錦被堆','徐積','宋','宋诗','song-poetry','','[]','春風蕭索爲誰張，日暖仍燻百和香。',64,'全唐诗/poet.song.37000.json','["春風蕭索爲誰張，日暖仍燻百和香。", "遮處好將羅作帳，襯來堪用玉爲床。", "風吹亂展文君宅，月下還鋪宋玉牆。", "好向謝家池上種，綠波深夜蓋鴛鴦。"]'),
('fbfd4170-6b6d-4cbc-b55f-049797a4628e','神宗皇帝輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','顧託艱難後，宮城晝閉關。',48,'全唐诗/poet.song.37000.json','["顧託艱難後，宮城晝閉關。", "師屯五校肅，日馭六龍閒。", "易貯金莖露，難尋玉府山。", "裕陵人散後，猶望白雲閒。"]'),
('64e55cbf-530d-474e-8104-f46b8e5d410d','神宗皇帝輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','啟殯龍輴動，森森鳳翣移。',48,'全唐诗/poet.song.37000.json','["啟殯龍輴動，森森鳳翣移。", "迎神帳殿遠，背闕梓宮遲。", "日慘河山路，草枯霜霰時。", "綵庭覺瀟灑，應誦廖莪詩。"]'),
('656b83b9-c431-418e-95b3-2d7148df9420','代人進太皇輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','九載憂勤事，傾心爲繼明。',48,'全唐诗/poet.song.37000.json','["九載憂勤事，傾心爲繼明。", "手扶天柱起，身御日車行。", "大業真無負，全功定有成。", "生民正歌舞，萬丈玉山傾。"]'),
('d97d9c8b-6cd1-409e-ae91-b64b5cf23163','代人進太皇輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','絳節排山仗，珠襦換玉衣。',48,'全唐诗/poet.song.37000.json','["絳節排山仗，珠襦換玉衣。", "不乘黄鵠去，即御赤鸞飛。", "受謚心無媿，朝真德有輝。", "太元庭上客，聞義亦歔欷。"]'),
('db62d247-f000-4798-9c30-95f57ee6300b','代人進太皇輓詞  其三','徐積','宋','宋诗','song-poetry','','[]','一自姬周後，難乎有此才。',48,'全唐诗/poet.song.37000.json','["一自姬周後，難乎有此才。", "明將照幽隠，澤欲被蒿萊。", "外屬私恩絕，本朝公道開。", "勒銘何處好，嵩嶽鬰崔嵬。"]'),
('591ab4bf-777b-4155-b24d-c6ee33ab9627','代人進太皇輓詞  其四','徐積','宋','宋诗','song-poetry','','[]','玉殿菆宮啟，龍輴叩陛初。',48,'全唐诗/poet.song.37000.json','["玉殿菆宮啟，龍輴叩陛初。", "嚴兵猶驚夜，列仗已當車。", "路指新陵闕，窗留舊簡書。", "移班近東處，風月一簾虛。"]'),
('cd264a5c-d85a-49a7-bf82-bd05e27386f2','代人進太皇輓詞  其五','徐積','宋','宋诗','song-poetry','','[]','導騎鳴鞭去，魂車戀闕遲。',48,'全唐诗/poet.song.37000.json','["導騎鳴鞭去，魂車戀闕遲。", "梓宮何處宿，幄殿夕陽時。", "天上有名姓，人閒無路歧。", "三泉深百尺，神御復何之。"]'),
('a8910830-2367-45ca-bd20-4dfa44fa1628','閻博士輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','可惜方剛士，平生氣貌嚴。',48,'全唐诗/poet.song.37000.json','["可惜方剛士，平生氣貌嚴。", "有朋搔白首，無路弔蒼髯。", "地下新潛德，人閒故養恬。", "儒林與孝友，二傳子須添。"]'),
('24210d03-685e-4694-9ecb-327b158ab6a4','閻博士輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','一夢龍蛇後，難尋博士星。',48,'全唐诗/poet.song.37000.json','["一夢龍蛇後，難尋博士星。", "所居城見月，仍用柏爲庭。", "白馬車齊送，黄宮戶永扃。", "松陵今夜客，慟哭入冥冥。"]'),
('0e9eba90-2ebd-4fba-b38e-9c54ef736fde','苗戶部輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','雖負文場志，何慚國士風。',48,'全唐诗/poet.song.37000.json','["雖負文場志，何慚國士風。", "王廷曾抗論，廟鼎合銘功。", "玉樹摧平地，朱霞落半空。", "故人遺歎在，秋後有驚鴻。"]'),
('c092b48f-13d8-4f1a-a2d5-e70c2cc7cb4a','苗戶部輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','已矣公歸矣，哀哉將奈何。',48,'全唐诗/poet.song.37000.json','["已矣公歸矣，哀哉將奈何。", "黄宮無處樂，玄冕有誰歌。", "南越生祠久，東川畫像多。", "孤窮親黨在，共立碣嵯峨。"]'),
('d182f97c-b4d0-4fd9-865f-4eafadbbb240','林漕輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','國士青雲器，儒林合抱松。',48,'全唐诗/poet.song.37000.json','["國士青雲器，儒林合抱松。", "羽儀丹穴鳳，頭角劍津龍。", "玉筍班雖貴，皇華使愈恭。", "人亡其政在，尚可訪遺蹤。"]'),
('2ef5577f-69c0-4162-bcb6-467a1f8eb50b','林漕輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','一夢無回處，龐眉坐柏庭。',48,'全唐诗/poet.song.37000.json','["一夢無回處，龐眉坐柏庭。", "幾時逢白日，萬事付哀鈴。", "畫翣行須緩，黄宮到便扃。", "松陵詩莫和，慟哭不堪聽。"]'),
('efcc474f-7de0-416b-b6ca-2e2055eb6171','蔡學士輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','斗分星孤隕，虞庭鳳不還。',48,'全唐诗/poet.song.37000.json','["斗分星孤隕，虞庭鳳不還。", "金龍拋使節，玉筍誤朝班。", "世德元明後，家聲王謝閒。", "國功圖未卒，歸老負江山。"]'),
('209c0f73-1ae7-4577-af32-012ce86812fc','蔡學士輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','命也雖亡矣，但須銘此墳。',48,'全唐诗/poet.song.37000.json','["命也雖亡矣，但須銘此墳。", "朝中尋故事，江外訪遺文。", "遠思歸流水，高風寄白雲。", "忠魂在斯否，義亦不忘君。"]'),
('9482f8d8-4d62-4b19-a6bf-5b77d7c6a4db','蔡學士輓詞  其三','徐積','宋','宋诗','song-poetry','','[]','舊業儒編富，新裝使橐空。',48,'全唐诗/poet.song.37000.json','["舊業儒編富，新裝使橐空。", "潔身辭白日，隨柩載清風。", "義與人心在，名須江水窮。", "諸山同峴首，有子勝羊公。"]'),
('f664228c-71a9-44de-a3a9-403561bff1d1','蔡學士輓詞  其四','徐積','宋','宋诗','song-poetry','','[]','且止明旌住，玄堂即閉關。',48,'全唐诗/poet.song.37000.json','["且止明旌住，玄堂即閉關。", "素絲蒙柩往，白堊洗車還。", "身後千詩在，生前萬事閒。", "松陵哀怨客，來弔自湖山。"]'),
('79a0bf1f-c00b-4121-aa5d-c4cff6dfcce9','蘇子瞻輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','起起公終矣，斯文將奈何。',48,'全唐诗/poet.song.37000.json','["起起公終矣，斯文將奈何。", "新書傳異域，舊隠寄東坡。", "直道謀身少，孤忠爲國多。", "死生公論在，高義山峨峨。"]'),
('124dda5f-8bf8-4619-9411-971b92dd973a','蘇子瞻輓詞  其二','徐積','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','白玉棺無價，青囊葬有書。',48,'全唐诗/poet.song.37000.json','["白玉棺無價，青囊葬有書。", "奔星來啟路，走電去隨車。", "官是修文號，人同上行居。", "峨嵋山下客，誰是跨鯨魚。"]'),
('c4946d14-d8ee-4bbc-8590-7705de2bbfef','蹇侍郎輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','舊德朝之望，平生勇所爲。',48,'全唐诗/poet.song.37000.json','["舊德朝之望，平生勇所爲。", "赤心逢誼主，皓首棄明時。", "路入皇宮近，誰將畫翣移。", "有人號欲絕，莫誦蓼莪詩。"]'),
('1c8211a2-ba8d-4e01-8eed-4a3a019c1f49','蹇侍郎輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','一閉玄堂後，更分明與幽。',48,'全唐诗/poet.song.37000.json','["一閉玄堂後，更分明與幽。", "雖辭白日去，不忘錦江游。", "古檜蒼顔在，孤雲壯氣收。", "文章如可訪，遣使入西州。"]'),
('e64c8d54-cf5a-4ce7-85bd-fedabbeddd32','楊集賢輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','彼美朝之望，光終不較年。',48,'全唐诗/poet.song.37000.json','["彼美朝之望，光終不較年。", "醇風隨入地，義氣去淩烟。", "身後人人慕，生前事事賢。", "故交貧與賤，沈痛欲呼天。"]'),
('accdb886-ef63-4b62-b652-8df0cae087a9','楊集賢輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','門靜車聲歇，庭虛燕几閒。',48,'全唐诗/poet.song.37000.json','["門靜車聲歇，庭虛燕几閒。", "芸籤新汗簡，玉筍舊清班。", "事寄浮雲外，身從大夢閒。", "復爲長夜寢，慟哭入玄關。"]'),
('5f02a65b-aa60-44e8-afd8-aab26d4f413c','韋侍郎輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','徹殯哀鈴動，蒙棺素幣舒。',48,'全唐诗/poet.song.37000.json','["徹殯哀鈴動，蒙棺素幣舒。", "明旌先啟路，畫翣側隨車。", "長夜玄堂近，平生燕坐虛。", "須臾泉戶闔，輓紼且徐徐。"]'),
('fba903ad-cbd2-4660-a012-6512d6e07eaf','韋侍郎輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','野水鶴猶回，舊山雲不歸。',48,'全唐诗/poet.song.37000.json','["野水鶴猶回，舊山雲不歸。", "不歸將奈何，但恐雲無依。", "公是吳中老，吳人愛公好。", "公好不來歸，淚濕江邊草。"]'),
('6df5c74d-7a8f-43da-895e-64bdd6a79477','林殿院輓詞','徐積','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','吁嗟人兮，而有斯人。',420,'全唐诗/poet.song.37000.json','["吁嗟人兮，而有斯人。", "以義爲質兮，以剛守身。", "內明白而外昭哲兮，氣貌甚真。", "動則不苟兮，可使之爲國，可使之爲民。", "使之爲國兮取義舍生，使之論事兮傾出赤心。", "世方好柔兮我方剛，彼爲轅下駒兮我方鷹揚。", "彼作威之臣人莫敢當，我方藐視兮直攻其强。", "彼作福之臣兮烹煎牛羊羅列酒漿，我方折其匕箸兮覆杯而不嘗。", "以甘易苦兮自以爲常，以退爲進兮如寢諸床。", "所往所居，不察刀筆者害兮簿書有蔽。", "隠必露兮伏必發，照姦膽兮破姦穴。", "小姦積忿兮五臟欲裂，大姦睚眦兮其眦有血，口且欲吞兮齒且欲嚙。", "何誣之不誣何說，哆兮侈兮三寸之舌。", "顔淵偷飯，曾參鬬殺。", "慈母投杼兮其誰不信，所頼公明兮得無悔吝。", "夫何不幸兮人之云亡，誰司有命兮付與之不長。", "揭丹旐兮歸晉疆，望江湖兮歸故鄉。", "太行山上秋風起，度浮梁兮盟津水。", "符離東畔更淒凉，山陽猶有舊吟窗。", "吳人俱望揚子江，素車白馬迎道旁。", "故人亦有孤與孀，更憂今歲寒無裳。", "洞庭橘柚正青黄，鱸魚鱠美蓴羹香。", "且緩哀鈴送酒觴，一辭白日掩玄堂。", "玄堂一掩難開扃，夜復夜兮何時停。"]'),
('f9357e97-41b2-4b86-a758-ec42025f4345','寧倅輓詞  其一','徐積','宋','宋诗','song-poetry','','[]','人生如逆旅，來去何容易。',48,'全唐诗/poet.song.37000.json','["人生如逆旅，來去何容易。", "對面正談笑，轉頭成夢寐。", "傷哉手上書，已矣胸中事。", "義不復駕驥，灑盡辭家淚。"]'),
('aa5fb247-0e5f-4e55-9037-1be78b182263','寧倅輓詞  其二','徐積','宋','宋诗','song-poetry','','[]','記得高山否，淮東非所歸。',48,'全唐诗/poet.song.37000.json','["記得高山否，淮東非所歸。", "誰迎玄冕去，自趁白雲飛。", "泣盡孤兒血，空遺舊日衣。", "容州公莫去，此地故人稀。"]'),
('07d468c0-3b03-4f9a-8cab-24437f5b9529','寧倅輓詞  其三','徐積','宋','宋诗','song-poetry','','[]','平生富情義，至死不寐悔。',48,'全唐诗/poet.song.37000.json','["平生富情義，至死不寐悔。", "更無桃花米，惟有銀魚佩。", "一家將奈何，九子尚無配。", "魂兮且勿憂，幸有山公在。"]'),
('fb444f72-d5fa-4ebc-91f2-3ed6e3241515','李朝議輓詞','徐積','宋','宋诗','song-poetry','','[]','一從洪井到處州，見說洪人總淚流。',64,'全唐诗/poet.song.37000.json','["一從洪井到處州，見說洪人總淚流。", "本望聖朝令久任，若論明吏合封侯。", "高才所至都無事，厚德于今可鎮浮。", "故作此詩傳野史，不須銘記掩諸幽。"]'),
('bf3fa15d-e262-4c15-9c20-bed9c5fb89bb','哭張六','徐積','宋','宋诗','song-poetry','','[]','欲視目已瞑，欲語口已噤。',72,'全唐诗/poet.song.37000.json','["欲視目已瞑，欲語口已噤。", "欲動肉已寒，欲書手已硬。", "惟有心上熱，惟存心中悲。", "此熱須臾閒，此悲無休時。", "所悲孤兒寒，所悲孤兒饑。", "苦苦復苦苦，此悲遂入土。"]'),
('c9dc0e63-adef-4b41-a041-434a9b320268','招陳顧魂輓詞','徐積','宋','宋诗','song-poetry','','[]','魚有所歸，鳥有所棲。',40,'全唐诗/poet.song.37000.json','["魚有所歸，鳥有所棲。", "孤墳纍纍，子將何依。", "束子之裝，裹子之糧。", "促登汝航，往歸汝鄉。"]'),
('486f6bc5-328c-4c61-822f-01da60ab597a','送程給事知越州','杜叔元','宋','宋诗','song-poetry','','[]','朝聞劍外夙行輈，夕喜江西改命優。',64,'全唐诗/poet.song.37000.json','["朝聞劍外夙行輈，夕喜江西改命優。", "已有才名喧北省，又宣風化入南州。", "一城民吏迎前牧，滿眼山川是舊遊。", "君富機籌足餘暇，清吟不負物華樓。"]'),
('ecf54a54-4515-47e7-a1f5-c7b49972b461','黄山作','杜叔元','宋','宋诗','song-poetry','','[]','占勝新安境，佳名千古聞。',48,'全唐诗/poet.song.37000.json','["占勝新安境，佳名千古聞。", "奇峰半天出，秀色數州分。", "邃谷春猶雪，懸巖霽亦雲。", "何時脫韁鎖，猿鶴此爲群。"]'),
('46429dc6-0ddd-42bc-be61-716bc4b352e4','天馬峰','范郁','宋','宋诗','song-poetry','','[]','惆悵孫陽世久無，紛紛駑驥逐齊驅。',32,'全唐诗/poet.song.37000.json','["惆悵孫陽世久無，紛紛駑驥逐齊驅。", "不教神物俱湮滅，猶幸深山天馬圖。"]'),
('58b8202a-72f2-48a2-8e88-ec64fa51ddf4','題福唐津亭','陳烈','宋','宋诗','song-poetry','','[]','溪山龍虎蟠，溪水鼓角喧。',48,'全唐诗/poet.song.37000.json','["溪山龍虎蟠，溪水鼓角喧。", "中宵鄉夢破，六月夜衾寒。", "風雨生殘樹，蛟螭喜怒瀾。", "殷勤祝舟子，移棹過前灘。"]'),
('07adf84a-254a-4111-bb3e-ea378fb4accb','題鼓門大燈籠','陳烈','宋','宋诗','song-poetry','','[]','富家一盞燈，太倉一粒粟。',40,'全唐诗/poet.song.37000.json','["富家一盞燈，太倉一粒粟。", "貧家一盞燈，父子相聚哭。", "風流太守知不知，惟恨笙歌無妙曲。"]'),
('9c372806-ac6b-44e0-abc4-c0d5587d509d','西湖亭','林東美','宋','宋诗','song-poetry','','["\u897f\u6e56"]','金山亭榭遍林泉，獨有湖山占得先。',64,'全唐诗/poet.song.37000.json','["金山亭榭遍林泉，獨有湖山占得先。", "一鑑靜開塵外境，數峰高插水中天。", "避人幽鳥聲如剪，隔岸奇花色欲然。", "太守與民同樂事，公餘不惜綺爲筵。"]'),
('d65cbbf7-718f-4d2c-81e4-a346ba8452d6','送鈐轄館使王公','王景','宋','宋诗','song-poetry','','[]','四稔總兵鈐，輕裘叔子慙。',48,'全唐诗/poet.song.37000.json','["四稔總兵鈐，輕裘叔子慙。", "抗棱遐徼伏，敦信遠民諳。", "赴召薰風布，離襟臘酒酣。", "吾皇思將帥，有意在燕南。"]'),
('33a73a7c-2ee4-4cb6-bf02-4cc52c8a81a5','遊龍城寺贈普訓','甘文政','宋','宋诗','song-poetry','','[]','閒中思衲友，曳杖輒相尋。',48,'全唐诗/poet.song.37000.json','["閒中思衲友，曳杖輒相尋。", "興廢關何事，浮沉惜此心。", "柏陰遮塔密，雨氣入鍾深。", "剔蘚碑堪讀，茫茫歲月侵。"]'),
('a8d4c652-b30f-45bb-949f-d8db2513be76','和運使學士浣花亭','葛琳','宋','宋诗','song-poetry','','[]','井絡西南區，成都號佳麗。',288,'全唐诗/poet.song.37000.json','["井絡西南區，成都號佳麗。", "錦城十里外，景物居然異。", "傍縈浣花溪，中開布金地。", "杜宅巋遺址，任祠載經祀。", "自昔歲一遊，有亭久摧廢。", "將期汎舟會，先此留旌騎。", "弗基矧肯構，後人莫予嗣。", "冠蓋或戾止，風雨亡所庇。", "我公至之初，行樂徇人意。", "柅車集賓組，幕天陳燕器。", "苟弗謀高明，胡爲革媮敝。", "鳩工度材用，奢儉求中制。", "舉從縣官給，下靡秋毫費。", "巍然大厦成，甚于折枝易。", "藩條息偃暇，時律清和際。", "落成及休辰，夙駕忻重詣。", "羣嬉逐使轂，雜處同蠶市。", "棟宇美可觀，席筵陳有次。", "芳樽既罷撤，綵舲爰登憩。", "夾岸布緹帟，中流喧鼓吹。", "泝沿烟靄間，禽鳥共翔戲。", "都人與士女，疊足連帷被。", "弄珠疑漢曲，浮觴均洛禊。", "晻晻日將暮，熙熙衆皆醉。"]'),
('8875fe65-608d-4444-95a4-e16ee5544f62','送程給事知越州','元耆寧','宋','宋诗','song-poetry','','[]','請符又作浙東行，六郡爭驅紺弩迎。',64,'全唐诗/poet.song.37000.json','["請符又作浙東行，六郡爭驅紺弩迎。", "環佩聲回堯陛遠，旌旗光動禹川明。", "山烘橘柚香浮席，溪漲菰蒲翠徹城。", "人在蓬萊仍晝錦，會稽故事兩兼榮。"]'),
('6c4b45bd-b6dd-420e-8be3-8da227e16f87','句  其一','陳知默','宋','宋诗','song-poetry','','[]','平地風烟橫白鳥，半山雲木卷蒼藤。',16,'全唐诗/poet.song.37000.json','["平地風烟橫白鳥，半山雲木卷蒼藤。"]'),
('28f6ed03-ece1-4257-bae8-b2af1577a4b1','句  其二','陳知默','宋','宋诗','song-poetry','','[]','雲埋山麓藏秋雨，葉脫林梢带晚風。',16,'全唐诗/poet.song.37000.json','["雲埋山麓藏秋雨，葉脫林梢带晚風。"]'),
('a97879f5-0b58-4f63-8a6a-a51aadaace41','宿濟州西門外旅館','晁端友','宋','宋诗','song-poetry','','[]','寒林殘日欲棲烏，壁裏青燈乍有無。',32,'全唐诗/poet.song.37000.json','["寒林殘日欲棲烏，壁裏青燈乍有無。", "小雨愔愔人假寐，卧聽疲馬齧殘芻。"]'),
('965da2de-f5de-414e-9734-82bc38e35057','九鎖山','晁端友','宋','宋诗','song-poetry','','[]','行盡青峰與碧溪，何須辛苦覓天梯。',32,'全唐诗/poet.song.37000.json','["行盡青峰與碧溪，何須辛苦覓天梯。", "九山不鎖尋真路，自是人心到後迷。"]'),
('df85a9e5-f9df-4a12-abe6-cbb85368d96b','登多景樓','晁端友','宋','宋诗','song-poetry','','[]','樓上無窮景，樓前正落暉。',120,'全唐诗/poet.song.37000.json','["樓上無窮景，樓前正落暉。", "開軒跨寥廓，覽物極纖微。", "雲破孤峰出，潮平兩槳飛。", "東溟看月上，西渡認僧歸。", "木落吳天遠，江寒越舶稀。", "魚龍鄰海窟，雞犬隔淮圻。", "草色迷千古，波聲蕩四圍。", "廢興懷霸業，融結想天機。", "浩浩群流會，沉沉百怪依。", "登臨真偉觀，回首重歔欷。"]'),
('a6f6a4e1-6190-4ad7-920d-4823edf9e085','甘露寺','晁端友','宋','宋诗','song-poetry','','[]','北固山頭寺，風烟昔縱觀。',48,'全唐诗/poet.song.37000.json','["北固山頭寺，風烟昔縱觀。", "卧亭秋石狠，環舍海濤寒。", "越舶樓前聚，江楓戶外丹。", "最宜清夜月，虛閣憶磐桓。"]'),
('57eb19ec-bea8-4179-b7ab-92fdc61efc8c','早行','晁端友','宋','宋诗','song-poetry','','[]','馬上雞初唱，天涯星未稀。',48,'全唐诗/poet.song.37000.json','["馬上雞初唱，天涯星未稀。", "驚風時墜笠，零露暗沾衣。", "山下疏鐘發，林梢獨鳥飛。", "遠峰烟靄淡，迤邐見朝暉。"]'),
('fe31d284-243d-40a4-a227-b00674115d32','馬處厚席上探得早梅','晁端友','宋','宋诗','song-poetry','','[]','嶺梅何處早，雪裏看芳菲。',48,'全唐诗/poet.song.37000.json','["嶺梅何處早，雪裏看芳菲。", "北陸寒猶在，南枝春已歸。", "曉妝初見妒，殘角未成飛。", "引我江頭夢，清香憶滿衣。"]'),
('08e773e0-4845-469f-8cb4-9b68c4f42e5c','梅花','晁端友','宋','宋诗','song-poetry','','[]','皎皎仙姿脈脈情，絳羅仙萼裹瑶英。',64,'全唐诗/poet.song.37000.json','["皎皎仙姿脈脈情，絳羅仙萼裹瑶英。", "色侔姑射無雙白，香比酴醾一倍清。", "臘後春前芳信密，水邊林下曉妝明。", "故應不屬東君管，冷艷孤芳取次成。"]'),
('ed30569c-230d-4b52-9180-974b387fcf64','遺偈','釋慶閑','宋','宋诗','song-poetry','','["\u8861\u5c71"]','露質浮世，奄質浮滅。',40,'全唐诗/poet.song.37000.json','["露質浮世，奄質浮滅。", "五十三歲，六七八月。", "南嶽天台，松風澗雪。", "珍重知音，紅爐優鉢。"]'),
('69dd050b-46d8-4e07-a9fe-fb86727d87ea','句','宇文之邵','宋','宋诗','song-poetry','','[]','安樂青且秀，琳宮跨巨鼇。',12,'全唐诗/poet.song.37000.json','["安樂青且秀，琳宮跨巨鼇。"]'),
('de2d382f-5f7a-49b2-9644-f56bfcc68f06','句','劉永年','宋','宋诗','song-poetry','','[]','一柱會擎天。',6,'全唐诗/poet.song.37000.json','["一柱會擎天。"]'),
('a2aec8ab-61c5-445e-8e3d-7dcb84cb5c3b','泛汝聯句','辛廱','宋','宋诗','song-poetry','','[]','平居厭城郭，具舟泛清汝。',288,'全唐诗/poet.song.37000.json','["平居厭城郭，具舟泛清汝。", "藍光一水遠，鐵色兩崖古。", "日華動中流，沙紋亂前渚。", "湍鳴達公橋，草綠襄王墓。", "園英擁流沫，風葉墮殘雨。", "停橈弄山泉，扶杖過花塢。", "澄潭數亂石，斷石橫顛樹。", "泳波魚鬣舒，闖穴蛙首怒。", "衝雲一雁遠，唼荇羣鷗聚。", "村間桑柘春，川闊牛羊暮。", "回頭綠樹失，卷幔青峰露。", "尋幽恣盤桓，泊淺屢回互。", "靈草不知名，珍禽啼在處。", "夕陽散鳴鳩，荒阡拱游兔。", "挽纜謠歌童，簪花立田婦。", "高歌客自如，歸涉人相負。", "青蒲戢戢生，紫燕翩翩度。", "雲烟波底明，井邑林外睹。", "欣逢閭里舊，愧乏雞黍具。", "緡水薦稏鱗，掘石羞山茹。", "繞塘梅實綠，冒桂禽殻素。", "我巾聊一頹，石榼煩屢注。", "朱櫻出芳林，紫笋侑雕俎。", "高篇爛珠璧，至樂謝鐘鼓。"]'),
('b68b59a0-4e8f-4d4b-a442-14af26ab7a9e','送詳禪師往靈巖','蔡延慶','宋','宋诗','song-poetry','','[]','靈巖川上白雲深，十里青松晝自陰。',64,'全唐诗/poet.song.37000.json','["靈巖川上白雲深，十里青松晝自陰。", "遠寺幽佳傳已古，名山絕勝冠於今。", "羣峰環翠凝秋色，危壁飛泉瀉暮音。", "此景去爲風月主，五湖應不起歸心。"]'),
('ae131505-a9c4-48f3-ab0a-cad07ba90fee','和丁寶臣遊五泄','胡宗愈','宋','宋诗','song-poetry','','[]','喜陪詩伯尋幽去，從此風騷覺有神。',64,'全唐诗/poet.song.37000.json','["喜陪詩伯尋幽去，從此風騷覺有神。", "明代應無高遯士，奇峰盡屬苦吟人。", "欲名地巧題難得，却恨圖經說未真。", "回想天童山迤邐，更多形勝亦非倫。"]'),
('e842e715-411d-4241-bde4-3b346b118432','衆樂亭  其一','胡宗愈','宋','宋诗','song-poetry','','[]','平湖拍岸海潮通，亭在平湖杳靄中。',64,'全唐诗/poet.song.37000.json','["平湖拍岸海潮通，亭在平湖杳靄中。", "莊艷含春雲島晚，波光照夜玉壺空。", "動摇人影兩橋月，洗滌塵襟四面風。", "野老半酣亭下笑，漁樵今日與民同。"]'),
('0da1ef7b-69a3-4626-b957-1c0c6e04a679','衆樂亭  其二','胡宗愈','宋','宋诗','song-poetry','','[]','平蕪十頃綠含烟，勝事興衰已百年。',64,'全唐诗/poet.song.37000.json','["平蕪十頃綠含烟，勝事興衰已百年。", "島榭漫隨民意樂，溪山應喜主人賢。", "點粧野趣灘邊鷺，彷彿妖容水上蓮。", "日日流風轉謠俗，棹歌長在釣魚船。"]'),
('6155e2e0-a35e-4287-aad7-a1275c80333e','咏左伯桃羊角哀','胡宗愈','宋','宋诗','song-poetry','','[]','古有二烈士，羊左哀與桃。',288,'全唐诗/poet.song.37000.json','["古有二烈士，羊左哀與桃。", "結交事遊學，心若膠漆牢。", "遠聞楚王賢，待士皆英髦。", "負笈首燕路，不憚千里勞。", "行行及梁山，雨雪填巖肧。", "途窮食不繼，餓口空嗸嗸。", "無爲俱死爾，原野涂身膏。", "我留子獨往，命各繫所遭。", "慷慨示一訣，併糧解衣袍。", "僵坐空穴中，視死輕鴻毛。", "角哀既仕楚，爵位聯執羔。", "顧懷交舊心，血泣聲號咷。", "王聞義其事，禮葬遷蓬蒿。", "孤風激頹俗，千古清蕭飈。", "叔世忠義喪，友道皆滔滔。", "平居論莫逆，握手相遊遨。", "利害一軋己，所得無秋毫。", "擠壑又下石，反若豺狼嘷。", "秦末餘耳輩，遇時方繹騷。", "誓爲刎頸交，名節初相高。", "一旦成眦睚，親勒兵相鏖。", "斬餘泜水上，論功傳子敖。", "較此豈不愧，清議安能逃。", "凜凜溧水傍，危墳望江臯。"]'),
('8f010d17-ab0e-45c5-9b7b-828263dea984','鳧鷖亭','胡宗愈','宋','宋诗','song-poetry','','[]','君爲鳧鷖亭，更作鳧鷖詩。',146,'全唐诗/poet.song.37000.json','["君爲鳧鷖亭，更作鳧鷖詩。", "鳧鷖爲鳥雖甚微，君心仁愛乃在茲。", "不忍壯者弋其母，兒童捕其兒，鳧鷖母子何嬉嬉。", "城頭草靜烟雲迷，城下水暖菰蒲低。", "鳧鷖朝傍雲烟飛，倦來暮入菰蒲棲。", "寄巢生子冬復夏，巢穩子大無人知。", "我思入境觀君爲，坐見三異於今時。", "知君官久行亦歸，亭上引滿傷別離。", "豈惟豐人惜君去，雖我亦爲鳧鷖悲。"]'),
('91af2180-fd4c-412e-9e13-0c8b84f4dd2f','試筆','羅適','宋','宋诗','song-poetry','','[]','金門禿筆積如山，黄閣磨煤夜不乾。',32,'全唐诗/poet.song.37000.json','["金門禿筆積如山，黄閣磨煤夜不乾。", "試借薦賢書稿看，應無一字及孤寒。"]'),
('200e1e29-5310-4da5-b47f-85108df6f3a8','巢父亭','羅適','宋','宋诗','song-poetry','','[]','泊然巢一枝，常靜不待息。',48,'全唐诗/poet.song.37000.json','["泊然巢一枝，常靜不待息。", "天地存遺井，聊以見清德。", "窺者在爾心，鑿者在爾力。", "何爲病夏畦，俯仰無慚色。"]'),
('3cdb5dc3-701b-4d86-b5b9-590f0c0f3dce','寄題池亭兼贈呂道正二首  其一','羅適','宋','宋诗','song-poetry','','[]','太一仙人天上來，口傳丹訣養真胎。',32,'全唐诗/poet.song.37000.json','["太一仙人天上來，口傳丹訣養真胎。", "赤城道士誰堪論，白髮先生或姓回。"]'),
('9f29738b-96fa-453f-b97d-c90e6a556f84','寄題池亭兼贈呂道正二首  其二','羅適','宋','宋诗','song-poetry','','[]','窗外方塘幾畝蓮，花開料亦似常年。',32,'全唐诗/poet.song.37000.json','["窗外方塘幾畝蓮，花開料亦似常年。", "先生菡萏香中坐，應有人呼作水仙。"]'),
('c20a59ff-62ae-4db5-bd7c-f77a917419e2','遊碧照庵','羅適','宋','宋诗','song-poetry','','[]','長松青似染，高杉翠欲滴。',48,'全唐诗/poet.song.37000.json','["長松青似染，高杉翠欲滴。", "餘陰入軒來，滿座瑠璃色。", "達人無六塵，靜見照中碧。", "庵內一爐香，萬緣自然息。"]'),
('5b450b35-121a-48a2-893e-cb87fded9321','崇教寺筠軒','羅適','宋','宋诗','song-poetry','','[]','夜憶清軒上，都忘居會稽。',48,'全唐诗/poet.song.37000.json','["夜憶清軒上，都忘居會稽。", "秋聲先在竹，月色最宜溪。", "銀漢簷前直，玉繩天外低。", "何人倚欄檻，爲聽下莊雞。"]'),
('c3ff79ad-b945-4222-86d0-2fec089bbdbd','石橋','羅適','宋','宋诗','song-poetry','','[]','傳得栴檀相甚奇，紺容光徹照須彌。',32,'全唐诗/poet.song.37000.json','["傳得栴檀相甚奇，紺容光徹照須彌。", "橋頭尊者來瞻禮，應憶靈山聽法時。"]'),
('533022b2-be28-4f11-8458-d0aef9154dae','石梁','羅適','宋','宋诗','song-poetry','','[]','飛瀑斷巖路，天然石似梁。',48,'全唐诗/poet.song.37000.json','["飛瀑斷巖路，天然石似梁。", "始知融結日，便作聖賢鄉。", "水靜魚龍樂，山靈草木香。", "茶花本餘事，留跡示諸方。"]'),
('c4a3957c-8d44-46e2-8f53-a72117e5694d','題萬年妙蓮閣','羅適','宋','宋诗','song-poetry','','[]','華頂西邊天姥東，妙蓮開閣對羣峰。',64,'全唐诗/poet.song.37000.json','["華頂西邊天姥東，妙蓮開閣對羣峰。", "清含銀漢三千界，香透金庭第八重。", "畫棟有聲啼海燕，澄波無影睡天龍。", "夜深講罷何人見，雲在青天月在松。"]'),
('29c1acc6-fd77-4b87-881f-238df22f8ae8','遊天台桐柏觀二首  其一','羅適','宋','宋诗','song-poetry','','[]','欲訪琳宮入翠微，滿山烟雨正梅時。',64,'全唐诗/poet.song.37000.json','["欲訪琳宮入翠微，滿山烟雨正梅時。", "神仙事祕人難問，造化功深世莫知。", "海近應通三島信，年多空見八分碑。", "身中龍虎吞天地，誰肯留心繼鍊師。"]'),
('f44b9a8b-5aa4-4e04-8795-2a4abc70897e','遊天台桐柏觀二首  其二','羅適','宋','宋诗','song-poetry','','[]','金庭福地竟如何，當日山前異事多。',64,'全唐诗/poet.song.37000.json','["金庭福地竟如何，當日山前異事多。", "子晉高風傳世表，仙翁遺跡在巖阿。", "三清路遠須由學，九轉功成豈怕魔。", "我有玉符真訣在，黄衣誰肯遠相過。"]'),
('60c9aded-5afa-4982-a472-e3a57b051eff','憶梁王寺過遠橋寄昉師','羅適','宋','宋诗','song-poetry','','[]','長憶溪橋避暑時，天風六月襲人肌。',64,'全唐诗/poet.song.37000.json','["長憶溪橋避暑時，天風六月襲人肌。", "水隨地脈來無盡，雲過山頭去不知。", "拂面稚松應偃蓋，當年游子已龐眉。", "憑師莫動溪邊石，留待東歸題好詩。"]'),
('9e0e3660-28bb-4bd0-b450-db4298327acc','題天台茅橋','羅適','宋','宋诗','song-poetry','','[]','京城濕墨遺相知，心繞天台四散飛。',32,'全唐诗/poet.song.37000.json','["京城濕墨遺相知，心繞天台四散飛。", "記得小田橋上月，五更河露濕人衣。"]'),
('6f5d38cd-6e4e-4079-8ca8-44a162714ca0','題慈雲院','羅適','宋','宋诗','song-poetry','','[]','七十有餘歲，不曾游此山。',48,'全唐诗/poet.song.37000.json','["七十有餘歲，不曾游此山。", "因尋白雲路，深入翠微間。", "曉澗烟霞合，春巖草木斑。", "誰灰心地火，占取一生閒。"]'),
('087e3be5-35ca-4a16-8a12-d7d08e831a39','題天柱山','羅適','宋','宋诗','song-poetry','','[]','孤峰插太清，天柱此垂名。',48,'全唐诗/poet.song.37000.json','["孤峰插太清，天柱此垂名。", "造化功成後，乾坤頼不傾。", "夜星千栱小，秋漢一梁橫。", "欲問登臨處，重梯四面生。"]'),
('697381bc-88ae-4d6f-bfe5-ac7896ea68a2','題瑞相院','羅適','宋','宋诗','song-poetry','','[]','招提臨古道，窣堵壓孤山。',24,'全唐诗/poet.song.37000.json','["招提臨古道，窣堵壓孤山。", "十里梅花樹，都來一望間。"]'),
('ca5ebf38-514b-482a-9d0b-b8cb737bdc4b','題潘幾道杲亭','羅適','宋','宋诗','song-poetry','','[]','行盡城西路，爲君登杲亭。',48,'全唐诗/poet.song.37000.json','["行盡城西路，爲君登杲亭。", "無雲生碧落，看日出滄溟。", "逐影成何事，負暄全我形。", "交情長在目，隔岸數峰青。"]'),
('f5e50bd7-747a-4f90-a78b-cb335796ec6a','慈母石','羅適','宋','宋诗','song-poetry','','[]','疊石江頭峻如壁，舟人指云慈母石。',348,'全唐诗/poet.song.37000.json','["疊石江頭峻如壁，舟人指云慈母石。", "慈母名兮不可聞，巉巖坑壓秋江碧。", "我聞慈母石，啟我父母思。", "人有父母誰不思，我思父母偏傷悲。", "憶昔生我童稚時，家貧日逐圖生資。", "父母衣我寧自寒，父母食我寧自饑。", "拾薪爲我代燈燭，鬻衣爲我買詩書。", "朝夕勸我苦勤讀，戒我弗作庸常兒。", "嗟哉我生命多疾，父母提携延歲日。", "忽朝卧病一呻吟，父母咿啞面如漆。", "有時爲我祝神祇，願我早著藍袍歸。", "此時我心常感發，願如夫子言無違。", "嗟哉我生命多蹇，少年不第第已晚。", "况兼父母未死時，食不飽兮衣不暖。", "今朝身爲一命仕，薄俸聊堪奉甘旨。", "雙親已逝掩荒丘，薄俸翻將飽妻子。", "有時舉筯食新鮮，默默不知雙淚漣。", "拭淚空將酒盃奠，酒盃不到陰容前。", "慈母石，世稀有，汝在江頭天地久。", "我思父母不得食，此恨當同汝不朽。", "嗚呼罔極恩難報，於今頼有移忠孝。", "行當竭力事明君，庶可揚名酬二親。"]'),
('31aa793a-7c29-49fa-b3bd-76c55b739060','送致政太師文潞公','羅適','宋','宋诗','song-poetry','','[]','曾將故老較量看，五福如公信是難。',64,'全唐诗/poet.song.37000.json','["曾將故老較量看，五福如公信是難。", "潞國封來多有歲，太師以上更無官。", "應留妙算安神器，必得人才薦將壇。", "他日宋家青史上，始終臣節雪霜寒。"]'),
('dff185a3-6891-4d98-95a6-4c821b3529c8','句','羅適','宋','宋诗','song-poetry','','[]','具州陰德即仙資。',8,'全唐诗/poet.song.37000.json','["具州陰德即仙資。"]'),
('e552aff3-5639-47cd-afe1-33a879bbaa7c','過吳江','高本','宋','宋诗','song-poetry','','[]','江吞大澤無西東，危亭聳立如驚鴻。',64,'全唐诗/poet.song.37000.json','["江吞大澤無西東，危亭聳立如驚鴻。", "曉晴不見天地色，上下澄碧迷雙瞳。", "菰蒲千頃鷗鷺國，風波萬丈魚龍宮。", "逢時自好盡忠義，莫學衰世鴟夷公。"]'),
('9e89cbf4-993e-475e-9ad1-18a1999238d2','送程給事知越州','李綖','宋','宋诗','song-poetry','','[]','伏節要符慣遠遊，再朝金陛付牙籌。',64,'全唐诗/poet.song.37000.json','["伏節要符慣遠遊，再朝金陛付牙籌。", "君王難識奇才晚，御史章言舊治優。", "三峽路長收使旆，九江波迥改行舟。", "不須重賦西山好，歸侍宸遊十二樓。"]'),
('1f0bd866-a8ac-4c61-a68a-13328ff62eef','雜詩','呂陶','宋','宋诗','song-poetry','','[]','夕陰斂層空，素月出西海。',144,'全唐诗/poet.song.37000.json','["夕陰斂層空，素月出西海。", "寥寥俯仰間，杳不見纖靄。", "清光信可掬，璀璨掌握內。", "虛庭縱遠目，中夜如有待。", "念我金石交，輕别己十載。", "德音響球琳，道味芬蘭茝。", "悠然阻聲容，況復接言誨。", "幽懷願一寫，四顧多泛愛。", "迴頭自珍惜，欲顯不如晦。", "賴此秋蟾魄，千里共光彩。", "思賢搖去意，對景慕良會。", "此夕雖圓明，清賞君何在。"]'),
('6611051e-def3-431e-a071-f40c40b0ee86','化阿','呂陶','宋','宋诗','song-poetry','','[]','子奇昔稚齒，得官化阿城。',120,'全唐诗/poet.song.37000.json','["子奇昔稚齒，得官化阿城。", "齊君疑其幼，且悔寄任輕。", "同車載白首，教告力奉行。", "一日鑄劍戟，二日促農耕。", "官倉不積粟，武庫皆無兵。", "魏人錯料事，來戰欲蕩平。", "阿俗且感義，子弟從父兄。", "小邑抗大國，魏敗齊以寧。", "千年陵谷變，猶有化阿聲。", "乃知謀人國，自古須老成。"]'),
('c47ff1ba-7b47-49ed-90db-6e06edef5df0','河津女','呂陶','宋','宋诗','song-poetry','','[]','河津女娟者，可與壯士儔。',180,'全唐诗/poet.song.37000.json','["河津女娟者，可與壯士儔。", "簡子欲南渡，誰人爲撐舟。", "娟奮紅袂起，姿容盛優柔。", "長篙與風快，大翼如雲浮。", "頃刻易千里，恬然濟中流。", "心情忽感慨，爲子發清謳。", "波濤激無際，駭畏事禱求。", "杳冥若影響，自爾蒙神休。", "交龍助其維，歸櫂勿夷猶。", "聞之意飽滿，春風滿華斿。", "禕褕響環佩，蘋藻奉薦羞。", "豈獨女子事，可況公與侯。", "一言固有合，半策或見收。", "惟其遇不遇，通塞難相謀。", "旬月取漢相，安怪田千秋。"]'),
('a535670d-898d-432e-9553-7b89c43b06c4','送周茂叔殿丞','呂陶','宋','宋诗','song-poetry','','[]','高帆颺漢水，六月南風温。',120,'全唐诗/poet.song.37000.json','["高帆颺漢水，六月南風温。", "下流乘漲怒，一日千里奔。", "湍威雷霆繫，石勢龍虎蹲。", "漂搖波濤際，渺漫天地昏。", "君心浩溟渤，目笑衆水煩。", "外任安濟德，中養澄靜源。", "青雲露三峽，寄傲開琴樽。", "白日滿平楚，放懷清夢魂。", "夷險既一致，卷舒惟義存。", "未易泛滄浪，時平斯道尊。"]'),
('3f90567a-17f4-47a8-8a86-72ec86d3ffed','百合','呂陶','宋','宋诗','song-poetry','','[]','盛夏衆芳息，景物殊寂寥。',216,'全唐诗/poet.song.37000.json','["盛夏衆芳息，景物殊寂寥。", "庭前有百合，穎然學春嬌。", "數枝己聳茂，百朵尤富饒。", "擁蔽因巨葉，紛數假長條。", "吐秀偏得地，爭妍欲干霄。", "素粉間瓔珞，輕黄染瓊瑤。", "靜若寶幢植，動如鳴佩搖。", "盡向杲日麗，不畏炎風飄。", "太守雅好事，得之詫朋僚。", "綺思入新句，彩圖上輕綃。", "衆目遂賞翫，英華不虛凋。", "此物既異常，論議有以招。", "人情愛惡間，輕重何以遼。", "或謂花之祥，或譏草木妖。", "嗟予豈博物，智慮隨日消。", "欲窮造化理，茫昧增無聊。", "疑此亦偶然，發之自根苗。", "莫議妖與祥，爲公續長謠。"]'),
('67172fd8-ba37-45ca-9042-39f1af23aeca','韓子定嘉雪應祈二首  其一','呂陶','宋','宋诗','song-poetry','','[]','晉地素瘠埆，所憂冬氣差。',216,'全唐诗/poet.song.37000.json','["晉地素瘠埆，所憂冬氣差。", "明神享其誠，瑞霰飄爲花。", "輕絲瞥已没，散漫撲水涯。", "大片殊易積，彷彿填丘窊。", "饑鷹健欲擊，伏虎凍不拏。", "北響少鳴鴈，南飛絕驚鴉。", "肅然天地中，靡聞一聲譁。", "樓觀動曉色，江湖壓晴沙。", "度曲宜鼓琴，卷葉難吹笳。", "顧此勤斂俗，趨時務耕畬。", "三冬苟失望，二麥將不芽。", "造化善從欲，沾滋罔遺遐。", "須爲盈尺喜，勿興祁寒嗟。", "清威儼開府，和氣方當衙。", "餘潤匝千里，歡聲同一家。", "天人報應間，其速如馳車。", "我公心在民，致禱誠乃加。", "康衢有歌詠，繼者慚餘哇。"]'),
('758c8e2e-b2d2-42a0-b05e-f36e1c7dcdec','韓子定嘉雪應祈二首  其二','呂陶','宋','宋诗','song-poetry','','[]','天道孰云遠，未嘗毫釐差。',216,'全唐诗/poet.song.37000.json','["天道孰云遠，未嘗毫釐差。", "鑒此金石心，報之瓊瑰花。", "旱氛滌已去，豐歲來何涯。", "高能累岌業，卑亦蒙汙窊。", "密布氣晃蕩，急飄勢奔拏。", "掘地得寶馬，集庭瞻白鴉。", "歲功助發洩，民口騰讙譁。", "髙原有瑤塵，絕漠無黄沙。", "山夫喜執來，戍卒愁聞笳。", "鐵甲彼固凝，石田吾將畬。", "雰雰既霑足，陳根其動芽。", "霏霏幸還反，歸路曾忘遐。", "待詔一何寒，映書誰肯嗟。", "鳴弓壯暮獵，凍鼓咽朝衙。", "羡君詩筆雄，退之昔名家。", "染翰動成集，卷軸可載車。", "矧此古琴操，應和無以加。", "雅鄭本末殊，中正蒙多哇。"]'),
('065bb8b2-f925-41ab-aec1-c5efed4f6fc8','朝陰','呂陶','宋','宋诗','song-poetry','','[]','朝陰晝多雨，少見日有光。',288,'全唐诗/poet.song.37000.json','["朝陰晝多雨，少見日有光。", "四顧天地慘，萬物皆茫茫。", "占書久不讀，何暇推雨暘。", "試以人事說，訝此非吉祥。", "日者人君象，照臨及遐荒。", "豈容一物掩，有若自晦藏。", "明主躬聽斷，萬事付紀綱。", "賞罰信且必，威令非不强。", "天子報應間，安得陰侵陽。", "疑是蠻寇起，勢力殊猖狂。", "王師僅四萬，靈旗指邊疆。", "州郡少羡卒，饋挽須丁黄。", "父子罷斂穫，女妻急縫裳。", "老母哭不忍，癡兒亦徬徨。", "將行痛訣别，意謂趨死鄉。", "小憂止竄匿，大患在殺傷。", "蜀人不慣此，聞者皆倉惶。", "所以作霾霧，終日爭飄颺。", "秋毫與天地，自古不比方。", "中國及夷獠，何足校短長。", "帷幄巳坐勝，虎貔誰可當。", "天威一掃蕩，不使存微芒。", "何時捷書至，喜聲復鏘鏘。", "霄漢忽開霽，金烏欲飛翔。"]'),
('db96df38-bc6f-494c-bacb-6be3c0842dde','和陳長蒨休致二首  其一','呂陶','宋','宋诗','song-poetry','','[]','惜君有高才，舒卷莫非道。',72,'全唐诗/poet.song.37000.json','["惜君有高才，舒卷莫非道。", "趨時忽倦游，謝事不待老。", "私謀惟恐晚，公論歎其早。", "平生恬淡懷，憂恨未嘗抱。", "白日由此閑，紅塵灑然少。", "鼓棹勿遲遲，湘川秋色好。"]'),
('6b0bce98-a13b-4629-92bb-1da0d344c03d','和陳長蒨休致二首  其二','呂陶','宋','宋诗','song-poetry','','[]','進取雖繫時，退藏亦在道。',72,'全唐诗/poet.song.37000.json','["進取雖繫時，退藏亦在道。", "儻與志不會，須惜流年老。", "不知笑君拙，知者羡君早。", "知與不知間，惡在愜予抱。", "得無鈞石重，失乃錙銖少。", "明鏡洗無心，向誰論醜好。"]'),
('e7818137-7283-4dbb-b305-acbd19c1b969','送劉希道龍圖赴秦亭','呂陶','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','君子異衆人，所繫惟大節。',288,'全唐诗/poet.song.37000.json','["君子異衆人，所繫惟大節。", "著見在功業，何嘗一毫缺。", "幽能動金石，明可貫日月。", "其間有用舍，舒卷不同轍。", "言之尺與尋，輕重自區别。", "公以道德進，義操非孑孑。", "早歲在言路，屢補衮衣闕。", "一語定大計，永祚慶綿瓞。", "西來委重鎮，遠業粗施施。", "岷峨固不動，江漢亦澄澈。", "譬如公輸木，巨細歸檃括。", "又如后夔音，合止付椌楬。", "爾其遂生成，吾豈任呴沬。", "愚者多競利，破産營酒蘖。", "官緡逋數萬，私計鮮毫髮。", "雖云鬻兒女，未免就縲紲。", "巨械壓羸頸，重箠困流血。", "亦有凍餒斃，枯骸不藏穴。", "兹事關進退，聞之宜結舌。", "壯哉仁者勇，拜疏爲論列。", "詔書即日下，蠲除允公說。", "皇慈極霶霑，治體非眇末。", "推此不忍心，疲瘵庶全活。", "方將秦川命，又仗元師鉞。"]'),
('f53b4293-668b-42c7-a966-2e8c91bd0fb4','送范希聲歸洛','呂陶','宋','宋诗','song-poetry','','[]','策馬太行道，西風動微凉。',72,'全唐诗/poet.song.37000.json','["策馬太行道，西風動微凉。", "之子去意遠，南望嵩洛鄉。", "日馳百里足，急歸拜高堂。", "天倫喜會合，親侍生輝光。", "惜此暫闊别，送君乏詞章。", "早晚揖回馭，秋深籬菊黄。"]'),
('285d7137-b0c9-4e08-b0bf-f3b88cda4c26','雲頂山','呂陶','宋','宋诗','song-poetry','','[]','崎嶇上層山，十里到巍頂。',192,'全唐诗/poet.song.37000.json','["崎嶇上層山，十里到巍頂。", "天形露空闊，物態蓄深靜。", "羣峰峙其旁，儼若挈裘領。", "廣野闢於下，誰爲畫廬井。", "殿閣聳盛觀，松檜富清景。", "蕭然古佛界，邈矣真仙境。", "枯株吐芽蘖，晴雲發祥慶。", "盡手矜妙逸，詩毫事奔騁。", "乘高縱閒目，幽意適遐迴。", "班班見彷彿，歷歷可窮省。", "茲山介兩蜀，鎮壓猶巨屏。", "南連三峨巔，北距雙劍嶺。", "東西數萬里，高下幾千頃。", "地産號充盈，天時與康靖。", "民間豐歲樂，事外化日永。", "攬轡一登臨，茲焉聊賦詠。"]'),
('fb884c71-d839-45f7-82e6-f9ae0d7c5638','見雲頂山','呂陶','宋','宋诗','song-poetry','','[]','朝見雲頂明，暮見雲頂暗。',216,'全唐诗/poet.song.37000.json','["朝見雲頂明，暮見雲頂暗。", "陰見雲頂濃，晴見雲頂淡。", "雲頂乃一物，百態異舒慘。", "朝暮不相失，陰晴可先探。", "于吾如有緣，靜景供遠瞰。", "搜求入風騷，刻琢費鉛槧。", "一語小如意，讀之惟自頷。", "深惟出處途，兩得亦誰敢。", "雲霄有達士，豐禄侈飲啗。", "終身落世網，塵垢漬衡紞。", "雖逢物境勝，何暇縱遊覽。", "丘壑有幽人，俗繩不可纜。", "茂林適情性，清泉滌肝膽。", "野飯止一盂，往往乏藜糝。", "予生安拙計，萬事恥浮濫。", "宦遊若不樂，進退殊壈坎。", "廩俸纔數斛，憂責如舍擔。", "飽食坐看山，閒心復何憾。"]'),
('41d4e3b9-0edb-45fb-876f-fc94d9692b9a','三亭詩','呂陶','宋','宋诗','song-poetry','','[]','三亭何爲者，吾友所繕營。',288,'全唐诗/poet.song.37000.json','["三亭何爲者，吾友所繕營。", "亭前有標榜，雅意異俗生。", "治己己孰治，清慮慮孰清。", "吾道固可味，未易貫至誠。", "惟天于斯人，一概授五行。", "生質本淳靜，外誘徒縱横。", "心術儻茅塞，耳目將聾肓。", "上聖貴復本，大賢猶性情。", "況其可上下，安得不勵精。", "四端匪外鑠，語默無自輕。", "百行皆吾分，積漸日有成。", "稂莠荒我懷，去之如鋤萌。", "波瀾擾我源，止之如澄泓。", "浩然滌萬慮，粹矣讀六經。", "不趨楊墨塗，將造周孔庭。", "出井見仁義，仰天瞻日星。", "甘若飲醇酎，珍若享太羮。", "清若餌芝术，和若聞咸莖。", "積中而恬愉，發外而光享。", "窮不失素守，達不孤羣氓。", "生不陷非義，死不忘英聲。", "道味固如此，身規從可明。", "本原何所來，慮之深以閎。", "欲知君子心，吾請觀亭名。"]'),
('528f6d29-ad18-4075-8215-ea4b8ee0d211','贈蔡山王潛','呂陶','宋','宋诗','song-poetry','','[]','王生性高閒，了不掛塵網。',240,'全唐诗/poet.song.37000.json','["王生性高閒，了不掛塵網。", "家居蔡山下，景物盡幽爽。", "山松何年植，老幹已增長。", "山雲終日飛，秀氣自飄蕩。", "山泉涓涓流，落澗有餘響。", "山月隱隱出，澄輝透林莾。", "生嘗坐巖石，寂爾遺萬想。", "横琴試一弄，意外忽忘象。", "千年幾興亡，六合一俯仰。", "惟傳太古聲，猶在五弦上。", "純皇與聖帝，作樂理和暢。", "志士及幽人，寄情多感愴。", "於焉得深趣，不返而遂往。", "銖石莫重輕，尺尋奚直枉。", "清哉此標節，抑可勸鄉黨。", "予生本靜默，意味欲恬養。", "偶然從宦遊，百態殊鞅掌。", "既無移時術，力軟不能强。", "亦有超世心，倦足欲焉往。", "作詩持贈生，厚顔尤惘惝。"]'),
('b1fab422-f965-4c09-9d03-2185d3ac05fb','送吳龍圖歸闕','呂陶','宋','宋诗','song-poetry','','[]','蜀山千尋立，奇勢凌穹蒼。',288,'全唐诗/poet.song.37000.json','["蜀山千尋立，奇勢凌穹蒼。", "岷水萬里走，怒流吞滄浪。", "南連楚越腹，北際秦隴吭。", "乾坤所造作，險固天下彊。", "四境高與深，沃野蟠中央。", "天時少凶旱，地力宜耕桑。", "生齒萬億計，貲貨豐且穰。", "運載實內府，重車不停箱。", "公廩己腐粟，私家始餘糧。", "恬然禮義俗，杳在無何鄉。", "王澤或壅閉，土風亦悲凉。", "所以二僭僞，草木罹凋傷。", "繼有三盜起，氛埃屢飛颺。", "耳目殊未遠，本末猶可詳。", "朝廷任連帥，指顧寧一方。", "聖造爾莫測，恩波但流長。", "我公來息蕃，琴瑟更而張。", "至誠極愷悌，大事費忖量。", "澄撓孰清濁，中和匪柔剛。", "蜀人自荷戴，頌口殊鏘洋。", "仰公若梁棟，愛公比琳琅。", "謂宜立大厦，豈特爲圭璋。", "願公保遐福，堅厚如陵岡。", "期公享眉壽，歲月過綺黄。"]'),
('047a5b8f-a7f9-47a3-b35e-ca7167c0e580','三黜詩','呂陶','宋','宋诗','song-poetry','','[]','下惠爲士師，子文乃令尹。',240,'全唐诗/poet.song.37000.json','["下惠爲士師，子文乃令尹。", "仕也固不喜，黜之何嘗愠。", "直道宜少合，高風諒難泯。", "大抵君子心，惟義素藏韞。", "進非爲私謀，退亦爲道隱。", "顧彼榮與辱，於吾不加損。", "我公天下賢，許國以誠悃。", "危言屢啟納，大事費量忖。", "審如秦和醫，良劑起疾疢。", "工如魯匠斵，鉅木赴繩準。", "昔嘗遷九江，誰謂去途窘。", "又嘗謫蘄水，恬然泛驚濆。", "于今已三黜，去就決不混。", "遠視前世賢，並驅而齊軫。", "大敵衆所畏，未戰勢自殞。", "惟公鼓而前，萬旅悚兵楯。", "晚節人所重，半道或凋隕。", "惟公久益壯，千古激忠憤。", "大明方乘離，元老反遇遯。", "得喪未易言，所繫在邦本。"]'),
('41e8de2b-50eb-403d-91dd-e7424d914aca','和毅甫惠梅竹茶麴','呂陶','宋','宋诗','song-poetry','','[]','春前識寒梅，雨裏見脩竹。',48,'全唐诗/poet.song.37000.json','["春前識寒梅，雨裏見脩竹。", "一水自浮花，六神休搗麴。", "清惠非塵埃，佳章亦金玉。", "毫髪無重輕，此意可勵俗。"]'),
('4d172da9-4454-49c1-94fe-9df5138de62e','即席送堯天','呂陶','宋','宋诗','song-poetry','','[]','行行重行行，千里秦蜀道。',48,'全唐诗/poet.song.37000.json','["行行重行行，千里秦蜀道。", "落日飛孤雲，秋風蕩衰草。", "極望快歸目，深思感幽抱。", "吾俗有謠言，公還一何早。"]'),
('e94bbf89-777c-48f9-8c84-d086d3b40504','說學送句輔元赴普慈','呂陶','宋','宋诗','song-poetry','','[]','六經聖人心，言以寓微意。',288,'全唐诗/poet.song.37000.json','["六經聖人心，言以寓微意。", "著示萬世教，大略歸簡易。", "先儒事研覃，傳注發奥秘。", "其間豈無失，十數纔一二。", "沿波而討源，自可見極致。", "學者不務此，紛紛競非是。", "所得方一毫，已謂盡千里。", "譬如就寸管，窺覘九清位。", "又如持小蠡，測度巨浸水。", "近年經術興，衆說尤鼎沸。", "或沿老佛解，或取鬼神議。", "或以對偶求，或用點畫治。", "往往勤萬言，區區釋數字。", "茫昧超洪荒，高闊等天地。", "幽欲根死生，明欲混愚智。", "五常孰爲常，百氏孰爲氏。", "古今名家學，一旦盡委棄。", "老生分退縮，鉗口深有畏。", "晚輩互馳騁，鋭力不少避。", "兹事繫風化，賢者慎措置。", "吾鄉句夫子，天禀最純粹。", "事親存至行，執卷考精理。", "平生耽道腴，大嚼得鼎味。", "使之典胄席，琢玉成貴器。"]'),
('71cfbc14-8354-4d73-801d-c57f2ef3b3cb','答宇文公南','呂陶','宋','宋诗','song-poetry','','[]','少年從君游，于今已頭白。',216,'全唐诗/poet.song.37000.json','["少年從君游，于今已頭白。", "逡巡三十載，光景如昨日。", "追懷當時事，感慨横胸臆。", "賢侯在泮水，多士凡數百。", "探道先淵源，學文重氣格。", "君常露華采，流品推第一。", "西南有豪俊，自此貴名出。", "天池可直上，中減扶摇力。", "不免逐鷦鷯，搶榆暫棲息。", "北窗換五斗，輕重固不敵。", "况當念赤子，安忍負愧色。", "歸來林下泉，屢把塵衣滌。", "南溟徒爾慕，腐鼠莫我嚇。", "清樽及黄卷，兩與聖賢覿。", "伊予最不肖，厚幸蒙賁飾。", "歸田尚無計，苟禄惟自責。", "因循得瘖病，放蕩成笑疾。", "持此答長謡，慚無雙白璧。"]'),
('294eb537-ad50-4eb1-b0ff-d114a8a9ed18','西風起高原一首奉送應之太博東歸','呂陶','宋','宋诗','song-poetry','','[]','西風起高原，萬象動秋色。',240,'全唐诗/poet.song.37000.json','["西風起高原，萬象動秋色。", "渺瀰潔寒流，慘淡升杲日。", "嗈嗈雲端雁，所響知自擇。", "豈獨順寒暑，行将避矰弋。", "蕭蕭林間葉，早暮見疏密。", "危梢怯摇撼，懔若遇彊敵。", "騷人與志士，趨向在幽寂。", "悲歌節物變，浩歎歳月失。", "遠憂積不解，難以斗酒滌。", "中夜撫鳴琴，餘聲寫沈鬱。", "竊嘗窮天運，舒慘固其職。", "胡爲世網中，情熊異休戚。", "達觀殊不爾，曠懷居自適。", "偉歟當世賢，明爽照今昔。", "孤高松柏操，肯與霜雪易。", "磊落鷹隼拳，何憚狐兔擊。", "天涯共一笑，肝膽露纖悉。", "相從恨不早，此别重嗟惜。", "夷途快覽望，還馭忘涉歷。", "悲哉宋玉賦，安可贈行客。"]'),
('8c228d17-b955-47b3-bb9e-f46b03ac778a','仁智亭夜集','呂陶','宋','宋诗','song-poetry','','[]','明月有深意，輝光滿層臺。',48,'全唐诗/poet.song.37000.json','["明月有深意，輝光滿層臺。", "佳景豈易得，對此持酒杯。", "坐久轉清曠，雄風爲時來。", "夜闌興未倦，歸步猶徘徊。"]'),
('6e741646-d1cc-4585-8a1a-f6aa00fd6d12','答梁子美召食','呂陶','宋','宋诗','song-poetry','','[]','湘中佳山水，使指重他部。',180,'全唐诗/poet.song.37000.json','["湘中佳山水，使指重他部。", "高賢駐行節，儒雅飾治具。", "雖云入郡廣，曾不假多慮。", "一扇清微風，融和及生聚。", "川原發陽和，草木均雨露。", "疏網悉舉綱，和聲已載路。", "時登華遠亭，每與勝景遇。", "秀巖及南峻，碧江爭北注。", "回環如戶庭，彷彿若繪素。", "彌望快遐目，縱吟盡幽趣。", "雍容接諸生，謙屈存異顧。", "飲食出誠眷，上下捐禮數。", "賤子慚不肖，萬里困飄寓。", "屢嘗造賓除，幸此聽談緒。", "斐然無所裁，安可繼大句。"]'),
('8cadb4c1-43be-445c-8b17-24dc046b3edb','送蔣熙州','呂陶','宋','宋诗','song-poetry','','[]','昔登蔣公門，忽忽五十載。',264,'全唐诗/poet.song.37000.json','["昔登蔣公門，忽忽五十載。", "于今見猶子，省記似前代。", "慶源得餘波，家範禀性誨。", "筆下吐雄文，滔滔湧江海。", "胸中抱英氣，落落等嵩岱。", "十嘗試一二，卓犖已稱最。", "還朝纔幾時，何時又補外。", "河湟復古地，形勢壯且大。", "冊府圖籍存，充國城壘在。", "臨洮建都府，節制中機會。", "守之扼喉吭，動則攻腹背。", "西羌輒犯順，種落異向背。", "呼嗟秦雍間，氛祲恐未艾。", "連年困飛輓，何日貯倉廥。", "一病費調養，已甚其可再。", "綏懷與剪蕩，黑白燦利害。", "吾君鑑勤遠，静制六合內。", "仁如天地心，萬類悉容貸。", "不矜靈旗伐，未奏短簫凱。", "一旦春風來，生意入窮塞。", "載瞻將軍鉞，猶識使者旆。", "治邊信有術，豈徒威克愛。"]'),
('a280a960-3408-460f-8979-44ef8003daab','送張子公','呂陶','宋','宋诗','song-poetry','','[]','康定用兵日，府谷尤孤危。',240,'全唐诗/poet.song.37000.json','["康定用兵日，府谷尤孤危。", "屬當治安久，多事盡廢隳。", "三面枕賊境，平易如通逵。", "重城輒議葺，浮論多背馳。", "賢哉光禄公，定慮先本基。", "百堵大興作，據險成藩籬。", "城完賊已至，善守莫敢窺。", "泉源衆所汲，公爲親解圍。", "兵勢弱不振，公能屢張威。", "賊退城可處，生聚始有歸。", "於今三十年，功勳書鼎彛。", "邊人毎記憶，言者感涕揮。", "近日羽書至，討伐加羌夷。", "廟算出帷幄，王師整熊羆。", "壯夫思報國，志士竊憂時。", "寒日朝惨淡，凄風夜號悲。", "昔人何卓犖，往事可追維。", "夫君實賢嗣，仕宦圖奮飛。", "家聲貴不墜，儒學當有爲。", "歸歟自磨礪，門閥增光輝。"]'),
('8b4ea8ab-217a-4d63-a952-426468abbace','送唐君益','呂陶','宋','宋诗','song-poetry','','[]','朝家設賢科，留意在豪彦。',204,'全唐诗/poet.song.37000.json','["朝家設賢科，留意在豪彦。", "三道詢天人，萬言極貫變。", "國論庶有補，謀身非自薦。", "昧者鮮知此，榮禄生貪羡。", "討論遺本原，文采事藻絢。", "假之爲捷塗，得以步華選。", "亦有附羣邪，藉以肆綺辯。", "心迹既自異，事業安可見。", "遂令權貴人，待物少明辨。", "概爲天下材，皆同秦士賤。", "夫君非好名，力學久忘倦。", "天資固彊直，道業益豐羡。", "純如后夔音，發若老羿箭。", "深有啟沃誠，恬無寵榮戀。", "時事方艱虞，乾心屢告譴。", "遠憂何時已，長策殊未獻。", "期君爲國醫，起疾須瞑眩。"]'),
('e86a70d2-7349-4400-b762-e81d5b4a706f','送杜翁東行','呂陶','宋','宋诗','song-poetry','','[]','我爲懷安官，君作什邡令。',216,'全唐诗/poet.song.37000.json','["我爲懷安官，君作什邡令。", "封疆苦不遠，音驛稍頻併。", "乘閒强吟詩，寄去同賦詠。", "其言類諧謔，間或有譏病。", "蒙君屢酬答，往問復來聘。", "長謠頗壯贍，短語亦清勁。", "大率如爲人，圭璋有餘瑩。", "得之每急讀，醉魄時暫醒。", "方從文字樂，忽爾報成政。", "秋風飄行色，萬里去意迥。", "知君最留滯，文價早馳騁。", "策名二十載，位未立朝廷。", "一官奚足論，百態委前定。", "自古有通塞，誰與造物爭。", "任此不繫舟，所至遂游泳。", "西山白雲起，回首念温凊。", "恭聞陛前語，歸拜堂上慶。", "僕馭倦遊否，塵中多捷徑。"]'),
('2a4b6594-8abf-45b7-86e5-8db6d7620251','寄題丹稜李令野亭','呂陶','宋','宋诗','song-poetry','','[]','前山翠光凝，後圃穠秀合。',96,'全唐诗/poet.song.37000.json','["前山翠光凝，後圃穠秀合。", "惜此衆景會，聊以一亭納。", "地勢得高爽，人情遠囂雜。", "縱懷百慮清，極望四遠匝。", "風行訟牒簡，晝永縣扉闔。", "居常玩文史，間亦理杯榼。", "雅趣適安静，嘉章屬酬答。", "門外有通衢，華輪正騰踏。"]'),
('c74cc3d3-620e-43b2-9cc0-6c0af6d1afad','南山有嘉木一首贈友人','呂陶','宋','宋诗','song-poetry','','[]','南山有嘉木，秀抜何亭亭。',180,'全唐诗/poet.song.37000.json','["南山有嘉木，秀抜何亭亭。", "盤根蓋得地，直幹自挺生。", "朝爲杲日照，暮得甘雨零。", "氣敵雪霜勁，勢凌雲霄青。", "豈非澗下材，獨賦輪囷形。", "屬當構大廈，量度審重輕。", "彼尺我已丈，一柱支百楹。", "夫君承顯家，累世公與卿。", "天質由慶禀，湛然寶純明。", "膏梁莫能遷，志操務潔清。", "紛華未易勝，仁義思力行。", "學殖固原本，詞章露葩英。", "早夜勤琢磨，日望貴器成。", "間歳下明詔，時哉會光亨。", "遥遥萬里塗，思君如户庭。"]'),
('2a1f86af-4345-4366-878a-9a3ee231c4cb','和巖起負暄','呂陶','宋','宋诗','song-poetry','','[]','凄風苦朝寒，愛日惜影短。',72,'全唐诗/poet.song.37000.json','["凄風苦朝寒，愛日惜影短。", "翹首望餘照，曝背希一暖。", "温如襲裘褐，美若悦芻豢。", "在陽頗舒暢，適性易飽滿。", "支頤殆忘形，縮手豈執版。", "却笑假春衣，無乃求之晚。"]'),
('96b3c4ea-5aa7-4ddc-9497-59d62f345cbf','感髪白','呂陶','宋','宋诗','song-poetry','','[]','少年事辛勤，老大涉憂患。',216,'全唐诗/poet.song.37000.json','["少年事辛勤，老大涉憂患。", "撫時感零落，髪白亦已慣。", "每思初白時，黑者尚千萬。", "晨梳滿一握，中有素絲間。", "及其白已甚，色勢頗滋蔓。", "種種漸無幾，星星忽大半。", "常情惡衰颯，不欲姿容變。", "持鑷屢剪摘，煮藥勤點換。", "久之反自笑，遂事固不諫。", "萬物入形器，盛衰有期限。", "葩英乘春芳，凋滅向秋晚。", "人生止百歳，稚耋如早晏。", "光陰白駒走，安得常總丱。", "形骸任驅役，膂力資治辦。", "其間得與喪，大率皆夢幻。", "既老遂休佚，萬熊無足盼。", "方當齊椿菌，未暇語鵬鷃。", "霜雪華滿頭，長吟又何怨。"]'),
('7f3e6d85-7ab1-4df4-9a63-bc026f53d32a','送翰林范侍郎','呂陶','宋','宋诗','song-poetry','','[]','進退爲大節，君子貴其全。',288,'全唐诗/poet.song.37000.json','["進退爲大節，君子貴其全。", "獻替實大事，良臣所宜先。", "二者苟一失，胡得稱至賢。", "況乃勢利誘，中性殊易遷。", "趨時或勇鋭，顧義少慤堅。", "崑山有良玉，烈燄不敢燔。", "太華有蒼松，嚴霜豈能干。", "公以學行起，華塗三十年。", "器業飽夔卨，文章富雲淵。", "徐行自廊廟，羣望惟陶甄。", "適會薰風琴，爲民更五弦。", "潔情思恤物，有道當危言。", "一旦謝簪紱，易若忘蹄筌。", "冥鴻颺雲霄，老鶴得芝田。", "天真適曠蕩，世網脱拘牽。", "安居返故里，盛事光塵寰。", "父老相歎詫，謂公乃神仙。", "士林素矜式，仰公如綺園。", "試閲前代史，昔人難比肩。", "嘗聞喬與固，精誠動皇乾。", "願仗至忠力，區區塞奔川。", "不幸遭戮辱，何由老林泉。", "徒使國士淚，至今爲之潸。", "又聞廣與受，知止皆求還。"]'),
('3a00a042-2be9-4620-870d-535d114d5354','奉和胡右丞視學所賦','呂陶','宋','宋诗','song-poetry','','[]','成都學最古，肇自西漢時。',288,'全唐诗/poet.song.37000.json','["成都學最古，肇自西漢時。", "寥寥千餘載，間有或盛衰。", "慶曆始下詔，四方如響隨。", "良哉樂安伯，治體由本基。", "遠模類文翁，故事循魯僖。", "課試月爲度，講解日有規。", "教育猶父兄，片言不邇遺。", "學子五百人，弦誦何儀儀。", "陶成禮義俗，大變西南維。", "距此已一世，繼者賢其誰。", "胡公廟堂老，天子深倚毗。", "下車急先務，勸學爲之師。", "時異心則同，兩哲吹壎箎。", "作詩遺諸生，字字皆典彛。", "近欲美材成，遠使純風熙。", "礱石建巨堂，豎柱不復欹。", "九經滿四壁，高下相支持。", "首尾傳注完，粲然日星垂。", "斯經與斯堂，天下難等夷。", "度地得勝勢，西隅敞高扉。", "氣象自宏顯，出門見通逵。", "嘉木種千本，敷陰接春暉。", "人將不剪伐，異日甘棠枝。", "賤子昔在泮，執經趨綘帷。"]'),
('6461fde6-4ac2-426c-86e7-925cd69b4434','再和胡右丞視學','呂陶','宋','宋诗','song-poetry','','[]','士有幸不幸，所逢皆一時。',288,'全唐诗/poet.song.37000.json','["士有幸不幸，所逢皆一時。", "道隆學自正，文敝俗亦衰。", "匪惟古今異，況復好惡隨。", "觀詩不觀政，爭議毓與基。", "窮經不窮法，區區論桓僖。", "必得大匠誨，然後圓中規。", "譬欲攷躔度，亦先由渾儀。", "所以君子教，衆材無棄遺。", "公来鎮西州，爲民張四維。", "且曰化未孚，執咎歸之誰。", "醇醲造禮義，偷薄生夸毗。", "予其本庠序，動以經爲師。", "善道易牖進，應和如壎箎。", "自此石室生，處躬無匪彛。", "勤誠戒挑達，美頌贊緝熙。", "屢聞講鼓集，不見儒冠欹。", "遠或千里至，篋笥相携持。", "公堂坐無地，布滿東西垂。", "學殖務栽培，心茅悉芟夷。", "前瞻數仞牆，競欲趨公扉。", "謂公富經術，執卷将問逵。", "誦公勤學篇，華柔鄙玄暉。", "杏壇乘春風，一日千萬枝。", "昔公長烏臺，奏囊成殿帷。"]'),
('2ced11aa-38ed-473e-bee6-4db4ea55601e','戲作客從中州来','呂陶','宋','宋诗','song-poetry','','[]','客從中州來，有旨謫嶺外。',216,'全唐诗/poet.song.37000.json','["客從中州來，有旨謫嶺外。", "道由長沙郡，行李極狼狽。", "地主惡遷客，不許宿闤闠。", "馳逐使之出，威勢如下礌。", "我嗟伏蒲君，力小忠謇大。", "一言犯雷霆，萬里竄江海。", "方當困羈旅，復爾招咎悔。", "誰爲守者謀，義理亦甚昧。", "人道異邪正，天時分否泰。", "外物慎取舍，中扄權利善。", "小人衒迎合，君子恥附會。", "如何鄙流放，輒欲登善最。", "所持況輕貨，安可遷重賄。", "惡名被諸身，巨衾不可蓋。", "羞色睟於面，洪水安能靧。", "嘗聞賢人生，希闊須異代。", "聲華無今昔，趣尚一進退。", "李唐距聖宋，乃有二徐晦。"]'),
('9242d70d-e597-4310-9806-81bab73386b9','送李鎮北歸','呂陶','宋','宋诗','song-poetry','','[]','昔爲并晉游，識子十數載。',216,'全唐诗/poet.song.37000.json','["昔爲并晉游，識子十數載。", "當時鄉曲譽，學行已可愛。", "公卿察亷孝，一命果霑霈。", "飄然從宦游，萬里適劍外。", "標操本孤直，鋒稜苦磨淬。", "研味冰蘖間，規爲準繩內。", "素節雖有常，往往駭流輩。", "違順既殊途，指此作瑕纇。", "好惡貴必察，丁寧昔賢誨。", "羣言徒爾爲，終有公議在。", "北歸太行道，極頂見嵩岱。", "下視丘與阜，岌屹殊瑣碎。", "洪河天外來，勢欲浮大塊。", "吁嗟衆流小，奔走爭合匯。", "長吟助超軼，壯氣增感慨。", "善惡忌太明，與奪宜少晦。", "此語所繫重，非特論進退。", "數路盛得人，期君赴亨會。"]'),
('831b226c-5d41-480a-be09-a312b52d6d18','勇烈侯廟','呂陶','宋','宋诗','song-poetry','','[]','唐衰中原亂，賊據西南疆。',288,'全唐诗/poet.song.37000.json','["唐衰中原亂，賊據西南疆。", "號令不出畿，疇能禦彊梁。", "楊侯仗直忠，寶劍凌穹蒼。", "誓將掃妖祲，得以完金湯。", "嘗膽過勾踐，食羮如樂羊。", "嚴顔頸未斷，霽雲指何傷。", "衆寡固不敵，歳月亦已長。", "孤城屹然峙，鋒鋭莫可當。", "譬如泛巨海，難以一葦航。", "天心未厭悔，人意忽蒼黄。", "百口同穴瘞，悲雲惨朝陽。", "寰區既澄静，往事極凄凉。", "封爵加美謚，幽明知寵章。", "近世修舊史，筆削嚴否藏。", "書曰侯死之，一褒踰繡裳。", "彭人念侯德，廟食墓之傍。", "水旱毎致禱，豐年屢倉箱。", "父老或有言，夜漏猶未央。", "見侯出自廟，凛然坐黄堂。", "此理實晦昧，有無何渺茫。", "子厚羅池神，海俗專祈禳。", "乖崖宛丘殯，醉者取滅亡。", "英靈果不泯，猶足威一方。", "予嘗假州紱，秉笏趨侯墻。"]'),
('cc3192c4-f3d0-4a11-a0d5-f74aa30e5a2c','答任師中','呂陶','宋','宋诗','song-poetry','','[]','石城山下居，草草已經歳。',216,'全唐诗/poet.song.37000.json','["石城山下居，草草已經歳。", "終日對山吟，何嘗問陰霽。", "自知有義命，百事安拙計。", "每蒙親朋念，尺書來者繼。", "豈徒問寒温，亦惑慰窮滯。", "惟公見愛心，不逐時情替。", "親迂老匠筆，特枉長吟惠。", "良金豈雕刻，文錦自燦麗。", "太羮充餒腸，靈藥去昏翳。", "所得適所懷，拜賜敢不勵。", "詩騷久寂寞，俗士鮮緝綴。", "公常得之深，豪贍有規制。", "頃聞湖州禍，文字倦且廢。", "朝廷極仁恕，風俗當訓厲。", "終令服寛典，不忍投四裔。", "吾儕今唱酬，正可頌治世。", "况當導情性，無自取罪戾。", "敢于韶濩前，率爾獻鄭衛。"]'),
('77df9298-e9c9-4c36-bf27-9d2f8f288a3d','和孔毅甫州名五首  其一','呂陶','宋','宋诗','song-poetry','','[]','毅甫生江南，藴有洙泗質。',168,'全唐诗/poet.song.37000.json','["毅甫生江南，藴有洙泗質。", "雄文極古今，通鑑盡疏密。", "瀛山繡衣使，高步尚淹屈。", "河水潤畎畝，隨珠照圭蓽。", "仁風信樂易，治體本誠一。", "昌時政多暇，豐歳民甚佚。", "撫琴得遺音，開卷終舊帙。", "天和內自保，萬事皆外物。", "我生本蒿萊，豈合顧簪紱。", "南遷至此處，惠養殊不失。", "傷心屈原棹，掩耳湘靈瑟。", "罪大敢放懷，恩深已淪骨。", "幸常從公遊，談笑度永日。", "我吟續郢唱，緘封彌戰栗。"]'),
('6713f3e1-cf71-44e8-8602-9390bbb226e3','和孔毅甫州名五首  其二','呂陶','宋','宋诗','song-poetry','','[]','衡陽古勝郡，齊民頗淳質。',168,'全唐诗/poet.song.37000.json','["衡陽古勝郡，齊民頗淳質。", "富饒幾維揚，樸静類高密。", "易將誠心感，難以威勢屈。", "水宿亦安枕，巖扉不施蓽。", "太平得良守，條教盡歸一。", "人方樂簡治，自爲宜老佚。", "窮通有定數，舒卷猶古帙。", "深思已詣理，達觀豈言物。", "屢嘗登賓階，毎許脱朝紱。", "共談海鵬志，不道塞馬失。", "金聲發鏘鏘，寶肆容瑟瑟。", "遂回岷山眼，未委瘴江骨。", "賡詠酬真樂，聊以歌化日。", "珷玞難重陳，黄玉似蒸栗。"]'),
('67924aad-6e61-478b-ab2f-87d887a5c4bb','和孔毅甫州名五首  其三','呂陶','宋','宋诗','song-poetry','','[]','謫宦寓湖南，憔悴變容質。',168,'全唐诗/poet.song.37000.json','["謫宦寓湖南，憔悴變容質。", "老懷極孤窮，益友最親密。", "高軒喜陪從，雅會煩揖屈。", "馨香襲芝蘭，文采輝陋蓽。", "談辯雖縱横，儀範甚專一。", "毎聞陽春曲，欽誦不敢佚。", "遂将蜀溪紙，連寫漸成帙。", "慚非高尚者，思古感事物。", "當時郢楚士，英秀盡簪紱。", "池臺今何在，冠劍久淪失。", "我憂復遼遠，試聽暮鳴瑟。", "何時還敝廬，一奠九泉骨。", "此心實虔望，昭昭有如日。", "未嘗果山柑，且饌湘江栗。"]'),
('77f4903d-5c7d-4cbf-a991-fe2c72bfa9d3','和孔毅甫州名五首  其四','呂陶','宋','宋诗','song-poetry','','[]','平生知求道，冀保衰朽質。',168,'全唐诗/poet.song.37000.json','["平生知求道，冀保衰朽質。", "金闕勞仰望，玉經探秘密。", "嘗聞造化理，虛静乃不屈。", "又聞棲真士，幽處遯荆蓽。", "深藏雖混同，安養自誠一。", "廣采與博訪，未遇敢懷佚。", "誦經期萬遍，掩卷復開帙。", "纔能簡思慮，了不見象物。", "誰将林泉屨，易取塵土紱。", "渠意良有得，吾曹又何失。", "愛君氣容和，忻樂不在瑟。", "得鼎必全神，逢丹可換骨。", "方蓬達去路，寰海空白日。", "願開循循誨，靈臺非縝栗。"]'),
('83f69610-8c1b-482c-8541-44f6c13ac3d0','和孔毅甫州名五首  其五','呂陶','宋','宋诗','song-poetry','','[]','羨君詩格雄，非謂文勝質。',168,'全唐诗/poet.song.37000.json','["羨君詩格雄，非謂文勝質。", "長篇自博雅，短語亦温密。", "筆端時一揮，鋒利不少屈。", "高情寓祥雲，幽意及疏蓽。", "豪縱嘆李賀，難以憲度一。", "窮愁傷孟郊，不欲懷抱佚。", "鋪陳黄堂上，一案凡幾帙。", "先倡乃前輩，形容何以物。", "瑁圭施華藻，錦段副朱紱。", "測海至千仞，穿楊無一失。", "寶器藏巨劍，古聲發瓊瑟。", "鳯羽翔德輝，龍種搜駿骨。", "嗟予澤畔吟，繼唱輒連日。", "果牓誤收采，小榛齊大栗。"]'),
('4128d308-b8fd-4523-a350-7a305ae0f200','雪意','呂陶','宋','宋诗','song-poetry','','[]','凄風向晚來何頻，潛與嘉雪爲塗津。',160,'全唐诗/poet.song.37000.json','["凄風向晚來何頻，潛與嘉雪爲塗津。", "重雲固結慘不動，六幕莾蕩空無塵。", "信哉北帝舉冬令，肅清萬類猶時巡。", "人思沾被率土濱，有若渴者欲飲醇。", "儻施餘潤及芽蘖，寸草亦望繁如茵。", "嘗聞洛陽縱高臥，抑有郢客歌陽春。", "何如酒陣與之敵，却退寒色其威振。", "天心安肯靳一灑，化力自可周羣倫。", "黎明忽見已盈尺，良瑞豈止山溢銀。", "預知豊年此足賀，十空九室皆斯民。"]'),
('224873fb-eb71-4057-a3b5-66b195c15179','苦寒','呂陶','宋','宋诗','song-poetry','','[]','朔風屢起聲驅雷，濃霜不許晨暉開。',128,'全唐诗/poet.song.37000.json','["朔風屢起聲驅雷，濃霜不許晨暉開。", "天高地遠槖籥動，凝然一氣從中來。", "坤靈至静體堅厚，大罅忽裂如剪裁。", "河流迅疾猛如箭，一朝水合舖瓊瑰。", "山川色勢尚慘沮，安恨草木遭衰摧。", "羣陰交盛固如此，均被和煦何時哉。", "傳聞西徼有積雪，平地數尺光皚皚。", "賊兵夜凍多死者，萬衆已望穹廬迥。"]'),
('7dd7d83b-6fb5-4d18-beb6-1603e36d06e3','有感','呂陶','宋','宋诗','song-poetry','','[]','春秋二百四十年，彗星三見書簡編。',128,'全唐诗/poet.song.37000.json','["春秋二百四十年，彗星三見書簡編。", "當時災異豈止此，無乃舊史失其傳。", "咸平距今十八載，數出妖象垂經躔。", "聖君憂勞畏天戒，責躬下詔殊惻然。", "吏之不良民失職，思得讜諭繩諸愆。", "太平日久德澤厚，濟濟多士追昔覧。", "窮幽極遠盡聞命，愛君慮國誰敢先。", "聞陳藥石宜有補，勿謂綸綍爲虚言。"]'),
('b0c31398-8b19-4219-82bd-b53913e11afb','焦夫子畫','呂陶','宋','宋诗','song-poetry','','[]','予不見夫子之身，不知夫子何如人。',270,'全唐诗/poet.song.37000.json','["予不見夫子之身，不知夫子何如人。", "但見藴之爲之贊，與可筆其神。", "二公規鑒少許與，獨于夫子何勤勤。", "意是抱道者，有志不得伸。", "潔操蜀江泉，棲心岷嶺雲。", "野飯有藜糝，濁杯無醨醇。", "平居不荷蓧，來者莫問津。", "笑歌千古已白日，睥睨六合皆紅塵。", "氣貌特怪陋，意味尤酸辛。", "破褐聊被體，如敝履之安貧。", "爬癢頗適興，如捫虱之自珍。", "五六十載一邑間，安寜寇亂昏復晨。", "世累不我及，浩然保天真。", "嘗聞西南維，是古多隱淪。", "令伯純好任公賢，風範皆足師吾民。", "仲元高明君平晦，聲迹長共日月新。", "當時傳公議，後世仰嘉問。", "夫子雖不達，見于繪像詩與文。", "清標可想味，素節難等倫。", "從此千萬年，焜燿寂寞濱。"]'),
('6e045572-b461-44e9-b5d2-6359249ef603','貽草萊章詧','呂陶','宋','宋诗','song-poetry','','[]','漢焰中熄哀平微，子雲有道不有時。',368,'全唐诗/poet.song.37000.json','["漢焰中熄哀平微，子雲有道不有時。", "立言盡括二儀數，八十一首淵而微。", "至神不形復不見，玄道固非人易知。", "劉歆嘗恐覆醬瓿，切憤學者斯言垂。", "桓譚亦謂傳必久，賤近貴遠可逆推。", "史臣俗筆擬僭號，數字豈免萬世譏。", "侯芭英骨久沒地，千均難用一髪維。", "幸且綿綿未歇絕，果與後代揚雄期。", "環中先生悟達者，力舉雄道潜其思。", "著圖課見歷象運，發隐扣達乾坤機。", "深嗟范望用心苦，意與測異将奚歸。", "乃覃精義述講疏，直論雄心非詭隨。", "愚聞是書百日就，瀝懇再拜求觀之。", "先生訓我有大略，筆端粗可言亳釐。", "在玄曰首易曰卦，玄凖易數不凖詞。", "方州部家雖列位，非類六爻高與卑。", "第當縱横以算計，豈可連缺如象爲。", "夜詞多凶晝多吉，陽家貴偶陰家奇。", "謹持此理讀九贊，人事粗可詳其宜。", "餘地三極藴奥妙，一朝未許以意窺。", "我從誨言日勉勉，始若得濟終無涯。", "性庸才下道悠遠，策發未進吁可悲。", "願從諸生北面請，庶幾一釋終身疑。"]'),
('8ab79650-783b-4ef3-9c0e-3bd6a8529fb9','以茶寄宋君儀有詩見答和之','呂陶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','九峰之民多種茶，山村櫛比千萬家。',352,'全唐诗/poet.song.37000.json','["九峰之民多種茶，山村櫛比千萬家。", "朝脯伏臘皆仰此，累歲憑恃爲生涯。", "一朝使者忽禁榷，振舉法令搖三巴。", "錐刀盡毫髪，鞭朴過網罝。", "悲哉西南人，生長逢勳華。", "垂髫以來至白首，未識此事徒憂嗟。", "議欲伐茗荈，不如植禾麻。", "一花五出最爲早，焙戶常于火前造。", "春來畏罪不敢言，芽甲任隨黄葉老。", "安得仙崖凝露膏，寄與交朋叙勤好。", "廣平先生風格清，坐聽萬事心無營。", "日高睡覺懶慵起，不欲世態昏瞳睛。", "誠宜玉筒摘佳品，或向武夷搜早英。", "汲将楚谷水，就取石鼎烹。", "可以助君淳深幽寂之道味，高古平淡之詩情。", "小方片甲洎觜翼，凡下不足論芳馨。", "西湖所採者，抑亦傳虛名。", "不執符移往，不由關市征。", "而乃輙贈遺，豈非干典刑。", "高賢接物自無間，野夫得以芹爲誠。", "長謠三百言，重報不稱輕。", "文錦方能致珠琲，木瓜安敢邀瑰瓊。", "再拜捧嘉貺，讀之如寵驚。", "感君裁詩誤題品，勸君避患宜詳審。"]'),
('d6bfa23d-4482-499f-9719-ca8520eadaff','和蒙軒','呂陶','宋','宋诗','song-poetry','','[]','蒙軒高占山之埡，其上五頂皆生茶。',192,'全唐诗/poet.song.37000.json','["蒙軒高占山之埡，其上五頂皆生茶。", "仙崖雲霧不復見，上峰紫筍今爲嘉。", "地宜物產種植廣，疲民所恃如禾麻。", "朝晡衣食足生計，賦税力役供王家。", "頃者憸人獻榷議，百弊滋長多蘗芽。", "川馳陸走窮歲月，泣血無告天之涯。", "近從吾蜀遠秦陜，生意凋落成咨嗟。", "天高聽卑詔令下，欲使德澤沾荒遐。", "使節西來善詢度，剗削弊蠧除網罝。", "山翁野老盡欣悦，市井歌舞尤諠譁。", "憑軒一望快遠目，滿山和氣凝丹霞。", "聖君仁政賢臣布，信矣原隰生光華。"]'),
('e65dad10-cf83-4272-8032-ebd371cdbbb0','遊文水壽寧院','呂陶','宋','宋诗','song-poetry','','[]','重巖一水源何長，下浸十頃同江鄉。',240,'全唐诗/poet.song.37000.json','["重巖一水源何長，下浸十頃同江鄉。", "環堤數里植垂柳，緣陰交蓋西風凉。", "危橋迤邐渡前岸，古寺直枕山之岡。", "門闌閟邃戶庭闊，金碧間鬬皆煌煌。", "并人事佛素已謹，挾以富力尤輝光。", "三朝宸札舊所賜，奎文寶蹟人間藏。", "有如方嶽處厚地，鎮壓萬衆傳無疆。", "西園嘉卉不知數，春暉盡許開琳琅。", "東偏小池亦足愛，秋色未老芙蕖香。", "寺旁有曰武陵者，高碑大字言其詳。", "武周一旦改唐祚，天傾地轉無乾綱。", "睿皇書碑李嶠記，常時氣燄安可量。", "神功距此四百載，孤墳雖在郊原荒。", "年年秋潦過墳側，枯盡白草空斜陽。", "且憐景物爲一飲，誰暇對酒論興亡。"]'),
('8a30ff11-a919-4a28-9b7f-742cf87bf621','送程彛仲赴東川教授','呂陶','宋','宋诗','song-poetry','','[]','與君同縣又同甲，家世相同學爲業。',224,'全唐诗/poet.song.37000.json','["與君同縣又同甲，家世相同學爲業。", "陪從最舊今老矣，四十餘年如一霎。", "吁嗟先德去已久，後嗣皆能守家法。", "君之一第得稍晚，更向小官勤檢押。", "鄉閭執友在嗣禁，奉詔親題薦賢剳。", "美材猶未立朝庭，歸馭依然走川峽。", "文章近歲頗頹靡，庠序得人須鎮壓。", "欲疏密網在提綱，思遏狂瀾當下牐。", "由來文黨俗寝盛，定見子昂才不乏。", "羡君高堂有慈母，日侍歡顔問單裌。", "寶牋銀絡累年封，他日恩書應滿匣。", "聖君文母切求治，數路招來不爲狹。", "讀書到老必有用，一發胸中補熙洽。", "喬松千丈雪中青，肯向西風感衰颯。"]'),
('7835be14-9e77-45d3-b4a1-6df54559dd1a','次伯通雲頂山長句韻','呂陶','宋','宋诗','song-poetry','','[]','金淵地界東西州，諺云錦擔垂兩頭。',192,'全唐诗/poet.song.37000.json','["金淵地界東西州，諺云錦擔垂兩頭。", "中間石城最佳勝，二十餘年嘗再遊。", "奇峰雖向郡城見，好景半是僧家收。", "松蘿四面圍絕頂，九夏不暑長如秋。", "東隅忽值海日出，下照巖壑無深幽。", "羣陰破散宿霧斂，萬象開闊晴雲浮。", "軒窗高處氣勢别，縱欲極望誠難周。", "藍凝後嶂遠更秀，雪壅前溪寒不流。", "軟草將春鹿麌麌，濃林未暝蟬啾啾。", "襌僧上堂演佛理，鏜然鍾韻喧層樓。", "問之浮世輙不語，應笑世人多謬悠。", "下山儻有頓悟者，直須作意無遲留。"]'),
('151fecc3-1600-445b-b822-9f5db966b87e','贈平羌狄尉','呂陶','宋','宋诗','song-poetry','','[]','梁公沒世五百年，殊勳茂烈存簡編。',288,'全唐诗/poet.song.37000.json','["梁公沒世五百年，殊勳茂烈存簡編。", "我懷忠議不復見，讀至舊史嘗喟然。", "窮山老尉有狄氏，問之乃曰公其先。", "誥書家牒盡炳炳，照出往事如目前。", "念公英節不見矣，見公遠孫良可賢。", "况公遠孫實賢者，本末趣尚疇能肩。", "昔從五季衰亂來，簪組飄墜歸農廛。", "平時下詔繼絕世，霑以一命聊襃甄。", "天資忠孝遂奮激，報祖許國惟勤拳。", "胸中已有霜雪在，飲冰食蘗甘如羶。", "嘗云起迹自畎畝，幸得寸禄因賞延。", "語言動静苟一失，辱及吾祖爲欺天。", "信者清白與剛毅，異代猶有芳風傳。", "如何十載走塵坌，綠髪减盡成華顛。", "青雲岐路苦悠遠，誰借跬步爲階緣。", "當途達者倘在念，一顧可使羽翼軒。", "不惟廉操足敦勸，抑見袓德光綿綿。", "嗟予之意止如此，感憤爲君書此篇。"]'),
('505d493b-7663-4943-9e8d-45b0274a4138','送曾尉赴漢初','呂陶','宋','宋诗','song-poetry','','[]','前年到官殊未久，君亦東來爲我友。',192,'全唐诗/poet.song.37000.json','["前年到官殊未久，君亦東來爲我友。", "握手一笑萬愁寛，平日語言期白首。", "山深縣僻庶事荒，雖植嘉苗半稂莠。", "我無長術剗芽蘗，坐見斯民顔甚厚。", "君有豪才生顯家，未涉要津甘五斗。", "巳将客意同休戚，復視世途均好醜。", "咄嗟吾屬皆壯年，當學古人所無苟。", "勞生險易固多岐，未必功名垂不朽。", "自知物理難揆量，惟勵身規務恃守。", "丈夫實藴四方志，方虔君命方趨走。", "崎嶇一邑勿云遠，赤子歡迎如父母。", "銅梁春晚亦開花，猛駕歸軒會文酒。"]'),
('5ca67770-06fb-41b8-89cc-b1c684b6722e','和運判孫聖微遊大慈','呂陶','宋','宋诗','song-poetry','','[]','西州都會坤之維，地產豊羡人熙熙。',320,'全唐诗/poet.song.37000.json','["西州都會坤之維，地產豊羡人熙熙。", "朝庭念遠勤撫養，欲壮心腹強四肢。", "精求守臣擇使者，故有賢業堪依毗。", "導宣德澤廣流派，講舉政教先本基。", "不容蠧弊長芽蘖，直欲赤子皆充肥。", "泰然一道遂無事，犴獄衰止文符希。", "燕閒何以度歲月，憑仗文酒相追隨。", "過從僧舍盡幽邃，閲徧畫手多神奇。", "因嗟唐人值喪亂，奔走至此常懷歸。", "韜藏絕藝鬰不發，壁間一掃窮精微。", "試登高閣凝望久，欲将遠眼窮天涯。", "山扃水遶氣象好，雲晴日暖光陰移。", "信哉浮生巨河上，鼎勢會以一足支。", "方今文軌慶混合，帝力何有民何知。", "長廊廣屢數百載，留得風景資遊嬉。", "清罇豈特具酬獻，髙論不廢評是非。", "宦游此會亦難得，投筆一笑毫無疑。", "又爲歌詩載盛事，更唱迭和猶壎箎。", "鄙夫幸爾陪雅集，懷抱芬馥蘭與芝。", "天閽九重勞夢想，回首鄉國空遲遲。"]'),
('22376633-0afc-468a-923c-68700e5ce587','青蠅','呂陶','宋','宋诗','song-poetry','','[]','去年十月青蠅藏，不見一點臨盤觴。',128,'全唐诗/poet.song.37000.json','["去年十月青蠅藏，不見一點臨盤觴。", "高堂小會頗清潔，肴有餘味酒有香。", "今年四月青蠅出，競逐腥羶誇羽翼。", "纔能擾擾上罇俎，又欲營營污圭璧。", "四月盛陽群物秀，十月積陰寒氣候。", "天時于爾本無私，爾自知時能避就。", "畏途榮悴如寒暄，流俗早夜趨貴權。", "一朝勢去即消散，可與青蠅同日言。"]'),
('b910b8bf-5c14-4b60-a03d-947e77a895bb','蜥蜴','呂陶','宋','宋诗','song-poetry','','[]','前年詔書褒蜥蜴，爲與生民致膏澤。',240,'全唐诗/poet.song.37000.json','["前年詔書褒蜥蜴，爲與生民致膏澤。", "聖君虔禱享嘉應，其功似共乾坤敵。", "載之令甲告天下，郡縣奉承誰敢易。", "大臣作詩紀盛事，更唱迭酬盈卷帙。", "去冬不雪春不雨，雲在西郊尚凝密。", "頓來熒惑犯太陽，曜靈無光如血色。", "九重焦勞念凶旱，細札數行殊怛惻。", "庶官群吏各奔走，欲以精誠干化力。", "佛宮老廟皆懇叩，龍宇鵝壇競搜索。", "又令中使持御香，岳瀆遍祈猶未獲。", "首種不入最大事，而況三農方失職。", "傳聞九路已蠲稅，應是田疇少禾麥。", "吁嗟蜥蜴厚顔否，造化至幽非爾責。", "青童柳枝宛如故，何事威靈減當日。", "蒼生若望爾爲霖，安用廟堂賢輔弼。"]'),
('455a9715-c959-47dc-8656-a3e78d7abcab','謝惠酒','呂陶','宋','宋诗','song-poetry','','[]','山徑雪深樵未歸，茅簷煙冷午未炊。',64,'全唐诗/poet.song.37000.json','["山徑雪深樵未歸，茅簷煙冷午未炊。", "黄精無苗菜甲沒，筠籃竹箬冰淋漓。", "松煙細火養晝坐，瓶笙妙音兒女嬉。", "窗下凍雞聲喔咿，誰家酒香入疏籬。"]'),
('1f499689-8227-4fa0-bfc2-c351997a4ebe','和思道招晦甫飲','呂陶','宋','宋诗','song-poetry','','[]','酒如仙藥應有靈，達士飲之不欲醒。',80,'全唐诗/poet.song.37000.json','["酒如仙藥應有靈，達士飲之不欲醒。", "花如浮榮易彫落，貪榮何似貪樽酌。", "青雲塗轍競奔走，富貴幾人能入手。", "朝遊赤墀暮丹禁，高懷未必常高枕。", "豈如良朋皆盡歡，而況又爲文字飲。"]'),
('b7f1b37f-f3e3-4c78-b7b2-0b54546b50cc','貽寬恤聞人太博','呂陶','宋','宋诗','song-poetry','','[]','治平日久法制寬，遠方民力尤衰殘。',192,'全唐诗/poet.song.37000.json','["治平日久法制寬，遠方民力尤衰殘。", "昔之陸海號富庶，今也樂歲嗟饑寒。", "不惟淺夫事苟簡，抑有能吏爭彫刓。", "天涯僻陋九重阻，自棄溝壑甘長嘆。", "咄嗟蚩蚩乃邦本，基本堅厚邦如磐。", "吾君仁聖重恤此，擇才將命圖全安。", "詔云詢訪民疾苦，可以革弊而更端。", "士之蓄藴貴及物，鎡基智慧乘時難。", "惟君措置有大略，高談所吐皆瑯玕。", "力蠲積祲少顧避，深體上意思保完。", "綱維修舉有條目，源流澄潔無波瀾。", "遲聞王澤得下究，淪浸骨髓其聲歡。"]'),
('61b5eb6f-e8dd-468b-826a-79437734a2e0','席上咏金橘','呂陶','宋','宋诗','song-poetry','','[]','江南種橘繁如秔，爾今獨以金爲名。',160,'全唐诗/poet.song.37000.json','["江南種橘繁如秔，爾今獨以金爲名。", "豈非彼俗甚珍惜，謂其可比百鍊精。", "千頭盡帯秋色老，一腹皆飽晨霜清。", "初筵特此獻磊落，滿座不覺窺光晶。", "寶肆豪華竸相勝，瑪瑙散入雕盤盈。", "珠庭變化望已久，仙丹忽向洪爐成。", "試侵香潤擘圓粒，齒牙滴瀝沾冰瓊。", "自憐孤根出遠土，得並衆果親杯觥。", "赤心可恥不嗤棗，虚表無用安須橙。", "辛酸甘苦各存味，賴有知者加題評。"]'),
('042619ac-d1e0-4a64-8717-8be8556fcd2a','奉寄單州太守王聖欽','呂陶','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','昔嘗請郡歸東川，衰遲幸會使者賢。',384,'全唐诗/poet.song.37000.json','["昔嘗請郡歸東川，衰遲幸會使者賢。", "開誠論議簡條目，一境草木沾春妍。", "公齋清暇弄詩筆，更唱迭和多長篇。", "歲豊民樂尚蠶市，撼罍鬬鼓殊喧闐。", "東山西寺頗壮觀，飲帳或在山之巔。", "踏青摸石循故事，浣花亦倣成都船。", "相從對酒毎一笑，聊與遠俗同欣然。", "北巖石穴廣似洞，疑是古昔棲神仙。", "火雲燒空赤日猛，及到此地如冰淵。", "清風滿懷興未盡，四望晚景增留連。", "平生宦遊此最適，不覺弦晦相推遷。", "郵筒忽報謫書至，君命嚴重敢不虔。", "試思衡嶽詢遠近，里堠去蜀凡八千。", "蒼黄去郡别我友，一意調琴中斷弦。", "回首鄉邦止數驛，欲頃血淚辭松阡。", "藩候迫逐倉使促，爭向墜羽誇鳴弦。", "天恩曠漡置不問，投放裔土懲其愆。", "闔門良賤三百指，孤舟一葉何翩翩。", "瞿唐灔澦遍涉歷，內訟過咎歸之天。", "洞庭阻淺輙三夕，怒風急兩聲相喧。", "此身恐污盜賊刃，不爾定沾蛟鱷涎。", "偶逢漁艇相援濟，稍覺神觀來歸還。", "長沙既下尤怪駭，半夜雷雹如烹煎。", "桅傾纜斷船脊折，四十餘里中流漩。"]'),
('f84183bd-6dc1-4463-8559-10aef21110b2','和成都道中','呂陶','宋','宋诗','song-poetry','','[]','溝畎清穿道，禾麻綠蔭疇。',48,'全唐诗/poet.song.37000.json','["溝畎清穿道，禾麻綠蔭疇。", "地形從此坦，山勢爲誰收。", "使指星言駕，皇恩雨既優。", "愛吟吟不盡，目斷錦江頭。"]'),
('8756be68-b0a3-44b8-8d5e-9f594936187c','嘉州陸氏涵秀樓','呂陶','宋','宋诗','song-poetry','','[]','勝地林泉近，層楹物象閒。',48,'全唐诗/poet.song.37000.json','["勝地林泉近，層楹物象閒。", "野平秋璋列，天闊暮雲還。", "快目登臨外，棲心嘯傲閒。", "羡君談雅概，持語寄江山。"]'),
('5a919b63-b6a9-441e-ad43-90599b12bd83','范才元參議求酒於延平使君邀予同賦謹次其韻','呂陶','宋','宋诗','song-poetry','','[]','桑落冷篘玉，菊衰霜滿天。',48,'全唐诗/poet.song.37000.json','["桑落冷篘玉，菊衰霜滿天。", "飄零河朔飲，悵望竹林賢。", "烏有防前轍，青州貴下田。", "使君能遣騎，端爲喚魚船。"]'),
('e6032e48-10b5-4564-bfef-e7d9d680383f','二月一日郡郊賞花得郊字','呂陶','宋','宋诗','song-poetry','','[]','春仲方迎朔，花農已滿郊。',48,'全唐诗/poet.song.37000.json','["春仲方迎朔，花農已滿郊。", "曉園香散路，晴樹錦垂梢。", "耽勝爲髙會，通歡有淡交。", "芳時去尤速，吟賞莫輕抛。"]'),
('0cc72651-2ddc-46b8-aa1a-1a2fb0c94dcc','寄句輔元','呂陶','宋','宋诗','song-poetry','','[]','普州公事少，太守讀書多。',48,'全唐诗/poet.song.37000.json','["普州公事少，太守讀書多。", "見得是非盡，無如今古何。", "老懷驚歲月，冷夢到雲蘿。", "郡下有佳士，幾人陪詠歌。"]'),
('f55fc174-733c-4113-b74d-da1b4c8be879','送李公擇同年赴嘉倅','呂陶','宋','宋诗','song-poetry','','[]','極目三峨頂，濃嵐切沓冥。',48,'全唐诗/poet.song.37000.json','["極目三峨頂，濃嵐切沓冥。", "宦心甘似水，親髪己如星。", "壽几陪春斝，吟齋息晝鈴。", "何須二千石，旟隼衒丹青。"]'),
('e691798d-b756-454b-bd66-f70a71adfd2f','過羅氏圜亭','呂陶','宋','宋诗','song-poetry','','[]','官暇無多事，春深偶一來。',48,'全唐诗/poet.song.37000.json','["官暇無多事，春深偶一來。", "溪隨芳榭轉，門入翠嵐開。", "有得供吟筆，將閒付酒盃。", "暫遊殊草草，空趁夕陽迴。"]'),
('e771dedb-ea5d-49f0-be95-a7b141ceb0e4','西郊','呂陶','宋','宋诗','song-poetry','','[]','西郊村落好，歲月甚優游。',48,'全唐诗/poet.song.37000.json','["西郊村落好，歲月甚優游。", "野性每自適，倦心何所求。", "鼓鐘催永晝，砧杵報新秋。", "若遇延形術，猶能換白頭。"]'),
('c0c79122-a0a7-4d96-a021-86c8ca730075','思道同晦甫春日過李氏園亭次思道韻','呂陶','宋','宋诗','song-poetry','','[]','官暇頻遊覽，春闌勿嘆嗟。',48,'全唐诗/poet.song.37000.json','["官暇頻遊覽，春闌勿嘆嗟。", "閒情寓文酒，好景付鶯花。", "笑語留長日，園林訪幾家。", "歸途最喧塞，紅燭數行斜。"]'),
('56bd6666-caef-48c1-8441-b2cb7851bb2c','和思道招晦甫','呂陶','宋','宋诗','song-poetry','','[]','相親未多時，相别已旬日。',48,'全唐诗/poet.song.37000.json','["相親未多時，相别已旬日。", "詩筒須奉招，棋手欲求敵。", "三春有餘閒，一醉安足惜。", "此樂真無涯，交情重金石。"]'),
('2549c941-4b8a-4831-a7cb-d2c6162b70fa','金竹','呂陶','宋','宋诗','song-poetry','','[]','修竹已可愛，況復如黄金。',48,'全唐诗/poet.song.37000.json','["修竹已可愛，況復如黄金。", "天地與正色，雪霜堅此心。", "雲芝生有節，栗玉種成林。", "回首渭川遠，山間饒翠陰。"]'),
('17e71305-741f-4bb8-b1b8-b07253fda956','送楊日卿移任潘原','呂陶','宋','宋诗','song-poetry','','[]','謫宦成流落，移官自寵恩。',48,'全唐诗/poet.song.37000.json','["謫宦成流落，移官自寵恩。", "窮通雖異迹，得喪盡忘言。", "車馬動行色，江山勞别魂。", "關西三十世，祠下見雲孫。"]'),
('7f334b47-a42a-4514-a358-862de232903a','歲除前五日獨往黎氏園見梅花盛發','呂陶','宋','宋诗','song-poetry','','[]','慘淡歲將暮，煙村忽見梅。',48,'全唐诗/poet.song.37000.json','["慘淡歲將暮，煙村忽見梅。", "年光背我去，春色爲誰開。", "半日憑軒檻，無人共酒盃。", "芳標深可惜，聊作看花回。"]'),
('92f09514-6cd3-4b5b-91a8-3e706c94a8c8','和賞梅','呂陶','宋','宋诗','song-poetry','','[]','何處爲真賞，芳園白玉英。',48,'全唐诗/poet.song.37000.json','["何處爲真賞，芳園白玉英。", "春前挺仙質，物外得花名。", "雪月資閒淡，風霜與潔清。", "偏宜文字歛，嘉客盡詩成。"]'),
('c4570799-f9d1-4d70-8cbd-8a5ae3242466','和聞蛩有感二首  其一','呂陶','宋','宋诗','song-poetry','','[]','志士感幽寂，杜門臨晚晴。',48,'全唐诗/poet.song.37000.json','["志士感幽寂，杜門臨晚晴。", "流年無奈老，永夜有餘清。", "秋夏欲交處，古今皆此聲。", "羈愁與離恨，爲爾忽相并。"]'),
('5ec5e6f5-31ff-4364-a706-fd9430623dd5','和聞蛩有感二首  其二','呂陶','宋','宋诗','song-poetry','','[]','思婦感離别，夕霖殊未晴。',48,'全唐诗/poet.song.37000.json','["思婦感離别，夕霖殊未晴。", "九秋消息近，千里夢魂清。", "續縷有深意，促機無緩聲。", "寒衣遠須寄，人去在幽并。"]'),
('22d7c94d-3367-43f5-871f-57ab183052ad','送杜常','呂陶','宋','宋诗','song-poetry','','[]','壯士軒昂早，窮塗蹭蹬多。',48,'全唐诗/poet.song.37000.json','["壯士軒昂早，窮塗蹭蹬多。", "直將天命說，其奈客愁何。", "晚歲饒歸興，青春亦浩歌。", "舊溪如何守，應便掛漁蓑。"]'),
('a86d4868-4950-4895-ab13-8ee97678077d','送榮咨道','呂陶','宋','宋诗','song-poetry','','[]','並府最多士，朋游皆喜君。',48,'全唐诗/poet.song.37000.json','["並府最多士，朋游皆喜君。", "小官雖困俗，秀氣自凌雲。", "道遠車方軋，風高酒未醺。", "親闈極西望，薄靄似秋汾。"]'),
('aef96f0e-0305-41be-b361-741d78e50179','送王侍禁','呂陶','宋','宋诗','song-poetry','','[]','塞上青雲暗，天涯碧草微。',48,'全唐诗/poet.song.37000.json','["塞上青雲暗，天涯碧草微。", "人情殊念遠，客意自懷歸。", "孤宦甘循默，亨塗會奮飛。", "田游如入蜀，肯鳥亦庭闈。"]'),
('1d677687-6b00-42e1-aa54-9312c38440b2','毛太君挽詞','呂陶','宋','宋诗','song-poetry','','[]','善慶平生積，康寧忽考終。',48,'全唐诗/poet.song.37000.json','["善慶平生積，康寧忽考終。", "人間爲上壽，閨內有清風。", "祿在蘭羞徹，恩深綵誥空。", "惟餘九原淚，灑恨到無窮。"]'),
('97c37316-914e-4e4f-89e1-6482834ef1e3','和黄夷仲雅安雜詩','呂陶','宋','宋诗','song-poetry','','[]','地產行將竭，人言信不訛。',48,'全唐诗/poet.song.37000.json','["地產行將竭，人言信不訛。", "錐刀名已甚，骨髓病尤多。", "漢詔十行札，湯仁三面羅。", "山翁也歡喜，屢舞欲婆娑。"]'),
('855d5b3a-de61-42d1-9a00-3db3836a319b','贈張迪山人','呂陶','宋','宋诗','song-poetry','','[]','岇玉溪頭坐，于今四十年。',48,'全唐诗/poet.song.37000.json','["岇玉溪頭坐，于今四十年。", "塵埃晦閑迹，是月改華顛。", "反覆談幽數，丁寧索贈篇。", "誰爲朱有傳，君合附前賢。"]'),
('d0ef5a9b-da2a-42ce-9fc9-0293c493ed0b','奉詔決獄過左綿見民間禱雨甚勤次龍安夜聞霈灑黎明測潤及五六寸詢諸父老未滿其意馬上口占','呂陶','宋','宋诗','song-poetry','','[]','雨氣收未盡，山巓雲又飛。',48,'全唐诗/poet.song.37000.json','["雨氣收未盡，山巓雲又飛。", "一犂猶有望，十日莫相違。", "野壠忙耕耨，雩壇罷禱祈。", "誰知好生德，歲歲及圜扉。"]'),
('3ff0a173-ea41-4fa9-ab0d-140a62973008','張允中挽詞','呂陶','宋','宋诗','song-poetry','','[]','道業隱君子，恩榮鄉大夫。',48,'全唐诗/poet.song.37000.json','["道業隱君子，恩榮鄉大夫。", "骨雖藏吉地，名不沒幽塗。", "夢兆飛蝴蝶，年華過白駒。", "千車來弔者，應有奠生芻。"]'),
('c96dd097-53dd-4cde-a93c-1d8bc2ef12a8','和毅甫惠茶相別','呂陶','宋','宋诗','song-poetry','','[]','茶新詩亦新，垂貺及羈客。',48,'全唐诗/poet.song.37000.json','["茶新詩亦新，垂貺及羈客。", "有味皆清真，無瑕可指摘。", "隴西飄何依，湘水流自北。", "別後誦高吟，料公猶相憶。"]'),
('9ec13b86-2c3b-4e64-b70a-b0febe76c71d','長江道中','呂陶','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春晝長江道，行人倦阻長。',48,'全唐诗/poet.song.37000.json','["春晝長江道，行人倦阻長。", "山花雜紅白，壠麥半青黄。", "灘外郵亭出，松間縣舍藏。", "簿書聊寓目，回轡已斜陽。"]'),
('d75280e4-68a4-442a-89fe-a45e346d0139','宋太傅挽詞','呂陶','宋','宋诗','song-poetry','','[]','福壽無餘恨，哀榮莫擬倫。',48,'全唐诗/poet.song.37000.json','["福壽無餘恨，哀榮莫擬倫。", "素風傳幾世，純行見終身。", "簪紱方優禮，星霜已古人。", "舊松高百尺，歸祔想寧神。"]'),
('588ae5c4-9853-46a3-9fd3-258fbd4467d9','趙府君挽詞','呂陶','宋','宋诗','song-poetry','','[]','養德輝光煜，傳家訓範成。',48,'全唐诗/poet.song.37000.json','["養德輝光煜，傳家訓範成。", "九泉無愧色，一子有清名。", "壽域高風在，天心福報明。", "他年霈醲渥，褒贈極哀榮。"]'),
('faf2535c-8c2c-40c0-a852-2fedbb95d29b','楊寺丞挽詞','呂陶','宋','宋诗','song-poetry','','[]','祿養平時失，人情重慘傷。',48,'全唐诗/poet.song.37000.json','["祿養平時失，人情重慘傷。", "千車來弔客，五鼎過前喪。", "章斷新語壠，雲低舊隱堂。", "終天猶飲恨，誰爲問蒼蒼。"]'),
('2410476d-65ad-45ec-af08-4eb7fb28aa5e','喻延平挽詞','呂陶','宋','宋诗','song-poetry','','[]','雍睦傳家本，詩書教子心。',48,'全唐诗/poet.song.37000.json','["雍睦傳家本，詩書教子心。", "平生潛德在，他日漏泉深。", "往事銘幽石，新阡長茂林。", "孝思何以慰，章句盡悲音。"]'),
('3cce3759-b4af-4989-a0d4-a154e087a22c','和春雪','呂陶','宋','宋诗','song-poetry','','[]','歲改春將半，春寒雪又飛。',120,'全唐诗/poet.song.37000.json','["歲改春將半，春寒雪又飛。", "積陰殊未散，生氣一何微。", "忽墜千尋險，偏增百仞巍。", "密難沾暖席，冷易襲征衣。", "憑仗凄風助，遲留煦景歸。", "聚來難得勢，消去乃知幾。", "衆喜勻萌潤，私憂氣候違。", "方當乘太蔟，慎勿掩靈威。", "尺地惟書異，豐年可免饑。", "持言問真宰，天道是耶非。"]'),
('b002ea47-a1bd-4494-ba22-e609db3c0103','再和初春微雪','呂陶','宋','宋诗','song-poetry','','[]','治有春陽感，和無月律差。',216,'全唐诗/poet.song.37000.json','["治有春陽感，和無月律差。", "濃雲方聚鶴，凍桞亦飄花。", "瑞應來如響，羣情喜溢涯。", "縱觀天勢淡，俄失地形窊。", "素月交暉耀，狂風助擊拏。", "一斑迷隱豹，三尺晦祥鴉。", "塞上威尤澟，軍中語敢譁。", "漢兵同被練，朔地訝吹沙。", "冷焰侵殘燧，寒聲入舊笳。", "飛紈安用裂，種玉豈須畬。", "清潔山川景，微茫草木芽。", "墾田因澤及，望歲已心遐。", "共荷沾濡力，應忘旱歉嗟。", "詩豪夜傳卷，賀客曉趨衙。", "滲漉元侯德，生成赤子家。", "指期三日耜，拭目萬箱車。", "况賴深仁恤，會蠲重賦加。", "願賡稱頌句，豈肯匿咬哇。"]'),
('4d1fabed-f611-4dca-ae52-2e4c08c934c8','和喜雪','呂陶','宋','宋诗','song-poetry','','[]','向夕層雲結，黎明漫漫飛。',120,'全唐诗/poet.song.37000.json','["向夕層雲結，黎明漫漫飛。", "山川都變色，松竹倍生輝。", "共喜飄方密，翻憂落漸稀。", "陰功施黑律，寒侯應璿璣。", "右席延文客，先塗奉玉妃。", "二儀清景混，四野遠光圍。", "愛日因藏照，狂飈間作威。", "三冬兹有得，一穀敢言饑。", "渇望於時久，華心在物微。", "霈然蒙大潤，化力少知歸。"]'),
('25225f44-ec24-4479-a755-83345cdfb3cf','和對雪','呂陶','宋','宋诗','song-poetry','','[]','嚴冬飛朔雪，此景望中嘉。',96,'全唐诗/poet.song.37000.json','["嚴冬飛朔雪，此景望中嘉。", "雲暗垂天幕，江平壓浪花。", "翅寒低獨鴈，枝重折叢葭。", "冷甲窮邊戍，凝煙野叟家。", "聚來風有助，消去日難遮。", "爐暖頻烘獸，盃濃不飲蜿。", "謝呤殊可愛，郢唱又何加。", "好盡登臨興，搜題徹四遐。"]'),
('6b692cf8-461a-4382-a3dd-989ea680c9c1','上韓端明','呂陶','宋','宋诗','song-poetry','','[]','要道根皇極，純王攬懿綱。',288,'全唐诗/poet.song.37000.json','["要道根皇極，純王攬懿綱。", "域中洪造廣，天下大形彊。", "臣主同千載，藩宣奠四方。", "乾文耀參井，地鎮聳岷梁。", "景谷餘波迥，靈關古塞荒。", "限蠻唐節制，析部漢封彊。", "石穴延通道，山扄設巨防。", "利源充內帑，兵勢壓巴羌。", "付畀關休戚，權宜任弛張。", "紫封傳墨敕，金印坐黄堂。", "自昔都俞重，其誰德業彰。", "乖崖施遠略，忠獻紹前良。", "樂得中和職，人躋富庶鄉。", "含生知化力，永日載春陽。", "滲漉淵源在，醲醇骨髓藏。", "深和流耳目，盛事載縑緗。", "歲月徒爲久，風猷信不忘。", "恩褒賈逵祀，人愛召公棠。", "檜有喬枝茂，蘭宜後葉芳。", "惟公真輔翼，與世會明昌。", "間發乾坤秀，親逢日月光。", "國華增黼黻，地寶獻琳琅。", "尹道存先覺，軻心藴至剛。", "朝廷尊閥閲，士黨貴文章。"]'),
('9bf14b0d-60aa-4597-9fbb-d4de6d09b12e','和質夫運使大夫久旱喜雨長句','呂陶','宋','宋诗','song-poetry','','[]','六月陽初亢，三農否忽傾。',120,'全唐诗/poet.song.37000.json','["六月陽初亢，三農否忽傾。", "應祈由化力，蒙惠得歡聲。", "草木英華動，山川氣象清。", "石間看燕舞，池上覺蛙鳴。", "水闊江尤渺，雲濃夜未明。", "逡巡煩暑薄，時序好風輕。", "喜意知餘潤，憂心恐易晴。", "秀園吟際適，豐野望中平。", "勤有賢侯志，霖非舊史評。", "不須窮造物，土俗但犂耕。"]'),
('90807e95-6dbc-49f2-94be-83043b6aa6d0','又和喜雨','呂陶','宋','宋诗','song-poetry','','[]','壇宇嚴封築，牲羞薦潔鮮。',96,'全唐诗/poet.song.37000.json','["壇宇嚴封築，牲羞薦潔鮮。", "精誠宜有感，惠澤果無愆。", "暑氣沈虛谷，濃雲布滿天。", "雷霆馳勢力，河漢動經躔。", "農作方勞甚，人情忽泰然。", "春渠慚訟水，夜鼓促芸田。", "優足過三日，豐登又一年。", "隨車循吏事，應可繼前賢。"]'),
('2e917974-5796-4808-8ce9-d170e4ee3375','雲頂山次韻','呂陶','宋','宋诗','song-poetry','','[]','地峻山形壯，周遭盡勝遊。',168,'全唐诗/poet.song.37000.json','["地峻山形壯，周遭盡勝遊。", "抱巖如拱手，轉嶺似回頭。", "老木凌空迥，濃雲覆石幽。", "朝陽千里快，暮雨數峰愁。", "澗底猿隨鹿，松顛鶴勝鷗。", "香花開靜宇，煙火認他州。", "寶翰中朝錫，神燈半夜留。", "勢容逋客戀，景許化工偷。", "雪色連年貯，嵐光幾院收。", "仙葩多躑躅，野果號獼猴。", "法印傳無礙，禪機問即酬。", "叢林分徑路，蓮社得朋儔。", "眼遠層霄闊，心澄外物浮。", "登臨豁塵抱，今古信悠悠。"]'),
('f7124859-4ca3-4936-bb01-54b60a1bdefe','送俞漕','呂陶','宋','宋诗','song-poetry','','[]','積有儒林望，聊從使節行。',120,'全唐诗/poet.song.37000.json','["積有儒林望，聊從使節行。", "髙文自經緯，壯志欲澄清。", "地鎮三峨重，江波萬里平。", "闊難求畛域，深不爲功名。", "吉象光圖籍，祥風卷旆旌。", "巢阿贍鳯彩，運海見鵬程。", "事外神鋒晦，胸中寶鑑明。", "淵源千慮極，肝膽一言傾。", "德業期康濟，諮詢屬老成。", "定知前席對，有以澤羣生。"]'),
('2a8a7cd4-dc16-449b-a329-f14774bc7776','送人爲郡回','呂陶','宋','宋诗','song-poetry','','[]','當世勳賢後，嶄然器業髙。',96,'全唐诗/poet.song.37000.json','["當世勳賢後，嶄然器業髙。", "劍鋒天際倚，虹氣玉中韜。", "列乘提藩總，雙旌署郡曹。", "至精憑寶鑑，大割見庖刀。", "曠闊非私物，周流不失毫。", "霜威摧吏瓜，春煦起民膏。", "治世須醫國，亨塗合擁旄。", "蜀人懷舊德，涪漢共滔滔。"]'),
('5de88576-48a5-4e9b-b17b-291121c0aa99','送楊秘丞赴戎南倅','呂陶','宋','宋诗','song-poetry','','[]','萬里南溪水，滔滔逼郡城。',168,'全唐诗/poet.song.37000.json','["萬里南溪水，滔滔逼郡城。", "四時多雨氣，終日是江聲。", "蠻市煙中合，山疇火後耕。", "孤村隨漑斷，絕嶂與雲平。", "甲冷三冬戍，烽髙半夜驚。", "盛朝咨鎮守，别乘委才明。", "愛日迎舟檝，春風卷旆旌。", "蘭陔新膳潔，花縣舊陰成。", "荔子瓊瑤破，藤梢琥珀傾。", "羈懷休念遠，淺醉易忘情。", "宦況如郵傳，年華似送迎。", "笑談聊布政，閒暇亦論兵。", "僻地非通轍，層霄有去程。", "行聞海沂詠，流入竹枝清。"]'),
('c7328c4d-fbfe-4cd1-ba7f-ecc005795412','送王昌州屯田','呂陶','宋','宋诗','song-poetry','','[]','百里鄰疆宇，詳聞懿迹多。',96,'全唐诗/poet.song.37000.json','["百里鄰疆宇，詳聞懿迹多。", "本原由簡厚，論議必中和。", "平日春陽愛，斯民德澤歌。", "藩宣聊息偃，名教足逶迤。", "遠業今猶鬱，亨塗去若何。", "蓬仙終到海，軒鳯必巢阿。", "裁割神鋒舉，光輝國鑑磨。", "公乎難隱讓，忠義貴無他。"]'),
('c173c9e8-69c0-47b4-a1f6-134d27cf02a8','送張景元','呂陶','宋','宋诗','song-poetry','','[]','方域提權重，朝廷擇士尊。',96,'全唐诗/poet.song.37000.json','["方域提權重，朝廷擇士尊。", "綱疏因正紀，流潔爲澄源。", "寒日風威靜，熙陽氣序溫。", "人知廉使體，物荷聖皇恩。", "清轡纔周境，歸途已駕轅。", "光華三節瑞，邃密九重閽。", "韶集丹山鳯，雲升北海鯤。", "聞公難避讓，天下盡元元。"]'),
('367fa816-c1d9-44b6-a01e-38a685697b10','送馮樞密','呂陶','宋','宋诗','song-poetry','','[]','帥領來全蜀，掄魁祗一人。',288,'全唐诗/poet.song.37000.json','["帥領來全蜀，掄魁祗一人。", "崧髙雪山勢，清徹錦江津。", "旒冕思長策，機衡屬老臣。", "部中方拜賜，天下又迴春。", "出處無非道，安危繫此身。", "巖贍殊慶快，塗說敢開陳。", "聖運重熙久，皇威萬里振。", "勒兵充宇宙，按劍待煙塵。", "權術輕三表，韜鈴貴五申。", "招懷及蠻徼，指顧下洮岷。", "文誥傳荒服，天聲壓外鄰。", "捷書連歲上，故壤一朝新。", "計費千金易，論功百勝頻。", "征衣空杼軸，戰骨委荆榛。", "水旱乾坤慘，錐刀畎畝貧。", "人情危欲鎮，帝澤壅難均。", "幸會公歸國，相歡物在鈞。", "華心生草野，和氣滿楓宸。", "士論歸依切，風謠禱頌真。", "嘉謨憑獻納，大事費經綸。", "治術關休戚，規模有革因。", "號寒思挾纊，引哺願嘗珍。", "圖治雖更化，封侯漫富民。", "髙明深鑒照，密勿定諮詢。"]'),
('3edf6af3-f81d-4975-af15-7fbd8c058a4a','送師厚','呂陶','宋','宋诗','song-poetry','','[]','毳冕登車後，薫琴易柱時。',216,'全唐诗/poet.song.37000.json','["毳冕登車後，薫琴易柱時。", "遐方新視聽，赤子繫安危。", "羅網難投足，錐刀漸削肌。", "激昂忠論發，絡繹奏封馳。", "有意同休戚，無心計險夷。", "海傾身亦禦，山轉力須支。", "沸鼎憂魚爛，沈疴待藥治。", "正邪雙辯起，義利兩塗知。", "帝德終柔遠，天聰善聽卑。", "丁寧詢使指，勞來及坤維。", "大法圖公共，憸言惡詭隨。", "弊從經歲積，恩許一朝釐。", "治體今殊昔，仁聲喜換悲。", "方期講原本，何暇語毫釐。", "虎噬猶吾怯，蠅營漫爾爲。", "陰功符監佑，直道擁祥禧。", "行色青雲棧，英游白玉遲。", "是非都一笑，歸旆卷晴曦。"]'),
('9375f3b6-db40-4a23-8625-72719998bcf8','送范堯夫','呂陶','宋','宋诗','song-poetry','','[]','欲賦旋歸樂，翻成感遇篇。',288,'全唐诗/poet.song.37000.json','["欲賦旋歸樂，翻成感遇篇。", "盛時惟道在，輿誦自民傳。", "伊昔更張議，於今造化權。", "綱條籠宇宙，號令震山川。", "大略先農穡，餘波及貨泉。", "俊豪爭援世，忠亮欲回天。", "暮對青蒲側，朝留赭案前。", "堪憂逐江海，猶許治蕃宣。", "此地勞飛輓，何人念瘠捐。", "壯心摧更激，高節困尤堅。", "晚歲松方茂，洪爐燄不燃。", "迂從鄒叟得，勇在孟賁先。", "坦若王良轍，端如后羿弦。", "一毫無畏惜，千慮極哀憐。", "定論予張膽，游辭彼脇肩。", "尺尋難枉直，鑿枘自方圓。", "止沸愁烘鼎，調音恥絕弦。", "漢緡寛酒榷，唐賦舍庸錢。", "睿智期開允，生靈懼削朘。", "弊端殊皎皎，物望甚拳拳。", "白日功名久，浮雲富貴遷。", "萬鍾均廩禄，一品漫貂蟬。", "儻爲升沈動，誰能事業全。", "寄言天下士，無愧屬真賢。"]'),
('50a72a8e-16af-4cae-85ae-ce76780f45b9','送蔡帥赴平涼','呂陶','宋','宋诗','song-poetry','','[]','劍外開三蜀，回中宿萬兵。',240,'全唐诗/poet.song.37000.json','["劍外開三蜀，回中宿萬兵。", "召還宜北覲，賜鉞又西征。", "體貌均先後，權綱一重輕。", "淵衷尤慎簡，輿意尚難平。", "伊昔藩條振，於今治體成。", "有爲終簡易，無迹但恢閎。", "筆下銷頑弊，樽前得隱情。", "快如長劍立，通若巨河傾。", "闊刃從虛落，醇源及物情。", "山川增氣象，草木遂勾萌。", "暖褐三冬足，豐疇百室盈。", "詠歌今父母，畏服古神明。", "方幸華輪柅，俄聞瑞節迎。", "渇心猶借寇，翹望欲還瓊。", "況復盤關路，常瞻部使旌。", "十連依玉帳，一道固金城。", "後詔光前出，新棠似舊榮。", "于宣推德業，所至盡功名。", "塞馬寜非福，溟鵬豈問程。", "惟期未温席，歸去纂家聲。"]'),
('af12a09e-05cc-4f11-9715-9170a3f903dc','郊祀禮成詩','呂陶','宋','宋诗','song-poetry','','[]','皇極恢臨照，嘉時屬盛隆。',288,'全唐诗/poet.song.37000.json','["皇極恢臨照，嘉時屬盛隆。", "八年登至治，大祀答圓穹。", "並報知坤道，推尊見祖功。", "先期齊廣殿，將旦謁真宫。", "杲日迎鑾皎，祥雲遶蓋紅。", "衣冠開秘寢，幢節下層空。", "東嚮經途近，前贍太室崇。", "過門遵往德，降輅屈清躬。", "八聖威神在，三牲薦品豐。", "奉璋人左右，進俎序西東。", "上意精純至，英靈顧享同。", "念深堯八彩，感切舜重瞳。", "地勝龍灣闊，塵清輦路通。", "綵城齊北闕，天仗轉南風。", "旂動三辰麗，兵嚴萬衞雄。", "國容殊肅穆，丘勢自穹窿。", "虛次移銅漏，升壇儼玉珫。", "禮惟三獻具，樂以六成終。", "燔燎交神聽，髙明鑒睿衷。", "岡陵均委積，箕翼等光融。", "海沸歡聲振，天旋瑞氣充。", "呼嵩喧宇宙，迎仗抃華戎。", "盛典千春備，洪恩庶彚蒙。", "山河皆户牖，寰海一帡幪。"]'),
('ca8f4a6e-495d-4c2c-a62a-b4e789b86fe1','送吳龍圖仲庶赴江寧','呂陶','宋','宋诗','song-poetry','','[]','方域開全晉，權綱委巨公。',240,'全唐诗/poet.song.37000.json','["方域開全晉，權綱委巨公。", "深仁吾所導，實惠爾常蒙。", "曠濶歸儒術，周流見治功。", "蠢生無不贍，豪利豈須籠。", "金糓邊屯鋭，農桑漢地豐。", "頌聲如響答，和氣與春融。", "天下殊庸冠，朝廷偉望隆。", "咨詢懷舊德，付畀出清衷。", "禁直圖書近，龎恩屏翰崇。", "鄉衣新粲錦，郡軾再憑熊。", "自昔金陵盛，於今玉節雄。", "江山三國勢，臺殿六朝風。", "地勝名區在，時移往事空。", "貢先淮甸入，化接海隅同。", "封宇綏安外，煙波賦詠中。", "民瞻深繫屬，國論素探窮。", "此日留藩鎮，何時補上聰。", "鈞衡須遠業，藥石仰真忠。", "孰謂勞申伯，前知用弱翁。", "南歸勿遲久，登弼代天工。"]'),
('c70716d4-cd2f-4723-9c44-40234a6a1c04','送江巨源奉議','呂陶','宋','宋诗','song-poetry','','[]','吳會儒林勝，坤維使節雄。',120,'全唐诗/poet.song.37000.json','["吳會儒林勝，坤維使節雄。", "人誰攀景躅，物自得清風。", "繅玉塵埃外，冰壺愷悌中。", "教源資濬遵，治具費磨礱。", "舉向權衡見，難相畛域窮。", "章傳青瑣闥，夢徹紫真宫。", "自昔文章手，能成造化功。", "夷途方濶步，公論況僉同。", "晝永朝紳接，天髙奏牘通。", "平生先遠業，有以助堯聰。"]'),
('d9f1585a-257c-4bd2-8255-1432013ae030','送聞人夷庚太博','呂陶','宋','宋诗','song-poetry','','[]','邑有循良政，人持介潔心。',72,'全唐诗/poet.song.37000.json','["邑有循良政，人持介潔心。", "庖刀發虛刃，廟瑟鼓遺音。", "閒草豐春野，修篁茂晚林。", "恤民中詔遠，及物上恩深。", "歲月吳江夢，山川蜀道吟。", "歸歟清議在，直筆待君簪。"]'),
('1bb48e81-fdaa-4277-8411-b45ca4257f75','送茹世美少卿','呂陶','宋','宋诗','song-poetry','','[]','切慕真仙理，能收至靜心。',120,'全唐诗/poet.song.37000.json','["切慕真仙理，能收至靜心。", "紛華雖爾共，勢利莫吾侵。", "造化歸三鼎，逍遙託五禽。", "一言平物我，萬事委浮沈。", "研味經翻玉，吁嗟礫變金。", "太霞方夢想，流水漫光陰。", "得郡情應樂，休官志已深。", "遐飛脱塵網，髙視笑蹄涔。", "舊德淹卿寺，清風聳士林。", "却憂公議在，未易解朝簪。"]'),
('01bb1d97-bd28-4ab4-92fb-1276380f2b60','和提舉遊上方南禪十韻','呂陶','宋','宋诗','song-poetry','','[]','宿約遊雲谷，晨興過寺扉。',120,'全唐诗/poet.song.38000.json','["宿約遊雲谷，晨興過寺扉。", "雨聲隨步急，暑氣逐風微。", "正午逢晴照，層霄歛夕霏。", "江濤千里湧，城郭萬山圍。", "清集同揮塵，髙談及轉璣。", "虛涼河朔飲，蕭散道家衣。", "適意朋簪盛，回頭世網非。", "棋休誇小勝，禪莫問餘機。", "對景聊行樂，因吟欲賦歸。", "髙人應笑我，白首戀輕肥。"]'),
('bf9ccedf-5621-4213-a5c8-09d20cdff5f2','答王仲髙','呂陶','宋','宋诗','song-poetry','','[]','從政宜師古，爲儒貴席珍。',120,'全唐诗/poet.song.38000.json','["從政宜師古，爲儒貴席珍。", "承流仰循吏，慮患屬孤臣。", "休戚同千里，輕肥止一身。", "虛名稱有土，慚色見斯民。", "羅網甘投足，波瀾恥問津。", "狂言干重辟，冷笑待憸人。", "琴瑟方調節，芻蕘願采詢。", "閉關聊度日，開卷易經春。", "地暖畦蔬足，年豐甕粟陳。", "惟特三不愧，通塞任天鈞。"]'),
('1967d6df-602b-45d9-9031-31562d84a096','和正月二日遊碑堂寺二首  其一','呂陶','宋','宋诗','song-poetry','','[]','農事初興欲及時，東城風物又春熙。',64,'全唐诗/poet.song.38000.json','["農事初興欲及時，東城風物又春熙。", "出郊開燕始今日，迎馬獻花纔幾枝。", "萬室遊人方雜遝，三竿煦景漸舒遲。", "乖崖真得綏懷術，八十年間俗不知。"]'),
('0714c13d-a09c-422f-b11e-ab84d58840d2','和正月二日遊碑堂寺二首  其二','呂陶','宋','宋诗','song-poetry','','[]','綵旗連道過重闉，却訪僧居暫柅輪。',64,'全唐诗/poet.song.38000.json','["綵旗連道過重闉，却訪僧居暫柅輪。", "平野一朝鋪秀色，輕風十里散香塵。", "此時燕賞須從俗，昨日陽和已發春。", "自古成都稱美酒，細傾聊以度良辰。"]'),
('e4927d12-7469-4790-bd27-cd68df37a7a3','觀打春牛和韻','呂陶','宋','宋诗','song-poetry','','[]','塊然形質本何殊，似爲春來出舊墟。',64,'全唐诗/poet.song.38000.json','["塊然形質本何殊，似爲春來出舊墟。", "以色配年疑未可，與耕爲候信非虚。", "升陽蓋自寅正始，取類還當丑位初。", "但得碎身資穡事，豈須功效載農書。"]'),
('44276418-d627-4f4d-93c2-a7d7b18855ba','浣花泛舟和韻','呂陶','宋','宋诗','song-poetry','','[]','野店村橋迤邐通，蜀江深處茂林中。',64,'全唐诗/poet.song.38000.json','["野店村橋迤邐通，蜀江深處茂林中。", "花潭遠漾春波綠，綵閣相迎畫舫紅。", "修岸幾朝經密雨，芳樽盡日得清風。", "詩翁舊隐知何在，且事嬉遊與俗同。"]'),
('4bdec8e4-d88a-4b72-b574-6da502dc8460','寒貪','呂陶','宋','宋诗','song-poetry','','[]','新火乘時焰已燃，寒雲收盡晚晴天。',64,'全唐诗/poet.song.38000.json','["新火乘時焰已燃，寒雲收盡晚晴天。", "欣逢佳節遊花圃，獨欠詩人泛酒船。", "南畝如雲鋪秀色，西樓照日起祥煙。", "傳聞里巷嬉游俗，盡說豊年勝去年。"]'),
('d1f0b05a-4434-4421-a652-1fcf5640ac82','和重九遊柳溪','呂陶','宋','宋诗','song-poetry','','[]','西溪景物似江鄉，無賴秋容到岸傍。',64,'全唐诗/poet.song.38000.json','["西溪景物似江鄉，無賴秋容到岸傍。", "勝事可懷樽酒樂，淒風渾減路塵香。", "半凋柳色猶垂带，欲凍泉源祗濫觴。", "會向明春重遊覽，春暉依舊倍舒長。"]'),
('74be61b9-9130-4875-9d3d-08f0bf621ff7','晚過西溪','呂陶','宋','宋诗','song-poetry','','["\u897f\u6e56"]','煩暑襟懷倦客情，西湖虛爽暫閒行。',64,'全唐诗/poet.song.38000.json','["煩暑襟懷倦客情，西湖虛爽暫閒行。", "林間聞雨未爲閙，池上得風尤覺清。", "斜日漸因山隔閡，斷雲應與月逢迎。", "牧之才調誰能繼，一爲憑髙賦晚晴。"]'),
('f4122645-856d-4e31-94a4-80641cc2b51a','多日牽俗闕西溪之遊和友人來韻','呂陶','宋','宋诗','song-poetry','','[]','西溪流水正涓涓，彷彿江村種稻田。',64,'全唐诗/poet.song.38000.json','["西溪流水正涓涓，彷彿江村種稻田。", "弱枊依風徒自困，晚花經雨更誰憐。", "已知榮謝椿如槿，莫問飛潛魚與鳶。", "結得勝遊須盡興，醉鄉岐路在傍邊。"]'),
('0ddb6c21-c769-484a-bbbe-13b94ad8bcd5','赴官唐安益帥吳公以詩寵行次韻爲謝','呂陶','宋','宋诗','song-poetry','','[]','二十年前許進趨，六科重沗薦論書。',64,'全唐诗/poet.song.38000.json','["二十年前許進趨，六科重沗薦論書。", "獻言悟主慚明詔，乞禄還家得副車。", "此日詩章形黼黻，當時匠手器輪輿。", "恩知最厚難圖報，有意髙賢一挽裾。"]'),
('d91ab60f-6999-4dd2-b347-23ac6068629d','送劉儀甫職方東歸二首  其一','呂陶','宋','宋诗','song-poetry','','[]','藍田良玉古稱珍，品屬瓊瑶異碔珉。',64,'全唐诗/poet.song.38000.json','["藍田良玉古稱珍，品屬瓊瑶異碔珉。", "純有英華爲國寶，貴無雕琢是天真。", "連城享價千金重，垂繅承光五采新。", "羣后在廷皆執瑞，大圭終得奉嚴宸。"]'),
('5798fda0-80cb-4094-a924-c4913a1e2a9c','送劉儀甫職方東歸二首  其二','呂陶','宋','宋诗','song-poetry','','[]','南山蒼柏自森森，長就喬枝出茂林。',64,'全唐诗/poet.song.38000.json','["南山蒼柏自森森，長就喬枝出茂林。", "肅政臺中思直幹，孔明祠下得清陰。", "風雲毎助孤髙勢，霜雪難移勁挺心。", "大厦有成梁棟在，平時燕雀望皆深。"]'),
('8e394802-bdeb-4120-ab24-7d4205eb73f1','題府廨清素軒','呂陶','宋','宋诗','song-poetry','','[]','蘭麝香濃玉少塵，開軒相對似交親。',64,'全唐诗/poet.song.38000.json','["蘭麝香濃玉少塵，開軒相對似交親。", "臘寒庭院春将近，晚吹簾櫳月又新。", "憑檻雅宜題雪女，銜盃俱是咏花人。", "碧瓜故事標圖記，從此嘉名亦等倫。"]'),
('9e865b5f-5fbc-4448-9843-bef7a4ce0252','懷鶴鳴','呂陶','宋','宋诗','song-poetry','','[]','棣華曾到翠微中，一别仙宮入泮宮。',64,'全唐诗/poet.song.38000.json','["棣華曾到翠微中，一别仙宮入泮宮。", "真景望如雲在上，年光去似水流東。", "青霄得志雖榮己，白髪多情亦念公。", "若許他時遂休逸，山翁携手有詩翁。"]'),
('9166ec2e-fec8-4dfc-8740-30d6b1d7ee87','偕友人遊上方南禪','呂陶','宋','宋诗','song-poetry','','[]','出郭行行数里村，石梯盤曲到禪門。',64,'全唐诗/poet.song.38000.json','["出郭行行数里村，石梯盤曲到禪門。", "亭開髙檻侵山脚，水過方池斷竹根。", "城市塵埃終日遠，煙嵐氣象四時存。", "約公乘興重來此，延納清風盡一樽。"]'),
('419ff08f-45af-46d9-8a76-dd3cfc7752d6','廨舍之北有海棠二本惜非其地移植庭前呈晦甫同年博士','呂陶','宋','宋诗','song-poetry','','[]','何事當庭植海棠，欲乘生氣待春光。',64,'全唐诗/poet.song.38000.json','["何事當庭植海棠，欲乘生氣待春光。", "恰逢輕雨渾如意，若得和風定吐芳。", "籬下不堪藏秀質，眼前從此識清香。", "一樽曾與嘉賓賞，屈指紅英在艷陽。"]'),
('1d415891-0b6d-4217-bfc7-4fa18df5fbc1','寄花廣漢守倅','呂陶','宋','宋诗','song-poetry','','[]','地産名花敢自珍，百枝聊且寄强鄰。',64,'全唐诗/poet.song.38000.json','["地産名花敢自珍，百枝聊且寄强鄰。", "分将雨後千金色，添得罇前一日春。", "檀板屢歌憑侍女，玉簪齊插奉嘉賓。", "明年紅爛還馳去，惟恐流光老却人。"]'),
('c2ff33bc-18fe-4148-86b2-29ba214777d1','答髙進賢南歸見别','呂陶','宋','宋诗','song-poetry','','[]','春波萬里已魂銷，況是分携過蜀橋。',64,'全唐诗/poet.song.38000.json','["春波萬里已魂銷，況是分携過蜀橋。", "吏隐有心終濟物，他山無術可除妖。", "好將醒醉迷千日，莫爲興亡感六朝。", "南望襄山何處是，悒然懷抱更無聊。"]'),
('7d99420a-1a48-4e8d-9d41-ff73e851eeed','答晦甫','呂陶','宋','宋诗','song-poetry','','[]','花往詩來報禮優，不慚蕪累願賡酬。',64,'全唐诗/poet.song.38000.json','["花往詩來報禮優，不慚蕪累願賡酬。", "青春易去何妨賞，白髪相欺未足羞。", "萬事放懷閒歲月，一樽髙笑好朋儔。", "公堂訟簡心情在，莫對風光取次休。"]'),
('621c52a0-5002-4498-96b9-e52f597ba224','次韻思道同晦甫春日過李氏園亭','呂陶','宋','宋诗','song-poetry','','[]','二賢談笑共爲州，深惜青春爛漫遊。',64,'全唐诗/poet.song.38000.json','["二賢談笑共爲州，深惜青春爛漫遊。", "吟到醉鄉須一飲，步回芳徑亦三休。", "風前幾點見蛺蝶，雨後數聲聞栗留。", "人望使旌應喜樂，此心於爾亦何羞。"]'),
('afad9e17-902d-4406-ab30-438c19c5f3b3','和晦甫答思道','呂陶','宋','宋诗','song-poetry','','[]','策馬悠悠倦往還，竹邊林下舉吟鞭。',64,'全唐诗/poet.song.38000.json','["策馬悠悠倦往還，竹邊林下舉吟鞭。", "忙中對酒成閒客，老去逢春憶少年。", "三島月來清入牖，十洲波浄碧涵天。", "歸歟且共良朋賞，花未飄紅柳未眠。"]'),
('c1b361af-2749-4c80-8199-6f5208d86d5b','次韻周思道喜正孺過廣漢二首  其一','呂陶','宋','宋诗','song-poetry','','[]','霜臺御史迥名藩，氣象光陰動故山。',64,'全唐诗/poet.song.38000.json','["霜臺御史迥名藩，氣象光陰動故山。", "此日郡中誇盛事，明朝堂上拜慈顔。", "御香持去仍輕别，天詔飛來即召還。", "南北唱酬皆勝絕，一窺方識豹文斑。"]'),
('fd2874d6-31b5-4372-9506-b8bdc6e71897','次韻周思道喜正孺過廣漢二首  其二','呂陶','宋','宋诗','song-poetry','','[]','鴈樓南畔報來期，遠俗駢闐望錦衣。',64,'全唐诗/poet.song.38000.json','["鴈樓南畔報來期，遠俗駢闐望錦衣。", "官府奉迎因直指，家庭喜樂是榮歸。", "款憑罇酌延談議，密獻囊封中事機。", "莫嘆宦遊多闊别，九重深待弼予違。"]'),
('6d670a5a-d6f4-4b11-a8bb-8976bac62317','送東方子春歸廣漢','呂陶','宋','宋诗','song-poetry','','[]','閒上層樓賦式微，暮雲重疊鴈南飛。',64,'全唐诗/poet.song.38000.json','["閒上層樓賦式微，暮雲重疊鴈南飛。", "三秋已有還鄉念，十日那堪送客歸。", "世路最宜心似水，年華休嘆露沾衣。", "一官擬得知何處，回首風標又闊違。"]'),
('30d07fbf-75c0-444d-bc4b-466b8c719312','送周思道郎中通理益昌','呂陶','宋','宋诗','song-poetry','','[]','閩見冤魄久艱伸，吾以仁心濟不仁。',64,'全唐诗/poet.song.38000.json','["閩見冤魄久艱伸，吾以仁心濟不仁。", "十室苟能全一子，萬家無慮活千人。", "于公治獄門生相，韓厥成功世有民。", "陰德所施陽報在，莫嘆孤宦老朝紳。"]'),
('d4abfa20-4dc6-405b-994f-9af3947ea11d','和寄周郎中','呂陶','宋','宋诗','song-poetry','','[]','省郎華髪倦遊時，却憶當年一布衣。',64,'全唐诗/poet.song.38000.json','["省郎華髪倦遊時，却憶當年一布衣。", "仕路更勞何足戀，家山可愛不如歸。", "吟中斗絕紅塵味，静裏能延白日輝。", "某水某丘真舊物，春來贏得掩重扉。"]'),
('fb64ffb8-a3c9-4c35-b375-10c0e548c85f','寄廣漢周思道','呂陶','宋','宋诗','song-poetry','','[]','鴈橋古郡誠佳絕，熊軾名郎暫鎮臨。',64,'全唐诗/poet.song.38000.json','["鴈橋古郡誠佳絕，熊軾名郎暫鎮臨。", "雨滿郊原千里潤，春歸臺榭百花深。", "將迎意味煩清燕，閒暇工夫屬静吟。", "若詫湖亭風物好，西鄰猶有不平心。"]'),
('c67522f9-abb6-44b9-89e1-1c2b51a3cb91','和陳圖南州學石柱題名之作三首  其一','呂陶','宋','宋诗','song-poetry','','[]','方柱鎸題誰厭頻，三年還見一番新。',64,'全唐诗/poet.song.38000.json','["方柱鎸題誰厭頻，三年還見一番新。", "姓名已載推前達，行列猶虚待後人。", "清世雲霄如坦道，壯夫思慮惜青春。", "瓊瑶定得連城價，至鑒從來不貴珉。"]'),
('bdcfb200-0966-4502-b560-e080e53bd4fc','和陳圖南州學石柱題名之作三首  其二','呂陶','宋','宋诗','song-poetry','','[]','鴈塔題名故事存，泮宮鎸柱又增新。',64,'全唐诗/poet.song.38000.json','["鴈塔題名故事存，泮宮鎸柱又增新。", "十行詔下方求士，千佛經中定有人。", "錦繡燐斌涪水畫，風雷變化集英春。", "公卿皆向此途出，豈待區區佩瓀珉。"]'),
('fb58d8a5-8894-4a77-bda0-6179592e4428','和陳圖南州學石柱題名之作三首  其三','呂陶','宋','宋诗','song-poetry','','[]','匠氏磨礱用力勤，先生序引亦清新。',64,'全唐诗/poet.song.38000.json','["匠氏磨礱用力勤，先生序引亦清新。", "尺書已報泥金帖，丹字仍題衣錦人。", "桂籍共誇亨有路，泮林無倦誦於春。", "東川素與西川敵，又見榮名上翠珉。"]'),
('88f4408c-5046-4fe3-8a0d-bda7ecc472db','和陳圖南安昌巖避暑詩二首  其一','呂陶','宋','宋诗','song-poetry','','[]','石穴虚深宛似房，石形方穏亦如床。',64,'全唐诗/poet.song.38000.json','["石穴虚深宛似房，石形方穏亦如床。", "千年知是誰人隱，一郡除非此地凉。", "山外雨來煙色暝，林間風過藥苗香。", "塵埃已斷尤清寂，今日禪僧不上堂。"]'),
('a54eaad0-ae1c-4bec-b188-239c6fc2fbc4','和陳圖南安昌巖避暑詩二首  其二','呂陶','宋','宋诗','song-poetry','','[]','巖前數步到幽房，巖裏聊安息偃床。',64,'全唐诗/poet.song.38000.json','["巖前數步到幽房，巖裏聊安息偃床。", "已得清風極瀟灑，休彈白雪恐凄凉。", "平時地籟乘空發，何日天花墜雨香。", "三伏屢來君莫厭，流年背我去堂堂。"]'),
('7b1a181b-d34e-40d2-a10c-e70aa48697ef','和再遊二首  其一','呂陶','宋','宋诗','song-poetry','','[]','仙居殊不類樊籠，瀟灑清涼皆可封。',64,'全唐诗/poet.song.38000.json','["仙居殊不類樊籠，瀟灑清涼皆可封。", "寒溜恰如揚子水，脩筠應有稚川龍。", "雲深況是門無客，人去惟聞鶴在松。", "向此却疑推律法，應鍾何事代林鍾。"]'),
('8dd4f528-de55-4b61-a279-e3ac7f326ca7','和再遊二首  其二','呂陶','宋','宋诗','song-poetry','','[]','石門髙下両相通，冰屋初開不復封。',64,'全唐诗/poet.song.38000.json','["石門髙下両相通，冰屋初開不復封。", "睡穏好欹方水玉，味清須試密雲龍。", "詩筒迭和難親筆，談柄閒摇屢折松。", "便寫姓名鎸翠壁，休論功烈刻華鍾。"]'),
('240f651a-6e39-4010-a5a7-be03cd075745','和三月二十一日遊海雲','呂陶','宋','宋诗','song-poetry','','[]','玉節重來鎮此州，暫驅千騎上峰頭。',64,'全唐诗/poet.song.38000.json','["玉節重來鎮此州，暫驅千騎上峰頭。", "春闌好爲良辰惜，俗樂誰知急景流。", "山色也疑今日盛，物情渾勝昔年遊。", "登臨賦詠知難再，持語鄉人早借留。"]'),
('a7892c0b-ce3c-4271-b379-0fd546a0721f','南充縣野翁亭','呂陶','宋','宋诗','song-poetry','','[]','勢利紛紛萬慮侵，縣亭聊可一登臨。',64,'全唐诗/poet.song.38000.json','["勢利紛紛萬慮侵，縣亭聊可一登臨。", "目前不近将迎路，塵外能消富貴心。", "燕處自知如隐遯，縱談誰更及浮沉。", "時平樂得常棲地，且向幽閒寄楚吟。"]'),
('59d2d74b-a836-470d-a1da-a5db7a750fa4','和義夫出文谷','呂陶','宋','宋诗','song-poetry','','[]','羸馬駸駸不厭驅，望中天勢接晴蕪。',64,'全唐诗/poet.song.38000.json','["羸馬駸駸不厭驅，望中天勢接晴蕪。", "一朝偶適林泉興，十里誰開水墨圖。", "枊線漸看金弄色，雪花猶見玉爲柎。", "登臨自得詩家路，寄語紅塵莫訝迂。"]'),
('10650ace-d175-482b-9453-9b3256ae0a5a','雲頂寺','呂陶','宋','宋诗','song-poetry','','[]','秀巘層層一徑通，秋來更植萬株松。',64,'全唐诗/poet.song.38000.json','["秀巘層層一徑通，秋來更植萬株松。", "閒中日永宜禪性，望處雲平見物容。", "半夜起風喧地籟，何年說佛響天鐘。", "塵埃滿馬遊從隔，寄恨煙蘿第幾重。"]'),
('4c58ae36-c664-42f5-a9e7-67f9877d4920','雲頂寺蹙雲軒','呂陶','宋','宋诗','song-poetry','','[]','寺枕山巔擁翠峰，幽棲更與白雲通。',64,'全唐诗/poet.song.38000.json','["寺枕山巔擁翠峰，幽棲更與白雲通。", "半空欄檻千尋外，兩蜀風煙一望中。", "晨霽最宜天浩蕩，夕陰先覺雨冥濛。", "頃年曾坐盤陀石，不到軒前目未窮。"]'),
('0ee89a2e-548a-4ba4-8b1e-39df402c590b','送唐誠老秘丞','呂陶','宋','宋诗','song-poetry','','[]','越溪千里碧滔滔，匹馬西遊豈憚勞。',64,'全唐诗/poet.song.38000.json','["越溪千里碧滔滔，匹馬西遊豈憚勞。", "文牘甚稀如吏隱，江山有助作詩豪。", "和風盡日生眉宇，白髪何年上鬢毛。", "好向堯庭露華彩，韶音方奏德輝髙。"]'),
('b4df7bc4-a3b5-4943-95b1-dc0600242c46','和紅蕉二首  其一','呂陶','宋','宋诗','song-poetry','','[]','嫩青叢裏色何如，猩血雖紅莫奪朱。',64,'全唐诗/poet.song.38000.json','["嫩青叢裏色何如，猩血雖紅莫奪朱。", "曉薦赤璋開繅藉，夜燃綘蠟照珊瑚。", "穠華如擘霞光紙，芳價堪酬明月珠。", "欲識此花堅與否，願將真偈叩文殊。"]'),
('400a5679-57ba-4ccf-86f2-eb2c445d4ae6','和紅蕉二首  其二','呂陶','宋','宋诗','song-poetry','','[]','綺窗開處畫堂西，紅綠相参數尺低。',64,'全唐诗/poet.song.38000.json','["綺窗開處畫堂西，紅綠相参數尺低。", "種得青琳生寶焰，裁將丹錦護封題。", "染因乘露皆鮮翠，舞爲交竿少整齊。", "惆悵夜來經暮雨，妝痕幾點带嬌啼。"]'),
('5b825afd-3a76-42ee-b99a-d9f13dd6e1a0','有惠詩求酒者和答二首贈以兩榼  其一','呂陶','宋','宋诗','song-poetry','','[]','閒居偏向酒中閑，已把人間比夢間。',64,'全唐诗/poet.song.38000.json','["閒居偏向酒中閑，已把人間比夢間。", "飲量欲希江海納，醉鄉應有路岐還。", "髙談好對清樽樂，屢舞猶嫌數斗慳。", "信有金船少風浪，莫乘輕舸下深灣。"]'),
('b97f86cc-5240-4692-881c-b50a0b5c6dfe','有惠詩求酒者和答二首贈以兩榼  其二','呂陶','宋','宋诗','song-poetry','','[]','愁腸思得濁醪澆，渾似春苗旱欲焦。',64,'全唐诗/poet.song.38000.json','["愁腸思得濁醪澆，渾似春苗旱欲焦。", "洗甕已於坊禁礙，典琴誰向息錢饒。", "醒心未免嗟牢落，醉眼偏宜望泬寥。", "酩酊到來須畫寢，信知畢卓勝邊韶。"]'),
('8ab62990-26fa-4b72-81e6-e39df33b3457','次韻劉希道龍圖鹿鳴燕進士','呂陶','宋','宋诗','song-poetry','','[]','賢能書上鹿鳴時，欲步丹梯别釣磯。',64,'全唐诗/poet.song.38000.json','["賢能書上鹿鳴時，欲步丹梯别釣磯。", "名世公卿加寵薦，故鄉親友待滎歸。", "通經豈比籯金價，成器難藏璞玉輝。", "威鳯有雛鵬有路，相將盡向九霄飛。"]'),
('8dd1dc02-a671-4771-9085-bb207f7818ef','和知府右丞秋貢燕士席上所賦','呂陶','宋','宋诗','song-poetry','','[]','應書羣彦稱旁求，勸駕賢公禮數優。',64,'全唐诗/poet.song.38000.json','["應書羣彦稱旁求，勸駕賢公禮數優。", "名出士林當赫赫，詩歌鹿野自呦呦。", "雲霄去路程皆遠，杞梓良材幹盡脩。", "登却龍門須變化，奪標人已在船頭。"]'),
('d43ec9da-f7be-4578-8b9b-699b000a283f','和鹿鳴燕進士二首  其一','呂陶','宋','宋诗','song-poetry','','[]','石室宏開化二川，文場今歲不遺賢。',64,'全唐诗/poet.song.38000.json','["石室宏開化二川，文場今歲不遺賢。", "鶯憑暖律方遷木，鶴遇祥雲必到天。", "隨貢充庭知有路，乘風破浪去如船。", "龍墀唱第程塗近，應在春餘數日前。"]'),
('25a195e0-be77-4da4-b80f-e5357b9bb1b0','和鹿鳴燕進士二首  其二','呂陶','宋','宋诗','song-poetry','','[]','里有賓興方啟燕，詩稱樂育願升歌。',64,'全唐诗/poet.song.38000.json','["里有賓興方啟燕，詩稱樂育願升歌。", "英才盡向師門出，貴器須憑匠手磋。", "澤射定誇楊葉箭，鄉衣便促錦機梭。", "諸生大捷諸公賜，先紀王勳後戰多。"]'),
('5eaee6c4-66e3-44fb-a230-ffeb93f8df8f','和八日登髙','呂陶','宋','宋诗','song-poetry','','[]','八日登髙九日同，拒霜寧有兩般紅。',64,'全唐诗/poet.song.38000.json','["八日登髙九日同，拒霜寧有兩般紅。", "流陰漸老三秋後，嘉客相歡一醉中。", "塵裏仙官應混俗，坐間談麈自生風。", "龍山故事今辰會，雖欠笙歌不是空。"]'),
('d1004bc8-b1cf-4987-8dff-94c36218114f','重陽登城','呂陶','宋','宋诗','song-poetry','','[]','上得層城暫倚欄，況逢佳節萬愁寛。',64,'全唐诗/poet.song.38000.json','["上得層城暫倚欄，況逢佳節萬愁寛。", "山青水綠等閒好，酒白花黄隨分歡。", "一月放懷能幾許，九秋生感又多端。", "龍山勝事今何在，空使騷人賦蕙蘭。"]'),
('e38fd9b4-5eec-4ad4-ab61-d0800d79e137','和氏月菊','呂陶','宋','宋诗','song-poetry','','[]','今辰誰道此花衰，更倚欄杆把酒巵。',64,'全唐诗/poet.song.38000.json','["今辰誰道此花衰，更倚欄杆把酒巵。", "白眼漫生秋後意，黄金不减夜來枝。", "化工應已均開落，心賞何須問速遲。", "歲歲樽前鎮相似，風光千萬莫差池。"]'),
('967cab4c-4be9-4d92-8b59-36202e2b228d','和郡齋即事','呂陶','宋','宋诗','song-poetry','','[]','表裏山河久鎮綏，府無留事縱懷時。',64,'全唐诗/poet.song.38000.json','["表裏山河久鎮綏，府無留事縱懷時。", "自將遠業更中外，不向榮塗計速遲。", "冲談本從天理得，安閒常有道心知。", "元元未盡躋仁壽，日望登庸爲審思。"]'),
('28c2fd50-783c-46e0-aeda-c8c0223bfe43','郡齋春暮','呂陶','宋','宋诗','song-poetry','','[]','自覺勞生萬事非，宦心從此更遲遲。',64,'全唐诗/poet.song.38000.json','["自覺勞生萬事非，宦心從此更遲遲。", "凄凉好飲悲春酒，閒暇猶吟送老詩。", "軒冕去來皆外物，雲山早晚是歸期。", "懷民報國終無術，空負慚顔對一麾。"]'),
('6bff728d-5a7b-497d-b255-a55fc95810c6','次韻張懷安題雲頂浴室院','呂陶','宋','宋诗','song-poetry','','[]','山門漸近少凡塵，佛子長棲物外身。',64,'全唐诗/poet.song.38000.json','["山門漸近少凡塵，佛子長棲物外身。", "款戶多因遊寺客，倚欄時有羨魚人。", "祥雲結蓋應非霧，法雨飄花别是春。", "數刻盤桓覺蕭散，回頭官事又勞神。"]'),
('7f78483c-f777-42c9-b31a-1a416890ce85','次韻張懷安喜雨詩','呂陶','宋','宋诗','song-poetry','','[]','雲密西郊末作霖，暫憑精禱快羣心。',64,'全唐诗/poet.song.38000.json','["雲密西郊末作霖，暫憑精禱快羣心。", "望如至寶難搜索，來似嘉賓忽訪臨。", "古廟有靈惟響答，洪鈞於物已恩深。", "春膏直待沾濡足，不使狂風取次侵。"]'),
('aba61aec-5bc1-4d83-bad8-fa0f9a452d24','過金堂偶記舊詩因贈宇文縣宰','呂陶','宋','宋诗','song-poetry','','[]','嘗聞縣古槐根出，最愛官清馬骨髙。',64,'全唐诗/poet.song.38000.json','["嘗聞縣古槐根出，最愛官清馬骨髙。", "前輩有詩談事實，今辰此景入風騷。", "飛雲幾處籠山頂，密雨連宵發土膏。", "公事稀疏吏歸去，不妨歡侍對春醪。"]'),
('7906c2e8-3476-475f-a07d-f61af4ada81c','和野軒答李著作見寄','呂陶','宋','宋诗','song-poetry','','[]','公居何事葺幽軒，客味蕭條稱養閒。',64,'全唐诗/poet.song.38000.json','["公居何事葺幽軒，客味蕭條稱養閒。", "人笑規模猶物外，我憐風景勝花間。", "穠林鬬影舒帷幕，淺溜餘聲雜佩環。", "欲把郡圖傳向此，座中常得見岷山。"]'),
('380e9d97-e8b0-4ef7-8d55-a4a64ae4d721','登攬秀亭','呂陶','宋','宋诗','song-poetry','','[]','亭在西山積翠中，煙嵐氣象一重重。',64,'全唐诗/poet.song.38000.json','["亭在西山積翠中，煙嵐氣象一重重。", "芟開簷際偏髙竹，見得雲問最後峰。", "野色爲誰長鬱茂，物情於我似從容。", "年來已有林泉興，倚著闌干興轉濃。"]'),
('7fbc50f0-1100-4acb-b58c-c3d403c2f9fc','次輔元韻','呂陶','宋','宋诗','song-poetry','','[]','山嵐穠秀望中青，路轉松陰步步迎。',64,'全唐诗/poet.song.38000.json','["山嵐穠秀望中青，路轉松陰步步迎。", "十里晴郊供野意，萬家和氣發歡聲。", "春臺不覺殘春景，樂國偏知衆樂情。", "公向蜀人深有意，更憐風物暫閒行。"]'),
('f8d660c2-65e5-4c61-acc0-d6e70b74d0eb','鍾陽道中和酬輔元','呂陶','宋','宋诗','song-poetry','','[]','忽捧瓊瑰俗眼驚，荷君深照舊交情。',64,'全唐诗/poet.song.38000.json','["忽捧瓊瑰俗眼驚，荷君深照舊交情。", "歸心自喜雙親壽，拙計難酬厚禄榮。", "十舍路岐平野闊，幾重村落霽烟生。", "羈遊毎憶家山樂，況是花時到錦城。"]'),
('ffd65d02-4f5a-4638-81a8-82b0265cab64','送任遵聖之官富順二首  其一','呂陶','宋','宋诗','song-poetry','','[]','千丈蒼松出故林，喬枝成就古根深。',64,'全唐诗/poet.song.38000.json','["千丈蒼松出故林，喬枝成就古根深。", "棟梁須負平生用，霜雪難移此日心。", "月白曾經丹鳳宿，風悲定有老龍呤。", "重巖複澗何緣幸，一旦家家得茂陰。"]'),
('db3d4d2d-c3fc-4408-8ecc-7b30dea41398','送任遵聖之官富順二首  其二','呂陶','宋','宋诗','song-poetry','','[]','野鶴孤髙舊羽儀，超然殊不事卑飛。',64,'全唐诗/poet.song.38000.json','["野鶴孤髙舊羽儀，超然殊不事卑飛。", "有心雲路翺翔去，迴首芝田迤邐歸。", "白日漫教羅網密，紅塵堪笑稻梁肥。", "仙家自有千年約，應許先生學令威。"]'),
('820dba59-dcad-43e0-855e-f3a961b348ce','竹枕','呂陶','宋','宋诗','song-poetry','','[]','不誇雕琢略磨礱，溪叟持來贈野翁。',64,'全唐诗/poet.song.38000.json','["不誇雕琢略磨礱，溪叟持來贈野翁。", "冰雪易侵毛髪際，塵埃難到夢魂中。", "消除暑愠宜無價，安養慵閒似有功。", "富貴人家應笑我，水晶新様極玲瓏。"]'),
('3a4e55ae-1ca9-4ff3-9559-aed6cfeb94f9','次韻家渠州承議春陰','呂陶','宋','宋诗','song-poetry','','[]','春工用意本華鮮，氣候陰沉未逞妍。',64,'全唐诗/poet.song.38000.json','["春工用意本華鮮，氣候陰沉未逞妍。", "風色送寒無甚雨，雲容垂遠又非煙。", "遷延鶯舌應嫌巧，抑遏花心恐占先。", "稍待新晴纖翳廓，穠芳齊媚艶陽天。"]'),
('51cfe354-5a43-4fe0-899b-bc8148dc44dd','官舍東偏海棠開最晚落亦後時以詩嘲之','呂陶','宋','宋诗','song-poetry','','[]','花到春深半已過，此花猶見滿枝柯。',64,'全唐诗/poet.song.38000.json','["花到春深半已過，此花猶見滿枝柯。", "傳來芳信雖爲晚，占得韶光却是多。", "愛惜錦文愁雨急，留連妝臉笑風和。", "後先榮謝人休問，且伴樽前一醉歌。"]'),
('34b55059-f8ff-42d4-83ec-1a049b461029','送秦漕歸淮南','呂陶','宋','宋诗','song-poetry','','[]','襲得芝蘭一室薰，更將三美向誰論。',64,'全唐诗/poet.song.38000.json','["襲得芝蘭一室薰，更將三美向誰論。", "光輝自可誇僚友，契愛猶能及子孫。", "金節暫求康爾俗，錦衣歸去大吾門。", "西南終是天涯遠，却羨鸞凰集九閽。"]'),
('56592735-7ff3-4e8d-a168-95449b4c491a','寄新甯黎叔蒨','呂陶','宋','宋诗','song-poetry','','[]','平日論交重久要，毎懷髙誼寸心搖。',64,'全唐诗/poet.song.38000.json','["平日論交重久要，毎懷髙誼寸心搖。", "君恩最是憂民社，吏隱偏宜遠市朝。", "諄誨佇聞流尺素，嘉篇頻爲寄瓊瑤。", "笑言契闊勞生甚，别後堪嗟壯氣消。"]'),
('d13e7f5d-d76e-4797-90cc-258d2f0ab760','寄周才叔','呂陶','宋','宋诗','song-poetry','','[]','天涯羈宦落蓬蒿，漫說平時器業髙。',64,'全唐诗/poet.song.38000.json','["天涯羈宦落蓬蒿，漫說平時器業髙。", "寒暖所逢皆物理，悲歡相較只秋毫。", "徒嗟壯士難行己，懶學風人便著騷。", "樂道養閒俱可羨，念君清誼甚魂勞。"]'),
('27cd5d0d-9019-4806-a15c-c01368368dbb','和周簡州寄范蜀公三章  其一','呂陶','宋','宋诗','song-poetry','','[]','禁林元老忽西歸，衆謂西州此事奇。',64,'全唐诗/poet.song.38000.json','["禁林元老忽西歸，衆謂西州此事奇。", "矰繳漫勞鴻去後，桑田未變鶴來時。", "一鄉金帛皆沾惠，千載松楸得奉祠。", "預想年前至京國，子孫持酒獻春祺。"]'),
('8f67315a-ef96-4f6a-914d-3763466c0772','和周簡州寄范蜀公三章  其二','呂陶','宋','宋诗','song-poetry','','[]','春深歸到錦江頭，笑傲光陰已晚秋。',64,'全唐诗/poet.song.38000.json','["春深歸到錦江頭，笑傲光陰已晚秋。", "內相貴名雖烜赫，山翁行李甚優游。", "詩中氣格超摩詰，方外情懷類子休。", "南下有期風月爽，鄉人從此望仙舟。"]'),
('e06f24e4-8312-4c0d-a901-ad4e6e525345','和周簡州寄范蜀公三章  其三','呂陶','宋','宋诗','song-poetry','','[]','法從深嚴寵禄榮，清標素節兩難并。',64,'全唐诗/poet.song.38000.json','["法從深嚴寵禄榮，清標素節兩難并。", "有心報國雖謀國，無意求名又得名。", "道服豈煩垂寶带，安居何用飾華纓。", "秋風一夜喬林減，惟見松篁不變更。"]'),
('19eb4393-8885-407e-8568-db850448684f','昨日','呂陶','宋','宋诗','song-poetry','','[]','昨日文書插羽毛，征夫連日整弓刀。',64,'全唐诗/poet.song.38000.json','["昨日文書插羽毛，征夫連日整弓刀。", "雲如野色隨時慘，風作邊聲特地號。", "八陣威靈今可託，六州形勢古稱髙。", "西南久不聞金鼓，莫遣人人著戰袍。"]'),
('f92dbaf2-eceb-4542-98c3-79f2c4ca3891','又賦二首  其一','呂陶','宋','宋诗','song-poetry','','[]','千里征蠻向不毛，坐籌先勝自三刀。',64,'全唐诗/poet.song.38000.json','["千里征蠻向不毛，坐籌先勝自三刀。", "井中蛙力狂雖躍，弓下猿聲怯便號。", "草白見城羌蝶淺，月明聞角漢天髙。", "將軍幾日當雄捷，速把功書上赭袍。"]'),
('83346fe0-e23f-4df4-92d5-09210b4ddb29','又賦二首  其二','呂陶','宋','宋诗','song-poetry','','[]','忠膽輕生甚一毛，奇謀破賊鋭於刀。',64,'全唐诗/poet.song.38000.json','["忠膽輕生甚一毛，奇謀破賊鋭於刀。", "横行容易平烏合，面縛須臾作犬號。", "霜甲共輝軍帳冷，煙烽齊出戍樓髙。", "羌酋若也投降早，定得君王瑞錦袍。"]'),
('a9cfc952-6016-475d-8d41-07f974dd0887','雪','呂陶','宋','宋诗','song-poetry','','[]','白金鋪野玉堆簷，獨上危亭喜再瞻。',64,'全唐诗/poet.song.38000.json','["白金鋪野玉堆簷，獨上危亭喜再瞻。", "多積豈能填澗底，已髙猶未累山尖。", "碎聲著物飄來急，寒色侵人霽後添。", "時節霏霏未還役，賊平消息願重占。"]'),
('18ffc60a-4e0c-408c-8154-845ebdb0923c','岷峨王髙士賫牟中秘墨帖來求跋自言能護真氣鍊大丹罹兵禍而輟同輩有志於斯事者皆然又言老人村凡二三百歲者亦皆死於兵嗟夫兵之禍生靈甚矣禍蜀則尤慘禍及髙士更不輕矣遂爲之賦詩','呂陶','宋','宋诗','song-poetry','','[]','道人少日鍊神形，兵禍俄乘竟不成。',64,'全唐诗/poet.song.38000.json','["道人少日鍊神形，兵禍俄乘竟不成。", "欠爲黄庭判一死，所酬丹事又三生。", "眼看殘盡雞窠老，膽破寧寒犬舐盟。", "豹養虎攻嗟爾似，却求翰墨作虛名。"]'),
('28cc40cd-d299-4cf0-9f95-1fd2b02dc263','石泉道中和綿州通判李朝散見寄','呂陶','宋','宋诗','song-poetry','','[]','深僻崎危不厭過，欲將涓滴助恩波。',64,'全唐诗/poet.song.38000.json','["深僻崎危不厭過，欲將涓滴助恩波。", "躡雲髙步三休在，踏雪清寒一倍多。", "依約度溪投野店，逡巡扶杖歷新坡。", "初春此去纔旬日，屈指流年奈老何。"]'),
('a6d71b48-dc1b-4e5f-a932-30f74b1c12a1','有觸','呂陶','宋','宋诗','song-poetry','','[]','三十餘年齒士林，青綸一命鬢霜侵。',64,'全唐诗/poet.song.38000.json','["三十餘年齒士林，青綸一命鬢霜侵。", "策名雖動遲留嘆，行已常存少壯心。", "月滿漲潭清遠夢，春歸平野付長吟。", "前溪況亦稱南浦，惜别情悰幾倍深。"]'),
('0ecd1948-fbd6-41f3-bf7a-76eee1cac098','城西龍祠二首  其一','呂陶','宋','宋诗','song-poetry','','[]','市橋官柳翠陰垂，路嚮西郊駐彩旂。',64,'全唐诗/poet.song.38000.json','["市橋官柳翠陰垂，路嚮西郊駐彩旂。", "故事毎從遐俗尚，清歡又送晚春歸。", "留連野色遲遲去，珍惜年華苒苒飛。", "老杜有詩殊有味，風光流轉莫相違。"]'),
('0718e1f3-83ae-4f11-a69e-9a24ed407d6a','城西龍祠二首  其二','呂陶','宋','宋诗','song-poetry','','[]','林密溪寒錦浦西，千年靈宇舊憑依。',64,'全唐诗/poet.song.38000.json','["林密溪寒錦浦西，千年靈宇舊憑依。", "竹村迎路堪行樂，麥壟連雲已應祈。", "詩將早從吟社去，遊人暮到醉鄉歸。", "隼旟莫倦徘徊久，化日舒長未夕輝。"]'),
('9358671b-82c6-4869-ba73-b430f51a90f3','和賞申氏園海棠','呂陶','宋','宋诗','song-poetry','','[]','誰裁錦段碎文章，憑借春工便吐芳。',64,'全唐诗/poet.song.38000.json','["誰裁錦段碎文章，憑借春工便吐芳。", "自是多花宜少葉，肯教仙格有凡香。", "妝容試酒偏增麗，舞興迎春擬作狂。", "使幕縣庭雖甲乙，更饒鄰圃借餘光。"]'),
('4adf6bac-4b76-4efb-b852-89a0b8b3b702','和姚提舉賞海棠','呂陶','宋','宋诗','song-poetry','','[]','曉霧籠花暖漸收，萬枝難盡數花頭。',64,'全唐诗/poet.song.38000.json','["曉霧籠花暖漸收，萬枝難盡數花頭。", "臙脂半爲傷春淡，錦带翻因拂地羞。", "圍飲舊風傳樂國，縱吟清味屬詩流。", "西園韶景真無價，紅滿池臺月滿樓。"]'),
('b38dbe16-630c-4f35-b202-5ae5f8d8d14b','和蜀守道中書事','呂陶','宋','宋诗','song-poetry','','[]','天恩流布下天津，沴氣消除生氣淳。',64,'全唐诗/poet.song.38000.json','["天恩流布下天津，沴氣消除生氣淳。", "昔慮早饑農失職，今逢賑惠澤如春。", "綏懷有術推儒者，全活爲功類古人。", "賢傑一心溝壑起，翕然歌頌在生民。"]'),
('5dc30140-6ca7-4b70-9e94-4ece09da8da7','題友人西行雜詩','呂陶','宋','宋诗','song-poetry','','[]','一官一集古稱賢，未似西征五十篇。',64,'全唐诗/poet.song.38000.json','["一官一集古稱賢，未似西征五十篇。", "雅頌純音流管磬，風騷餘味到林泉。", "光生曉岫刊岷石，價踴春溪費錦牋。", "愧幸師門舊林教，得爲家寶子孫傳。"]'),
('8ef1e6da-5783-4f9f-bb35-a5d9e546aa41','讀黜邪詔','呂陶','宋','宋诗','song-poetry','','[]','天詔丁寧逐佞柔，不須請劍復持矛。',64,'全唐诗/poet.song.38000.json','["天詔丁寧逐佞柔，不須請劍復持矛。", "平生邪膽君前落，後世汙名紙上傳。", "寶鑑乍開消魍魅，正聲纔作罷離兜。", "便爲葅醢何嗟及，貪得浮榮似食鈎。"]'),
('59e07cce-36c5-4777-a636-78fdccdb3eec','晚倚南樓','呂陶','宋','宋诗','song-poetry','','[]','野情無限物無窮，一凭危樓又晚空。',64,'全唐诗/poet.song.38000.json','["野情無限物無窮，一凭危樓又晚空。", "過雨郊原渾積翠，送春亭榭尚餘紅。", "煙光已屬綃圖上，湖影初歸寶鑑中。", "飛鳥潛魚應自得，倚欄小憩豁雙瞳。"]'),
('ac008917-cf5b-4632-afb9-4c1468597c44','送張穎達屯田','呂陶','宋','宋诗','song-poetry','','[]','西風獵獵馬駸駸，極目歸途寄静呤。',64,'全唐诗/poet.song.38000.json','["西風獵獵馬駸駸，極目歸途寄静呤。", "美玉自藏圭璧用，寒松偏有雪霜心。", "皆知舊德淹郎署，合寵耆儒鎮士林。", "勢利競馳孤介少，爲懷清誼動離襟。"]'),
('6cd490e6-f075-4a3f-a8df-71d50d9a3649','和寄治之少卿','呂陶','宋','宋诗','song-poetry','','[]','榮路層層滿眼開，家山在望懶徘徊。',64,'全唐诗/poet.song.38000.json','["榮路層層滿眼開，家山在望懶徘徊。", "霜侵客鬢須歸去，塵拂朝冠是儻來。", "一棹綠波遊不厭，三竿紅日夢初回。", "更聞觴咏同幽趣，應少閒人可預陪。"]'),
('1e33bad6-3250-4e74-937f-473fa9b721f7','送張静之少卿東歸','呂陶','宋','宋诗','song-poetry','','[]','禮寺居卿寵搢紳，若求清議尚沈淪。',64,'全唐诗/poet.song.38000.json','["禮寺居卿寵搢紳，若求清議尚沈淪。", "三千里外甘投足，四十年前已化鱗。", "何必萬鍾如己欲，好將一笑寓天真。", "當時共獻藏珠賦，壽考康寧有幾人。"]'),
('fd9da082-0b01-43dc-be89-6deb93ef36c4','象棋二首  其一','呂陶','宋','宋诗','song-poetry','','[]','咫尺楸枰計慮深，偶緣嬉戯便交侵。',64,'全唐诗/poet.song.38000.json','["咫尺楸枰計慮深，偶緣嬉戯便交侵。", "縱横各有往來道，勝負豈無名利心。", "終局漫誇兵得地，在宫渾倚士如林。", "安危成敗何殊此，付與閒人爲討尋。"]'),
('bbbaa9d0-890d-4098-8873-e6a3e645fe0a','象棋二首  其二','呂陶','宋','宋诗','song-poetry','','[]','星布重重陣脚深，不須輕敵事相侵。',64,'全唐诗/poet.song.38000.json','["星布重重陣脚深，不須輕敵事相侵。", "渡河雖藉奇兵勢，對壘難知老將心。", "酬酢巨杯宜燕席，消磨永日稱山林。", "呼盧格五前賢有，莫笑年來共講尋。"]'),
('24b3d6e4-d326-4d33-9f5e-eb1d8fb91f11','送楊聖愈口中赴益倅','呂陶','宋','宋诗','song-poetry','','[]','畫轅曾記到西州，莫爲題輿厭滯留。',64,'全唐诗/poet.song.38000.json','["畫轅曾記到西州，莫爲題輿厭滯留。", "官況優如支郡樂，風光渾似昔年游。", "日無餘事知閒暇，時有清呤競唱酬。", "政績易成恩典在，天涯不覺兩經秋。"]'),
('2e426af5-9399-4f63-bf06-5e07f69c1028','寓意','呂陶','宋','宋诗','song-poetry','','[]','夕陽芳草自天涯，倦客何須感物華。',64,'全唐诗/poet.song.38000.json','["夕陽芳草自天涯，倦客何須感物華。", "無計可能逃世網，有心剛欲慕詩家。", "將烹誰惜能鳴鴈，安足翻成強畫蛇。", "白髪漸多瞳漸翳，少年相見莫揄揶。"]'),
('ccf9934c-2c04-47a0-b755-e41cedaaa3a2','秋郊','呂陶','宋','宋诗','song-poetry','','[]','西風蕭瑟動年華，村望猶將景物誇。',64,'全唐诗/poet.song.38000.json','["西風蕭瑟動年華，村望猶將景物誇。", "山色半隨雲勢斷，浮光多被竹陰遮。", "社前歸興雙飛燕，雨後新聲幾處蛙。", "萬里橋南亦如此，十分有意作農家。"]'),
('3c13a1bc-300b-4000-8694-bf35e3f327d9','寄唐君益','呂陶','宋','宋诗','song-poetry','','[]','秋日晴如春日遲，山間水際盡光輝。',64,'全唐诗/poet.song.38000.json','["秋日晴如春日遲，山間水際盡光輝。", "江湖頓減騷人詠，父老爭誇太守歸。", "歲晚莫驚松易葉，時來又見錦爲衣。", "門前行馬雖崇峻，應許衰翁一叩扉。"]'),
('7c728f26-9452-4bf9-9ff1-3c2dea6005df','廣安鹿嗚燕送諸進士','呂陶','宋','宋诗','song-poetry','','[]','文章得雋自雄飛，平地青雲有路岐。',64,'全唐诗/poet.song.38000.json','["文章得雋自雄飛，平地青雲有路岐。", "勸駕寂寥慚漢詔，升歌彷彿見周詩。", "九秋煙雨登臨日，三月風雷變化時。", "回首不須題競渡，錦標爭勝已先知。"]'),
('cc41b173-f1c2-418f-885d-2d427a9011f8','次韻李才元舍人二首  其一','呂陶','宋','宋诗','song-poetry','','[]','求閒得請信賢哉，曾歷星垣侍從來。',64,'全唐诗/poet.song.38000.json','["求閒得請信賢哉，曾歷星垣侍從來。", "標節向人清似玉，紛華於己冷如灰。", "仙壇露重吟懷爽，禪榻風輕睡眼開。", "昨日尋梅奉談笑，竹軒松塢共徘徊。"]'),
('b5812816-a50e-4f43-a7a9-36f0eefb8465','次韻李才元舍人二首  其二','呂陶','宋','宋诗','song-poetry','','[]','當年累疏徹堯廷，不爲虚名自得名。',64,'全唐诗/poet.song.38000.json','["當年累疏徹堯廷，不爲虚名自得名。", "霜雪盛來松秀茂，風波散後水澄清。", "紅塵漸與高情隔，綠髪應隨喜氣生。", "否泰卷舒公自悟，不須端筴問君平。"]'),
('01f91560-5c0f-4f4d-bcc5-ebc1b3e41a3f','致政侍郎知郡學士賡和詩凡數篇謹用元韻寄呈知郡學士','呂陶','宋','宋诗','song-poetry','','[]','玉色諸兒馥若蘭，綵衣想見日承顔。',64,'全唐诗/poet.song.38000.json','["玉色諸兒馥若蘭，綵衣想見日承顔。", "塵纓遠濯滄浪水，燕几深居畏壘山。", "俗眼漫譏身察察，人情方喜志閒閒。", "夕陽歸興隨飛鳥，真意無人語此還。"]'),
('2f36ab7c-1fe5-4785-8f2b-856b6a291219','遊交城石壁寺二首  其一','呂陶','宋','宋诗','song-poetry','','[]','十里縈紆路轉山，山城深入翠微間。',64,'全唐诗/poet.song.38000.json','["十里縈紆路轉山，山城深入翠微間。", "何年勝地雲霞老，終日清風歳月閒。", "池上蟄龍方隱伏，巖前遊客暫躋攀。", "却嗟鸞綽遺居在，難向空堦一叩關。"]'),
('4e473152-1bd4-4ece-af7b-23599b596b62','遊交城石壁寺二首  其二','呂陶','宋','宋诗','song-poetry','','[]','山僧何事下山迎，步徹山腰到寺庭。',64,'全唐诗/poet.song.38000.json','["山僧何事下山迎，步徹山腰到寺庭。", "清梵一聲沈夕籟，碧嵐千幅展春屏。", "自慚韁鎖非真賞，乍見林泉似獨醒。", "回首暮鐘留恨處，斷煙層靄倍青青。"]'),
('e66ce927-61d2-4707-811a-c3a80f28ff8a','題信相院林亭','呂陶','宋','宋诗','song-poetry','','[]','深靜禪門秋復春，不知門外是紅塵。',64,'全唐诗/poet.song.38000.json','["深靜禪門秋復春，不知門外是紅塵。", "滿庭修竹有君子，終日好風如故人。", "曲徑最宜巢翠羽，澄潭猶足養纖鱗。", "年年寓泊知閒味，毎謝林泉作四鄰。"]'),
('0cdc1d68-780b-4283-bb8b-a7e6d67617a2','按視麋棗堰次韻','呂陶','宋','宋诗','song-poetry','','[]','郊原氣象欲迎春，祠下喬林秀色勻。',64,'全唐诗/poet.song.38000.json','["郊原氣象欲迎春，祠下喬林秀色勻。", "數里舊防能禦患，二江流水不迷津。", "輿言此日蒙深利，惠政當時念遠人。", "公意勤勤議增築，又逢賢傑繼芳塵。"]'),
('ec7dd7e1-dc6e-4dc6-8cf8-5c2f4fbb6841','麋棗道中','呂陶','宋','宋诗','song-poetry','','[]','藩政雍容慮在民，暫行千騎按江津。',64,'全唐诗/poet.song.38000.json','["藩政雍容慮在民，暫行千騎按江津。", "寒侵客袂逢輕雨，翠拂林梢覺淺春。", "極望風光迷綠野，縱吟懷抱脱紅塵。", "願公改作劉公堰，留得嘉名諭蜀人。"]'),
('133f37fa-b15f-4e5b-ba10-8f2f33e84fa4','松','呂陶','宋','宋诗','song-poetry','','[]','游人何事種芳菲，試把庭松較盛衰。',64,'全唐诗/poet.song.38000.json','["游人何事種芳菲，試把庭松較盛衰。", "得地不將天質改，有心惟與歳寒期。", "一軒野色栽培後，十月霜華秀茂時。", "造化果能周及物，亦須千丈引喬枝。"]'),
('036fd2c2-9947-401f-95ab-43c90155ad19','遣興','呂陶','宋','宋诗','song-poetry','','[]','毎嗟無計遠紅塵，願讀仙書學養真。',64,'全唐诗/poet.song.38000.json','["毎嗟無計遠紅塵，願讀仙書學養真。", "收得寸心清似水，放教雙鬢白於銀。", "功名見誤回頭晚，風物相驚滿眼新。", "一卷黄庭有深趣，誦持聊以愛吾身。"]'),
('414dcc67-7f1d-4cad-84de-057ef7705cb1','和李寶文紫庭玉節花','呂陶','宋','宋诗','song-poetry','','[]','雲枝玉蘂兩難加，應是殊庭種此花。',64,'全唐诗/poet.song.38000.json','["雲枝玉蘂兩難加，應是殊庭種此花。", "地產有時呈秀異，仙標無意競繁華。", "已持寶瑞傳君命，更擁香幢送道家。", "若預景文方物志，定先羣卉贊祥葩。"]'),
('b7573b3a-1557-4d41-bd59-84d219cd26da','送李寶文還朝','呂陶','宋','宋诗','song-poetry','','[]','使華西指主恩深，又見鰲頭此鎮臨。',64,'全唐诗/poet.song.38000.json','["使華西指主恩深，又見鰲頭此鎮臨。", "十載星霜皆化日，百城桃李盡穠陰。", "層霄自得翺翔路，止水難摇淡靜心。", "全蜀蒼黔共傾耳，即聞和氣入薰琴。"]'),
('e18db660-496d-4e9f-9280-c7906607deb2','古松館','呂陶','宋','宋诗','song-poetry','','[]','大字新題重古松，標題不與衆人同。',64,'全唐诗/poet.song.38000.json','["大字新題重古松，標題不與衆人同。", "何年直幹藏山驛，半夜寒聲滿道宫。", "並秀雅宜雲壑外，相逢最愛雪霜中。", "秋深縱使喬林減，未許堅姿墜晚風。"]'),
('66a1e8ae-bbf2-4ce8-bbca-9b10d63dd436','和郄仲輔開化寺三首  其一','呂陶','宋','宋诗','song-poetry','','[]','寺在西山第幾重，山僧相遇喜相容。',64,'全唐诗/poet.song.38000.json','["寺在西山第幾重，山僧相遇喜相容。", "寂無塵慮到禪室，瞥有秋聲來野松。", "已恨夕陽催返轡，又過危磴聽殘鐘。", "煙霞更約他時望，未必高懷負翠峰。"]'),
('f3a03097-1cf0-4fcb-b8eb-66d80bfeda4e','和郄仲輔開化寺三首  其二','呂陶','宋','宋诗','song-poetry','','[]','目前塵坌最重重，乍見名山喜動容。',64,'全唐诗/poet.song.38000.json','["目前塵坌最重重，乍見名山喜動容。", "選勝道裝堪著屐，談禪麈柄亦揮松。", "千尋急欲攀秋徑，十里猶聞擊午鐘。", "下得巒林又牽俗，特書歸恨寄晴峰。"]'),
('240c76b8-b547-4c53-af57-d597e382652e','和郄仲輔開化寺三首  其三','呂陶','宋','宋诗','song-poetry','','[]','煙嵐深處幾千重，難向丹靑寫物容。',64,'全唐诗/poet.song.38000.json','["煙嵐深處幾千重，難向丹靑寫物容。", "層閣試憑窺百里，函經慵讀倚雙松。", "喬林乍響因秋籟，棲鳥頻驚爲晚鐘。", "莫笑下山猶悵望，浪仙平昔愛三峰。"]'),
('fa2bb9b0-7416-47da-8ed4-fcec45432e28','送錢端履歸二曲','呂陶','宋','宋诗','song-poetry','','[]','君去金淵十五春，暫歸翻是客中身。',64,'全唐诗/poet.song.38000.json','["君去金淵十五春，暫歸翻是客中身。", "千年丘壟勝當日，兩世親朋無幾人。", "麈尾幸能銷白書，馬蹄還厭踏紅塵。", "錦衣會有重來約，應笑衰翁漉酒巾。"]'),
('2dfecb9b-defc-47eb-bd48-f9d9c196a0ed','晚飲','呂陶','宋','宋诗','song-poetry','','[]','霽景宜將遠眼看，綠陰垂地已春闌。',64,'全唐诗/poet.song.38000.json','["霽景宜將遠眼看，綠陰垂地已春闌。", "山巓日出方乘暖，峽口風來又作寒。", "老去心情非往事，閒中談笑有餘歡。", "玉盤四照江如練，忍對澄輝不倚闌。"]'),
('8a9955b9-6196-4e26-9826-89c647fbc239','送文達甫贊善','呂陶','宋','宋诗','song-poetry','','[]','洪河一曲晉溪濱，自有餘波及四鄰。',64,'全唐诗/poet.song.38000.json','["洪河一曲晉溪濱，自有餘波及四鄰。", "循吏風聲今慕昔，淡交情味故如新。", "江山極目登臨遠，歲月驚心聚散頻。", "無限名園費吟賞，化工偏與洛陽春。"]'),
('8e3ef3d5-a090-4ff9-b7da-8b25638d41be','和成都轉運判官孫聖微見寄','呂陶','宋','宋诗','song-poetry','','[]','文章平昔擅才名，使指於今總列城。',64,'全唐诗/poet.song.38000.json','["文章平昔擅才名，使指於今總列城。", "甲乙常聯榜中第，東西俱作劍南行。", "清吟愈覺交朋厚，老别難堪歲月驚。", "惟喜歸途近霄漢，吾鄉留得是嘉聲。"]'),
('f4ea979c-d6ce-4482-8ed4-da45e28e79c5','和重己晚菊三首  其一','呂陶','宋','宋诗','song-poetry','','[]','衆菊爭開此獨遲，已過重九見新枝。',64,'全唐诗/poet.song.38000.json','["衆菊爭開此獨遲，已過重九見新枝。", "自甘化力均先後，不與春芳較盛衰。", "秀蘂漸繁微雨夜，清香終在早霜時。", "詩人未便移青眼，會有金樽是己知。"]'),
('86308e3f-819c-4a2f-a7e0-1cd464d1c269','和重己晚菊三首  其二','呂陶','宋','宋诗','song-poetry','','[]','花開雖晚莫嗟遲，落盡千葩發幾枝。',64,'全唐诗/poet.song.38000.json','["花開雖晚莫嗟遲，落盡千葩發幾枝。", "清露有恩殊未報，寒風無賴不能衰。", "幽芳自占三秋景，真賞堪同九日時。", "蝶少蜂愁人事别，餐英獨有屈平知。"]'),
('4bb4b1c2-fb89-435e-a844-c99e4ab9f256','和重己晚菊三首  其三','呂陶','宋','宋诗','song-poetry','','[]','仙翁培種一何遲，點綴黄金更滿枝。',64,'全唐诗/poet.song.38000.json','["仙翁培種一何遲，點綴黄金更滿枝。", "秋色已高方秀茂，物華皆老未凋衰。", "幾多俗客慵留意，無限妖花笑後時。", "獨向風霜對松竹，潔清標格自相知。"]'),
('bc6afc0b-0ded-41a4-926c-28cd1e4e21f9','聞說一首寄與可爲堯夫作','呂陶','宋','宋诗','song-poetry','','[]','聞說蓬仙作小麾，湛恩從此破羣疑。',64,'全唐诗/poet.song.38000.json','["聞說蓬仙作小麾，湛恩從此破羣疑。", "平生直道宜三黜，自古周防用四知。", "松竹何嘗凋晚秀，稻梁應且續朝饑。", "不須利口歸豺虎，皎皎清穹未易欺。"]'),
('9a6876e9-c0b0-4143-8f6e-91d450012871','次韻贈陳季常','呂陶','宋','宋诗','song-poetry','','[]','一塵殊不掛胸中，標韻高閒辯論雄。',64,'全唐诗/poet.song.38000.json','["一塵殊不掛胸中，標韻高閒辯論雄。", "詩得江山深有助，道因橐籥易爲功。", "平生擬效漆園吏，何日相逢黄石公。", "可惜壯年長策在，却陪明月與清風。"]'),
('a3232f05-8716-4ca7-bef1-dece7e9de5cb','伏日池上二首  其一','呂陶','宋','宋诗','song-poetry','','[]','塵氛不到此池亭，庚伏長來駐旆旌。',64,'全唐诗/poet.song.38000.json','["塵氛不到此池亭，庚伏長來駐旆旌。", "波蕩畫船衝岸急，露明翠蓋遇風傾。", "一先有得棋頻勝，衆樂無嫌酒屢行。", "紅日漸低鐘鼓近，路人歌笑望專城。"]'),
('3b457555-ee84-4933-8bc2-64939abbaf59','伏日池上二首  其二','呂陶','宋','宋诗','song-poetry','','[]','南風時起有餘溫，晷影炎炎勢欲焚。',64,'全唐诗/poet.song.38000.json','["南風時起有餘溫，晷影炎炎勢欲焚。", "堤上遊人皆樂俗，坐中豪客少將軍。", "深思闊沼生冰色，尤畏晴霞散錦紋。", "待得清凉到襟袖，斷煙重疊送西曛。"]'),
('bc3efbc6-b3c6-4060-906c-5fb4ee44ef05','題致仕袁成均燕申亭','呂陶','宋','宋诗','song-poetry','','[]','掛冠歸後愛林泉，擇地爲亭欲看山。',64,'全唐诗/poet.song.38000.json','["掛冠歸後愛林泉，擇地爲亭欲看山。", "清畫絕無塵坌到，白雲常與性情閒。", "詩書教子雍容外，琴酒娛賓笑傲間。", "堂構不隳門有慶，綵衣終約錦衣還。"]'),
('61c2a7f6-aeb2-4db7-897e-294208f4c290','送李寶之','呂陶','宋','宋诗','song-poetry','','[]','流落文場晚得名，十年猶未脱銓衡。',64,'全唐诗/poet.song.38000.json','["流落文場晚得名，十年猶未脱銓衡。", "軒昂本爲太平起，憤歎却因多難成。", "方略滿懷期樹立，塵埃蒙袂且將迎。", "由來不遇須藏器，豈是佯愚學甯生。"]'),
('9fc560e7-9d17-46f4-81ec-06ef44aead28','送修孺歸通泉用陳圖南韻','呂陶','宋','宋诗','song-poetry','','[]','猿鶴皆飛昔日聲，安車歸去路岐平。',64,'全唐诗/poet.song.38000.json','["猿鶴皆飛昔日聲，安車歸去路岐平。", "高懷無累能知止，半禄雖微亦代耕。", "林下光陰尤覺永，環中氣象有餘清。", "塵埃滿抱華顛客，笑指泉山羡此行。"]'),
('d99a0816-7d06-42de-8a31-72397778b270','次韻送人有感','呂陶','宋','宋诗','song-poetry','','[]','三月山城送客時，山頭芳草又離離。',64,'全唐诗/poet.song.38000.json','["三月山城送客時，山頭芳草又離離。", "紅塵道路今猶古，清酒罇罍樂勝悲。", "鄉外忽搖懷遠意，坐中聊賦惜春詩。", "洛陽風景别來久，應屬少年游俠兒。"]'),
('dd43f086-ffe2-4c1b-8fdc-44fd18580f3f','送交代茹安禮二首  其一','呂陶','宋','宋诗','song-poetry','','[]','平日陽和已浹民，浪馳幽迹紹芳塵。',64,'全唐诗/poet.song.38000.json','["平日陽和已浹民，浪馳幽迹紹芳塵。", "芝蘭秀品推前輩，桃李清陰及後人。", "諄誨有聞知契厚，縱談無間覺情親。", "去思從此憑何慰，待刻銘詞上翠珉。"]'),
('c608fca9-1ba1-4c8f-bae5-c087cbff4975','送交代茹安禮二首  其二','呂陶','宋','宋诗','song-poetry','','[]','越溪春水碧迢迢，岷岫晴嵐翠欲飄。',64,'全唐诗/poet.song.38000.json','["越溪春水碧迢迢，岷岫晴嵐翠欲飄。", "故國風光頻夢斷，殊鄉景物易魂銷。", "何時執友無暌索，此日長亭倍寂寥。", "把酒送君同一醉，羡君東去客心搖。"]'),
('cb2f84bf-7a13-47e2-9e0c-bf66d22b1daf','送曹憲州','呂陶','宋','宋诗','song-poetry','','[]','山頭紅日照紅旌，祖席仍歌塞上行。',64,'全唐诗/poet.song.38000.json','["山頭紅日照紅旌，祖席仍歌塞上行。", "慷慨有心終破敵，燕閒無事暫專城。", "朔風動色驊騮健，秋水澄光寶劍輕。", "萬一羽書飛到郡，定煩方略取功名。"]'),
('508ba332-e8e5-4df1-8991-c38c43e93ad4','送范庠博','呂陶','宋','宋诗','song-poetry','','[]','十載閒經紫塞秋，辟書連上得君留。',64,'全唐诗/poet.song.38000.json','["十載閒經紫塞秋，辟書連上得君留。", "一身已共冰壺潔，八法堪同墨寶收。", "壽几歡心憐綵服，詩庭虚席待良籌。", "古今京洛風埃甚，去有亨途莫倦遊。"]'),
('bb57d0e8-5886-4206-9220-1a58f7c6a7e8','再和送李大夫','呂陶','宋','宋诗','song-poetry','','[]','莫聽灘前漲水聲，少遲樽酒話平生。',64,'全唐诗/poet.song.38000.json','["莫聽灘前漲水聲，少遲樽酒話平生。", "堪嘉祁老初辭位，却笑樊須欲問耕。", "落日望君三舍遠，西風惠我一襟清。", "江流自在悠哉興，得得回船十里行。"]'),
('7bcbf25e-61fc-435c-932f-1f34b595dfbd','送永康司理張思純東歸','呂陶','宋','宋诗','song-poetry','','[]','曾把叢蓍叩大鈞，少逢升漸屢逢屯。',64,'全唐诗/poet.song.38000.json','["曾把叢蓍叩大鈞，少逢升漸屢逢屯。", "平生道在惟藏器，今日途窮恥問津。", "萬事感懷歸白髪，九衢欺客是紅塵。", "何須便作林泉計，未必文章誤此身。"]'),
('f09beffa-a1f8-40b1-9129-37d256b4ef36','送秭歸胡宜甫','呂陶','宋','宋诗','song-poetry','','[]','京洛前年困客塵，孤舟今去楚江濱。',64,'全唐诗/poet.song.38000.json','["京洛前年困客塵，孤舟今去楚江濱。", "位無高下在行己，邑有政刑宜福民。", "人子歡心憐白髪，壯夫幽抱感青春。", "弦歌已治庭闈樂，休說窮通問大鈞。"]'),
('5be31033-0422-4ea1-9a37-1d9653b86b42','送淳于温其','呂陶','宋','宋诗','song-poetry','','[]','五陵豪客攬歸鞍，行矣休嗟蜀道難。',64,'全唐诗/poet.song.38000.json','["五陵豪客攬歸鞍，行矣休嗟蜀道難。", "世治不須專將閫，才雄自可陟詩壇。", "虎符金印亨途在，夜笛秋琴逸氣安。", "至寶投人猶按劍，慎將騷雅載毫端。"]'),
('f6c24318-d846-4e2f-b867-34585469d01b','送道粹','呂陶','宋','宋诗','song-poetry','','[]','泛交如面頗紛紛，珍重賢豪有所存。',64,'全唐诗/poet.song.38000.json','["泛交如面頗紛紛，珍重賢豪有所存。", "高論向人須藥石，壯心於俗不寒温。", "已懷忠孝歸儒術，誓取功勳襲將門。", "蜀道阻長秦塞闊，夕陽芳草最銷魂。"]'),
('2ab2da3f-2865-4d1e-b45e-e7376328fbde','大享肆赦府帥賦詩次其韻','呂陶','宋','宋诗','song-poetry','','[]','運際重熙講克禋，祖宗嚴配答慈仁。',64,'全唐诗/poet.song.38000.json','["運際重熙講克禋，祖宗嚴配答慈仁。", "典章備物該三代，殿寶殊名應五辰。", "早歲侍祠曾受嘏，外方留鎮屢頒春。", "皇恩更遠皆宣布，自此祥風起八垠。"]'),
('07443a6f-550d-441c-a5af-2b158c0128ea','答文通即席見及','呂陶','宋','宋诗','song-poetry','','[]','春華穠處客心闌，俗事勞勞近萬端。',64,'全唐诗/poet.song.38000.json','["春華穠處客心闌，俗事勞勞近萬端。", "嘉景良朋豈常遇，清詩濁酒暫相歡。", "飄零宦況誠非欲，烜赫名途未易干。", "惜别戀游深意在，寄聲絃上約誰彈。"]'),
('8acc9cb8-bae5-45fa-982b-eb58757d86b6','喜文通西歸','呂陶','宋','宋诗','song-poetry','','[]','毎記江頭舉别觴，别來如昨幾炎涼。',64,'全唐诗/poet.song.38000.json','["毎記江頭舉别觴，别來如昨幾炎涼。", "年華莫問當時水，鬢髪皆添近日霜。", "伏櫪已甘常蹭蹬，凌雲猶滯遠翺翔。", "羨君標韻終蕭灑，恰是花開到故鄉。"]'),
('c9a36112-a939-4269-888d-0997067ff0ef','喻明仲自成都憲使領漕湖北','呂陶','宋','宋诗','song-poetry','','[]','荆楚旬宣盛事誇，十年重復賦皇華。',64,'全唐诗/poet.song.38000.json','["荆楚旬宣盛事誇，十年重復賦皇華。", "更弦已見調疏越，切玉猶須試鏌鎁。", "隨手春風飄塞下，迴頭膏雨潤天涯。", "親聞父老慇懃說，溝壑沾恩數百家。"]'),
('ebeb5301-09e6-4915-bef2-2ab0ca73e4b5','寄眉守黎希聲','呂陶','宋','宋诗','song-poetry','','[]','千騎駸駸出錦城，鄉人翹首望先生。',64,'全唐诗/poet.song.38000.json','["千騎駸駸出錦城，鄉人翹首望先生。", "二年爲郡應須樂，數日遊山已快晴。", "泉石有誰陪道話，雲霞無限愜詩情。", "紅塵拂袂良朋少，時向西風願寄聲。"]'),
('e081ea1f-2e6f-4784-86fe-d25e48fb05f9','送戴正仲大夫歸玉局','呂陶','宋','宋诗','song-poetry','','[]','請得琳宫别未央，西行行色重增光。',64,'全唐诗/poet.song.38000.json','["請得琳宫别未央，西行行色重增光。", "官曹冷淡如逋客，風物鮮明類故鄉。", "歸去林泉謀已定，閒中詩酒味偏長。", "市橋側畔鄰居日，應許過從亦道裝。"]'),
('8ec86325-f9c4-4672-a402-b32739c39d00','送陳正臣遊昌元','呂陶','宋','宋诗','song-poetry','','[]','三月狂風不惜春，客愁千斛付行人。',64,'全唐诗/poet.song.38000.json','["三月狂風不惜春，客愁千斛付行人。", "平生操履由吾道，何日安閒遂此身。", "陌上紛華空白晝，山中氣味少紅塵。", "歸來必遇求賢詔，莫向窮途苦問津。"]'),
('89f246ba-86af-42b4-af31-ccdd242ba81b','答趙賓與同年見寄','呂陶','宋','宋诗','song-poetry','','[]','羨君方寸最澄清，何必滄浪更濯纓。',64,'全唐诗/poet.song.38000.json','["羨君方寸最澄清，何必滄浪更濯纓。", "玉麈縱談聊入幕，錦衣歸養自專城。", "交情久似喬松茂，詩興濃如皎月明。", "閲味來章佩勤好，却慚塵耳聽咸莖。"]'),
('c72c5798-ab7d-48c6-ab38-9c39606aeaf5','和子瞻寄希聲二首  其一','呂陶','宋','宋诗','song-poetry','','[]','通江山水甲岷川，和氣融融滿四邊。',64,'全唐诗/poet.song.38000.json','["通江山水甲岷川，和氣融融滿四邊。", "儒者易成千里政，鄉人近得兩重天。", "金罍淺飲雖歌舞，玉麈高談盡聖賢。", "不是春秋爲冷學，借留何計及三年。"]'),
('e8d5b3db-d56b-4a81-8aef-4ff5a0dc6291','和子瞻寄希聲二首  其二','呂陶','宋','宋诗','song-poetry','','[]','海勢茫茫會百川，一麾正在海西邊。',64,'全唐诗/poet.song.38000.json','["海勢茫茫會百川，一麾正在海西邊。", "鴻收迅翮方棲渚，鶴吐清音自徹天。", "落筆盡降詩裏將，放懷常對酒中賢。", "及鋒急用應非晚，留滯紅塵已數年。"]'),
('975db7e0-d80d-431e-86fe-7f48cd315ac5','和信夫屯田疾間偶作二首  其一','呂陶','宋','宋诗','song-poetry','','[]','安居無事莫興嗟，聊放高情喜溢涯。',64,'全唐诗/poet.song.38000.json','["安居無事莫興嗟，聊放高情喜溢涯。", "攬照不驚頭染雪，讀書未信眼生花。", "謳吟罷後詩筒減，方論搜來藥劑加。", "見說道心從此壯，幾因清夢到仙家。"]'),
('ef3e4f96-5e20-47b9-923d-55cb07a72b46','和信夫屯田疾間偶作二首  其二','呂陶','宋','宋诗','song-poetry','','[]','仕路浮沈不足嗟，到頭何處是津涯。',64,'全唐诗/poet.song.38000.json','["仕路浮沈不足嗟，到頭何處是津涯。", "庭中度日多無事，湖上經年各有花。", "熟焙春芽香不散，輕澄臘醑味偏加。", "憑君莫賦思歸引，一郡相歡似一家。"]'),
('9031e9f9-cf93-4a63-b444-98bf613e0fdf','和王霽太博見寄','呂陶','宋','宋诗','song-poetry','','[]','惜别心情彼此難，想君歸去自能安。',64,'全唐诗/poet.song.38000.json','["惜别心情彼此難，想君歸去自能安。", "輕舟盪槳依平岸，快水流冰下險灘。", "夢到親聞方歲晚，路迎江國少春寒。", "牡丹時節西園醉，不得相同一倚闡。"]'),
('de3c64f0-16f0-4643-9a70-04fe6ced9c37','送皇甫秉彛殿丞','呂陶','宋','宋诗','song-poetry','','[]','征車千里極關河，特遣離懷賦綠波。',64,'全唐诗/poet.song.38000.json','["征車千里極關河，特遣離懷賦綠波。", "晚節不隨華髪變，歸裝還載異書多。", "雲霄有約增攀望，文酒相逢異嘯歌。", "若相清朝許投筆，生平孤劍願重磨。"]'),
('ec82868a-30c5-4ec3-b9af-a87d982cf954','戢武堂書事和韻','呂陶','宋','宋诗','song-poetry','','[]','永日華堂靜掩扉，道腴深味敵珍肥。',64,'全唐诗/poet.song.38000.json','["永日華堂靜掩扉，道腴深味敵珍肥。", "一軒有景詩求勝，十邑無塵寇懾威。", "雅性自髙閒去樂，汎交難合信來稀。", "誦君清句知君意，祗任天真不任機。"]'),
('5ed435f1-cc22-4fe0-81be-a1913d4af74f','和董奉議喜雨','呂陶','宋','宋诗','song-poetry','','[]','需雲廿澤爲時來，間作雄風鼓迅雷。',64,'全唐诗/poet.song.38000.json','["需雲廿澤爲時來，間作雄風鼓迅雷。", "信有威靈周闔境，應無偏黨限枯荄。", "滿山和氣卷舒易，一夜豐年消息回。", "愆亢霖霪皆吏責，幸憑神力庇凡材。"]'),
('96bcd50a-be9f-4e79-aec7-9228792fec15','提舉道祖監丞愛靈隱泉之景因廣其地可置坐席賦詩見貺極有雅味次韻奉謝','呂陶','宋','宋诗','song-poetry','','[]','巘溜涓涓在目前，更開餘地助賓筵。',64,'全唐诗/poet.song.38000.json','["巘溜涓涓在目前，更開餘地助賓筵。", "方池可鑑無深淺，罇酒相逢有聖賢。", "每爲野情貪勝概，暫憑清味滌塵緣。", "何時學得琴書趣，一寫林間石上泉。"]'),
('e6f89597-17aa-44b1-8ff8-b2e3baedd2d1','登兜率寺閣次薛道祖韻','呂陶','宋','宋诗','song-poetry','','[]','乘閒極望興悠哉，遠眼宜於此處開。',64,'全唐诗/poet.song.38000.json','["乘閒極望興悠哉，遠眼宜於此處開。", "危磴直穿修竹徑，虛窗深占白雲堆。", "江湖有景侵平野，棟宇何年倚巨材。", "自是登髙乃能賦，誰嗟古往與今來。"]'),
('70df231c-3069-4b08-b90b-c165b38605fc','道祖訪趙太賓舊居惜其荒毁慨然賦詩有懷賢念往之深意次韻','呂陶','宋','宋诗','song-poetry','','[]','經濟書成秘府收，依然蓬蓽在巖丘。',64,'全唐诗/poet.song.38000.json','["經濟書成秘府收，依然蓬蓽在巖丘。", "淒凉往事慵開卷，想像髙風合倚樓。", "山色無言終日見，泉聲有恨爲誰留。", "懷賢訪古閒中味，宜與詩人作勝遊。"]'),
('1d44636e-711f-41d9-b867-0c222d0ff6c0','道祖示及遠祖刻像及唱和佳什次韻','呂陶','宋','宋诗','song-poetry','','[]','山深縣古蜀江濱，往哲聲華尚未湮。',64,'全唐诗/poet.song.38000.json','["山深縣古蜀江濱，往哲聲華尚未湮。", "物外低昂應絕品，榜間廋硬亦通神。", "名稱三鳯古爲瑞，書倣二家今有人。", "首唱繼酬皆盛事，通泉從此識陽春。"]'),
('6a91d930-84ae-44d4-a0aa-12579d3f8e7e','清風閣晚景','呂陶','宋','宋诗','song-poetry','','[]','晚際閒將景物看，郡人休笑苦憑闌。',64,'全唐诗/poet.song.38000.json','["晚際閒將景物看，郡人休笑苦憑闌。", "遠山露色知晨霽，素月籠光報夜寒。", "野燒順風穿絕頂，漁舟随浪轉長灘。", "故鄉回首七百里，歸去不辭行路難。"]'),
('7bee6620-7dce-40e5-8518-8d8224d7a1e0','伏承原伯安撫侍郎爲江雨所阻未即會見遠寄雅章深叙勤眷次韻奉答','呂陶','宋','宋诗','song-poetry','','[]','憑髙日日望交遊，方寸飄如一葉舟。',64,'全唐诗/poet.song.38000.json','["憑髙日日望交遊，方寸飄如一葉舟。", "文酒相從期賦詠，江山何事尚遲留。", "洲中橘熟輝晴晝，潭上花繁送暮秋。", "南路士民應有語，旌麾早晚到吾州。"]'),
('fc552933-403a-49e3-89c8-ad78085ca7aa','和寄景仁致政侍郎','呂陶','宋','宋诗','song-poetry','','[]','文章道德有源流，進退瀟然信自由。',64,'全唐诗/poet.song.38000.json','["文章道德有源流，進退瀟然信自由。", "身在禁林方倚望，年侵老景便歸休。", "素雲收雨還層岫，勁柏凌霜茂晚秋。", "何日家山縱吟賞，閒中情味更優游。"]'),
('7bfd5c22-486f-4372-93e7-3916bf182812','榴花','呂陶','宋','宋诗','song-poetry','','[]','十分紅色占亭臺，不恨春風不許開。',64,'全唐诗/poet.song.38000.json','["十分紅色占亭臺，不恨春風不許開。", "摺疊染成隨日麗，芳菲過後爲時來。", "賦詩多是題千葉，醸酒誰能飲百杯。", "翠蕚丹鬚無計學，佳人屢把絳紗裁。"]'),
('07a3833a-b272-464b-8356-029755597491','殘葉和韻','呂陶','宋','宋诗','song-poetry','','[]','秋光何事易陵侵，不許芳條展茂陰。',64,'全唐诗/poet.song.38000.json','["秋光何事易陵侵，不許芳條展茂陰。", "曉色向風生别意，夜聲隨雨入愁吟。", "已嗟禽鳥幽棲淺，漸失園林幾處深。", "榮謝循環都物理，肯將零落動予心。"]'),
('565f1b83-4b1d-4e07-97d5-cd501cdd1cd7','和禮部孔經甫齋宫三首  其一','呂陶','宋','宋诗','song-poetry','','[]','試思離合數光陰，日月消磨世累侵。',64,'全唐诗/poet.song.38000.json','["試思離合數光陰，日月消磨世累侵。", "晚歲心懷如止水，舊交情分敵兼金。", "相從不厭春壇遠，共語誰知夜漏深。", "頻閲來書諭勤意，愧無青玉報璆琳。"]'),
('3eb5ff83-fcbe-4a7a-8561-46011577bf1d','和禮部孔經甫齋宫三首  其二','呂陶','宋','宋诗','song-poetry','','[]','讀書到老應成癖，了事他人莫笑癡。',64,'全唐诗/poet.song.38000.json','["讀書到老應成癖，了事他人莫笑癡。", "敲印舊曹煩夜直，看花新句感春熙。", "已聞騏驥騰千里，應許鷦鷯附一枝。", "薦牘屢交虛席久，壎篪應喜共君吹。"]'),
('7ed1e09b-38c1-41aa-a374-e4e811235a9c','和禮部孔經甫齋宫三首  其三','呂陶','宋','宋诗','song-poetry','','[]','嘗馳别乘走龍沙，過盡春寒始到家。',64,'全唐诗/poet.song.38000.json','["嘗馳别乘走龍沙，過盡春寒始到家。", "已置功名如外物，只憑詩酒作生涯。", "迴頭忽上青雲路，洗眼重看紫禁花。", "百日絲綸君定掌，文章從此燦朝霞。"]'),
('eace35af-fd76-445f-93c4-367ba78d63b4','瑞聖園齋宫','呂陶','宋','宋诗','song-poetry','','[]','苑鑰重開不禁闌，眼前芳景未凋殘。',64,'全唐诗/poet.song.38000.json','["苑鑰重開不禁闌，眼前芳景未凋殘。", "仙花笑日欲爭媚，禁柳受風疑怯寒。", "詩興似春多麗藻，齋心如水自澄瀾。", "憑君賦盡園中景，免向綃圖指點看。"]'),
('03fd0bd6-06fd-4d4e-b356-c5676a281357','致齋北園因記舊遊書呈經甫','呂陶','宋','宋诗','song-poetry','','[]','齋館深沈舊苑開，嘗從祀事偶參陪。',64,'全唐诗/poet.song.38000.json','["齋館深沈舊苑開，嘗從祀事偶參陪。", "故人已步青雲去，倦客還尋紫陌來。", "清景暫將塵慮滌，流年長恨物華催。", "唱酬不講詩情懶，獨對風光彊剪裁。"]'),
('3beb148d-5163-4d80-8625-f702009254ff','與臺中同飲答諫院王明叟','呂陶','宋','宋诗','song-poetry','','[]','休沐無多欵聚難，暫留佳客解朝冠。',64,'全唐诗/poet.song.38000.json','["休沐無多欵聚難，暫留佳客解朝冠。", "鰕頭泛酒罇前樂，麈尾生風席上寒。", "陪集敢誇言路盛，詼諧漸覺醉鄉寛。", "敲門又報青蒲信，捧得新詩似執桓。"]'),
('ecc54349-549c-4700-a996-5d4d397735e2','再和','呂陶','宋','宋诗','song-poetry','','[]','温風一袖己董然，燕坐何須更整冠。',64,'全唐诗/poet.song.38000.json','["温風一袖己董然，燕坐何須更整冠。", "沈李杯盤聊避暑，飲冰懷抱暫生寒。", "縱談無間情相照，清句難酬韻不寛。", "莫笑未曛車馬散，嘗聞陳仲諷齊桓。"]'),
('d797d300-1c76-4963-9d74-25f4b256b513','同文館諸君遊金明池','呂陶','宋','宋诗','song-poetry','','[]','春風拂拂動輕陰，四望歡聲雜雅音。',64,'全唐诗/poet.song.38000.json','["春風拂拂動輕陰，四望歡聲雜雅音。", "人在華胥無限樂，路經蓬島幾重深。", "潛鱗可羡游靈沼，巧舌時聞轉上林。", "况有賜罇堪一醉，百愁從此定消沈。"]'),
('54a52bcd-fcc3-4530-a825-f4143932bb45','和觀瑞聖宫殿有感','呂陶','宋','宋诗','song-poetry','','[]','屬車何日泛塵清，舊苑沈沈隔禁城。',64,'全唐诗/poet.song.38000.json','["屬車何日泛塵清，舊苑沈沈隔禁城。", "别殿未聞天蹕響，華封常聽寶鸞聲。", "禽魚欲遂靈臺樂，燕雀終期大厦成。", "敢告冬官舉常職，莫將池籞等閒輕。"]'),
('d49db7e2-5c2f-4623-bee4-d3bc4a2e576a','次韻芸叟燕瓊林苑','呂陶','宋','宋诗','song-poetry','','[]','御水休論九曲池，宫花爭發萬年枝。',64,'全唐诗/poet.song.38000.json','["御水休論九曲池，宫花爭發萬年枝。", "長虹駕浪人間去，大翼乘風海際垂。", "均被上恩容燕集，共憐嘉景事遊嬉。", "願公早獻金明賦，紀述吾朝全盛時。"]'),
('f51f1f03-464f-4310-be2d-b89eb55b221b','和芸叟左司被資治通鑑之賜感事賦詩','呂陶','宋','宋诗','song-poetry','','[]','廟席詞林一二臣，校讎撰述體惟均。',64,'全唐诗/poet.song.38000.json','["廟席詞林一二臣，校讎撰述體惟均。", "聖心欲以古爲鑑，史法有如王次春。", "神武略中書事類，天和覽後得名新。", "羡君受此傳家寶，遺與兒孫似昔人。"]'),
('70676a3f-23d1-4774-ac45-40d504712948','和彦常舍人元夕扈從二首  其一','呂陶','宋','宋诗','song-poetry','','[]','東風將暖不鳴條，霽景曈曈薄霧銷。',64,'全唐诗/poet.song.38000.json','["東風將暖不鳴條，霽景曈曈薄霧銷。", "五隊繡衣華廣陌，一聲天蹕振層霄。", "清塵少拂鸞旗動，紫氣長隨鳳蓋飄。", "向晚都人相與語，更誇明日似今朝。"]'),
('b7960bda-cbc7-41a2-9680-45034d481ff3','和彦常舍人元夕扈從二首  其二','呂陶','宋','宋诗','song-poetry','','[]','羽衛森然翠輦平，仰贍天步出西清。',64,'全唐诗/poet.song.38000.json','["羽衛森然翠輦平，仰贍天步出西清。", "月行青道夜如晝，春入皇州花滿城。", "三五良辰傳盛觀，九重歸路沸歡聲。", "君王已向龍樓望，喜奉慈顔酒數行。"]'),
('28f5bba5-c964-4a77-88bc-d8339cabb1b0','己夘冬至後','呂陶','宋','宋诗','song-poetry','','[]','月律潛萌斗柄移，陽和氣象等閑知。',64,'全唐诗/poet.song.38000.json','["月律潛萌斗柄移，陽和氣象等閑知。", "五雲已驗天心順，一刻先添日腳遲。", "燕雁待時思北嚮，嶺梅乘暖發南枝。", "人人盡有春臺興，料得東風不失期。"]');
